export const category = "database";
export const questions = [{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 索引的底层数据结构","content":"为什么 MySQL InnoDB 使用 B+ 树而不是 B 树或红黑树作为索引结构？","answer":"答案：B+ 树在范围查询和磁盘 IO 上优于 B 树和红黑树\n\n解析：B+ 树相比 B 树的优势 1）只有叶子节点存数据，非叶子节点只存键，单节点可存更多索引项，树高度低（3-4 层即可支持千万级数据，范围查询仅 3-4 次 IO）2）叶子节点用链表连接，范围查询只需遍历链表，无需中序遍历。红黑树是二叉树，高度 logN，大数据量下 IO 次数远多于 B+ 树。\n\n扩展延伸：聚簇索引（InnoDB 主键）的叶子节点存整行数据，二级索引叶子节点存主键值。回表查询：二级索引查到主键 → 再查聚簇索引。覆盖索引：查询字段在二级索引中已包含，无需回表。索引下推（ICP）：MySQL 5.6 优化，在索引遍历时提前过滤，减少回表次数。","hints":["磁盘 IO 和树高度的关系","B+ 树的叶子节点链表怎么优化范围查询"],"tags":["MySQL","索引"],"company":"美团","id":1331},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 事务隔离级别","content":"请解释 MySQL 的四种事务隔离级别及其解决的问题。","answer":"答案：读未提交、读已提交、可重复读（MySQL 默认）、串行化\n\n解析：隔离级别由低到高：读未提交→脏读、不可重复读、幻读都可能；读已提交→避免了脏读，不可重复读和幻读可能；可重复读→脏读和不可重复读已避免，幻读可能（InnoDB 的 MVCC + Next-Key Lock 在 RR 级别基本解决了幻读）；串行化→全部解决，但并发极低。\n\n扩展延伸：MVCC（多版本并发控制）通过 undo log 实现数据多版本，每条记录有事务 ID 和回滚指针。Read View 决定事务能看到哪个版本。Next-Key Lock = 行锁 + Gap Lock（间隙锁），是 InnoDB 在 RR 级别防止幻读的关键。","hints":["MVCC 如何实现不同隔离级别","间隙锁（Gap Lock）解决什么问题"],"tags":["MySQL","事务","并发"],"company":"美团","id":1332},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 慢查询排查与优化","content":"线上 SQL 查询突然变慢，你怎么排查和优化？","answer":"答案：慢查询日志 → EXPLAIN 分析执行计划 → 优化索引/SQL\n\n解析：排查流程 1）set global slow_query_log=ON 开启慢查询 2）分析慢日志，找到耗时 SQL 3）EXPLAIN SQL 看 type（ALL=全表扫描需优化→range→ref→const）、rows（扫描行数）、Extra（Using filesort/Using temporary=需要优化）4）确认是否缺索引或索引失效。常见索引失效：函数操作、隐式类型转换、LIKE '%xx'、OR 条件、联合索引未用最左前缀。\n\n扩展延伸：优化策略 a）覆盖索引消除回表 b）大分页优化：select * from t WHERE id > 10000 LIMIT 10 而非 LIMIT 100000,10 c）分批处理大量数据 d）读写分离减轻主库压力 e）必要时上缓存（Redis）。线上操作规范：先在测试环境 EXPLAIN，大表加索引用 pt-osc（在线 DDL 工具）。","hints":["EXPLAIN 的 type 字段有哪些值，分别代表什么","为什么 LIMIT 100000,10 比 LIMIT 10 慢很多"],"tags":["MySQL","排查","性能"],"company":"美团","id":1333},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 的数据结构和应用场景","content":"请列举 Redis 的常用数据类型及对应的典型应用场景。","answer":"答案：String/Hash/List/Set/ZSet，每种对应不同场景\n\n解析：String—缓存（set/get）、计数器（incr）、分布式锁（setnx）。Hash—存储对象字段（用户信息），省内存且可单独更新字段。List—消息队列（LPUSH+BRPOP）、最新列表（LPUSH+LTRIM）。Set—标签/去重、共同关注（sinter 交集）。ZSet—排行榜（score 排序）、延迟队列（按时间戳排序）。\n\n扩展延伸：高级数据结构 Bitmap（签到统计、布隆过滤器）、HyperLogLog（UV 统计，12KB 存 2^64 唯一值）、Geo（地理位置、附近的人）。Redis 单线程模型为什么快？纯内存操作 + IO 多路复用 + 避免上下文切换，但单个 key 不应存过大（超过 10MB 会阻塞）。","hints":["ZSet 底层跳表（Skip List）的原理","Redis 单线程模型如何处理并发请求"],"tags":["Redis","缓存"],"company":"美团","id":1334},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 分布式锁的实现与陷阱","content":"用 Redis 实现分布式锁需要注意哪些问题？Redlock 算法是什么？","answer":"答案：核心坑：锁超时、不可重入、主从切换导致锁丢失\n\n解析：正确实现：SET key uuid NX PX 30000（原子操作设值和过期时间）。UUID 作为 value 用于释放时校验（防止释放别人锁）。释放用 Lua 脚本确保原子性（先 get 比较再 del）。注意事项：1）过期时间需大于业务执行时间，否则需看门狗（Watch Dog）续期 2）不可重入需额外支持 3）主从架构下 master 宕机后 slave 未同步锁信息，新 master 被其他客户端加锁。\n\n扩展延伸：Redlock 是 Redis 官方的分布式锁算法，在大多数（N/2+1）节点上成功加锁才算成功，适用于需要严格互斥的场景。但 Redlock 也有争议（时钟漂移问题），分布式一致性要求极高的场景建议用 ZooKeeper 的临时顺序节点实现锁。","hints":["释放锁时为什么用 Lua 脚本","主从切换导致锁丢失怎么解决"],"tags":["Redis","分布式","锁"],"company":"美团","id":1335},{"category":"database","difficulty":"easy","type":"short_answer","title":"MySQL 三大日志：binlog、redo log、undo log","content":"请解释 MySQL 的 binlog、redo log、undo log 各自的作用。","answer":"答案：redo log 保证崩溃恢复（crash-safe），binlog 用于备份和主从同步，undo log 实现事务回滚和 MVCC\n\n解析：redo log（InnoDB 特有，物理日志）记录「做了什么修改」，事务提交时先写 redo log 再刷盘（WAL——Write-Ahead Logging），崩溃后重放恢复。binlog（Server 层，逻辑日志）记录 SQL 语句或行变更，用于主从同步和时间点恢复。undo log（逻辑日志，反向记录）用于事务回滚和 MVCC 的快照读。\n\n扩展延伸：两阶段提交（2PC）保证 redo log 和 binlog 的一致性——prepare 阶段写 redo log，commit 阶段写 binlog。崩溃恢复时比较两个日志的状态，决定事务是提交还是回滚。这样主从数据才不会不一致。","hints":["为什么 MySQL 需要两份日志（redo + binlog）","两阶段提交如何保证主从一致"],"tags":["MySQL","基础"],"company":"美团","id":1336},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 缓存穿透、击穿、雪崩","content":"请解释缓存穿透、缓存击穿、缓存雪崩的区别及应对方案。","answer":"答案：穿透→查询不存在数据；击穿→热点 key 过期；雪崩→大量 key 同时过期或 Redis 宕机\n\n解析：缓存穿透：查询的 key 在缓存和 DB 都不存在，请求直接打到 DB。方案：布隆过滤器（Bloom Filter）拦截不存在 key 或缓存空值（短过期时间）。缓存击穿：某一热点 key 过期，高并发全部打到 DB。方案：互斥锁（setnx）保证只有一个线程查 DB 重建缓存；或逻辑过期（value 里存过期时间，异步刷新）。缓存雪崩：大量 key 集中过期或 Redis 挂掉。方案：过期时间加随机值分散、多级缓存（本地 + 远程）、Redis 高可用（主从/集群）。\n\n扩展延伸：布隆过滤器原理：多个哈希函数映射到 bit 数组，判断「一定不存在」或「可能存在」。存在误判率（false positive），可通过调整位数组大小和哈希函数数量控制。Google Guava 的 BloomFilter 可算最优参数。","hints":["布隆过滤器为什么说「一定不存在」和「可能存在」","互斥锁方案在高并发下性能如何"],"tags":["Redis","缓存","高并发"],"company":"美团","id":1337},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 死锁场景与排查","content":"描述一个常见的 MySQL 死锁场景，以及如何排查和处理。","answer":"答案：最常见的是两个事务以不同顺序加锁导致互相等待\n\n解析：场景：事务 A：UPDATE t SET x=1 WHERE id=1 → UPDATE t SET x=2 WHERE id=2。事务 B：UPDATE t SET x=3 WHERE id=2 → UPDATE t SET x=4 WHERE id=1。互相持有对方需要的锁。排查：SHOW ENGINE INNODB STATUS 查看 LATEST DETECTED DEADLOCK 部分，输出中会显示两个事务各自持有和等待的锁。\n\n扩展延伸：InnoDB 自动检测死锁并使其中一个事务回滚（代价更小者）。预防策略 1）所有事务以相同顺序访问资源 2）尽量缩短事务时间，减少锁持有 3）合理设置隔离级别 4）使用等值查询而非范围查询（减少间隙锁冲突）。事务中快排查，才是最好的防死锁策略。","hints":["SHOW ENGINE INNODB STATUS 的输出怎么看","为什么等值查询比范围查询更少死锁"],"tags":["MySQL","事务","排查"],"company":"美团","id":1338},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis 持久化机制","content":"请比较 Redis 的 RDB 和 AOF 持久化方式，各自优缺点和适用场景。","answer":"答案：RDB 是快照，AOF 是追加写日志\n\n解析：RDB 定期将内存数据 dump 到磁盘，文件紧凑适合备份和全量恢复。缺点是宕机可能丢失上次快照后的数据，fork 子进程进行 BGSAVE 时如果数据量大可能耗时。AOF 记录每次写命令，数据安全度高（可配 always 每秒），文件可重写压缩。缺点是文件通常比 RDB 大，恢复速度比 RDB 慢。\n\n扩展延伸：Redis 4.0 起支持混合持久化——RDB 做全量快照 + 增量 AOF 日志，既保证重启快速加载，又保证数据安全性。生产建议：开启混合持久化，同时配置 AOF fsync 每秒一次。主从复制中从节点也建议开启持久化，但应优先保证主节点性能。","hints":["RDB 的 BGSAVE 和 COW（写时复制）原理","AOF 重写（rewrite）做了什么"],"tags":["Redis","基础"],"company":"美团","id":1339},{"category":"database","difficulty":"hard","type":"short_answer","title":"分库分表策略","content":"什么时候需要分库分表？分片键如何选择？分页/跨分片查询怎么处理？","answer":"答案：单表数据量过大（MySQL 建议不超过千万级）或 QPS 过高时考虑分库分表\n\n解析：分库分表策略 1）垂直分库：按业务模块拆分（用户库/订单库）2）水平分表：同结构多表，按分片键取模或范围。分片键选择原则：业务最常用的查询条件（用户 ID 或订单 ID），保证大多数查询路由到单一分片。跨分片查询：尽量避免（违背分片初衷），可通过全局表（字典类数据不改动）+ 冗余字段（如订单表存用户名避免 join）。\n\n扩展延伸：分页难题 a）全局排序后取 offset+N → 各分片查 offset+N 条再归并，性能差 b）业务妥协：禁止深度分页、只用游标分页（WHERE id > last_id LIMIT 10）。常用中间件：ShardingSphere、MyCat。更现代的方案：TiDB（分布式 NewSQL）自动分片，对应用透明。","hints":["分片键为什么选用户 ID 或订单 ID","分布式 ID 生成方案有哪些（雪花算法）"],"tags":["MySQL","分布式","架构"],"id":1340},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL InnoDB 中的聚簇索引","content":"关于 MySQL InnoDB 的聚簇索引（Clustered Index），以下哪个说法是正确的？","options":["A) 每张表可以有多个聚簇索引","B) 聚簇索引的叶子节点存储整行数据","C) 聚簇索引默认使用 B 树而非 B+ 树","D) 不指定主键时 InnoDB 不会创建聚簇索引"],"answer":"答案：B) 聚簇索引的叶子节点存储整行数据\n\n解析：InnoDB 的聚簇索引（主键索引）叶子节点直接存储整行数据，因此通过主键查询只需一次 B+ 树查找即可拿到完整数据。每张表只能有一个聚簇索引（数据物理排列方式只能有一种）。如果不指定主键，InnoDB 会选第一个 UNIQUE NOT NULL 列作为聚簇索引，如果没有则自动生成隐藏的 ROW_ID。\n\n扩展延伸：二级索引（非聚簇索引）的叶子节点存储主键值，通过二级索引查询需要「回表」——先查到主键再到聚簇索引查完整数据。覆盖索引就是在二级索引中已包含查询所需的所有字段，避免了回表。","hints":["为什么一张表只能有一个聚簇索引","回表查询是什么意思"],"tags":["MySQL","索引"],"company":"美团","id":1341},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 的过期删除策略","content":"Redis 对已过期的 key 使用什么策略来删除？","options":["A) 定时删除，每隔 100ms 扫描全部 key","B) 惰性删除 + 定期删除","C) 只靠惰性删除，访问时检查","D) 当内存满时一次性全部删除过期 key"],"answer":"答案：B) 惰性删除 + 定期删除\n\n解析：Redis 采用两种策略结合：定期删除（每 100ms 随机抽取部分设置了过期时间的 key 检查并删除）和惰性删除（访问 key 时检查是否过期，过期则删除）。定期删除避免集中扫描全库造成卡顿，惰性删除兜底避免过期 key 长期占用内存。\n\n扩展延伸：即使有两种策略，当大量 key 同时过期而删除不及时，Redis 内存可能被写满。此时 Redis 的内存淘汰策略（eviction）生效：noeviction（默认，写入返回错误）、allkeys-lru（淘汰最近最少用）、volatile-ttl（淘汰剩余 TTL 最短的）等。生产推荐 allkeys-lru 或 allkeys-lfu。","hints":["定期删除为什么不是定时遍历全部 key","内存淘汰策略和过期删除策略的区别"],"tags":["Redis","缓存"],"company":"美团","id":1342},{"category":"database","difficulty":"easy","type":"choice","title":"SQL 中 JOIN 查询的类型","content":"以下哪个 SQL JOIN 会返回左表中所有记录以及右表中匹配的记录？","options":["A) INNER JOIN","B) LEFT JOIN","C) RIGHT JOIN","D) FULL OUTER JOIN"],"answer":"答案：B) LEFT JOIN（LEFT OUTER JOIN）\n\n解析：LEFT JOIN 保留左表全部记录，右表无匹配时返回 NULL。INNER JOIN 只返回两表匹配的记录。RIGHT JOIN 保留右表全部。FULL OUTER JOIN 保留两表全部记录。MySQL 不支持 FULL OUTER JOIN，可通过 LEFT JOIN + UNION + RIGHT JOIN 模拟。\n\n扩展延伸：在 SQL 优化中，应优先使用 INNER JOIN（结果集最小，扫描数据少）。LEFT JOIN 要确保右表关联字段有索引，否则全表扫描性能极差。注意：LEFT JOIN 加上 WHERE 右表字段非空条件会隐式转为 INNER JOIN——因为 NULL 比较永远为 FALSE。","hints":["LEFT JOIN 加上 WHERE 右表 IS NOT NULL 会怎样","MySQL 为什么不支持 FULL OUTER JOIN"],"tags":["MySQL","SQL"],"id":1343},{"category":"database","difficulty":"easy","type":"true_false","title":"Redis 单线程模型","content":"Redis 在 6.0 版本后完全改为多线程模型，所有操作都由多线程执行。","options":["正确","错误"],"answer":"答案：错误\n\n解析：Redis 6.0 引入了多线程 IO（网络读写由多线程处理），但核心的命令执行（命令解析、数据操作）仍然是单线程的。多线程 IO 解决了网络读写瓶颈（大报文收发），而核心操作保持单线程避免了并发竞争问题。Redis 7.0 进一步优化了多线程 IO 的效率和灵活性。\n\n扩展延伸：Redis 单线程模型为什么快？1）纯内存操作 2）IO 多路复用（epoll）3）避免线程切换和锁竞争。即使核心是单线程，单个 key 的操作过长（如 KEYS、HGETALL 大 hash）会阻塞其他请求。Redis 6/7 的多线程 IO 默认关闭（io-threads-do-reads no），需手动配置启用。","hints":["Redis 6.0 到底哪些部分变成多线程了","单线程模型为什么 redis 性能仍然很高"],"tags":["Redis","基础"],"company":"美团,腾讯","id":1344},{"category":"database","difficulty":"easy","type":"true_false","title":"数据库索引会降低写入性能","content":"数据库表中建立的索引越多，数据的插入、更新和删除操作就越慢。","options":["正确","错误"],"answer":"答案：正确\n\n解析：索引维护需要额外的开销：INSERT 需要在所有索引中插入新记录，UPDATE 可能涉及索引列的修改（删除旧索引条目 + 插入新条目），DELETE 需要在所有索引中删除对应记录。索引越多，写入操作涉及的索引维护就越多，性能下降越明显。\n\n扩展延伸：索引优化的 trade-off：读多写少的场景可以适当多建索引（覆盖查询），写多读少的场景要严格控制索引数量。常见优化：联合索引代替多个单列索引（减少索引数量同时覆盖多查询条件），冗余索引清理（如已有 (a,b) 联合索引则不需要单独的 a 索引）。","hints":["索引维护在写入时具体做了哪些操作","联合索引和最左前缀原则"],"tags":["MySQL","索引"],"company":"美团","id":1345},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Join 算法","content":"请介绍 MySQL 执行 JOIN 查询的几种算法及优化策略。","answer":"答案：MySQL 支持 Nested Loop Join、Hash Join（MySQL 8.0.18+）、Batched Key Access（BKA）三种 JOIN 算法。\n\n解析：1）Nested Loop Join（NLJ）——驱动表逐行匹配被驱动表，被驱动表有索引时高效（Index Nested-Loop Join），无索引时全表扫描极慢（Simple Nested-Loop Join）。Block Nested-Loop Join（BNL）优化：将驱动表的多行缓存到 Join Buffer 中批量匹配。2）Hash Join（MySQL 8.0.18+）——将小表构建哈希表，大表逐行探测。适用于等值 JOIN、被驱动表无索引的场景，性能远超 NLJ。MySQL 8.0 在 ON 条件无索引时自动选择 Hash Join。3）Batched Key Access（BKA）——从被驱动表批量获取主键后再回表（配合 MRR，Multi-Range Read 优化），减少随机 IO。\n\n扩展延伸：JOIN 优化核心原则：1）小表驱动大表——驱动表越小，匹配次数越少 2）JOIN 字段建索引——被驱动表的关联字段必须有索引（否则退化成 BNL 或全表扫描）3）只 SELECT 需要的字段——减少 Join Buffer 和网络传输 4）EXPLAIN 的 Extra 列出现 Using join buffer (Block Nested Loop) 说明需要优化索引。MySQL 8.0 移除 BNL 后 Hash Join 成为无索引 JOIN 的默认选择。","hints":["为什么小表驱动大表能提升 JOIN 性能","Hash Join 在什么条件下比 Nested Loop Join 更优"],"tags":["MySQL","JOIN","优化"],"id":1346},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 优化器与执行计划","content":"MySQL 优化器如何选择执行计划？SQL 提示（Hint）和统计信息的作用是什么？","answer":"答案：MySQL 优化器基于表的统计信息（行数、索引基数、数据分布）估算各执行计划成本，选择成本最低的计划。SQL Hint 可强制优化器走特定路径，但应谨慎使用。\n\n解析：优化器决策过程：1）语法解析和语义检查 2）查询重写（子查询展开、谓词下推、常量折叠等）3）生成多个候选执行计划（各索引选择、JOIN 顺序）4）基于统计信息估算每个计划的成本（IO 成本 + CPU 成本）5）选择成本最低的计划。统计信息：InnoDB 通过随机采样（默认 20 个 B+ 树页面）估算索引基数，ANALYZE TABLE 可手动更新。统计信息过时会导致选错索引。SQL Hint：FORCE INDEX（强制走某索引）、IGNORE INDEX（忽略某索引）、STRAIGHT_JOIN（固定 JOIN 顺序）。\n\n扩展延伸：优化器的局限性：1）统计信息不准确导致选错索引——可 ANALYZE TABLE 更新统计，或手动 FORCE INDEX。2）OR 条件难以优化——MySQL 通常无法对 OR 条件使用索引合并（Index Merge），建议用 UNION ALL。3）深度分页优化器不知道业务语义——LIMIT 100000,10 仍然扫描 100010 行。优化器参数：optimizer_switch 可开启/关闭各种优化特性（如 hash_join=on、index_merge=on）。生产建议：上线前用 EXPLAIN 验证关键 SQL 的执行计划，首次发现 Using filesort/Using temporary 应立即优化。","hints":["统计信息过时会导致什么问题","FORCE INDEX 在什么场景下是必要的"],"tags":["MySQL","优化器","执行计划"],"id":1347},{"category":"database","difficulty":"easy","type":"short_answer","title":"数据库连接池配置","content":"请介绍 HikariCP 连接池的核心配置参数和调优建议。","answer":"答案：HikariCP 是目前性能最好的 Java 数据库连接池（Spring Boot 2.x+ 默认）。核心参数：maximumPoolSize（最大连接数）、minimumIdle（最小空闲数）、connectionTimeout（获取连接超时）、idleTimeout（空闲超时）、maxLifetime（最大生命周期）。\n\n解析：HikariCP 的设计哲学：轻量级、高性能。核心优化：1）代码级优化——字节码精简（减少代理层）、FastList（替代 ArrayList 提升 Statement 关闭性能）、ConcurrentBag（无锁集合，比 LinkedBlockingQueue 更优）。2）参数调优：maximumPoolSize——不是越大越好，HikariCP 作者建议公式：pool_size = Tn × (C - 1) + 1（Tn = CPU 核数，C = 单连接队列深度），一般在线程池大小附近即可（如 4C8G 服务器设 10-20）。connectionTimeout——默认 30 秒，快速失败场景可设 5 秒。maxLifetime——默认 30 分钟，建议小于数据库侧连接超时（如 MySQL wait_timeout=28800s，HikariCP maxLifetime 设 60000ms）。\n\n扩展延伸：连接池监控：Spring Boot Actuator 暴露 /actuator/health 查看连接池状态。关键指标：active（活跃连接数，<80% maximumPoolSize 正常）、idle（空闲连接数）、pending（等待连接的线程数，>0 说明连接池不够或慢 SQL 多）、timeout（连接获取超时次数）。生产告警：active 持续高水位 + pending > 0 应立即排查。注意：连接池泄漏（Connection Not Returned）是最常见问题——确保 try-with-resources 或 finally 中关闭连接。","hints":["为什么 HikariCP 比 C3P0/Druid 快","maximumPoolSize 设得越大性能越好吗"],"tags":["MySQL","HikariCP","连接池"],"id":1348},{"category":"database","difficulty":"medium","type":"short_answer","title":"NoSQL 数据库选型对比","content":"请对比 MongoDB、Cassandra、Redis 的适用场景和数据模型差异。","answer":"答案：MongoDB 适合文档型灵活 schema 和快速迭代，Cassandra 适合高写入吞吐的时序/日志场景，Redis 适合缓存和实时数据处理。\n\n解析：1）MongoDB——文档数据库（BSON JSON 格式），灵活 schema、二级索引、聚合管道、副本集 + 分片。适合：内容管理、用户画像、日志、物联网（schema 多变场景）。不适合：复杂事务、多表 JOIN（MongoDB 4.0+ 支持多文档事务但性能有限）。2）Cassandra——宽列存储，LSM-Tree 写入极快、可线性扩展（加节点 = 加性能）、无单点故障。适合：时序数据（监控/指标）、消息/日志、IoT 传感器数据。不适合：复杂查询（需按 Partition Key 查询）、强一致性要求。3）Redis——内存 KV 存储，丰富的数据结构、毫秒级延迟、发布订阅。适合：缓存、会话、排行榜、分布式锁、实时计数器。不适合：大规模数据持久化（内存成本高）、复杂查询。\n\n扩展延伸：选型决策树：需要强事务 + 复杂 JOIN → MySQL/PostgreSQL。灵活 schema + 快速迭代 → MongoDB。高写入吞吐 + 线性扩展 → Cassandra。缓存/实时/计数器 → Redis。全文搜索 → Elasticsearch。图关系 → Neo4j。图数据库（Neo4j/ArangoDB）虽然使用场景集中，但在社交关系、推荐引擎、权限管理中不可替代。多模数据库趋势：PostgreSQL + 插件（TimescaleDB 时序 + PostGIS 空间）可减少技术栈复杂度。","hints":["Cassandra 的 LSM-Tree 相比 B+ 树有什么优势","什么时候不应该用 MongoDB 而应该坚持用 MySQL"],"tags":["NoSQL","MongoDB","Cassandra","Redis","选型"],"id":1349},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 高可用方案对比","content":"请对比 Redis Sentinel 和 Redis Cluster 的架构差异和适用场景。","answer":"答案：Sentinel 提供主从切换的高可用（主从复制 + 哨兵监控），Cluster 提供数据分片 + 高可用（去中心化，自动分片和容错）。\n\n解析：Redis Sentinel（哨兵模式）：1 主 N 从，Sentinel 进程监控主节点健康，主宕机时自动将从节点提升为主。问题：写能力只有单节点容量（内存上限），分片需客户端自己做。Redis Cluster（集群模式）：16384 个哈希槽自动分配到多个主节点，每个主节点有 N 个从节点做 HA。去中心化——所有节点通过 Gossip 协议通信，客户端可连接任意节点，MOVED/ASK 重定向到正确节点。分片：CRC16(key) % 16384 计算槽位，自动迁移槽位实现在线扩缩容。\n\n扩展延伸：选型建议：数据量 < 单节点内存（<32GB）且只需要高可用 → Sentinel（简单稳定）。数据量超过单节点内存、需要水平扩展 → Cluster（自动分片）。Proxy 方案：Twemproxy（Twitter，静态分片，不支持自动故障转移）和 Codis（豌豆荚，支持在线扩缩容，但已停维），现在基本被 Redis Cluster 替代。Redis Cluster 的局限：1）不支持多 key 操作（不同槽位的 key 无法事务/管道）2）批量操作需保证 key 在同一槽位（用 hash tag）3）带宽消耗大（节点间 Gossip 通信）。Redis 7.0 优化了集群链路和迁移机制，减少了迁移期间的阻塞时间。","hints":["Redis Cluster 的 16384 个哈希槽如何分布","为什么 Redis Cluster 不支持跨槽位的事务操作"],"tags":["Redis","高可用","Sentinel","Cluster"],"id":1350},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 主从复制原理与数据一致性","content":"请解释 MySQL 主从复制的原理，以及如何保证从库的数据一致性。","answer":"答案：MySQL 主从复制基于 binlog（二进制日志），主库将数据变更写入 binlog，从库的 IO 线程拉取并写入 relay log，SQL 线程重放 relay log 完成数据同步。\n\n解析：复制流程：1）主库事务提交时写入 binlog（两阶段提交确保 crash-safe）。2）从库 IO 线程连接主库，请求 binlog 的指定偏移量。3）主库 binlog dump 线程发送新的 binlog event。4）从库 IO 线程将 event 写入 relay log（中继日志）。5）从库 SQL 线程读取 relay log 并顺序重放。\n\n复制模式：异步复制（MySQL 默认）——主库提交后立即返回，不等待从库确认，吞吐最高但主库宕机时从库可能丢数据。半同步复制（Semisync）——至少一个从库写入 relay log 后主库才返回，保证不丢数据但增加延迟。组复制（MGR，MySQL Group Replication）——基于 Paxos 的多主复制，强一致性。\n\n扩展延伸：常见问题：1）主从延迟——从库重放是单线程的（MySQL 5.6 后支持并行复制，按数据库/按提交时间分组并行），主库高并发写入时延迟明显。监控：`SHOW SLAVE STATUS` 的 `Seconds_Behind_Master`（但可能不准）。2）数据一致性——主从切换时可能丢数据（异步模式）。GTID（Global Transaction Identifier，MySQL 5.6+）为每个事务分配全局唯一 ID，简化主从切换和故障恢复。3）读写分离——主库写、从库读。问题：从库读到旧数据（主从延迟导致）。方案：对一致性敏感的请求强制走主库、等待从库追上（`WAIT_FOR_EXECUTED_GTID_SET`）、缓存中间层。","hints":["半同步复制在半数从库不响应时会退化为什么模式","Seconds_Behind_Master 为什么在高负载下可能不准"],"tags":["MySQL","主从","复制"],"id":1351},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 底层数据结构详解","content":"请详细解释 Redis 的底层数据结构：SDS、跳表、压缩列表、整数集合。这些结构在什么条件下会转换？","answer":"答案：Redis 的底层数据结构与对外数据类型是两回事。String -> SDS，List -> quicklist（3.2+，之前是 ziplist + linkedList），Hash/Set（有整数时）-> 压缩列表或哈希表，ZSet -> 跳表 + 哈希表。\n\n解析：1）SDS（Simple Dynamic String）——C 字符串的替代。相比 C 字符串的优势：O(1) 获取长度（len 字段）、二进制安全（以 len 而非 \\0 判断结束）、预分配空间减少内存分配次数（小于 1MB 时双倍扩容，大于 1MB 时每次加 1MB）、惰性释放（缩短时多余空间不立即释放）。\n\n2）跳表（Skiplist）——ZSet 的有序部分使用跳表（平均 O(log n) 查找/插入/删除）。多层索引：最底层有序链表，上层是稀疏索引。Redis 的跳表实现：最大层数 32，每次插入时随机计算层数（1/4 概率上升一层）。相比平衡树：实现简单、范围查询高效、无需复杂的旋转操作。\n\n3）压缩列表（ziplist）——Hash 和 ZSet 在元素数少且值小时使用的紧凑内存结构。内存连续、减少碎片。缺点是插入删除可能引发连锁更新（长度变化导致后续所有节点长度编码扩展）。Hash 的阈值：field 数 < 512 且每个 field/value < 64 字节。\n\n4）整数集合（intset）——Set 中元素全是整数且数量不大时使用。自动升级编码（int16 → int32 → int64），节省内存。\n\n扩展延伸：数据结构的转换：Hash 的 ziplist → hashtable 转换条件：field 数 > 512 或某个 field/value > 64 字节。ZSet 的 ziplist → skiplist 转换条件：元素数 > 128 或某个 member 长度 > 64 字节。Redis 7.0 引入 listpack 替代 ziplist——listpack 解决了连锁更新问题（每个元素不再保存前一个元素的长度，而是保存自身长度），使编码更稳定。Redis 的 key-value 总用哈希表存（全局 dict），value 用具体结构。","hints":["跳表相比红黑树的优势是什么","ziplist 的连锁更新问题在什么情况下触发"],"tags":["Redis","数据结构","底层实现"],"id":1352},{"category":"database","difficulty":"hard","type":"short_answer","title":"多模型混合架构：SQL + NoSQL + Cache","content":"请设计一个混合存储架构：在什么场景下同时使用 MySQL + Redis + Elasticsearch？如何保证数据一致性？","answer":"答案：MySQL 做核心事务存储（强一致性、ACID），Redis 做缓存（毫秒级读），Elasticsearch 做全文搜索和复杂聚合。三者组合覆盖不同维度的需求。\n\n解析：典型架构：写路径——业务写入 → MySQL（事务提交）→ 同步到 Elasticsearch（canal 消费 binlog）→ 更新/失效 Redis 缓存。读路径——先查 Redis（缓存命中直接返回）→ miss 则查 MySQL/ES → 回填 Redis 后返回。\n\n组件分工：1）MySQL——核心结构化数据：用户账户、订单、交易流水。特点是强一致性、支持事务、复杂 JOIN。2）Redis——热点缓存：用户 session、商品详情（反序列化后）、排行榜。特点是毫秒级响应、支持多种数据结构和 TTL。3）Elasticsearch——搜索服务：商品搜索（分词/排序/过滤）、日志分析（聚合统计）。特点是倒排索引、海量数据近实时查询。\n\n扩展延伸：数据一致性策略：1）最终一致性——MySQL 写成功后通过 binlog 异步同步到 ES 和 Redis，短暂不一致可接受（秒级）。2）强一致性要求——先更新 MySQL，标记缓存失效，切换到「查 MySQL 不回填缓存」模式直到确认同步完成。3）双写问题——MySQL 和 ES/Redis 同时写时可能不一致。解决方案：先写 MySQL，通过 binlog 订阅同步到 ES/Redis（canal + MQ 解耦），保证「以 MySQL 数据为准」。避免先写 ES 再写 MySQL的方式。4）CQRS 模式——写模型用 MySQL，读模型用 ES + Redis，两者通过事件总线异步同步。适用于搜索和报表场景。混合存储的核心原则：每种数据库做自己最擅长的事情，不做数据全量的拷贝。","hints":["为什么通过 canal 监听 binlog 比双写更可靠","混合存储中如何设计缓存淘汰策略"],"tags":["架构","MySQL","Redis","Elasticsearch"],"id":1353},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 锁机制：行锁、间隙锁、意向锁","content":"请详细解释 MySQL InnoDB 的锁机制：行锁（Record Lock）、间隙锁（Gap Lock）、Next-Key Lock、意向锁（Intention Lock）的作用和使用场景。","answer":"答案：InnoDB 的锁机制基于索引实现。行锁锁住索引记录，间隙锁锁住记录间的间隙，Next-Key Lock = 行锁 + 间隙锁（区间左开右闭），意向锁加速表级锁和行级锁的冲突检测。\n\n解析：1）行锁（Record Lock）——锁住索引的某一条记录。只有通过索引条件检索时 InnoDB 才会使用行锁，否则退化为表锁。Update/Delete/Select ... For Update 对扫描到的索引记录加锁。\n\n2）间隙锁（Gap Lock）——锁住两个索引记录之间的间隙（包括不存在的记录），防止幻读。只在 RR（可重复读）隔离级别下生效。间隙锁是纯粹的抑制冲突的锁——它不阻止其他事务加行锁，只阻止其他事务在间隙中插入新行。\n\n3）Next-Key Lock——行锁 + 间隙锁的组合，锁住一个左开右闭的区间（前一个索引值，当前索引值]。InnoDB 在 RR 级别默认使用 Next-Key Lock。示例：对 id=5 的行加 Next-Key Lock，不仅锁住 id=5 这一行，还锁住 (previous_id, 5] 这个区间，阻止其他事务在间隙中插入 id=4.5 的新行。\n\n4）意向锁（Intention Lock）——表级锁，分为意向共享锁（IS，事务打算对某些行加共享锁）和意向排他锁（IX，事务打算对某些行加排他锁）。目的：快速判断表锁和行锁是否冲突。当事务要给整个表加锁时，只需检查是否有 IX/IS 锁，不需要逐行检查。\n\n扩展延伸：加锁分析：等值查询唯一索引——加行锁（无间隙）。等值查询普通索引——加 Next-Key Lock + 行锁。范围查询——对范围内的每个索引加 Next-Key Lock。死锁预防：1）获取锁的顺序一致。2）小事务尽早提交。3）不用 `SELECT ... FOR UPDATE` 扫描多余的行。4）间隙锁在高并发下触发死锁概率较高，可考虑降级为 RC（读已提交）级别（binlog_format = ROW 时 RC 也安全，且没有间隙锁）。","hints":["为什么等值查询唯一索引不产生间隙锁","RR 级别下范围查询的加锁范围如何确定"],"tags":["MySQL","锁","并发"],"id":1354},{"category":"database","difficulty":"easy","type":"short_answer","title":"数据库备份与恢复策略","content":"请介绍数据库的备份策略：全量备份、增量备份、差异备份的区别，以及如何进行时间点恢复（PITR）。","answer":"答案：全量备份保存完整数据，增量备份保存自上次备份以来的变更，差异备份保存自上次全量备份以来的变更。PITR（Point-In-Time Recovery）通过全量备份 + binlog 回放恢复到任意时间点。\n\n解析：1）全量备份（Full Backup）——备份整个数据库或所有表。物理备份（直接复制数据文件，速度快，用 xtrabackup/mysqldump），逻辑备份（导出 SQL 或分隔符文本，跨版本可用）。频率：通常每天一次（凌晨低峰期）。2）增量备份（Incremental Backup）——只备份自上次备份（全量或增量）以来的变更。速度快、占用空间小，但恢复时需要依次恢复全量 → 增量1 → 增量2 → …… 恢复链长，任一增量损坏导致后面不可用。3）差异备份（Differential Backup）——只备份自上次全量备份以来的所有变更。恢复时只需全量 + 最新一次差异。空间比增量大，但恢复简单可靠。\n\n生产策略示例：每周日凌晨 2 点全量备份、每天凌晨 2 点差异备份、每 30 分钟 binlog 备份 + 保留 7 天。PITR 流程：还原最近一次全量备份 → 还原最近的差异备份（或依次还原增量备份）→ 重放 binlog 到目标时间点（`mysqlbinlog --stop-datetime`）。\n\n扩展延伸：MySQL 备份工具对比：1）mysqldump——逻辑备份，`--single-transaction` 对 InnoDB 做一致性快照（不锁表），适合小到中型数据库。2）XtraBackup——物理备份（Percona 出品），支持热备份 InnoDB（不锁库），速度快，适合大型数据库。3）MySQL Shell——MySQL 8.0 的 util.dumpInstance()/util.loadDump() 支持并行备份/恢复。备份验证：定时做恢复演练（至少每月一次），确保备份文件可用。3-2-1 原则：3 份副本、2 种介质（如本地 + 云端）、1 份异地。","hints":["mysqldump 的 --single-transaction 如何保证一致性","为什么增量备份的恢复链越长风险越大"],"tags":["MySQL","备份","恢复"],"id":1355},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 慢查询优化：从 EXPLAIN 到索引优化","content":"当发现 MySQL 查询缓慢时，如何分析和优化？EXPLAIN 输出的关键字段（type、Extra、rows、key）怎么解读？","answer":"答案：MySQL 慢查询优化的标准流程：1）开启慢查询日志识别慢 SQL。2）用 EXPLAIN 分析执行计划。3）根据 type、key、rows、Extra 等字段判断优化方向。4）加索引或改写 SQL。EXPLAIN 输出中 type 从好到差：system > const > eq_ref > ref > range > index > ALL。Extra 出现 Using filesort 或 Using temporary 通常是优化信号。\n\n解析：1）慢查询日志——set global slow_query_log = ON；设置 long_query_time（通常 1 秒）。用 mysqldumpslow 或 pt-query-digest 分析慢查询日志找出最常见的慢 SQL。2）EXPLAIN 解读——type：访问方法，const（唯一索引等值查询）→ ref（普通索引等值查询）→ range（索引范围查询）→ index（索引全扫描）→ ALL（全表扫描）。ALL 是危险信号。key：实际使用的索引，如果为 NULL 表示没有使用索引。rows：预估扫描行数，这个值越小越好（但不精确，只是估算）。Extra：Using index（覆盖索引，好）、Using where（在索引上过滤后还要回表检查条件）、Using filesort（需要额外排序，考虑加排序索引）、Using temporary（使用临时表，通常需要优化）。\n\n扩展延伸：索引优化策略——1）复合索引的最左前缀原则：索引 (a,b,c) 能加速 a、a,b、a,b,c 的查询，但不能加速 b、c 的查询。2）覆盖索引：索引包含查询需要的所有列（Extra 出现 Using index），避免回表。3）索引选择性：SELECT COUNT(DISTINCT col)/COUNT(*) 越高越好（低选择性如性别字段不适合加索引）。4）索引下推（ICP）：MySQL 5.6+ 的优化，减少回表次数。5）MRR（Multi-Range Read）：将随机 IO 转为顺序 IO。避免索引失效的常见情况：对索引列使用函数、隐式类型转换、LIKE 以 % 开头、OR 条件中有非索引列、不等于（!=）操作。","hints":["EXPLAIN 中 type 字段 const->ref->range->index->ALL 的优化级别","什么是覆盖索引——为什么 Extra 显示 Using index 是好事"],"tags":["MySQL","SQL优化","索引","EXPLAIN"],"id":1356},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 分区表","content":"请介绍 MySQL 分区表的原理和类型。分区表适合什么场景？分区在什么情况下反而会降低性能？","answer":"答案：MySQL 分区表将一张大表的数据物理拆分为多个分区，每个分区可以独立管理和存储。分区方式包括：RANGE（按范围）、LIST（按值列表）、HASH（哈希）、KEY（MySQL 内部哈希）。适合需要按时间归档的场景，但不适合跨分区查询和频繁更新的场景。\n\n解析：1）分区类型——RANGE 分区：按连续区间划分，如 PARTITION p2023 VALUES LESS THAN (20240000)。适合按日期、ID 范围归档历史数据。LIST 分区：按离散值列表划分，如 PARTITION p_south VALUES IN ('GD','GX','HN')。HASH 分区：按用户定义表达式的哈希值取模，适合均匀分布数据。KEY 分区：类似 HASH 但由 MySQL 内置哈希函数处理。2）分区优势——分区裁剪（Partition Pruning）：查询只扫描相关分区，不是全表扫描。历史数据管理：删除旧分区 DROP PARTITION 比 DELETE 快得多（元数据操作，物理删除文件）。并行扫描：多分区查询可以并行扫描。3）分区劣势——跨分区查询性能差（扫描所有分区，不如非分区表的全表扫描）。分区键选择不当导致数据倾斜（某分区数据远超其他分区）。分区表不支持外键、全文索引（InnoDB 分区限制）。分区数量不宜过多（建议不超过 1024）。\n\n扩展延伸：分区 vs 分表 vs 分库——1）分区：在同一个数据库实例内部，将一个表的数据分到多个物理文件中。对应用透明（SQL 不需要改）。2）分表（水平分表）：将一张表拆成多个结构相同的物理表。应用需要感知分表规则。3）分库（分片，Sharding）：拆分到不同数据库实例。需要中间件（MyCAT、ShardingSphere）或应用层路由。MySQL 8.0 开始分区表也支持一些改进——支持分区表的 Transportable Tablespace（可移动表空间，方便数据迁移）。但总体来说，分区表在 MySQL 中的定位比较尴尬——大多数场景下用分表分库或 NoSQL 替代。Oracle 的分区比 MySQL 成熟得多。","hints":["分区表的分区裁剪（Partition Pruning）是如何减少扫描数据的","为什么分区数量不宜过多"],"tags":["MySQL","分区","性能优化"],"id":1357},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库连接池","content":"为什么应用程序需要数据库连接池？连接池的核心参数（最小连接数、最大连接数、连接超时、空闲回收）如何配置？连接池泄露如何诊断和预防？","answer":"答案：数据库连接池复用 TCP 连接，避免频繁创建/销毁连接的开销（TCP 三次握手 + MySQL 认证 每次约 100ms）。核心参数配置：最小连接数（保持活跃连接数）、最大连接数（防止打垮数据库）、连接超时（等待连接的超时时间）、空闲回收（空闲连接超过时间后关闭）。\n\n解析：1）为什么需要连接池——建立数据库连接的开销大：TCP 三次握手（1 RTT）、MySQL 认证（用户名密码验证、权限检查）、连接初始化（设置默认字符集、autocommit 等）。不使用连接池时每次请求都创建新连接，延迟高且数据库连接数暴增。2）核心参数——最小空闲连接（minimumIdle）：保持空闲连接数，应对突发流量（一般设为 5-10）。最大连接数（maximumPoolSize）：池子最大容纳的连接数，避免用尽数据库连接（一般设为 20-100，取决于数据库规格）。连接超时（connectionTimeout）：应用等待从池中获取连接的最长时间（一般 5-30 秒）。空闲超时（idleTimeout）：超过此时间未使用的连接被回收。最大存活时间（maxLifetime）：连接的最大存活时间（建议小于数据库的 wait_timeout）。\n\n扩展延伸：连接池泄露——应用获取连接后没有归还（调用 close()），导致连接池中可用连接逐渐耗尽。症状：应用卡死、获取连接超时、数据库连接数打满。诊断：监控连接池的 active 连接数是否持续增长。预防：1）事务中必须用 try-with-resources 或 try-finally 确保 close()。2）设置连接池的 leakDetectionThreshold（HikariCP）——连接被持有超过此时间输出警告堆栈。3）设置连接池的 validate（验证连接有效性）和 testWhileIdle。主流的 Java 连接池：HikariCP（Spring Boot 默认，性能最好、轻量）、Druid（监控功能丰富，国内常用）、Tomcat JDBC Pool。原则：连接池的最大连接数不是越大越好——过大的连接数会导致数据库端上下文切换开销增加（MySQL 的线程模型是 1 连接 1 线程）。","hints":["最大连接数设置太大为什么反而会降低性能","如何在代码层面防止连接池泄露"],"tags":["数据库","连接池","性能","HikariCP"],"id":1358},{"category":"database","difficulty":"easy","type":"short_answer","title":"乐观锁与悲观锁","content":"请解释乐观锁（Optimistic Locking）和悲观锁（Pessimistic Locking）的区别。各自适用于什么场景？在数据库中如何实现乐观锁？","answer":"答案：悲观锁假设并发冲突频繁发生，每次操作都加锁防止冲突（SELECT ... FOR UPDATE）。乐观锁假设并发冲突较少，操作时不加锁，在提交时检查冲突（通过版本号或条件更新）。乐观锁适合并发冲突少的场景，悲观锁适合冲突多的场景。\n\n解析：1）悲观锁——读取数据时立即加锁（行锁或表锁），其他事务必须等待。在 MySQL 中使用 SELECT ... FOR UPDATE（行锁排他锁）实现。缺点：并发性能差（锁等待），可能死锁。适用：库存扣减（票务系统）、金融交易、冲突频繁的场景。2）乐观锁——不加锁，在更新时检查数据是否被修改过。实现方式：用版本号字段（version，更新时 SET version = version + 1 WHERE version = oldVersion）或时间戳（更新时检查时间戳是否不变）或 CAS。如果更新影响行数为 0，说明冲突发生，需要重试。优点：没有锁等待和死锁，并发性能好。缺点：冲突频繁时重试次数多，性能急剧下降。\n\n扩展延伸：乐观锁的 CAS 问题和 ABA 问题：1）CAS（Compare-And-Swap，比较并交换）在数据库层面的实现是 UPDATE ... WHERE version = oldVersion，如果版本不匹配则更新 0 行。2）ABA 问题——一个值从 A 变成 B 又变回 A，版本号 CAS 会被绕过（因为值没变）。解决方案：使用持久版本号（单调递增，不循环使用）。3）重试策略——乐观锁冲突后的重试：立即重试 + 间隔重试（指数退避）+ 最大重试次数。4）并发控制选择图谱——读多写少冲突少 → 乐观锁。写多冲突多 → 悲观锁。超高并发（库存扣减）→ Redis Lua 脚本 + 最终一致。不需要强一致 → 无锁 + 异步补偿。先尝试乐观锁，冲突频繁时降级为悲观锁——这种「先乐后悲」策略在很多系统中使用。","hints":["乐观锁在高冲突场景下为什么性能会急剧下降","ABA 问题在数据库乐观锁场景中是否真的会出现"],"tags":["数据库","锁","并发控制"],"id":1359},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 死锁检测与预防","content":"什么是数据库死锁？MySQL InnoDB 如何检测死锁？如何通过 SQL 设计和业务逻辑预防死锁？","answer":"答案：死锁是两个或多个事务各自持有对方需要的资源，互相等待无法继续执行。InnoDB 通过等待图（Wait-For Graph）检测死锁，检测到后回滚代价较小的事务（持有锁较少、事务较小）。预防死锁的关键是统一锁的获取顺序和减少锁的范围。\n\n解析：1）死锁的四个必要条件——互斥（资源一次只能一个事务用）、持有并等待（持有锁并等待其他锁）、不可剥夺（已获取的锁不能强行剥夺）、循环等待（每个事务在等待另一个事务持有的锁）。2）InnoDB 死锁检测——等待图（WFG）：节点是事务，边是等待关系（T1 → T2 表示 T1 在等待 T2 释放锁）。InnoDB 周期性地检测等待图中是否存在环（深度优先搜索）。检测到死锁后选择「牺牲者」（victim）回滚——选择 undo 量最小的事务回滚。SHOW ENGINE INNODB STATUS 可以查看最后的死锁信息。3）预防死锁——统一的锁获取顺序：如果总是先锁表 A 再锁表 B，就不会出现 T1 锁 A 等 B、T2 锁 B 等 A 的死锁。缩小事务范围和锁持有时间：长事务持有锁的时间长，增加死锁概率。尽量使用等值条件（行锁）而不是范围条件（间隙锁）。\n\n扩展延伸：死锁的常见模式和处理：1）不同表加锁顺序不同——解决：约定全局加锁顺序。2）同一表的不同行——T1 先锁 row1 再锁 row2，T2 先锁 row2 再锁 row1。解决：操作行时按主键排序。3）间隙锁导致的死锁——在 RR 隔离级别下，范围查询会加间隙锁阻止幻读，但间隙锁不互斥——插入意向锁与间隙锁冲突。解决：不一定需要 RR 级别时可降级为 RC（binlog_format=ROW 时 RC 也安全）。4）超时兜底——设置 innodb_lock_wait_timeout（默认 50 秒），超时回滚。虽然是被动方式，但作为死锁防御的最后防线。5）实际常见做法：代码层重试（检测到 DeadlockException 时重试整个事务），大部分死锁在重试一次后即可解决。","hints":["InnoDB 如何决定死锁时回滚哪个事务","为什么 RR 级别下的间隙锁容易导致死锁"],"tags":["MySQL","死锁","事务","并发"],"id":1360},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 索引优化实战","content":"如何判断一个查询是否使用了索引？执行计划中 type、key、rows、Extra 字段各代表什么含义？在什么情况下索引不会被使用（索引失效场景）？","answer":"答案：通过 EXPLAIN SELECT 查看执行计划。关键字段——type（访问类型，从好到差：system > const > eq_ref > ref > range > index > ALL）、key（使用的索引名）、rows（扫描的行数估计值）、Extra（额外信息）。索引失效的常见场景：隐式类型转换、对索引列使用函数、LIKE 以 % 开头、OR 条件中有非索引列。\n\n解析：执行计划解读——1）type 的最好到最坏：const（主键/唯一索引等值查询，最多 1 行）→ eq_ref（JOIN 时主键关联）→ ref（非唯一索引等值查询）→ range（范围查询 >、<、BETWEEN、IN）→ index（全索引扫描）→ ALL（全表扫描，最差）。2）Extra 的重要信息：Using index（覆盖索引，不回表）、Using where（过滤条件）、Using index condition（索引下推 ICP）、Using filesort（需要排序无法用索引排序）、Using temporary（使用了临时表，通常表示需要优化）。\n\n扩展延伸：索引失效场景及修复——1）隐式类型转换：WHERE varchar_col = 123（字符串列和数字比较会导致类型转换，索引失效）。修复：WHERE varchar_col = '123'。2）函数操作：WHERE DATE(create_time) = '2024-01-01'。修复：WHERE create_time >= '2024-01-01' AND create_time < '2024-01-02'（范围查询）。3）LIKE 前缀模糊：WHERE name LIKE '%keyword'。修复：考虑全文索引（FULLTEXT INDEX）或 Elasticsearch。4）OR 条件：WHERE indexed_col = 1 OR non_indexed_col = 2。修复：将两个列都建立索引，或使用 UNION 替代。5）联合索引违反最左前缀：索引 (a,b,c) 但 WHERE b=1（跳过了 a）。","hints":["type 字段从好到差——const > eq_ref > ref > range > index > ALL，优化目标是避免 ALL 全表扫描","WHERE DATE(col) = '2024-01-01' 应改写为范围查询——col >= '2024-01-01' AND col < '2024-01-02'"],"tags":["数据库","MySQL","索引优化","EXPLAIN"],"id":1361},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 内存淘汰策略","content":"Redis 在内存满时有哪些淘汰策略？volatile-lru、allkeys-lru、volatile-ttl、noeviction 的区别？如何选择合适的淘汰策略？LRU 和 LFU 算法的区别？","answer":"答案：Redis 提供 8 种淘汰策略（maxmemory-policy）：noeviction（不淘汰，写操作直接报错）、volatile-lru（淘汰已设置过期时间的 key 中最久未使用的）、allkeys-lru（淘汰所有 key 中最久未使用的）、volatile-lfu（淘汰已设置过期时间的 key 中访问频率最低的）、allkeys-lfu（淘汰所有 key 中访问频率最低的）、volatile-random（随机淘汰过期的 key）、allkeys-random（随机淘汰任何 key）、volatile-ttl（淘汰过期时间最近的 key）。\n\n解析：策略选择——1）如果所有缓存数据都有过期时间（典型缓存场景）→ volatile-lru 或 volatile-lfu（让可过期数据被淘汰，永不过期的数据保留）。2）如果 Redis 用作纯缓存（所有数据都可以被淘汰）→ allkeys-lru（最常用）。3）如果数据访问频率差异大（热门数据访问远多于冷门）→ lfu（最不经常使用）比 lru（最近最少使用）更好。LRU vs LFU——LRU 淘汰最近最少使用的：一个 key 昨天被频繁访问但今天没被访问 → 会被 LRU 淘汰。LFU 淘汰访问频率最低的：统计访问频次（近似计数，用 Morris 算法节省空间），LFU 对周期性的批量访问更友好。\n\n扩展延伸：Redis 的近似 LRU——Redis 不实现精确 LRU（需要维护双向链表，代价高）。而是采用采样 LRU：从 maxmemory-samples（默认 5）个 key 中随机采样，淘汰其中最久未使用的。采样数越大越接近精确 LRU，性能开销也越大。配置建议——maxmemory 设置为物理内存的 60-80%（留出内存给系统和其他进程）。maxmemory-policy 明确配置（不要使用默认的 noeviction，线上会导致写失败）。maxmemory-samples 10 在精度和性能间取得平衡。","hints":["LRU vs LFU——LRU 看「多久没访问」，LFU 看「访问频率」。周期性访问的场景下 LFU 更准确","Redis 的近似 LRU（采样淘汰）vs 精确 LRU——采样 5 个 key 淘汰最旧的，性能好但精度有限"],"tags":["数据库","Redis","内存淘汰","LRU"],"id":1362},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 数据页结构","content":"MySQL InnoDB 的数据页（Page）结构是怎样的？Page Header、Infimum/Supremum、User Records、Free Space、Page Directory、Page Trailer 各自的作用是什么？Page 如何影响行存储和查询？","answer":"答案：InnoDB 数据页是磁盘和内存之间交互的基本单位（默认 16KB）。页内结构：File Header（38 字节，页号/上一页/下一页/LSN/校验和）→ Page Header（56 字节，槽数/记录数/页类型等）→ Infimum + Supremum（虚拟最小/最大记录，构成页内的双向链表边界）→ User Records（实际存储的行记录）→ Free Space（空闲空间，插入新记录时申请）→ Page Directory（页目录，槽数组用于二分查找记录）→ File Trailer（8 字节，校验和校验页完整性）。\n\n解析：数据组织——1）行记录（User Records）以单链表形式按主键顺序排列（物理上不连续，通过 next_record 指针串联）。2）Page Directory 将记录分组（每组 4-8 条），每组最末的记录的偏移量记录在 Page Directory 中（槽）。在 Page Directory 上用二分查找找到记录所在的组，再在组内顺序遍历。复杂度 O(log(N)) 定位到组 + O(1) 遍历组内记录。3）Infimum（小于任何记录）和 Supremum（大于任何记录）作为虚拟记录构成双向链表的边界。\n\n扩展延伸：相关影响——1）页分裂（Page Split）：当 Page 满时插入新记录，需要将约一半记录移到新 Page。代价高（需要分配新页、调整 B+ Tree 指针、更新 Page Directory）。2）页合并（Page Merge）：相邻 Page 的使用率低于 50% 时自动合并。3）Page Size 选择：默认 16KB，支持 4KB/8KB/32KB。大 Page 空间利用率更高但 IO 浪费更多（读取一行也读整个 Page）。Page 校验机制——File Header 和 File Trailer 都包含校验和（Checksum）。写入时两个位置都写入，读取时对比（发现损坏可尝试从 Doublewrite Buffer 恢复）。","hints":["Page Directory 允许在页内二分查找——先二分查到记录所在的槽，再在组内顺序遍历","页分裂的代价——分配新 Page 并更新 B+ Tree 指针，高频插入时建议优化主键（使用自增 ID）"],"tags":["数据库","MySQL","InnoDB","数据页"],"id":1363},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL 隔离级别与锁","content":"在 MySQL 默认的 RR（可重复读）隔离级别下，以下哪个锁机制用于解决幻读（Phantom Read）问题？","options":["A) Record Lock（记录锁）","B) Gap Lock（间隙锁）","C) Next-Key Lock（临键锁）","D) Intention Lock（意向锁）"],"answer":"答案：C) Next-Key Lock（临键锁）\n\n解析：Next-Key Lock = Record Lock + Gap Lock（记录锁 + 间隙锁）。在 RR 隔离级别下，InnoDB 使用 Next-Key Lock 锁定「一个区间及该区间内的一条记录」，阻止其他事务在范围内插入新记录，从而解决幻读。Gap Lock 只锁定间隙（不锁定记录本身），Next-Key Lock 锁定记录及前面的间隙。Record Lock 只锁定单条记录（不会阻止新记录插入）。Intention Lock（意向锁）是表级锁，表示事务将在某些行上加锁（用于快速检测表级锁冲突）。\n\n扩展延伸：锁范围举例——假设索引值为 5, 10, 15。对 10 加 Next-Key Lock 锁定 (5, 10]（5 到 10 的间隙 + 10 本身），阻止其他事务插入 6-9 的新记录。Gap Lock 的副作用——间隙锁可能降低并发（大量插入被阻塞）。因此在 RC（读已提交）隔离级别下间隙锁被禁用（只保留 Record Lock），通过 binlog row 格式解决幻读问题。RR 下的锁升级——当唯一索引等值查询命中唯一记录时，Next-Key Lock 降级为 Record Lock（无幻读风险）。","hints":["Next-Key Lock = Record Lock + Gap Lock——保护记录及记录前面的间隙防止幻读","唯一索引等值查询命中记录时 Next-Key Lock 降级为 Record Lock——没有间隙需要保护"],"tags":["数据库","MySQL","锁","隔离级别"],"id":1364},{"category":"database","difficulty":"easy","type":"true_false","title":"Redis Lua 脚本原子性","content":"Redis 执行 Lua 脚本时，脚本中所有的 Redis 命令在执行过程中是原子性的，不会被其他客户端的命令打断。但如果 Lua 脚本在执行过程中抛出了运行时错误，之前已经执行的 Redis 写操作会自动回滚。","options":["正确","错误"],"answer":"答案：错误。\n\n解析：Redis 的 Lua 脚本执行确实是原子性的（单线程执行，中间不会被其他命令打断）。但 Lua 脚本出错时不会自动回滚已经执行的写操作——Redis 不支持事务回滚。如果脚本在第 3 个命令上出错，前 2 个已经执行的命令不会撤销。这和 Redis MULTI/EXEC 事务的行为一致（「部分执行」不回滚）。\n\n扩展延伸：Redis 设计哲学——Redis 的开发者认为「不支持回滚是因为回滚需要复杂的状态管理，而且 Redis 命令的错误通常是编程错误（如对 string 类型执行 list 操作），应该由开发者在脚本编写时避免」。Lua 脚本的原子性保证——1）脚本执行期间不会处理其他命令（包括其他客户端的命令）。2）脚本执行中不会被主从切换中断。3）但是脚本中的 O(N) 命令（如 KEYS *）会阻塞 Redis 很长时间（影响所有客户端），因此 Lua 脚本应尽量简短。EVAL 命令的缓存——Redis 缓存已加载的 Lua 脚本（使用 SCRIPT LOAD），后续用 EVALSHA 通过 SHA1 调用（减少带宽）。","hints":["Lua 脚本和 Redis 事务一样——不保证回滚，出错前已执行的写操作保留","Redis 不支持回滚的原因——设计哲学认为回滚是数据库的责任而非缓存的责任，且大多数错误是开发阶段的编程错误"],"tags":["数据库","Redis","Lua","原子性"],"id":1365},{"category":"database","difficulty":"medium","type":"short_answer","title":"联合索引的最左前缀原则","content":"什么是联合索引的最左前缀原则？创建一个 (a, b, c) 的联合索引后，哪些查询能用到索引，哪些用不到？","answer":"答案：最左前缀原则指联合索引的查询必须从最左侧的列开始匹配，不能跳过中间的列。查询条件必须包含索引的最左前缀才能用到该索引。\n\n解析：以联合索引 (a, b, c) 为例，能用到索引的场景：1）WHERE a = 1 —— 用到 a 列索引。2）WHERE a = 1 AND b = 2 —— 用到 a 和 b。3）WHERE a = 1 AND b = 2 AND c = 3 —— 全用到。4）WHERE a = 1 AND c = 3 —— 用到 a 列（c 列的索引用不到，跳过了 b）。5）WHERE a IN (1, 2) AND b = 2 —— 用到 a 和 b 列。\n不能用到的场景：1）WHERE b = 2 —— 没有从最左列开始。2）WHERE c = 3 —— 没有从最左列开始。3）WHERE b = 2 AND c = 3 —— 没有 a 列。\n\n扩展延伸：联合索引设计的核心原则——1）辨识度高的列放前面（区分度：count(distinct col) / count(*)），越快缩小范围越好。2）等值条件的列放前面，范围查询（>、<、BETWEEN）的列放后面——范围查询后的列无法用到索引（索引下推 ICP 可部分缓解）。3）索引列顺序也影响排序——如果查询 ORDER BY a, b，联合索引 (a, b) 可以直接返回有序数据避免 filesort。4）索引不是越多越好——每张表的索引建议控制在 5 个以内，写多的表更要注意（每次 DML 需要更新所有索引）。5）可以用 (a, b) 索引覆盖查询 WHERE a = ? ORDER BY b，避免回表和排序。","hints":["where a = 1 AND c = 3 只能用 (a, b, c) 索引的 a 列——跳过了 b 所以 c 列的索引用不上","设计联合索引时等值条件列放前面、范围查询列放后面——范围条件后的索引列无法用于查询（ICP 可部分缓解）"],"tags":["数据库","索引","联合索引","MySQL"],"id":1366},{"category":"database","difficulty":"medium","type":"short_answer","title":"常见索引失效场景","content":"有哪些常见的 SQL 写法会导致索引失效？如何优化这些查询？","answer":"答案：常见索引失效场景：对索引列使用函数、隐式类型转换、LIKE 以通配符开头、OR 条件连接、联合索引未用最左前缀、使用 != 或 <>、IS NOT NULL 等。\n\n解析：各场景及优化——1）函数操作：WHERE DATE(create_time) = '2024-01-01' → 改为 WHERE create_time >= '2024-01-01' AND create_time < '2024-01-02'。任何对索引列的计算（数学运算、函数调用）都会使索引失效。2）隐式类型转换：WHERE phone = 123456（phone 是 varchar 类型）→ 改为 WHERE phone = '123456'。MySQL 会将 varchar 转为数字做全表扫描。3）LIKE 通配符开头：WHERE name LIKE '%张三' → 改为 WHERE name LIKE '张三%'（前缀匹配仍可用索引）。4）OR 条件：WHERE a = 1 OR b = 2 —— 如果 a 和 b 没有都建索引 → 改为 UNION ALL 或建复合索引。5）联合索引未用最左前缀：索引 (a, b, c) 但 WHERE b = 1 —— 必须包含最左列 a。6）优化器判断走索引不如全表扫描快（当查询结果占全表比例很大时，MySQL 可能选择全表扫描而非回表）。\n\n扩展延伸：索引下推（ICP——Index Condition Pushdown，MySQL 5.6+）——当使用联合索引 (a, b) 查询 WHERE a LIKE '张%' AND b = '1' 时，虽然 b 列的索引因 LIKE 前缀匹配后用不到（需要回表），但 ICP 会在索引层面先过滤 b 条件再回表，减少回表次数。Extra 列显示 Using index condition。MRR（Multi-Range Read）——回表前按主键排序，变随机 IO 为顺序 IO。覆盖索引（Covering Index）——查询字段全部在索引中，无需回表，是最彻底的优化手段。Explain 的 Extra 列显示 Using index 代表使用了覆盖索引。","hints":["对索引列使用函数、隐式类型转换、LIKE '%xxx' 都是最常见的索引失效场景","索引下推（ICP）在 LIKE 前缀匹配后仍可在索引层过滤后续条件——减少回表但不是完全用上索引"],"tags":["数据库","索引","性能优化","MySQL"],"id":1367},{"category":"database","difficulty":"hard","type":"short_answer","title":"Spring 事务传播行为","content":"请列举 Spring 事务传播行为（Propagation）的常见类型及其适用场景。REQUIRED 和 REQUIRES_NEW 的行为区别是什么？","answer":"答案：Spring 事务传播行为定义了事务方法被另一个事务方法调用时的事务边界处理策略。核心类型：REQUIRED（默认）、REQUIRES_NEW、SUPPORTS、NOT_SUPPORTED、MANDATORY、NEVER、NESTED。\n\n解析：详解各类型——1）REQUIRED（默认）：如果当前存在事务则加入，否则创建新事务。大部分业务操作使用此级别。当前方法抛异常会使整个事务回滚（包括调用方已执行的操作）。2）REQUIRES_NEW：不管当前是否存在事务，都创建新事务。如果当前存在事务则挂起当前事务。内部事务抛异常回滚不影响外部事务，外部事务抛异常也不影响内部事务。适用于：独立记录操作日志、发送消息通知等——不管主业务是否成功，这些操作都应该提交。3）SUPPORTS：如果当前有事务就加入，没有就以非事务方式执行。适用于查询方法。4）NOT_SUPPORTED：以非事务方式执行，如果当前有事务则挂起。5）MANDATORY：必须在事务中执行，没有事务抛异常。6）NEVER：必须在非事务中执行，有事务抛异常。7）NESTED：如果当前有事务，则创建一个 Savepoint 嵌套执行——内部回滚只回滚到 Savepoint（外部可继续提交）；没有事务则创建新事务（行为同 REQUIRED）。利用 JDBC 的 Savepoint 机制实现。\n\n扩展延伸：REQUIRED vs REQUIRES_NEW —— 实际开发中最常混淆的两种。选择依据：1）内部操作失败不应该影响外部事务 → REQUIRES_NEW（如日志记录、消息发送、审计）。2）内部操作是外部事务的一部分，失败后整体回滚 → REQUIRED（如订单和库存更新必须同时成功或失败）。注意：@Transactional 默认只在 RuntimeException 和 Error 时回滚，checked exception 不回滚。可以配置 rollbackFor 指定哪些异常触发回滚。事务只在 public 方法上生效（Spring AOP 原理限制）——同一个类中内部调用 @Transactional 方法会失效（自调用问题，可以通过注入自身或使用 AopContext 解决）。","hints":["REQUIRED: 加入当前事务，失败一起回滚——适合业务强一致性操作","REQUIRES_NEW: 挂起当前事务创建新事务——适合日志记录、消息通知等独立操作"],"tags":["数据库","事务","Spring","传播行为"],"id":1368},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB 行锁、间隙锁、临键锁","content":"请说明 MySQL InnoDB 的行锁（Record Lock）、间隙锁（Gap Lock）、临键锁（Next-Key Lock）的区别和作用。","answer":"答案：行锁锁住索引记录，间隙锁锁住索引记录之间的间隙，临键锁 = 行锁 + 间隙锁（区间左开右闭）。InnoDB 默认使用临键锁（在 RR 隔离级别下）来防止幻读。\n\n解析：三种锁详解——1）行锁（Record Lock）：锁住具体的索引记录。当 WHERE id = 10 FOR UPDATE 时，只在 id=10 的索引记录上加锁。其他记录不受影响，其他会话可以修改 id=20 的记录。2）间隙锁（Gap Lock）：锁住两个索引记录之间的间隙（范围但不包括记录本身），防止其他会话在间隙中插入新记录。WHERE id BETWEEN 10 AND 20 FOR UPDATE——间隙锁锁住 (10,20) 的范围，禁止插入 id=15 的新记录。间隙锁只在 RR（可重复读）隔离级别存在，RC 级别没有间隙锁（这也是 RC 级别可能产生幻读的原因）。3）临键锁（Next-Key Lock）：行锁 + 间隙锁的组合，锁住一个左开右闭的区间 (prev, current]。InnoDB 的默认锁机制。WHERE id > 10 FOR UPDATE——临键锁锁住 (10, +∞) 范围。\n\n扩展延伸：锁的退化——1）当等值查询命中唯一索引时，临键锁退化为行锁（因为已锁定唯一记录，其他会话无法插入相同值）。2）当查询的列没有索引时，行锁会升级为表锁（全表扫描每一行的索引都会加锁——相当于锁全表）。这是 InnoDB 最重要的一个坑：不带索引条件的 DML 可能导致大量锁冲突。3）间隙锁只在 RR 级别生效，这也是为什么很多高并发系统选择 RC（读已提交）级别的原因——减少间隙锁竞争，提高并发度，但要配合 binlog=ROW 模式保证主从一致。死锁排查 —— 通过 SHOW ENGINE INNODB STATUS 中的 LATEST DETECTED DEADLOCK 部分查看事务持有和等待的锁信息。","hints":["临键锁 = 行锁 + 间隙锁，RR 级别默认使用——等值查询命中唯一索引时退化为行锁","没有索引的 DML 会导致行锁升级为表锁——大量锁冲突的常见原因"],"tags":["数据库","InnoDB","锁","MySQL"],"id":1369},{"category":"database","difficulty":"hard","type":"short_answer","title":"分库分表策略与实战","content":"什么时候需要考虑分库分表？请介绍常见的拆分策略（垂直拆分、水平拆分）和 Sharding 方案。","answer":"答案：当单表数据量超过千万级且索引优化已到极限、DB 连接数成为瓶颈、磁盘 IO 无法满足要求时，考虑分库分表。拆分策略分两类：垂直拆分（按业务模块拆分库、按字段冷热拆分表）和水平拆分（按某种规则将数据分散到多个库/表）。\n\n解析：垂直拆分——1）垂直分库：按业务领域拆分为独立的数据库（用户库、订单库、商品库），每个库独立部署、独立扩容。微服务架构天然对应垂直分库。2）垂直分表：将表中不常用的大字段拆分到单独的表。「冷热分离」——热数据（高频查询的字段）放主表，冷数据（大文本、日志等）放扩展表。\n水平拆分——1）范围分片：按时间（按月/年分区）、按 ID 范围（1-1000 万在分片1，1000 万-2000 万在分片2）。优点：分布均匀可控，按时间分区方便冷热数据分离和归档。缺点：容易产生热点（当月数据写入集中到最新分片）。2）哈希分片：shard_id = hash(shard_key) % N。优点：数据均匀分布。缺点：扩容时需要迁移数据，扩缩容困难。3）一致性哈希分片：用一致性哈希算法分配数据，扩容时影响范围小。在分库分表中间件（如 ShardingSphere）中广泛使用。\n\n扩展延伸：分库分表带来的挑战和解决方案——1）跨分片查询：分页、排序、聚合等操作需要汇总各分片数据再合并，性能差。解决方案：避免跨分片操作，或使用 ES 做搜索层。2）分布式事务：跨库操作需要分布式事务协调（Seata、TCC、Saga）。不是所有场景都需要强一致性——很多场景最终一致性就够了。3）全局主键：自增 ID 不再适用。方案：雪花算法（Snowflake，趋势递增、不依赖 DB）、发号器（Redis/数据库独立生成）。4）数据迁移：分片规则变更时数据重新分布很困难。建议设计时留好余量，或使用「双层映射」路由规则。5）能不拆就不拆——分库分表是最后的手段，优先考虑：索引优化 + 读写分离 + 缓存 + 冷热分离 + 分区表（MySQL Partition）。","hints":["分库分表是最后的手段——优先做索引优化、缓存、读写分离、分区表","哈希分片数据均匀但扩容困难；范围分片容易扩容但可能产生热点——一致性哈希平衡两者"],"tags":["数据库","分库分表","分布式","性能优化"],"id":1370},{"category":"database","difficulty":"hard","type":"short_answer","title":"MVCC 实现原理","content":"请解释MySQL InnoDB中MVCC（多版本并发控制）的实现原理，以及它在不同隔离级别下的工作方式。","answer":"答案：MVCC通过为每行数据维护多个版本（基于undo log）实现读不阻塞写、写不阻塞读，是InnoDB实现高并发的核心机制。\n\n解析：MVCC依赖三个核心组件：1）隐藏字段——每一行有两个隐藏列：DB_TRX_ID（最近修改该行的事务ID）、DB_ROLL_PTR（回滚指针，指向undo log中该行的前一个版本）。2）undo log——事务修改数据时，将旧值写入undo log（通过回滚指针串联成版本链）。3）Read View——事务在某一时刻的快照，包含：当前活跃事务ID列表（m_ids）、最小活跃事务ID（up_limit_id）、下一个分配的事务ID（low_limit_id）。判断规则：对于版本链中的每个版本，如果创建该版本的事务ID小于up_limit_id且不在活跃列表中则可见，如果大于等于low_limit_id则不可见。\n\n扩展延伸：不同隔离级别下的MVCC行为：RC（读已提交）——每次SELECT都生成新的Read View，所以能读到其他事务已提交的更改（不可重复读）。RR（可重复读）——只在事务第一次SELECT时生成Read View，之后的查询复用同一个Read View，保证同一事务内多次读取结果一致。MVCC不适用于当前读（SELECT ... FOR UPDATE、UPDATE、DELETE），当前读使用Next-Key Lock加锁。undo log除了支持MVCC外，还用于事务回滚。历史版本的清理由Purge线程异步执行。","hints":["Read View在RC和RR级别下的生成时机有何不同","undo log形成的版本链如何决定哪些版本可见"],"tags":["MySQL","MVCC","事务","并发控制"],"id":1371},{"category":"database","difficulty":"hard","type":"short_answer","title":"间隙锁的作用与实现","content":"请解释InnoDB中间隙锁（Gap Lock）和Next-Key Lock的作用、触发条件及对并发性能的影响。","answer":"答案：间隙锁锁住索引记录之间的间隙，防止其他事务在该间隙插入数据，用于解决幻读（Phantom Read）问题。Next-Key Lock = 行锁 + 间隙锁。\n\n解析：1）行锁（Record Lock）——锁住单条索引记录。2）间隙锁（Gap Lock）——锁住两个索引值之间的间隙（开区间，不包含两端），防止间隙内插入新记录。3）Next-Key Lock——前开后闭区间（如(10, 20]），同时锁住记录和间隙。触发条件：在可重复读（RR）隔离级别下，使用当前读（SELECT ... FOR UPDATE / FOR SHARE、UPDATE、DELETE）时，InnoDB会根据查询条件对索引记录加Next-Key Lock。如果查询条件没有匹配到记录，则对间隙加Gap Lock。\n\n扩展延伸：间隙锁的优化策略：1）使用唯一索引（Unique Index）等值查询——如果匹配到记录，Next-Key Lock退化为行锁（Record Lock）。2）唯一索引等值查询未匹配到记录——对间隙加Gap Lock。3）普通索引等值查询——锁住匹配记录及其前后间隙（包括下一个键值）。4）范围查询——锁住范围内的所有记录及其间隙。间隙锁的劣势：降低并发插入性能，尤其是在高并发插入场景下可能导致锁冲突。MySQL 8.0引入了更多优化，如INSERT ... ON DUPLICATE KEY UPDATE的锁行为改进。读已提交（RC）级别下间隙锁不生效，这也是为什么RC下可能出现幻读但并发性能更好的原因。","hints":["间隙锁只在什么隔离级别下生效","为什么唯一索引等值查询可以退化为行锁"],"tags":["MySQL","间隙锁","锁","并发"],"id":1372},{"category":"database","difficulty":"hard","type":"short_answer","title":"Join 的底层实现方式","content":"请解释MySQL中Join操作的主要实现算法（Nested Loop Join、Hash Join、Sort-Merge Join）的工作方式和适用场景。","answer":"答案：MySQL实现Join的主要算法包括：Nested Loop Join及其变种（Index Nested Loop Join、Block Nested Loop Join）、Hash Join（MySQL 8.0.18引入）和Sort-Merge Join。\n\n解析：1）Simple Nested Loop Join——外层驱动表的每一行去匹配内层表的每一行（全表扫描），复杂度O(N*M)，性能差。2）Index Nested Loop Join（INLJ）——如果内层表有索引，直接通过索引查找匹配行，复杂度O(N*logM)，是MySQL Join最常用的方式。3）Block Nested Loop Join（BNLJ，MySQL 8.0.20前）——将驱动表的多个行组合成块（Join Buffer），一次传给内层表匹配，减少内层表的扫描次数。4）Hash Join——将驱动表数据构建为哈希表，内层表逐行探测。适合大表等值Join，无索引时性能优于BNLJ。5）Sort-Merge Join——先对两个表排序再合并，适合排序字段的Join或非等值Join。\n\n扩展延伸：优化策略：1）小表驱动大表——用小表做驱动表减少循环次数。2）Join字段加索引——让INLJ生效。3）控制Join Buffer大小——通过join_buffer_size参数。4）拆分成多个查询——有时多个简单查询比一个复杂Join更高效（尤其是分布式数据库场景）。MySQL优化器通过EXPLAIN显示的执行计划来决定使用哪种Join算法，分析type字段和Extra字段可以了解具体策略。","hints":["什么情况下MySQL会使用Hash Join","Join优化的一般原则是什么"],"tags":["MySQL","Join","查询优化","SQL"],"id":1373},{"category":"database","difficulty":"hard","type":"short_answer","title":"查询优化器的工作流程","content":"请描述MySQL查询优化器的工作流程，以及它是如何选择最优执行计划的。","answer":"答案：MySQL查询优化器将SQL语句转化为多个可能的执行计划，基于代价模型（Cost Model）估算各计划的代价，选择代价最小的执行计划。\n\n解析：优化器工作流程：1）词法/语法解析——通过bison/yacc解析SQL语句生成解析树。2）逻辑优化（基于规则的优化RBO）——应用启发式规则对查询进行等价变换，如：谓词下推（将过滤条件提前到Join前）、子查询优化（将子查询转为Join或半连接）、常量折叠（表达式求值）、投影消除（只取需要的列）、外连接转内连接。3）物理优化（基于代价的优化CBO）——确定Join顺序（Multi-way Join的Reorder）、选择访问路径（全表扫描/索引扫描/索引查找）、选择Join算法（NLJ/Hash Join等）、选择索引。枚举所有可能的执行计划，根据统计信息估算代价（IO代价+CPU代价）。4）生成执行计划——优化器最终输出一个执行计划树，交给执行引擎执行。\n\n扩展延伸：关键统计信息包括：表的行数、数据大小、索引基数、字段选择度（Cardinality）、值的分布直方图（MySQL 8.0支持）。通过ANALYZE TABLE更新统计信息。当优化器选择不当时，可以通过FORCE INDEX、USE INDEX、STRAIGHT_JOIN、优化器Hints干预。MySQL还支持Adaptive Hash Index和Index Condition Pushdown（ICP）等执行期优化。理解优化器的工作方式，对编写高效的SQL至关重要——很多「优化技巧」的本质是帮助优化器做出更好的选择。","hints":["RBO和CBO分别做什么","统计信息不准确时可能导致什么后果"],"tags":["MySQL","查询优化器","SQL","性能"],"id":1374},{"category":"database","difficulty":"medium","type":"short_answer","title":"主从延迟的原因与解决方案","content":"请分析MySQL主从同步延迟的常见原因，以及有哪些有效的应对策略。","answer":"答案：主从延迟是指从库的数据落后于主库的时间差，核心原因是主从同步是单线程的（或有限的并行度）从库应用日志速度跟不上主库写入速度。\n\n解析：常见原因：1）主库写入压力过大——主库的写并发高，生成的binlog量超过了从库单线程SQL Thread的回放速度。2）从库配置过低——从库的CPU/IO/磁盘性能低于主库。3）大事务——一个大事务产生大量binlog，从库需要完整执行完才能赶上。4）从库上的读负载——从库上运行了查询或报表任务，消耗了系统资源。5）网络延迟——主从之间的网络带宽或延迟问题。6）锁竞争——从库回放时的锁冲突。\n\n扩展延伸：解决方案：1）开启并行复制（MySQL 5.7的slave_parallel_type=LOGICAL_CLOCK，MySQL 8.0完善）——从库使用多个线程并行应用不同数据库或不同事务组的binlog。2）读写分离策略调整——将强一致性读路由到主库，允许最终一致性的读走从库。3）减少大事务——拆分大批量操作，避免单条SQL影响大量行。4）优化硬件配置——从库使用与主库相同或更好的硬件配置。5）监控和告警——通过seconds_behind_master或Heartbeat机制监控延迟，设置合理的告警阈值。6）半同步复制（Semi-sync Replication）——确保至少一个从库收到binlog后才提交，减少数据丢失风险但不直接减少延迟。7）终极方案——使用MySQL Group Replication（MGR）或引入分布式数据库中间件（如TiDB、OceanBase）。","hints":["并行复制如何缓解主从延迟","为什么大事务会加剧主从延迟"],"tags":["MySQL","主从","复制","高可用"],"id":1375},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 半同步复制原理与配置","content":"请说明 MySQL 半同步复制（Semisynchronous Replication）的工作原理、与异步复制的差异，以及在数据一致性要求高的场景下的配置建议。","answer":"答案：MySQL 半同步复制介于异步复制和全同步复制之间。在异步复制中，主库提交事务后立即返回客户端响应，不等待从库确认；在半同步复制中，主库提交事务后至少等待一个从库（slave）确认收到 binlog 后才返回客户端响应。这确保了事务在主库提交时至少在一个从库上已经有了完整 binlog。\n\n解析：半同步复制的流程：1) 主库执行事务并写入 binlog；2) 主库将 binlog 发送给从库；3) 主库等待从库写入 relay log 并返回 ACK；4) 主库收到 ACK 后提交事务并返回客户端成功。如果在超时时间（rpl_semi_sync_master_timeout，默认 10 秒）内未收到从库 ACK，主库自动降级为异步复制（保证可用性），从库恢复后自动切回半同步。半同步复制有两个版本：AFTER_COMMIT（旧版，在提交后才等待，主库挂了可能丢失最近事务）和 AFTER_SYNC（5.7+ 默认，在 binlog 同步到磁盘后立即等待，确保提交的数据已被从库确认）。\n\n扩展延伸：生产配置建议：1) 至少配置两个从库参与半同步确认 —— 如果唯一的同步从库故障，主库降级为异步；2) 超时时间设置需平衡可用性和一致性 —— 太短容易降级，太长影响主库性能；3) 配合 lossless replication（AFTER_SYNC + rpl_semi_sync_master_wait_point=AFTER_SYNC）实现最大数据保护；4) 半同步复制不是强一致性 —— 它保证事务在主库提交时已有从库确认，但不保证后续从库的查询一定看到最新数据（还需等待从库 SQL Thread 执行）；5) 不建议跨地域部署半同步 —— 网络延迟会严重影响主库写入性能。","hints":["半同步复制在超时后自动降级为异步，不会阻塞主库写入","AFTER_SYNC 模式比 AFTER_COMMIT 提供更强的数据安全","跨地域部署半同步会因网络延迟严重影响主库性能"],"tags":["MySQL","半同步复制","主从复制","数据一致性"],"id":1376},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Group Replication 组复制架构","content":"请介绍 MySQL Group Replication（MGR）的架构设计、一致性协议（Paxos/Group Communication）、容错模型以及和传统主从复制的核心区别。","answer":"答案：MySQL Group Replication（MGR）是 MySQL 5.7.17+ 的高可用方案，基于 Paxos 变种（Group Communication System，XCom）实现多节点间的数据一致性。与传统的异步/半同步复制不同，MGR 是多主（Multi-Primary）或单主（Single-Primary）模式的组内复制 —— 每个节点都能写入，组内通过共识协议决定事务提交顺序。\n\n解析：MGR 的核心架构：1) 组通信层（GCS）—— 使用 XCom（基于 Paxos 的组通信系统）实现成员管理、消息广播和原子投递；2) 冲突检测 —— 在 Multi-Primary 模式下，不同节点同时修改同一行时触发冲突检测，通过 certificate 机制决定哪个事务提交哪个回滚（基于行级别的 optimistic 并发控制）；3) 集团成员管理 —— 节点加入/离开时自动协商 group view，更新组成员列表。容错模型：MGR 支持多数派容错 —— 3 节点集群最多容忍 1 个节点故障，5 节点容忍 2 个故障（N > 2F + 1）。\n\n扩展延伸：MGR 与传统复制的对比：1) 传统复制提供最终一致性（异步）或几乎一致（半同步），MGR 提供强一致性（组内多数派确认后提交）；2) Single-Primary 模式下 MGR 与半同步复制的功能等价，但 MGR 的自动故障切换比传统的 MHA 或 Orchestrator 方案更原生；3) MGR 的瓶颈在于组通信延迟 —— 跨 AZ 部署时网络延迟直接影响写入性能（每个事务需要多数派确认），建议 MGR 节点部署在同一机房；4) MGR 的 Multi-Primary 模式限制了 SQL 兼容性 —— 不支持 AUTO_INCREMENT、Foreign Key（级联更新冲突）、LOCK TABLES 等语法；5) MySQL InnoDB Cluster（从 MySQL Shell 创建）是基于 MGR + MySQL Router 的全套高可用方案。","hints":["MGR 使用 Paxos/XCom 实现组内共识","Multi-Primary 模式下需要冲突检测机制","MGR 建议同机房部署避免网络延迟影响写入性能"],"tags":["MySQL","MGR","组复制","高可用"],"id":1377},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Optimizer Trace 与查询优化器深入分析","content":"请说明如何使用 MySQL Optimizer Trace 调试查询优化器的决策过程，包括 JOIN 顺序选择、索引选择、成本估算等关键信息的解读方法。","answer":"答案：MySQL Optimizer Trace（优化器追踪）是 5.6+ 提供的一个诊断特性，通过 OPTIMIZER_TRACE 表记录优化器为 SQL 语句生成执行计划时的完整决策过程。启用方式：SET optimizer_trace='enabled=on'; 执行目标 SQL；SELECT * FROM INFORMATION_SCHEMA.OPTIMIZER_TRACE。输出是 JSON 格式的决策树，包含表访问顺序、索引选择、行数估算、成本模型等关键信息。\n\n解析：Optimizer Trace 的主要 JSON 节点解读：1) \"join_preparation\" —— 语法解析和查询重写阶段；2) \"join_optimization\" —— 核心优化阶段，包括条件化简（where_optimization）、表连接顺序枚举（greedy_search）、成本估算（cost_estimation）；3) \"condition_processing\" —— 条件被如何转换（等值传递、常量折叠等）；4) \"considered_execution_plans\" —— 优化器评估过的候选执行计划列表及各自的总成本（cost 字段）。重点关注 complete_candidates（完整候选计划）和 best_so_far（当前最优计划），以及\"cause\"字段解释某个计划被淘汰的原因。\"rows_estimation\"中的成本估算包括 table_scan（全表扫描成本）和 range_scan（范围扫描成本）。\n\n扩展延伸：Optimizer Trace 调试实战：1) 索引选择问题 —— 如果优化器没有选择你认为最优的索引，查看 considered_execution_plans 中各计划的成本比较，看看为什么优化器认为全表扫描更便宜；2) JOIN 顺序异常 —— 查看 greedy_search 中表的排列顺序，是否因行数估算偏差导致顺序选择错误；3) 修正优化器行为 —— 根据 Trace 发现的问题可通过 ANALYZE TABLE（更新统计信息）、FORCE INDEX（强制索引）、STRAIGHT_JOIN（强制连接顺序）纠正；4) 注意 optimizer_trace_offset 和 optimizer_trace_limit 参数控制追踪记录保存数量；5) 生产环境不建议长时间开启优化器追踪（有轻微性能开销），只在调优特定查询时临时启用。","hints":["Optimizer Trace 的核心是 join_optimization 阶段的 considered_execution_plans","行数估算偏差是优化器选择次优计划的最常见原因","ANALYZE TABLE 可以刷新统计信息改善优化器决策"],"tags":["MySQL","优化器","Optimizer Trace","执行计划"],"id":1378},{"category":"database","difficulty":"easy","type":"short_answer","title":"SQL 注入原理与防护方案","content":"请说明 SQL 注入攻击的原理和常见形式，以及服务端防范 SQL 注入的完整方案。","answer":"答案：SQL 注入（SQL Injection）是攻击者将恶意 SQL 代码拼接到应用程序的 SQL 查询中，从而绕过认证、窃取数据或破坏数据库的攻击方式。原理是应用程序在执行 SQL 之前未正确转义或分离数据和代码，用户的输入被解释为 SQL 语句的一部分。\n\n解析：常见注入形式：1) 经典注入 —— ' OR '1'='1 绕过登录验证；2) 联合查询注入 —— UNION SELECT 窃取其他表数据；3) 报错注入 —— 利用数据库报错信息获取数据（如 extractvalue、updatexml 函数）；4) 布尔盲注 —— 通过页面返回真/假逐字符推断数据；5) 时间盲注 —— 通过 SLEEP/BENCHMARK 判断条件真假。防护方案的第一道防线是参数化查询（Prepared Statement）—— 将 SQL 结构（代码）和数据分离，确保用户输入始终作为数据处理而非代码执行。所有主流语言都支持：Java PreparedStatement、Python 的 cursor.execute(sql, params)、Go 的 db.Query(sql, args)、Node.js 的 mysql2/pool.execute。\n\n扩展延伸：纵深防御体系：1) 输入验证 —— 对用户输入做类型校验和白名单过滤（如 ID 必须是整数、邮箱格式检查），作为参数化查询的补充；2) 最小权限 —— 数据库连接使用最小权限账户（只读用户、写用户分离），限制存储过程的执行权限；3) Web 应用防火墙（WAF）—— 检测和拦截 SQL 注入攻击流量；4) 透明加密 —— 敏感字段使用列级加密存储；5) 定期扫描 —— 使用 SQLMap 等自动化工具定期对应用做注入测试。ORM（JPA、MyBatis、GORM、SQLAlchemy）本身不防注入 —— 当使用原生 SQL（@Query 注解、MyBatis 的 ${} 插值、Raw SQL）时仍需使用参数化方式。","hints":["参数化查询是防止 SQL 注入最核心的手段","ORM 中的原生 SQL 仍需手动防范注入","盲注虽然速度慢但隐蔽性强，WAF 难以检测"],"tags":["MySQL","SQL注入","安全","防护"],"id":1379},{"category":"database","difficulty":"hard","type":"short_answer","title":"gh-ost 与 pt-osc 在线表结构变更原理","content":"请对比分析 gh-ost（GitHub Online Schema Transformation）和 pt-online-schema-change（pt-osc）的在线 DDL 实现原理，包括数据同步机制、触发器使用、流量影响和回滚能力。","answer":"答案：两种工具都旨在解决 MySQL 在线 DDL（如 ALTER TABLE）期间锁表或主从延迟问题，但其实现思路不同。pt-osc 通过触发器（Trigger）捕获增量数据变更，gh-ost 通过解析 binlog（伪装为从库）捕获增量变更。两者都创建一个影子表、在影子表上执行 DDL、增量同步数据后切换。\n\n解析：pt-osc 的工作流程：1) 创建与源表结构相同的影子表（_new 结尾）；2) 在源表上创建三个触发器（INSERT/DELETE/UPDATE 各一个），捕获 DDL 执行期间的增量变更；3) 分批从源表拷贝数据到影子表（每次几万行，chunk-size 控制）；4) 触发器确保增量数据同步到影子表；5) 执行 RENAME TABLE 原子切换。gh-ost 的工作流程：1) 创建影子表；2) 连接 MySQL 主库模拟从库（连接 binlog dump thread），实时解析 binlog 获取增量变更；3) 从源表批量拷贝数据；4) 将 binlog 解析的增量变更应用到影子表；5) 完成数据同步后原子切换。\n\n扩展延伸：对比优劣：1) 触发器开销 —— pt-osc 的触发器增加源表的写入延迟（每条 DML 额外触发一次触发器），高写入场景下影响明显。gh-ost 无触发器，通过 binlog 解析同步增量，对源表几乎无影响。2) 主从延迟 —— pt-osc 的触发器在主库执行，增量数据在主库直接写入影子表，主从延迟较小。gh-ost 的 binlog 应用在 gh-ost 进程所在主机上异步执行，不占用主库资源。3) 暂停与恢复 —— gh-ost 支持运行时暂停（—throttle），通过 HTTP 接口或文件控制节流。4) 切换安全 —— gh-ost 在切换前检查复制延迟，若延迟超过阈值则等待；pt-osc 可通过 —check-slave-lag 检查。5) 推荐场景：大表（千万级）且写入量大 → gh-ost（无触发器、可暂停、binlog 驱动）；中小表或对触发器接受度高 → pt-osc（成熟稳定、社区支持广泛）。","hints":["pt-osc 使用触发器捕获增量数据，gh-ost 使用 binlog 解析","gh-ost 对主库写入性能影响更小，适合高压力场景","pt-osc 的触发器会额外增加每条 INSERT/UPDATE/DELETE 的开销"],"tags":["MySQL","DDL","gh-ost","pt-osc","在线变更"],"id":1380},{"category":"database","difficulty":"hard","type":"short_answer","title":"LSM 树存储引擎","content":"请解释 LSM-Tree（日志结构合并树）的读写原理及其在 NoSQL 中的应用。","answer":"答案：LSM-Tree 通过顺序写 + 分层合并实现高写入性能，广泛应用于现代 NoSQL 数据库\n\n解析：写入流程：数据先写内存中的 MemTable（有序结构，常为跳表或红黑树）和 WAL（Write Ahead Log 保证持久化）。MemTable 满了后冻结为不可变的 SSTable（Sorted String Table）写入磁盘。后台 Compaction 线程不断将小 SSTable 合并排序成大 SSTable并删除冗余数据。多个 SSTable 层级（Level 0 -> Level 1 -> ...），上层的 SSTable 被合并到下层。读取流程：先查 MemTable（活跃 MemTable + 冻结中的 MemTable），然后从最新到最旧查各层 SSTable。为了解决读放大问题，使用布隆过滤器（快速判断数据是否在 SSTable 中）、块索引（稀疏索引定位块偏移）、块缓存。\n\n扩展延伸：LSM-Tree vs B+ Tree：LSM 写入性能高（顺序写替代随机写），读性能差（需查多层 SSTable），写放大会消耗大量 IO（Compaction），写入量是实际数据量的 10-50 倍。RocksDB/LevelDB（Google）是 LSM 实现的代表，LevelDB Level 0 有 4 个 SSTable，第 N 层容量是第 N-1 层的 10 倍，每层覆盖范围越来越大。Compaction 策略：Size-Tiered Compaction（Cassandra，按大小合并 SSTable，写放大较小但读放大较大）vs Leveled Compaction（LevelDB/RocksDB，按层合并，读放大较小但写放大较大）。WiscKey 提出 KV 分离技术，大 Value 存专门文件只在 LSM 中存地址，进一步优化读写性能。","hints":["LSM-Tree 的写放大和读放大的来源是什么","布隆过滤器在 LSM 读取优化中起什么作用"],"tags":["存储引擎","LSM-Tree","NoSQL"],"id":1381},{"category":"database","difficulty":"hard","type":"short_answer","title":"MVCC 实现机制","content":"请详细解释 MVCC（多版本并发控制）在 InnoDB 中的实现原理。","answer":"答案：MVCC 是多版本并发控制机制，通过数据多版本实现读不阻塞写、写不阻塞读\n\n解析：InnoDB 中每行数据包含两个隐藏列：DB_TRX_ID（创建/最后一次修改这条记录的事务 ID）和 DB_ROLL_PTR（回滚指针，指向 undo log 中上一个版本）。每次事务修改记录时会创建一个新版本并通过回滚指针链接旧版本形成版本链。Read View（读视图）决定事务能看到哪些版本：trx_ids（当前活跃事务 ID 列表，包括自身吗？不包括）、low_limit_id（当前最大事务 ID+1）、up_limit_id（trx_ids 中最小事务 ID）、creator_trx_id（创建 Read View 的事务 ID）。可见性规则：如果一个版本的事务 ID < up_limit_id，可见；如果事务 ID = creator_trx_id，可见；如果事务 ID 在活跃列表，不可见（需要沿 undo log 找更老的版本）；如果事务 ID > low_limit_id，不可见。\n\n扩展延伸：MVCC 与隔离级别：读未提交直接用最新行，不创建 Read View；读已提交在每次语句执行时创建 Read View，所以同一事务内两次查询可能看到不同结果（不可重复读）；可重复读在事务开始第一次查询时创建 Read View（快照），事务内一直用同一个快照，解决了不可重复读但可能出现幻读。MVCC 的局限性：对于 UPDATE/DELETE 需要加锁（行锁 + Gap Lock）才能真正防止幻读。Read View 的创建时机（RR 级别下）是第一个读操作创建 Snapshot，不是事务开始。所以如果在 RR 级别先 UPDATE 再 SELECT，SELECT 用的是当前读（current read）而非快照读。快照读 vs 当前读：快照读（普通的 SELECT）不加锁利用 MVCC，当前读（SELECT FOR UPDATE/UPDATE/DELETE）加锁读最新版本。","hints":["事务开始和 Read View 创建是同一时刻吗","快照读和当前读分别使用什么机制"],"tags":["MySQL","MVCC","事务"],"id":1382},{"category":"database","difficulty":"hard","type":"short_answer","title":"查询优化器工作原理","content":"请解释数据库查询优化器的工作流程和执行计划生成过程。","answer":"答案：查询优化器将 SQL 语句转化为最优执行计划，决定如何访问数据和做连接\n\n解析：查询优化分为逻辑优化（RBO，基于规则的优化）和物理优化（CBO，基于代价的优化）。逻辑优化基于关系代数等价变换规则：1）谓词下推（Predicate Pushdown）— 尽早过滤数据减少后续处理数据量 2）投影下推 — 只读取需要的列 3）子查询扁平化（Subquery Unnesting）— 将子查询转换为 JOIN 使其更优执行 4）常量折叠 — 计算常量表达式 5）外连接转内连接 — 在语义允许时。物理优化：枚举多种执行计划（不同的 JOIN 顺序、访问路径、算法选择），用代价模型估算各计划的 CPU + IO 成本，选择最低者。\n\n扩展延伸：MySQL 的优化器在估算时依赖统计信息（cardinality、表行数、数据分布直方图），统计信息过期会导致选错索引。表连接算法：Nested Loop Join（小表驱动大表）、Hash Join（等值连接大表，MySQL 8.0 引入）、Sort-Merge Join（排好序的数据连接）。索引选择：优化器不一定选择（主要看 Cardinality 估算）。通过 FORCE INDEX/IGNORE INDEX 干预，或 ANALYZE TABLE 更新统计信息改善选择。MySQL Optimizer Trace（SET optimizer_trace='enabled=on'）跟踪优化器每一步决策细节。Oracle 的优化器有更丰富的统计信息和灵活性（自适应游标共享、动态采样）。","hints":["为什么统计信息过时会导致索引选错","Hash Join 和 Nested Loop Join 各自的适用场景"],"tags":["MySQL","查询优化","执行计划"],"id":1383},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库连接池原理","content":"请解释数据库连接池的工作原理和关键配置参数。","answer":"答案：连接池维护一组已建立好的数据库连接，供应用重复使用，避免频繁创建和销毁连接的开销\n\n解析：核心机制：初始化时创建一定数量的数据库连接（称为初始连接数/initialSize），应用从池中获取连接（getConnection），使用完毕归还（close -> 释放回池而非真正关闭）。当所有连接被占用时，后续请求等待其他连接归还（池满等待，通过 maxWait 配置超时）。池中的空闲连接超过 maxIdle 时关闭多余连接节省资源；当请求量增加时创建新连接直到最大连接数（maxActive）。工作流程也可以总结为：1）获取连接：检查是否有空闲连接，有空闲则取一个；没有则检查是否达到 maxActive，未达到则创建新连接；已达上限则等待有连接释放 2）归还连接：检查空闲数是否超过 maxIdle，超过则真正关闭，否则放回空闲队列 3）连接保活：定期发送测试查询（如 SELECT 1）验证连接有效性，清理断开的连接。\n\n扩展延伸：常见连接池框架：HikariCP（Spring Boot 默认，性能极高、字节码优化）、Druid（阿里开源，功能全面SQL监控/防火墙）、Tomcat JDBC Pool（Tomcat 内置）。连接池配置：1）maximumPoolSize 不是越大越好，过大会增加数据库负载和连接管理开销 2）minimumIdle 和 maximumPoolSize 建议相等（避免动态创建的风险，HikariCP 推荐）3）maxLifetime 应小于数据库连接超时时间（MySQL wait_timeout，通常 8 小时）4）connectionTimeout 不宜太长（默认 30 秒，可设为 5-10 秒让用户快速失败而不是无限等待）。事务和服务线程数的协调：连接池大小一般等于服务线程数，避免太多并发连接压垮数据库。","hints":["连接池最大连接数设置过大会有什么问题","MySQL 的 wait_timeout 和连接池 maxLifetime 的关系"],"tags":["数据库","连接池","性能"],"id":1384},{"category":"database","difficulty":"hard","type":"short_answer","title":"分片策略详解","content":"请详细分析各种数据库分片（Sharding）策略的优缺点及实现要点。","answer":"答案：分片将大型数据库拆分为多个独立的小型数据库实例以突破单机性能瓶颈\n\n解析：分片策略：1）范围分片（Range Sharding）— 按 ID/时间范围将数据分配到不同分片。优点：实现简单、范围查询高效、可扩展（增加新分片无需迁移）。缺点：写热点（最近数据集中在最新分片）、数据分布不均匀。2）哈希分片（Hash Sharding）— 对分片键取模/hash。优点：数据分布均匀、写压力分散。缺点：扩缩容需要大规模数据迁移（N 变 N' 群迁移问题），范围查询失效。3）一致性哈希分片 — 每个分片对应哈希环上多个虚拟节点。优点：增减节点只影响相邻节点，迁移量最小。4）基于目录的分片 — 维护表映射关系。优点：灵活。缺点：映射表有单点风险。\n\n扩展延伸：分片键选择：最优的分片键使大部分业务查询落在单个分片上，分散写入热点同时保证读性能。通常选用户 ID、商户 ID 等业务实体 ID。常见反模式：按时间分片（大量历史数据冷热不均），按随机 ID 分片（跨分片查询多）。分布式主键：分片后无法用自增 ID，需用 Snowflake/UUID/Segment 模式。跨分片查询难点：1）跨分片 JOIN — 应用层聚合或数据冗余 2）分布式事务 — 使用 Saga 或 TCC 3）全局排序/分页 — 各分片分别取结果后在应用层合并排序。扩缩容方案：1）停机迁移（传统但影响业务）2）MySQL N -> 2N 加倍迁移策略（数据迁移时只搬一半数据）3）基于 Proxy 的在线迁移（通过中间件逐步路由到新分片）。中间件选型：ShardingSphere-JDBC（客户端直连，去中间层无额外网络跳转）、MyCat（服务端代理，对应用透明）、Vitess（K8s 原生，云原生分片方案）。","hints":["范围分片为什么会出现热点问题","分片扩容时数据迁移量如何最小化"],"tags":["数据库","分片","分布式"],"id":1385},{"category":"database","difficulty":"hard","type":"short_answer","title":"B+ 树结构与维护","content":"请介绍 B+ 树的数据结构和维护操作。B+ 树相比 B 树的优势是什么？为什么数据库索引使用 B+ 树而不是二叉树或哈希表？","answer":"答案：B+ 树是多路平衡搜索树，是现代数据库索引的核心数据结构。\n\nB+ 树的结构：\n- 内部节点（非叶子节点）：只存储 key（不存 data），用于路由\n- 叶子节点：存储 key 和 data（或指向 data 的指针），叶子节点通过链表连接\n- 阶数（M）：每个节点最多 M 个子节点，最少 ceil(M/2) 个子节点\n- 根节点例外：最少 2 个子节点（不是 ceil(M/2)）\n\nB+ 树 vs B 树：\n- B 树的内部节点也存储 data（一个节点存储 key + data）\n- B+ 树的内部节点不存 data（更小，一次 IO 可读取更多 key）\n- B+ 树的叶子节点链表支持范围查询（范围扫描只需遍历链表）\n- B+ 树的范围查询性能远优于 B 树（B 树需要中序遍历）\n- 读取 100 条连续数据：B+ 树只需 O(log N + 100)，B 树需要 O(log N × 100)\n\nB+ 树 vs 其他结构：\n- 二叉树（如 AVL/红黑树）：树高 O(log₂N)，B+ 树树高 O(log_M N)。\n  100 万数据：二叉树 20 层，B+ 树（M=1000）3 层→ 3 次 IO vs 20 次 IO\n- 哈希表：精确查询 O(1)，但无法做范围查询（>、<、BETWEEN）\n- 跳表：范围查询性能好（类似 B+ 树），但内存占用更多\n\nB+ 树维护操作：\n- 插入：定位叶子节点 → 插入并排序 → 如果节点满 → 分裂（split）→ 将中间 key 提升到父节点\n- 删除：定位叶子节点 → 删除 → 如果节点低于下限 → 从兄弟节点借（rebalance）或合并（merge）\n- 分裂和合并向上传播（可能导致树高度变化）\n\n扩展延伸：B+ 树的 IO 优化——节点大小通常=磁盘页大小（4KB/16KB），一次 IO 读取完整节点。MySQL InnoDB 的 B+ 树——主键索引的叶子节点存完整行数据，二级索引的叶子节点存主键值（回表查询）。LSM-Tree（LevelDB/RocksDB/TiDB 使用）——B+ 树的写优化替代方案。","hints":["B+ 树 = 内部节点只存 key（窄/浅） + 叶子节点存 key+data + 叶子链表（范围查询快）","数据库索引选择 B+ 树而非二叉树/哈希：低 IO 次数（树高 3-4） + 支持范围查询"],"tags":["数据库","B+树","索引","数据结构"],"id":1386},{"category":"database","difficulty":"hard","type":"short_answer","title":"间隙锁与 Next-Key Lock","content":"请介绍 MySQL InnoDB 的行锁、间隙锁（Gap Lock）和 Next-Key Lock。间隙锁如何防止幻读？Next-Key Lock 在什么情况下退化为行锁或间隙锁？","answer":"答案：Next-Key Lock = 行锁（Record Lock）+ 间隙锁（Gap Lock），InnoDB 默认的锁定机制。\n\n三种锁：\n1. Record Lock（行锁）：锁定单个索引记录。\n   - SELECT ... WHERE id = 1 FOR UPDATE（锁定 id=1 的行）\n2. Gap Lock（间隙锁）：锁定索引记录之间的间隙，防止其他事务在间隙插入。\n   - 锁定范围 (a, b) 但不锁定记录本身\n   - 示例：SELECT ... WHERE id BETWEEN 1 AND 10 FOR UPDATE（锁定 1-10 之间的间隙）\n3. Next-Key Lock：行锁 + 间隙锁的组合。锁定记录及其前面的间隙。\n   - 锁定范围 (a, b]——开区间 + 闭区间\n\n间隙锁如何防止幻读：\n- 幻读：同一个事务内两次相同的查询，第二次看到了第一次没有的行\n- 间隙锁阻止其他事务在间隙中插入新行（Gap Lock 阻塞 INSERT）\n- 可重复读（REPEATABLE READ）级别下，InnoDB 自动使用 Next-Key Lock\n- 读已提交（READ COMMITTED）级别下只使用行锁（不防幻读）\n\nNext-Key Lock 的退化：\n1. 退化为 Gap Lock：当锁定的是唯一索引且记录不存在时（只锁间隙，不锁行）\n2. 退化为 Record Lock：当锁定的是唯一索引且记录存在时。唯一索引唯一确定一条记录，不需要锁间隙\n   - WHERE id = 10（id 是主键）→ Record Lock（只锁 id=10 的行）\n   - WHERE id > 10（范围查询）→ Next-Key Lock\n3. 如果是普通索引：即使用于等值查询，也会使用 Next-Key Lock（因为可能有多个匹配行）\n\n间隙锁的问题：\n- 间隙锁无法在 READ COMMITTED 级别使用（幻读可能发生，但并发更高）\n- 间隙锁可能导致死锁（尤其是并发插入时）\n- 间隙锁的锁定范围可能比预期大（索引树的相邻间隙都被锁定）\n\n扩展延伸：MySQL 8.0 的改进——SELECT ... FOR UPDATE SKIP LOCKED（跳过已锁定的行，适合队列消费场景）。意向锁（Intention Lock）——表级别的锁（IS/IX），表示事务准备在行上加锁，用于快速判断表锁是否冲突。","hints":["Next-Key Lock = Record Lock + Gap Lock，锁定范围 (a, b]，防止幻读","唯一索引等值查询退化为 Row Lock，范围查询使用 Next-Key Lock"],"tags":["数据库","InnoDB","间隙锁","Next-Key Lock"],"id":1387},{"category":"database","difficulty":"medium","type":"short_answer","title":"覆盖索引与索引下推","content":"请介绍 MySQL 的覆盖索引（Covering Index）和索引下推（Index Condition Pushdown, ICP）优化。它们如何减少回表次数？查询计划的 Extra 列中 Using index 和 Using index condition 分别代表什么？","answer":"答案：覆盖索引和索引下推是减少回表（从二级索引回主键索引取数据）的重要优化。\n\n回表（Bookmark Lookup）：\n- 二级索引叶子节点存储的是主键值（不是完整数据行）\n- 查询二级索引后需要再根据主键值去主键索引取完整行数据\n- 回表是随机 IO（主键索引的 B+ 树与二级索引不同），开销大\n\n覆盖索引（Covering Index）：\n- 索引包含了查询需要的所有字段（不需要回表）\n- 示例：索引 (city, age) + 查询 \"SELECT city, age FROM user WHERE city = '北京'\"\n- 索引 (city, age) 包含 city 和 age，直接返回索引中的数据即可\n- Extra 列显示 \"Using index\"（表示使用了覆盖索引）\n- 覆盖索引可以显著减少 IO（减少回表的随机 IO 次数）\n\n索引下推（ICP, Index Condition Pushdown）：\n- 在 MySQL 5.6 引入，将 WHERE 条件中可以用索引判断的条件\"下推\"到存储引擎层\n- 示例：索引 (city, age) + 查询 \"SELECT * FROM user WHERE city = '北京' AND age > 18\"\n  - 无 ICP：存储引擎找到 city='北京' 的所有记录 → 回表 → Server 层过滤 age > 18\n  - 有 ICP：存储引擎在索引遍历时同时判断 age > 18 → 只对通过的行回表\n- Extra 列显示 \"Using index condition\"（表示使用了索引下推）\n- ICP 减少了回表次数（不符合条件的行不需要回表）\n\n覆盖索引 vs 索引下推：\n- 覆盖索引：不需要回表（Extra: Using index）\n- 索引下推：需要回表，但回表前过滤掉不符合条件的行（Extra: Using index condition）\n- 两者可以同时使用：覆盖索引 + ICP（先 ICP 过滤，再通过覆盖索引取数据）\n\n扩展延伸：MySQL 8.0 的 Invisible Index——可以标记索引为不可见，测试删除索引对查询的影响而不实际删除。MRR（Multi-Range Read）优化——将回表产生的随机 IO 排序为顺序 IO。索引统计信息——MySQL 通过采样统计索引的区分度（Cardinality），用于优化器选择索引。","hints":["覆盖索引（Extra: Using index）= 索引包含所有查询字段，无需回表","索引下推（Extra: Using index condition）= 存储引擎层用索引条件过滤后再回表"],"tags":["数据库","索引","覆盖索引","ICP"],"id":1388},{"category":"database","difficulty":"medium","type":"short_answer","title":"MVCC 并发控制","content":"请介绍 MySQL InnoDB 的多版本并发控制（MVCC）原理。MVCC 如何通过 Undo Log 实现不同隔离级别的读？Read View 中的活跃事务列表如何工作？","answer":"答案：MVCC 通过维护数据的多个版本，实现读不阻塞写、写不阻塞读的并发控制。\n\nMVCC 的核心组件：\n1. 隐藏字段：每行包含三个隐藏字段\n   - DB_TRX_ID（最近修改该行的事务 ID）\n   - DB_ROLL_PTR（回滚指针，指向 Undo Log 中的旧版本记录）\n   - DB_ROW_ID（行 ID，聚簇索引使用）\n2. Undo Log（回滚日志）：\n   - INSERT Undo：事务回滚时删除插入的行\n   - UPDATE Undo：记录更新前的旧版本数据（形成版本链）\n   - 版本链：行记录 → DB_ROLL_PTR → 旧版本 → 更旧版本...\n3. Read View（读视图）：\n   - 事务开始/执行快照读时生成当前活跃事务的列表\n   - 包含：low_limit_id（最大事务 ID + 1）、up_limit_id（最小活跃事务 ID）、trx_ids（活跃事务 ID 列表）\n\nRead View 的判断逻辑：\n- 当前读：读取已提交的最新版本（SELECT ... FOR UPDATE / LOCK IN SHARE MODE）\n- 快照读：基于 Read View 读取可见的版本\n  - 遍历版本链，比较 DB_TRX_ID 与 Read View：\n  - DB_TRX_ID == creator_trx_id（本事务创建的）→ 可见\n  - DB_TRX_ID < up_limit_id（已提交的）→ 可见\n  - DB_TRX_ID >= low_limit_id（将来开始的）→ 不可见\n  - up_limit_id <= DB_TRX_ID < low_limit_id：如果在 trx_ids列表中 → 不可见，否则可见\n\n隔离级别的 MVCC 行为：\n- READ UNCOMMITTED：总是读取最新版本（不检查可见性）\n- READ COMMITTED：每条语句执行时生成新的 Read View（同一事务的不同 SELECT 看到不同数据）\n- REPEATABLE READ：事务开始时生成 Read View（整个事务使用同一个 Read View，可重复读）\n- SERIALIZABLE：不使用 MVCC，所有读都加锁（退化为锁并发控制）\n\n扩展延伸：MVCC 只对 READ COMMITTED 和 REPEATABLE READ 有效。当前读（SELECT ... FOR UPDATE/LOCK IN SHARE MODE/INSERT/UPDATE/DELETE）使用行锁 + Next-Key Lock（不是 MVCC）。MVCC 的 Undo Log 在事务提交后清理（如果没有更早的活跃事务需要访问旧版本）。","hints":["MVCC = DB_TRX_ID + DB_ROLL_PTR（Undo 版本链）+ Read View（事务隔离）","Read View 判断：比较行版本事务 ID 与活跃事务列表。RC 每条 SQL 新创建 Read View，RR 事务开始时创建一次"],"tags":["数据库","MVCC","事务","隔离级别"],"id":1389},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redo Log vs Undo Log vs Binlog","content":"请介绍 MySQL 的三种日志：Redo Log、Undo Log 和 Binlog。它们分别用于什么场景？Redo Log 的两阶段提交（2PC）如何保证 Binlog 和 Redo Log 的一致性？","answer":"答案：Redo Log 保障持久性、Undo Log 支持回滚和 MVCC、Binlog 用于复制和恢复。\n\nRedo Log（重做日志）：\n- 用途：保证事务的持久性（Durability）——服务器崩溃后可以恢复已提交的事务\n- 记录内容：物理变更——记录对数据页的修改（如\"将页 10 的偏移量 100 处的值改为 X\"）\n- 存储：固定大小的环形缓冲区（ib_logfile0 + ib_logfile1，默认各 48MB）\n- WAL（Write-Ahead Logging）：事务提交前，Redo Log 必须刷盘（先写日志，后写数据）\n- Crash Recovery：重启时扫描 Redo Log，重新应用已提交但未写入磁盘的变更\n\nUndo Log（回滚日志）：\n- 用途：事务回滚（原子性）+ MVCC 快照读\n- 记录内容：逻辑逆操作——记录如何撤销变更（如\"删除时记录原数据，回滚时重新插入\"）\n- 存储：存储在 Undo Tablespace 中\n- 事务回滚：读取 Undo Log 执行逆操作恢复数据\n- MVCC：通过 Undo Log 构建版本链（见 MVCC 部分）\n\nBinlog（二进制日志）：\n- 用途：主从复制（从节点读取 Binlog 同步数据）+ 数据恢复（PITR, Point-In-Time Recovery）\n- 记录格式：\n  - STATEMENT（SQL 语句）：记录原始 SQL（可能主从不一致）\n  - ROW（行变更，默认）：记录每行的变更（最安全）\n  - MIXED：混合模式\n- 存储：追加写入（不覆盖），形成连续的日志序列\n\n两阶段提交（Redo Log + Binlog 的一致性）：\n1. Prepare 阶段：Redo Log 写入 Prepare 记录并刷盘\n2. Commit 阶段：写入 Binlog 并刷盘 → Redo Log 写入 Commit 标记\n\n崩溃恢复时的一致性判断：\n- Redo Log 有 Prepare 标记，Binlog 已写入：提交事务（已完成两阶段中的 commit）\n- Redo Log 有 Prepare 标记，Binlog 未写入：回滚事务（两阶段未完成）\n- Redo Log 有 Prepare + Commit 标记：直接提交（已经全部完成）\n\n扩展延伸：组提交（Group Commit）——多个事务的 Redo Log 刷盘可以合并为一次 fsync（MySQL 5.6 优化）。Binlog 的写入频率控制——sync_binlog=1（每事务刷盘，最安全）、sync_binlog=N（N 个事务刷一次，性能好但可能丢 N 个事务的数据）。","hints":["Redo Log（物理/持久性/WAL） + Undo Log（逻辑/回滚/MVCC） + Binlog（逻辑SQL/复制/恢复）","两阶段提交：Prepare Redo Log → Write Binlog → Commit Redo Log（崩溃时 Binlog 存在则提交，否则回滚）"],"tags":["数据库","Redo Log","Undo Log","Binlog"],"id":1390},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL MVCC 实现原理","content":"请介绍 MySQL InnoDB 的 MVCC（多版本并发控制）实现原理。","answer":"答案：MVCC 是 InnoDB 实现 RC（读已提交）和 RR（可重复读）隔离级别的核心机制。\n\n核心组件：\n\n1. 隐藏列：\n   - DB_TRX_ID：最近修改该行的事务 ID\n   - DB_ROLL_PTR：回滚指针，指向 Undo Log 中的上一版本\n   - DB_ROW_ID：隐式自增行 ID（无主键时使用）\n\n2. Undo Log（回滚日志）：\n   - Insert Undo：插入操作的回滚日志（事务提交后可直接删除）\n   - Update Undo：更新/删除操作的回滚日志（用于 MVCC 快照读）\n   - 多个版本的记录通过 DB_ROLL_PTR 链式连接\n\n3. Read View（读视图）：\n   - 创建快照时活跃事务的集合\n   - 关键字段：\n     - low_limit_id：当前已分配的最大事务 ID + 1\n     - up_limit_id：活跃事务中的最小事务 ID\n     - creator_trx_id：创建该 Read View 的事务 ID\n     - m_ids：活跃事务 ID 列表\n\n可见性判断规则：\n- 比较 DB_TRX_ID 与 Read View 的边界：\n  1. DB_TRX_ID < up_limit_id：该版本在 Read View 创建前已提交 → 可见\n  2. DB_TRX_ID >= low_limit_id：该版本在 Read View 创建后生成 → 不可见\n  3. DB_TRX_ID 在 m_ids 中：该版本由活跃事务生成 → 不可见\n  4. DB_TRX_ID == creator_trx_id：当前事务自己的修改 → 可见\n  5. 其他：该版本由已提交事务生成 → 可见\n\nRC vs RR 的区别：\n- RC：每次 SELECT 都生成新的 Read View\n- RR：事务中第一次 SELECT 生成 Read View，后续复用\n\n扩展延伸：MVCC 只解决了快照读（普通 SELECT）的幻读问题。当前读（SELECT FOR UPDATE/UPDATE/DELETE）通过 Gap Lock（间隙锁）防止幻读。这也是 RR 级别能防止幻读的原因。","hints":["三个核心组件：隐藏列（DB_TRX_ID/DB_ROLL_PTR）、Undo Log（版本链）、Read View（活跃事务快照）","可见性：比较行版本的 DB_TRX_ID 与 Read View 的边界，决定哪个版本可见","RC vs RR：RC 每次 SELECT 建新 Read View，RR 复用第一次的 Read View"],"tags":["数据库","MySQL","MVCC","InnoDB"],"id":1391},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 索引下推与 MRR","content":"请介绍 MySQL 的索引下推（Index Condition Pushdown, ICP）和多范围读（Multi-Range Read, MRR）优化技术。","answer":"答案：ICP 和 MRR 是 MySQL 优化索引扫描的两种技术。\n\n索引下推（ICP）：\n\n定义：\n- 将 WHERE 条件下推到存储引擎层过滤，减少回表次数\n- 适用于：联合索引 + 范围条件（范围条件后的列无法用于索引查询）\n\n示例：\n- 索引 (name, age)，查询 WHERE name LIKE '张%' AND age = 25\n- 无 ICP：先按 name 范围扫描索引，找到所有 name 以张开头的记录，回表后过滤 age\n- 有 ICP：在索引遍历时同时检查 age = 25，只满足两个条件的才回表\n\n条件：\n- 需要 ICP 的列不是索引的最左前缀列\n- 适用于 range/ref/eq_ref/ref_or_null 访问方法\n- InnoDB 和 MyISAM 都支持\n\n多范围读（MRR）：\n\n定义：\n- 将随机回表转为顺序回表，减少磁盘 I/O\n\n原理：\n1. 从索引中收集一批主键值（rowid）\n2. 对主键值排序（变为有序）\n3. 按主键顺序回表读取完整行\n4. 磁盘读取从随机 I/O 变为顺序 I/O\n\n优化效果：\n- 机械硬盘（HDD）：显著提升（随机 I/O 比顺序慢 10 倍）\n- SSD：提升有限但仍有（减少随机读取）\n\n条件：\n- 适用于 range/ref 等扫描大量行的情况\n- 由 MRR 优化器开关控制（optimizer_switch 中的 mrr 和 mrr_cost_based）\n\n对比：\n| 技术 | 优化点 | 减少什么 |\n|------|--------|----------|\n| ICP | 提前过滤 | 回表次数 |\n| MRR | 排序回表 | 随机 I/O 变为顺序 I/O |\n\n扩展延伸：两者可以同时生效——ICP 减少需要回表的行数，MRR 优化必须回表的行的读取顺序。在分析型查询（范围大、回表多）中效果尤其明显。","hints":["ICP：下推 WHERE 过滤到索引扫描层，减少回表次数（适用于联合索引范围查询后的列）","MRR：收集主键值后排序再回表，将随机 I/O 变顺序 I/O","两者可以同时生效，ICP 减量，MRR 优化读取顺序"],"tags":["数据库","MySQL","索引优化","ICP","MRR"],"id":1392},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库三范式的定义与反范式","content":"请介绍数据库设计中的三个范式（1NF、2NF、3NF）的定义以及反范式设计的适用场景。","answer":"答案：数据库范式是减少数据冗余和避免更新异常的设计规范。\n\n第一范式（1NF）：\n- 定义：每个列都是不可再分的原子值\n- 违反示例：一个字段存储多个电话号码（1, 2, 3）\n- 目标：确保每行每列只有一个值\n\n第二范式（2NF）：\n- 前提：满足 1NF\n- 定义：所有非主键列完全依赖于主键（消除部分依赖）\n- 违反示例：（学生ID, 课程ID）作为联合主键，但\"学生姓名\"只依赖学生ID（部分依赖）\n- 方法：将部分依赖的列拆分到新表\n- 适用：联合主键的场景\n\n第三范式（3NF）：\n- 前提：满足 2NF\n- 定义：非主键列不传递依赖于主键（消除传递依赖）\n- 违反示例：订单表包含（客户ID、客户姓名、客户地址）→ 客户姓名/地址通过客户ID传递依赖于订单ID\n- 方法：将传递依赖的列拆分到客户表\n- 目标：非键列之间不互相依赖\n\n范式的 trade-off：\n- 高范式（3NF+）：数据冗余少、更新异常少、查询需要关联多表\n- 低范式（反范式）：数据冗余多、更新开销大、查询效率高（减少 JOIN）\n\n反范式设计的适用场景：\n1. 读多写少：如内容系统、数据仓库（冗余字段减少 JOIN）\n2. 报表/分析：宽表设计减少关联查询\n3. 高性能查询：预留冗余字段避免大表 JOIN\n4. 数据仓库：星型模型和雪花模型本质上是反范式设计\n\n扩展延伸：实际系统中通常混合使用——核心业务表（订单、支付）保持高范式，查询频繁的聚合表/冗余表使用反范式。不要为范式牺牲性能，也不要全盘反范式导致数据不一致。","hints":["1NF：列不可再分；2NF：非主键列完全依赖于主键（消除部分依赖）；3NF：非主键列不传递依赖","高范式减少冗余但查询慢，反范式查询快但有冗余和一致性问题","实际系统：核心表高范式，查询聚合表反范式"],"tags":["数据库","范式","反范式","设计"],"id":1393},{"category":"database","difficulty":"medium","type":"short_answer","title":"PostgreSQL 与 MySQL 核心差异","content":"请比较 PostgreSQL 和 MySQL 的核心差异和各自的优势场景。","answer":"答案：PostgreSQL 和 MySQL 是两种最流行的开源关系型数据库。\n\n核心差异对比：\n\n| 维度 | PostgreSQL | MySQL |\n|------|-----------|-------|\n| 协议 | 进程模型（每个连接一个进程） | 线程模型（每个连接一个线程） |\n| SQL 标准 | 更严格遵循 | 有扩展和偏离 |\n| 索引类型 | B-tree, Hash, GiST, GIN, BRIN | B-tree（InnoDB） |\n| 存储引擎 | 统一存储引擎 | 插件式（InnoDB, MyISAM 等） |\n| 并发控制 | MVCC（多版本存储） | MVCC（InnoDB） |\n| 复制 | 流复制（物理/逻辑） | 异步/半同步复制，Group Replication |\n| JSON 支持 | JSONB（二进制，可索引） | JSON（文本存储，部分可索引） |\n| 全文检索 | 内置（tsvector） | 内置（InnoDB） |\n| GIS 支持 | PostGIS（业界最强） | 基础 Spatial 扩展 |\n| 分区表 | 声明式分区（10+） | 分区表（5.7+） |\n| 外部数据 | FDW（Foreign Data Wrappers） | FEDERATED 引擎 |\n\nPostgreSQL 优势：\n- 复杂查询优化器更好（嵌套循环/哈希连接/合并连接选择更智能）\n- 高级索引（部分索引、表达式索引、GiST/GIN 支持全文/GIS）\n- CTE 递归查询、窗口函数支持更全面\n- 扩展性强（PostGIS, TimescaleDB, Citus 等生态）\n- 更适合 OLAP 和数据仓库场景\n\nMySQL 优势：\n- 简单查询性能更好（读写分离、主从复制成熟）\n- 生态更广泛（几乎所有语言框架都优先支持 MySQL）\n- 运维工具更丰富（Percona Toolkit, Orchestrator）\n- 分区和分库分表方案成熟（MyCAT, ShardingSphere）\n- 更适合高并发 OLTP 场景\n\n选择建议：\n- OLTP + 简单查询 → MySQL（更成熟的读写分离和分片方案）\n- OLAP + 复杂查询 → PostgreSQL（更好的优化器和高级功能）\n- GIS/JSON/全文检索 → PostgreSQL\n- 新项目无特殊要求 → PostgreSQL（功能更丰富）\n\n扩展延伸：云数据库时代，RDS/Aurora 同时支持 MySQL 和 PostgreSQL，选择更多取决于团队的熟悉度和生态需求。","hints":["PostgreSQL：进程模型、严格 SQL 标准、高级索引（GiST/GIN/BRIN）、扩展性强（PostGIS/TimescaleDB）","MySQL：线程模型、插件式引擎、成熟读写分离、丰富分库分表方案","OLTP+简单查询→MySQL；OLAP+复杂查询/GIS→PostgreSQL"],"tags":["数据库","PostgreSQL","MySQL","对比"],"id":1394},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库连接池设计要点","content":"设计一个高性能数据库连接池，需要考虑哪些关键参数和机制？","answer":"答案：连接池是提升数据库性能的关键组件，通过复用连接减少频繁创建/关闭的开销。\n\n关键参数：\n\n1. 最小/最大连接数：\n   - minIdle：保持的最小空闲连接数（突发流量缓冲）\n   - maxActive：最大活跃连接数（受数据库 max_connections 限制）\n   - 建议：min=2~5, max=CPU核数×2+1（公式源自 PostgreSQL 社区）\n\n2. 连接超时：\n   - connectTimeout：建立 TCP 连接的超时（通常 1~5s）\n   - socketTimeout：等待数据库响应的超时（通常 5~30s）\n   - idleTimeout：空闲连接的最大存活时间（通常 10~60min）\n   - maxLifetime：连接的最大生命周期（通常 30~60min，避免连接泄漏）\n\n3. 等待队列：\n   - 当所有连接忙时，请求是等待还是立即失败\n   - maxWait：最大等待时间（通常 1~10s，-1 表示无限等待）\n   - 队列策略：FIFO（公平）或公平竞争\n\n核心机制：\n\n1. 连接有效性检查：\n   - 定时检测：定期执行 SELECT 1 或 ping\n   - 惰性检测：获取连接时才检查（减少检测开销）\n   - 推荐：惰性检测 + 定时清理无效连接\n\n2. 连接泄漏检测：\n   - 记录连接借出时间戳\n   - 超过阈值未归还的打印告警日志和堆栈\n\n3. 动态伸缩：\n   - 低负载：缩小到 minIdle（释放数据库连接资源）\n   - 高负载：逐步扩展到 maxActive（避免雪崩）\n   - 平滑伸缩：使用信号量或令牌桶控制伸缩速度\n\n4. 数据库自适应：\n   - 检测数据库负载，自动调整连接数上限\n   - 检测数据库故障（宕机/主从切换），快速清空连接池\n\n5. 连接亲和性：\n   - 读写分离：读连接池连接到从库，写连接池连接到主库\n   - 事务绑定：事务内的所有操作使用同一连接\n\n扩展延伸：HikariCP 是目前性能最好的 Java 连接池实现。其核心优化——利用 FastList 替代 ArrayList、利用 ConcurrentBag 实现无锁连接获取、利用 JNDI 延迟初始化。生产环境中推荐 HikariCP。","hints":["关键参数：minIdle/maxActive、各类超时（connect/socket/idle/maxLifetime）、等待策略","核心机制：连接有效性检查、泄漏检测、动态伸缩、数据库自适应","推荐：HikariCP（Java 最快连接池，FastList + ConcurrentBag 等优化）"],"tags":["数据库","连接池","HikariCP","性能优化"],"id":1395},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 自适应哈希索引 AHI","content":"请解释 MySQL InnoDB 的自适应哈希索引（AHI）的工作原理和适用场景。","answer":"答案：AHI 是 InnoDB 根据索引页访问模式自动构建的哈希索引，用于加速等值查询\n\n解析：InnoDB 监测对 B+ 树索引页的访问模式，当发现某个索引页的访问满足一定条件（如连续 100 次通过 B+ 树访问同一页）且通过哈希访问有明显优势时，自动为该页构建哈希索引。AHI 使用分区哈希表（由 innodb_adaptive_hash_index_parts 控制分区数，默认 8）减少锁冲突。哈希索引基于 B+ 树索引的搜索键构建，只支持等值查询（= 和 IN），对范围查询无加速效果。\n\n扩展延伸：AHI 的收益在 高并发等值查询场景（如主键或唯一索引等值查找）明显。但也不是没有代价：1）哈希索引维护有额外开销（写操作需同时维护 B+ 树和哈希结构）2）哈希表锁争用（分区越多越好）3）占用的 buffer pool 内存不可用于缓存数据页。MySQL 5.7 起可通过 PERFORMANCE_SCHEMA 监控 AHI 使用率。在写密集型或范围查询为主的场景，禁用 AHI（innodb_adaptive_hash_index=OFF）可能获得更好性能。AHI 在 MySQL 8.0 中进一步优化，减少了全局锁的争用。","hints":["AHI 在什么查询场景下收益最大","为什么写密集型场景可能更适合禁用 AHI"],"tags":["MySQL","索引","InnoDB"],"id":1396},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL 加锁规则","content":"以下关于 MySQL InnoDB 加锁规则的说法，正确的是？","options":["A) 使用主键索引的 UPDATE 语句只对命中行加行锁","B) REPEATABLE READ 隔离级别下所有查询都会加间隙锁","C) UPDATE 语句的 WHERE 条件列没有索引时，会对所有行加行锁","D) 唯一索引搜索只会加记录锁，不会加间隙锁"],"answer":"A","hints":["间隙锁只在 REPEATABLE READ 及以上级别出现","唯一索引等值搜索确实只加记录锁"],"tags":["MySQL","锁","InnoDB"],"id":1397},{"category":"database","difficulty":"hard","type":"choice","title":"MySQL 主从同步线程","content":"以下关于 MySQL 主从同步的线程的说法，错误的是？","options":["A) 主库有 binlog dump 线程负责推送二进制日志给从库","B) 从库 IO 线程负责接收主库推送的 binlog 并写入 relay log","C) 从库 SQL 线程负责读取 relay log 并在从库上重放","D) 主库的 binlog dump 线程由从库发起连接请求时创建"],"answer":"A","hints":["binlog dump 线程是在主库上创建的，但需要从库连接才启动"],"tags":["MySQL","主从","复制"],"id":1398},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 双写缓冲区 DoubleWrite Buffer","content":"请解释 MySQL InnoDB 的双写缓冲区（DoubleWrite Buffer）的作用和原理。","answer":"答案：双写缓冲区是 InnoDB 用于解决页写入部分失效（partial page write）问题的机制\n\n解析：InnoDB 的数据页通常是 16KB，而磁盘写入的最小单位是 512 字节（扇区）。当操作系统/磁盘在写入 16KB 页的过程中崩溃（写了一半），会导致页的部分数据被覆盖而部分未被写，形成损坏的页（页撕裂）。双写缓冲区在这种情况发生前先备份整页到双写缓冲区文件，然后再写入实际位置。崩溃恢复时通过扫描 doublewrite 检查页是否损坏并用备份修复。双写缓冲区位于系统表空间，大小约 2MB（128 个页 × 2 个区）。\n\n扩展延伸：性能影响：双写带来额外的写入开销（数据先写到 doublewrite buffer 再写回实际位置，放大写操作），但 InnoDB 通过合并写入（fsync 一次写出 batch）缓解。如果文件系统支持原子写入（如 ZFS、某些 SSD 开启了原子写），可以禁用双写缓冲区（innodb_doublewrite=OFF）。Percona 优化的并行双写提升了并发场景下的吞吐。MySQL 8.0.20+ 对双写缓冲区进行了并行化重构，允许各 buffer pool instance 独立写入双写缓冲区，显著减少了并发写入的瓶颈。","hints":["partial page write 在什么场景下发生","为什么 SSD 场景仍然建议开启双写"],"tags":["MySQL","InnoDB","可靠性"],"id":1399},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库分库分表中间件对比","content":"请对比 ShardingSphere、MyCAT 和 Vitess 三种分库分表方案。","answer":"答案：三种方案各有不同的架构哲学和适用场景\n\n解析：ShardingSphere — 提供 JDBC 驱动层分片（Sharding-JDBC）和代理层（Sharding-Proxy），JDBC 方式无需额外部署，应用直连数据库性能好；支持分布式事务（SEATA/本地事务）、读写分离、数据加密、影子库压测等功能。MyCAT — 基于 AOP 的数据库中间件，类似 Cobar，支持分片、全局序列号、跨库 JOIN 和全局表。作为独立代理部署，应用通过 MySQL 协议连接 MyCAT，对应用透明。但文档和技术生态相对落后。Vitess — YouTube 开源的数据库集群系统，基于 SQL 层的连接代理和分布式路由。使用 VTGate（查询路由器）+ VTTablet（表管理器）架构，支持水平分片、自动重分片、元数据管理等。\n\n扩展延伸：选型建议：1）Java 生态项目优先考虑 ShardingSphere（功能丰富、社区活跃、JDBC 方式部署简单）2）大规模 MySQL 集群推荐 Vitess（生产验证广泛，Kubernetes 集成好，自动重分片功能成熟）3）传统项目需要数据库中间件且对性能要求不高可选 MyCAT。分布式场景的核心挑战：跨分片事务（尽量用单分片事务）、跨分片查询（需聚合层）、分片键选择（关系型频繁查询的维度）、扩容和重分片（数据迁移工具成熟度）。","hints":["Sharding-JDBC 相比代理模式有什么优势","Vitess 的 VTGate 和 VTTablet 各负责什么"],"tags":["数据库","分片","中间件"],"id":1400},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 8.0 不可见索引（Invisible Indexes）","content":"MySQL 8.0 引入了不可见索引（Invisible Indexes）特性。什么是不可见索引？它与普通索引有什么区别？在什么场景下应该使用不可见索引？","answer":"答案：不可见索引是对优化器不可见的索引，MySQL 8.0 通过 ALTER TABLE t ALTER INDEX idx INVISIBLE/VISIBLE 控制。优化器在生成执行计划时不会考虑不可见索引，但索引数据仍在维护（插入/更新仍需更新索引）。\n\n解析：不可见索引的核心作用——在不删除索引的情况下测试索引对查询性能的影响。传统做法是删除索引 -> 测试性能 -> 需要时重建。删除和重建大表索引消耗巨大（重建索引需要扫描全表重新构建 B+Tree）。不可见索引可以安全地「关闭」一个索引，观察对查询的影响，如果发现性能下降只需 ALTER VISIBLE 重新启用。\n\n扩展延伸：使用场景——1）判断某个索引是否被使用：先设为 INVISIBLE，观察慢查询和性能指标，如果没有变化说明该索引没有被使用，可以安全删除。2）灰度下线索引：先设为不可见观察一段时间，确认无影响再 DROP。3）唯一索引虽然可以设为不可见，但唯一性约束仍然生效——唯一索引的不可见只是对优化器不可见，插入重复值仍然报错。注意事项：系统变量 optimizer_switch 中的 use_invisible_indexes=ON 可以让优化器看到不可见索引（调试用）。主键索引不能被设为不可见（因为 InnoDB 聚簇索引必须有主键）。","hints":["不可见索引和普通索引在数据维护上的区别是什么","为什么唯一索引设为不可见后仍然能阻止重复插入"],"tags":["MySQL","索引","不可见索引","MySQL 8.0"],"id":1401},{"category":"database","difficulty":"hard","type":"short_answer","title":"PostgreSQL MVCC 与 MySQL MVCC 实现差异","content":"PostgreSQL 和 MySQL InnoDB 都使用 MVCC 实现并发控制，但两者的实现机制有显著不同。请对比分析它们在多版本存储、垃圾回收、事务快照等方面的核心差异。","answer":"答案：PostgreSQL 将多版本数据直接存储在数据页中（通过元组标记可见性），MySQL InnoDB 将旧版本存储在 Undo Log 中（通过回滚指针链接）。垃圾回收方面：PostgreSQL 使用 VACUUM 回收死元组，MySQL 使用 Purge 线程异步清理 Undo Log。\n\n解析：1）多版本存储——PostgreSQL：每个元组（Tuple）头部包含 xmin（创建事务 ID）和 xmax（删除/更新事务 ID），旧版本和新版本都存在于数据页中。更新时产生新的元组版本，旧版本标记为死亡。MySQL InnoDB：数据页只存储最新版本，旧版本通过 Undo Log 链存储（DB_ROLL_PTR 回滚指针）。更新时写入新数据行到数据页，旧行数据写入 Undo Log。\n\n2）垃圾回收——PostgreSQL VACUUM：需要手动或自动（autovacuum）回收数据页中的死元组空间。VACUUM 不足会导致表膨胀（数据文件持续增大）。MySQL Purge：后台 Purge 线程异步清理 Undo Log 中不再需要的旧版本数据（由系统自动管理，无需人工干预）。\n\n3）事务快照——PostgreSQL 使用全局事务状态（通过 clog 和事务快照结构），MVCC 可见性判断比 MySQL 更复杂。MySQL InnoDB 的 Read View 只需要比较事务 ID 和活跃事务列表。\n\n扩展延伸：4）事务 ID 管理——PostgreSQL 事务 ID 是 32 位（约 42 亿个），有回卷（wraparound）问题，需要定期 FREEZE 防止回卷。MySQL InnoDB 事务 ID 也是 32 位但通过系统表空间管理，不存在回卷问题。5）HOT（Heap-Only Tuple）更新——PostgreSQL 允许同一页内的更新通过 HOT 机制避免索引维护。MySQL InnoDB 没有 HOT，更新二级索引列时需要更新所有相关索引。6）性能影响——PostgreSQL 的 VACUUM 开销在大并发更新场景下显著（IO 和 CPU），MySQL 的 Purge 开销相对较小但 Undo Log 可能增长很快。","hints":["PostgreSQL 的 VACUUM 和 MySQL 的 Purge 线程在处理旧版本上的核心区别","PostgreSQL 事务 ID 回卷（Wraparound）问题是什么"],"tags":["PostgreSQL","MySQL","MVCC","数据库对比"],"id":1402},{"category":"database","difficulty":"hard","type":"short_answer","title":"查询重写与物化查询表（Materialized Query Tables）","content":"什么是查询重写（Query Rewrite）？物化查询表（Materialized Query Table，MQT）如何加速查询？MySQL 和 PostgreSQL 在物化视图支持上有哪些差异？","answer":"答案：查询重写是数据库优化器将用户 SQL 转换为更高效执行计划的过程，包括视图展开、谓词推入、子查询去关联等。物化查询表（MQT）预计算并存储查询结果，以空间换时间加速复杂聚合查询。MySQL 不支持原生物化视图（需通过触发器或 Event 模拟），PostgreSQL 支持原生物化视图（MATERIALIZED VIEW）。\n\n解析：1）查询重写的常见类型——常量折叠（WHERE 1=1 被优化掉）、谓词推入（将 WHERE 条件下推到子查询内部）、子查询去关联（将相关子查询改写为 JOIN 或半连接）、视图展开（将视图定义合并到主查询）、OR 条件优化（将 OR 改写为 UNION）。\n\n2）物化查询表（MQT）——在 DB2 等数据库中称为 MQT，在 PostgreSQL 中称为物化视图。预计算并存储查询结果集，读时直接返回已计算好的数据。适用场景：复杂的聚合查询（多表 JOIN + GROUP BY + 多级聚合）、BI 报表查询、大数据量的统计查询。维护成本：MQT 需要刷新（REFRESH MATERIALIZED VIEW），全量刷新代价大，增量刷新（ON COMMIT REFRESH）实时性更好但实现复杂。\n\n扩展延伸：3）MySQL 的物化视图替代方案——MySQL 8.0 支持 CTE 和窗口函数但不支持原生物化视图。替代方案：a) 使用触发器维护汇总表（INSERT/UPDATE/DELETE 时同步更新汇总表）。b) 使用 Event Scheduler 定期执行 INSERT ... SELECT 重建汇总表。c) 使用 Flexviews 第三方工具。4）PostgreSQL 物化视图——REFRESH MATERIALIZED VIEW CONCURRENTLY（PG 9.4+）支持不阻塞读的并发刷新（需要物化视图上建立唯一索引）。5）查询重写优化案例——a) 将 NOT IN 子查询改写为 NOT EXISTS 或 ANTI JOIN（MySQL 8.0 优化器自动处理）。b) 将 UNION 改写为 UNION ALL（如果不需要去重，UNION ALL 避免排序去重开销）。c) 将 COUNT(column) 改写为 COUNT(*)（语义等价时后者性能更好）。","hints":["MySQL 为什么没有原生物化视图支持——InnoDB 的 MVCC 和物化视图刷新机制的实现冲突","PostgreSQL CONCURRENTLY 刷新如何做到不阻塞读"],"tags":["查询重写","物化视图","MySQL","PostgreSQL","优化"],"id":1403},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库链接（DBLink）与跨库查询","content":"什么是数据库链接（Database Link / DBLink）？MySQL、PostgreSQL、Oracle 分别如何实现跨数据库查询？DBLink 有哪些安全风险和性能限制？","answer":"答案：数据库链接是一种跨数据库实例访问数据的机制，允许在一个数据库中查询另一个数据库的表。Oracle 原生支持 DBLink（CREATE DATABASE LINK），PostgreSQL 通过 dblink 扩展或 postgres_fdw 实现，MySQL 通过 FEDERATED 存储引擎实现。\n\n解析：各数据库的实现方式——1）Oracle DBLink：最成熟，支持公/私有两种类型，通过 CREATE DATABASE LINK 创建。可通过 DBLink 执行查询、DML、远程过程调用。支持同义词配合使用简化 SQL。2）PostgreSQL：dblink 扩展（较旧，基于函数）和 postgres_fdw（较新，基于 SQL/MED 标准，推荐使用）。postgres_fdw 通过 CREATE FOREIGN TABLE 映射远程表，支持 IMPORT FOREIGN SCHEMA 批量导入，支持排序和 JOIN 下推到远程端（PG 10+）。3）MySQL FEDERATED 引擎：需要创建 FEDERATED 表映射远程表，功能有限（不支持远程 DDL、事务行为复杂、性能较差）。\n\n扩展延伸：安全风险——1）凭据暴露：DBLink 连接字符串中可能包含数据库密码，查看 DBLink 定义的用户可以获取远程库凭据。2）网络攻击面：DBLink 开启跨网络访问，增加了被攻击的风险（远程端可能成为跳板）。3）权限放大：DBLink 通常以固定用户身份连接，如果该用户权限过高，可能导致越权访问。性能限制——1）跨库查询无法使用远程索引优化（需要将数据拉到本地再过滤）。2）网络延迟叠加（多次跨库查询时 RTT 累加）。3）大数据量传输可能压垮网络或内存。4）分布式事务：跨 DBLink 的分布式事务（两阶段提交）在高并发下可能锁等待严重。生产建议——DBLink 适合轻量级、低频率的跨库查询，高频场景应考虑数据同步（CDC + 异构数据库同步工具如 Canal、Debezium）。","hints":["postgres_fdw 的查询下推（Pushdown）优化了什么","FEDERATED 引擎为什么在 MySQL 中较少使用"],"tags":["DBLink","跨库查询","Oracle","PostgreSQL","MySQL"],"id":1404},{"category":"database","difficulty":"hard","type":"short_answer","title":"SQL 窗口函数：ROWS vs RANGE vs GROUPS 帧","content":"SQL 窗口函数中的窗口帧（Window Frame）有 ROWS、RANGE、GROUPS 三种定义方式。它们的差异是什么？各自适用于什么场景？请举例说明。","answer":"答案：ROWS 基于物理行偏移定义帧边界（如 BETWEEN 1 PRECEDING AND 1 FOLLOWING），RANGE 基于逻辑值范围定义边界（如 BETWEEN INTERVAL '7' DAY PRECEDING AND CURRENT ROW），GROUPS 基于分组数定义边界（如 BETWEEN 1 GROUP PRECEDING AND 1 GROUP FOLLOWING）。\n\n解析：三种帧的区别——1）ROWS 帧：最直观，按 ORDER BY 排序后的物理位置计算。ROWS BETWEEN 2 PRECEDING AND CURRENT ROW 表示取当前行和前 2 行共 3 行。适合：移动平均（如近 3 笔交易的平均值）、累计求和。ROWS 帧不考虑并列（Ties）——如果 ORDER BY 值相同，相邻行也属于不同物理行。\n\n2）RANGE 帧：按 ORDER BY 列的值范围计算帧范围。RANGE BETWEEN 100 PRECEDING AND 100 FOLLOWING 表示取当前行值 ±100 范围内的所有行。如果多行的 ORDER BY 值相同，这些行都会被包含在帧中。适合：基于值的窗口计算（如价格 ±10% 范围的平均值）。RANGE 帧要求 ORDER BY 列是单一列且数据类型支持加减运算。\n\n3）GROUPS 帧：SQL:2011 标准新增，按 ORDER BY 值的分组（Group/Peer Group）计算。GROUPS BETWEEN 1 GROUP PRECEDING AND 1 GROUP FOLLOWING 表示取当前行所在的分组及其前后各 1 个分组的所有行。同一值视为同一组。适合：需要按值分组进行窗口计算，且需要考虑组内多行的场景。\n\n扩展延伸：实际应用——1）移动平均（ROWS）：SUM(amount) OVER (ORDER BY date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) 计算近 7 天的移动总和。2）滑动时间窗口（RANGE）：SUM(revenue) OVER (ORDER BY sale_date RANGE BETWEEN INTERVAL '30' DAY PRECEDING AND CURRENT ROW) 计算过去 30 天的滚动收入。3）分组滑动（GROUPS）：AVG(score) OVER (ORDER BY score GROUPS BETWEEN 1 PRECEDING AND 1 FOLLOWING) 取当前分数段及其前后分数段的平均。MySQL 8.0+ 支持所有三种帧定义。PostgreSQL 也支持全部三种。注意：默认帧（未指定帧时）是 RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW，可能导致意外结果（因为 RANGE 包含并列行）。","hints":["RANGE 帧和 ROWS 帧在 ORDER BY 有并列值时的行为差异是什么","为什么默认窗口帧（RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW）可能导致计算结果不符合预期"],"tags":["SQL","窗口函数","ROWS","RANGE","GROUPS"],"id":1405},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 间隙锁加锁规则","content":"详细解释 MySQL InnoDB 在 REPEATABLE READ 隔离级别下，间隙锁（Gap Lock）的加锁规则。什么情况下加间隙锁？什么情况下只加记录锁？唯一索引、非唯一索引、无索引三种场景的加锁范围分别是什么？","answer":"间隙锁锁定索引记录之间的间隙（Gap），目的是防止幻读（Phantom Read）。在 REPEATABLE READ 级别下，间隙锁默认生效。\\n加锁规则如下：\\n1. 唯一索引等值查询：如果命中唯一记录，只加记录锁（Record Lock），不加间隙锁。因为唯一索引能精确锁定行，无需间隙锁防止幻读。\\n2. 唯一索引等值查询未命中：对查询范围内但不存在的记录间隙加间隙锁（Gap Lock）。\\n3. 非唯一索引等值查询：对命中的索引记录加记录锁，同时对前后的间隙加间隙锁（Next-Key Lock = Record Lock + Gap Lock）。\\n4. 无索引或全表扫描：对所有记录和所有间隙加锁，相当于锁住整张表。\\n5. 范围查询：对范围内的所有记录加记录锁，对边界前后的间隙加锁。\\n间隙锁与插入意向锁不互斥——间隙锁只阻止其他事务插入到该间隙，不阻止空隙被锁。间隙锁在 READ COMMITTED 级别下自动禁用。","hints":["思考唯一索引与非唯一索引在 RR 级别下的加锁差异","范围查询与等值查询的加锁范围有何不同"],"tags":["MySQL","间隙锁","InnoDB","隔离级别","幻读"],"id":1406},{"category":"database","difficulty":"medium","type":"short_answer","title":"索引下推 ICP","content":"什么是 MySQL 的索引下推（Index Condition Pushdown, ICP）？它是如何优化查询执行的？在哪些条件下生效？有哪些限制？","answer":"ICP 是 MySQL 5.6 引入的查询优化技术，将索引过滤条件下推到存储引擎层执行。\\n工作原理：\\n- 不使用 ICP：存储引擎通过索引定位到记录后，将完整行记录返回给 Server 层，Server 层再应用 WHERE 条件过滤。\\n- 使用 ICP：存储引擎在读取索引记录时，直接使用索引包含的列进行条件过滤，只将满足条件的记录返回给 Server 层。\\n\\n生效条件：\\n1. 只能用于 InnoDB 和 MyISAM 表。\\n2. 作用于二级索引（非聚簇索引），不能用于聚簇索引（因为聚簇索引本身就包含完整行）。\\n3. WHERE 条件中部分列必须是索引的组成部分（覆盖索引的部分列）。\\n4. 不支持子查询和存储过程。\\n\\n收益：减少存储引擎到 Server 层的行数据传输量，减少回表次数，显著提升查询性能。\\n可通过 EXPLAIN 的 Extra 列看到「Using index condition」表示 ICP 生效。","hints":["ICP 把过滤逻辑从哪一层下移到了哪一层？","ICP 对二级索引和聚簇索引的效果有何不同"],"tags":["MySQL","ICP","索引优化","查询优化"],"id":1407},{"category":"database","difficulty":"hard","type":"short_answer","title":"B+树页分裂合并","content":"解释 InnoDB B+树索引的页分裂（Page Split）和页合并（Page Merge）机制。什么情况下触发分裂？分裂策略是什么？对索引性能有什么影响？","answer":"页分裂：\\n1. 触发条件：B+树页面已满（默认 16KB），需要插入新记录时发生。\\n2. 分裂策略：InnoDB 采用平衡分裂（Balanced Split），将页面中大约一半的记录移到新页。在 B-Tree 索引的右侧插入时（自增主键），InnoDB 还会尝试简单的乐观分裂仅分配新页。\\n3. 影响：写放大（一次分裂涉及原页、新页和父页的修改），产生索引碎片，降低页面填充率。\\n\\n页合并：\\n1. 触发条件：页面删除操作后，相邻页面填充率较低（通常合并后可放入同一页时），由 Purge 操作在适当时机触发。\\n2. 合并过程：将两个相邻页的数据合并到一页，释放另一页。\\n3. 影响：减少空间浪费，改善缓存效率。\\n\\n优化建议：\\n- 自增主键可减少随机插入导致的频繁页分裂（右分裂只需新分配页）。\\n- 避免频繁的随机插入操作（如 UUID 作为主键会导致大量随机分裂）。\\n- 监控 innodb_buffer_pool_stats 和索引统计信息评估碎片程度。","hints":["自增主键和 UUID 主键在页分裂方面有何不同表现","InnoDB 默认页大小是多少？页分裂后填充率大约是多少"],"tags":["MySQL","B+树","InnoDB","页分裂","页合并"],"id":1408},{"category":"database","difficulty":"medium","type":"short_answer","title":"主从复制半同步","content":"解释 MySQL 半同步复制（Semi-Synchronous Replication）的工作原理。它与异步复制和全同步复制有何区别？超时机制如何处理？是否保证数据不丢失？","answer":"半同步复制机制：\\n1. 主库提交事务时，等待至少一个从库确认已收到 Binlog 事件后，才向客户端返回提交成功。\\n2. 从库写入 Relay Log 后返回 ACK，不要求已经应用（Apply）。\\n3. 通过插件实现（semisync_master.so / semisync_slave.so）。\\n\\n与异步复制对比：\\n- 异步复制：主库不等待从库确认，性能最高但有数据丢失风险。\\n- 半同步复制：主库等待至少一个从库回复 ACK，兼顾性能和数据安全。\\n- 全同步复制：主库等待所有从库确认，数据最安全但延迟最高。\\n\\n超时降级机制：\\n参数 rpl_semi_sync_master_timeout（默认 10 秒）控制等待超时。超时后自动降级为异步复制。当从库恢复并追上进度时，自动恢复半同步模式。\\n\\n数据安全性：\\n半同步不保证数据不丢失——它只保证从库已收到 Binlog，但不保证已应用。如果从库在收到 Binlog 但未应用时宕机，切换后可能丢失数据。还可设置 rpl_semi_sync_master_wait_point=AFTER_SYNC（在 Binlog 落盘后等待 ACK，客户端看到提交前已同步）或 AFTER_COMMIT（默认，提交后等待 ACK，性能稍好但窗口更大）。","hints":["半同步等待的是从库的什么操作完成——收到还是应用？","超时后主库会怎么做？从库恢复后又如何"],"tags":["MySQL","主从复制","半同步","高可用"],"id":1409},{"category":"database","difficulty":"medium","type":"short_answer","title":"InnoDB 自适应哈希","content":"解释 InnoDB 自适应哈希索引（Adaptive Hash Index, AHI）的工作原理。它如何加速查询？什么情况下反而会降低性能？如何监控和调优？","answer":"AHI 是 InnoDB 在内置 B+树索引之上自动构建的哈希索引结构，无需手动创建。\\n\\n工作原理：\\n1. InnoDB 监控对 B+树索引页的访问模式（持续观察索引搜索的匹配前缀）。\\n2. 当发现某个页面被反复以相同前缀模式访问时，自动为该页面构建哈希索引。\\n3. 哈希索引以 B+树页为哈希表的值，以索引前缀为键。\\n4. 将 B+树的 O(log n) 查找降为 O(1) 哈希查找。\\n\\n收益场景：\\n- 大量等值查询（如主键或唯一索引的点查）。\\n- 工作集（Working Set）能够放入 Buffer Pool 的场景。\\n\\n负面影响：\\n- 写操作需要维护哈希表，增加开销。\\n- 占用额外内存（由 innodb_adaptive_hash_index_parts 控制分区数，默认 8）。\\n- 对于写密集型负载或全表扫描场景，AHI 维护开销可能超过收益。\\n\\n监控与调优：\\n- SHOW ENGINE INNODB STATUS 的 SEMAPHORES 部分显示 AHI 相关等待。\\n- 通过 innodb_adaptive_hash_index=OFF 可完全禁用。\\n- 在读写比例 1:1 以下的场景通常建议禁用。\\n- 分区数（innodb_adaptive_hash_index_parts）可减少 AHI 的锁竞争。","hints":["AHI 是建立在什么之上的？它替换了什么查找路径","什么类型的负载下 AHI 反而会变成负担"],"tags":["MySQL","InnoDB","自适应哈希","索引"],"id":1410},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 索引合并（Index Merge）优化原理","content":"当一条 SQL 查询的 WHERE 条件涉及多个独立索引列时，MySQL 优化器可以选择 Index Merge（索引合并）优化。请说明 Index Merge 的三种算法（Intersection、Union、Sort-Union）的工作原理，以及什么情况下 Index Merge 反而比使用单个复合索引更差。","answer":"答案：MySQL 5.1+ 引入的 Index Merge 优化允许单条查询同时使用多个索引，通过 Intersection、Union 或 Sort-Union 三种算法合并结果。优化器选择 Index Merge 的前提是合并后成本低于全表扫描或使用单个索引。\n\n解析：三种算法：1）Intersection（交集）——适用于 WHERE a=1 AND b=1 场景，索引 a 和 b 各自获取 RowID 集合后求交集。两个条件都必须有索引且选择性都好，合并后显著减少回表次数。2）Union（并集）——适用于 WHERE a=1 OR b=1 场景，各自获取 RowID 集合后求并集（去重）。3）Sort-Union——适用于无法直接合并的场景（如 a > 1 OR b > 1），先对 RowID 排序再合并。\n\n扩展延伸：Index Merge 并非总是最优——多个索引扫描本质上仍是大量随机 I/O，不如一个覆盖索引高效。优化策略：1）用复合索引替代多个单列索引（让一个索引同时覆盖多个条件）。2）关闭 Index Merge 优化器开关（optimizer_switch 中 index_merge=off）强制优化器选择复合索引。3）EXPLAIN 中 Extra 字段显示 Using intersect/union/sort_union 说明触发了 Index Merge。注意：Index Merge 不适用于全文索引。","hints":["EXPLAIN 中 Extra 的 Using intersect 和 Using union 分别对应什么 SQL 模式","Index Merge 为什么比单个复合索引更差的情况发生在什么时候"],"tags":["MySQL","索引合并","Index Merge","SQL优化"],"id":1411},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 8.0 直方图统计信息","content":"MySQL 8.0 引入了直方图（Histogram）统计信息。直方图解决了优化器选择执行计划时的什么问题？singleton 和 equi-height 两种直方图类型有什么区别？如何创建和维护直方图？","answer":"答案：MySQL 8.0 的直方图为非索引列提供数据分布信息，帮助优化器更准确地估计 WHERE 条件的选择性（Selectivity），解决数据分布严重倾斜时优化器选错执行计划的问题。Singleton 为每个不同值创建一个 bucket（适合枚举值少的列），Equi-height 按值排序后均分到定数 bucket（适合连续值列）。\n\n解析：没有直方图时，优化器假设列数据均匀分布→当实际分布严重倾斜时（如 99% 行 status='active'，仅 1% 行 status='inactive'），优化器可能误认为 status='inactive' 条件需要扫描大量行，错误选择全表扫描而非索引。直方图将列值划分为多个 bucket，每个 bucket 记录区间内行数、频次等统计信息，优化器据此做出更准确的成本估算。\n\n扩展延伸：创建语法：ANALYZE TABLE t UPDATE HISTOGRAM ON col1, col2 WITH 100 BUCKETS。删除：ANALYZE TABLE t DROP HISTOGRAM ON col1。查看：SELECT * FROM INFORMATION_SCHEMA.COLUMN_STATISTICS。注意事项：1）直方图只对非索引列有意义（索引列已有更精确的 Cardinality 统计）。2）统计数据非实时——数据大量变更后需要手动更新直方图。3）直方图存储为 JSON 格式，在 MySQL 8.0 数据字典中。应用建议：对数据倾斜严重且频繁参与 WHERE 条件查询的非索引列创建直方图，可显著改善 JOIN 和子查询的执行计划。","hints":["直方图为什么只对非索引列有用","equi-height 直方图的 overflow bucket 处理什么极端场景"],"tags":["MySQL","直方图","Histogram","优化器","统计信息"],"id":1412},{"category":"database","difficulty":"hard","type":"choice","title":"InnoDB Purge 历史版本清理机制","content":"关于 InnoDB 的 Purge 线程清理 Undo Log 中历史版本数据的行为，以下描述正确的是？","options":["A) 事务执行 COMMIT 后，Purge 线程立即清理该事务的所有 Undo Log，保证 undo 表空间尽快释放","B) Purge 线程只清理已提交事务中、且在所有当前活跃事务的 ReadView 中均不可见的历史版本","C) Purge 线程数量通过 innodb_purge_threads 配置，MySQL 8.0 中最大只能配置为 1","D) Purge 操作由用户事务线程在提交时同步触发，不存在独立的后台 Purge 线程"],"answer":"答案：B) Purge 线程只清理已提交事务中、且在所有当前活跃事务的 ReadView 中均不可见的历史版本\n\n解析：InnoDB 的 Purge 采用延迟清理策略——事务提交后不会立即删除 Undo Log 中的历史版本。只有当一个历史版本不再被任何活跃事务的 ReadView 需要时（既不属于活跃事务，也不在任何活跃事务的可视范围内），Purge 线程才会将其清理。这是 MVCC 的核心设计：长时间运行的事务会阻止 Purge 进度，导致 Undo Log 膨胀。\n\n扩展延伸：Purge 相关配置：innodb_purge_threads（MySQL 8.0 默认 4，最大可配 32）控制并发 Purge 线程数。innodb_max_purge_lag——当 Purge 落后超过此阈值时限制新事务进入速度。监控关键指标：SHOW ENGINE INNODB STATUS 中的 HISTORY LIST LENGTH——未 Purge 的事务数，持续增长说明 Purge 落后。Purge 落后的后果：Undo 表空间无法收缩、聚簇索引中产生大量标记删除的旧版本占用额外空间。优化建议：避免长事务、innodb_purge_threads 根据并发写入负载调整。","hints":["Purge 线程的延迟清理策略为什么可能导致 Undo 表空间膨胀","HISTORY LIST LENGTH 持续增长说明什么问题"],"tags":["MySQL","InnoDB","Purge","MVCC","Undo Log"],"id":1413},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL Hash Join 实现原理与优化","content":"MySQL 8.0.18+ 引入了 Hash Join 算法。请说明 Hash Join 的工作原理、与 Nested Loop Join 相比的优势和劣势，以及优化器如何选择使用哪种 JOIN 算法。","answer":"答案：Hash Join 适用于等值连接且关联列上无索引或选择性差的场景，用小表构建内存哈希表、大表逐行探测。相比 Nested Loop Join（适合小表驱动且有索引的场景），Hash Join 在无索引的大表关联场景下性能远优于 NLJ，但需要额外内存构建哈希表，不支持非等值连接。\n\n解析：Hash Join 执行流程：1）选择较小的表作为构建表，计算 join 列的 hash 值构建内存哈希表。如果构建表超过 join_buffer_size（默认 256KB），MySQL 会分块写入临时文件（分批 on-disk Hash Join）。2）扫描探测表（另一个表），逐行计算 hash 值在哈希表中查找匹配。In-Memory 一次完成，On-Disk 分块进行（部分写入磁盘再合并），性能显著下降。\n\n扩展延伸：MySQL 优化器选择 JOIN 算法的决策因素：1）关联列有索引且驱动表小 → Nested Loop Join。2）关联列无索引且表较大 → Hash Join。3）/*+ HASH_JOIN(t1) */ 和 /*+ NO_HASH_JOIN(t1) */ 可提示优化器。Hash Join 的限制：不支持非等值连接（如 >、<、LIKE）。注意：Hash Join 只在 join_buffer_size 足够存放构建表时性能最优，内存不足时的分块模式可能大幅退化。OLAP 大表关联场景 Hash Join 效果最显著，OLTP 短查询中 NLJ 仍然占主导。","hints":["Hash Join 在内存不足时的分块模式如何工作","什么情况下 Nested Loop Join 仍然优于 Hash Join"],"tags":["MySQL","Hash Join","SQL优化","JOIN"],"id":1414},{"category":"database","difficulty":"hard","type":"true_false","title":"MySQL 分区表的查询剪裁限制","content":"MySQL 分区表在查询时自动触发分区剪裁（Partition Pruning），排除不包含目标数据的分区。因此，对于任何 SQL 查询，分区表的性能都一定优于等价的非分区表。","options":["A) 正确","B) 错误"],"answer":"B","hints":["分区剪裁在什么情况下不会生效——WHERE 条件与分区键的关系","分区表为什么可能在有些场景下比非分区表性能更差"],"tags":["MySQL","分区表","Partition Pruning","SQL优化"],"id":1415},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Next-Key Lock 加锁规则与幻读处理","content":"请详细解释 MySQL InnoDB 在可重复读隔离级别下，Next-Key Lock 的加锁规则。什么情况下会退化为 Record Lock 或 Gap Lock？如何通过加锁规则分析线上死锁？","answer":"答案：Next-Key Lock = Record Lock + Gap Lock，锁住索引记录及记录之前的间隙。等值唯一索引命中退化为 Record Lock；等值无匹配退化为 Gap Lock；范围查询全程 Next-Key Lock。\n\n解析：加锁规则（基于 MySQL 8.0）：1）等值查询且唯一索引命中——退化为 Record Lock（只锁记录本身）。2）等值查询且无匹配记录——退化为 Gap Lock（锁住该值应在的间隙）。3）范围查询——覆盖范围内的所有记录及间隙，精确匹配的等值部分退化。4）非唯一索引等值查询——锁定命中记录的行锁 + 前后间隙锁，以及相邻的下一个键的 Gap Lock。\n\n扩展延伸：死锁分析技巧：事务 A 锁了记录 1 请求记录 2，事务 B 锁了记录 2 请求记录 1。更隐蔽的是同一条 SQL 在不同索引上加锁顺序不同——二级索引先锁（使用二级索引的 Next-Key Lock），再回表锁聚簇索引。如果另一个事务从聚簇索引反向操作，加锁顺序相反则死锁。排查工具：SHOW ENGINE INNODB STATUS\\G 查看 LATEST DETECTED DEADLOCK，关注两个事务的 SQL 语句和等待的锁模式。","hints":["Gap Lock 只在 REPEATABLE READ 级别存在，READ COMMITTED 级别没有 Gap Lock","为什么 RC 级别比 RR 级别更少出现死锁——因为没有 Gap Lock"],"tags":["MySQL","InnoDB","锁","Next-Key Lock","间隙锁"],"id":1416},{"category":"database","difficulty":"hard","type":"choice","title":"MySQL 快照读与当前读的区别","content":"关于 MySQL InnoDB 的快照读（Consistent Read）和当前读（Locking Read），以下说法错误的是？","options":["A) 快照读通过 Read View + undo log 实现，不加锁，读不会阻塞写","B) 当前读会对读取的记录加锁，SELECT...FOR UPDATE 加排他锁，SELECT...LOCK IN SHARE MODE 加共享锁","C) 在 REPEATABLE READ 级别下，快照读的 Read View 在事务开始时创建并复用，保证多次读结果一致","D) UPDATE 语句的 WHERE 条件即使使用非索引列，也只会对匹配的记录加 Record Lock"],"answer":"答案：D)。解析：UPDATE/DELETE 的 WHERE 条件如果使用非索引列，InnoDB 会对聚簇索引进行全表扫描，并对扫描过程中遇到的所有记录加 Next-Key Lock（或 Record Lock），不是只锁匹配的记录。如果扫描了 100 万行，即使只更新 1 行，100 万行都会被锁定——这是线上常见的「锁风暴」根因。A) 正确，快照读是 MVCC 的非阻塞读。B) 当前读包括 SELECT...FOR UPDATE（X 锁）、SELECT...LOCK IN SHARE MODE（S 锁）以及 UPDATE/DELETE/INSERT 操作的隐含读。C) 正确，RR 的 ReadView 在事务首次读时创建并复用。","hints":["全表扫描时加锁的传染范围——「锁住扫描过的所有行」","为什么 DELETE 大量数据时可能锁住整个表"],"tags":["MySQL","MVCC","锁","快照读","当前读"],"id":1417},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 索引选择性（Cardinality）与优化器","content":"什么是索引选择性（Cardinality/区分度）？MySQL 优化器如何基于它选择执行计划？当优化器选错索引时该如何处理？","answer":"答案：索引选择性 = 不同值的数量 / 总行数。选择性越高，索引过滤效果越好。优化器通过 Cardinality 统计信息估算扫描行数，选择成本最低的方案。选错索引时可用 USE INDEX 或 ANALYZE TABLE 刷新统计信息。\n\n解析：Cardinality 是 SHOW INDEX 中显示的字段，表示索引中不同值的估算数量。选择性 = Cardinality / 表行数，越接近 1 越好。MySQL 通过随机采样（innodb_stats_sample_pages 控制采样页数，默认 8）估算 Cardinality，不是精确值。\n\n扩展延伸：优化器选错索引的根因：1）统计信息过时——大量增删改后未触发自动更新，执行 ANALYZE TABLE 刷新。2）回表成本被忽略——二级索引选择性不高（如性别索引选择性 50%），优化器可能选择全表扫描，因为随机 IO 回表成本高。3）ORDER BY 与 WHERE 冲突——优化器优先满足排序走排序列索引，而非过滤条件索引。解决方案：建立覆盖索引（让二级索引包含所有查询字段，消除回表）；FORCE INDEX 强制指定；调整 SQL 或索引结构。","hints":["innodb_stats_sample_pages 参数如何影响 Cardinality 准确性","为什么「性别」字段通常不适合建索引——选择性太低"],"tags":["MySQL","索引","优化器","Cardinality","SQL优化"],"id":1418},{"category":"database","difficulty":"hard","type":"true_false","title":"MySQL RR 级别与幻读的关系","content":"MySQL InnoDB 在 REPEATABLE READ 隔离级别下，通过 MVCC 和 Next-Key Lock 完全消除了幻读（Phantom Read）问题。","options":["A) 正确","B) 错误"],"answer":"B","hints":["快照读和当前读在幻读处理上的差异——RR 级别下快照读无幻读但当前读仍可能有","什么场景下 RR 级别会出现「幻读」——先快照读再当前读"],"tags":["MySQL","幻读","RR","隔离级别","事务"],"id":1419},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 分库分表策略与分布式 ID","content":"如何设计 MySQL 分库分表方案？分片键如何选择？分库分表后如何实现跨分片查询和全局唯一主键生成？","answer":"答案：水平分片按 Range 或 Hash 分配；垂直分片按业务模块拆分。分片键选高频查询条件且分布均匀。全局 ID 常用雪花算法（Snowflake）。\n\n解析：1）分片策略——Range：按 ID/时间范围分片，易扩展但数据倾斜。Hash：按分片键哈希取模（如 user_id % 16），分布均匀但扩表需 Rehash（可预先用一致性哈希或分片数取 2 的幂减少迁移）。2）分片键选择——出现在 WHERE 条件最频繁的字段，数据分布均匀，尽量不跨分片。3）跨分片查询——聚合层（ShardingSphere/MyCat）合并结果；分页需逐分片查再内存排序。\n\n扩展延伸：分布式 ID 方案对比：雪花算法（Snowflake）——64 位 long：1 bit 符号位 + 41 bit 毫秒时间戳（69 年） + 10 bit 机器 ID + 12 bit 序列号（4096/ms），趋势递增，不依赖 DB。美团 Leaf——雪花模式 + 号段模式（预先取一批 ID 到本地）。UUID——36 位字符串，无序，不适合做聚簇索引（B+ 树频繁分裂）。推荐：雪花算法或其变种（如美团的 Leaf-snowflake），或 Redis INCR 生成短 ID。","hints":["雪花算法的时间回拨问题如何解决——等待或记录上次时间戳","分库分表后 ORDER BY + LIMIT 分页的「深翻页」问题为什么比单库更严重"],"tags":["MySQL","分库分表","Sharding","分布式ID","雪花算法"],"id":1420},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL 二级索引叶子节点存储内容","content":"关于 MySQL InnoDB 二级索引（Secondary Index）的叶子节点，以下哪个说法是正确的？","options":["A) 二级索引的叶子节点存储整行数据","B) 二级索引的叶子节点存储指向聚簇索引的物理地址指针","C) 二级索引的叶子节点存储索引列的值和对应主键值","D) 二级索引的叶子节点存储数据的磁盘文件偏移量"],"answer":"答案：C) 二级索引的叶子节点存储索引列的值和对应主键值\n\n解析：InnoDB 的二级索引（非聚簇索引）叶子节点存储的是索引列的值 + 对应的主键值（而非行数据的物理地址）。通过二级索引查询时，先找到主键值，再到聚簇索引中通过主键查找完整行数据（这个过程称为回表）。如果查询的列都在二级索引中则不需要回表（覆盖索引）。A 描述的是聚簇索引的特性，B 和 D 是 MyISAM 引擎的实现方式。\n\n扩展延伸：InnoDB 的聚簇索引（主键索引）叶子节点直接存储整行数据，而二级索引叶子节点存储「索引列 + 主键」。这意味着主键越小，二级索引占用的空间也越小（每个二级索引条目都包含主键值）。这也是为什么 InnoDB 推荐使用自增整数主键而非 UUID 的原因之一。","hints":["二级索引回表的完整路径是什么","为什么主键越小二级索引性能越好"],"tags":["MySQL","索引","InnoDB"],"id":1421},{"category":"database","difficulty":"medium","type":"true_false","title":"MySQL ICP 与最左前缀的关系","content":"MySQL 的索引下推（Index Condition Pushdown，ICP）可以在联合索引不满足最左前缀原则时，仍然使用索引中后续列的过滤条件减少回表次数。","options":["正确","错误"],"answer":"答案：正确\n\n解析：索引下推（ICP）是 MySQL 5.6 引入的优化。当使用联合索引（a, b, c）查询时，如果 WHERE 条件为 a = 1 AND c LIKE '%keyword%'，由于 c 的查询不满足最左前缀（跳过了 b），传统方式只能通过 a 列定位到记录后回表，再在 Server 层过滤 c 条件。开了 ICP 后，存储引擎在索引遍历时就能用 c 条件过滤一部分记录，减少回表次数。\n\n扩展延伸：EXPLAIN 输出中 Extra 列显示 Using index condition 表示 ICP 生效。ICP 只对二级索引有效（聚簇索引不需要回表，所以不适用）。ICP 对范围查询（>、<、BETWEEN）也能生效，但条件必须来自同一个索引。ICP 不适用于子查询、存储函数等复杂场景。","hints":["EXPLAIN 中 Extra 列的 Using index condition 代表什么","ICP 为什么只对二级索引有效"],"tags":["MySQL","索引下推","ICP"],"id":1422},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 大表 DDL 在线变更方案","content":"线上 MySQL 大表（1 亿行）需要加索引或修改列，如何在线执行而不影响读写？pt-online-schema-change 和 gh-ost 的原理是什么？","answer":"答案：MySQL 大表 DDL 的在线变更方案主要有两种：pt-online-schema-change（Percona Toolkit）和 gh-ost（GitHub Online Schema Migration）。两者都通过创建影子表、同步数据、切换表名的方式实现无锁 DDL。\n\n解析：pt-online-schema-change 原理：1）在原表上创建触发器（AFTER INSERT/UPDATE/DELETE），将增量变更同步到影子表。2）创建一张结构相同的影子表，在影子表上执行 DDL 变更。3）通过 INSERT ... SELECT ... LOCK IN SHARE MODE 分批将原表数据拷贝到影子表。4）拷贝完成后，通过 RENAME TABLE 原子切换原表和影子表。5）删除原表和触发器。问题：触发器带来的额外负载较高（每个 DML 操作多一次触发器执行），在主从延迟大的场景下可能触发 GTID 错误。\n\nextending gh-ost 原理：1）不依赖触发器，直接读取 MySQL binlog（作为伪从库连接主库或从库）。2）创建影子表执行 DDL，通过 binlog 流式同步增量变更。3）分批拷贝存量数据（通过 SELECT ... WHERE id BETWEEN ? AND ?）。4）数据追平后自动切换。优势：无触发器（对源库影响更小）、支持暂停/恢复/动态控制节流、可审计和回滚。\n\n扩展延伸：MySQL 8.0 原生的 Instant DDL：支持 ALTER TABLE ... ALTER COLUMN ... SET DEFAULT/DROP DEFAULT、ADD INDEX（仅 B-Tree 索引）等操作的即时完成（仅修改元数据，不重建表）。但大多数 DDL（增删列、修改列类型）仍然需要重建表。InnoDB 的 Online DDL（ALGORITHM=INPLACE）比传统 COPY 方式好，但在大表上仍然有长锁等待和日志暴涨的风险。生产建议：1 亿行以上的表，优先使用 gh-ost（无触发器，安全性高），配置 max-load 和 throttle 参数控制迁移速度。","hints":["pt-online-schema-change 的触发器方案有什么风险","gh-ost 如何通过 binlog 实现无触发器的数据同步"],"tags":["MySQL","DDL","运维"],"id":1423},{"category":"database","difficulty":"hard","type":"choice","title":"MySQL 事务两阶段提交崩溃恢复","content":"在 MySQL 两阶段提交（Prepare + Commit）过程中，如果写完 Redo Log（Prepare 阶段）和 Binlog 之后、写入 Redo Log Commit 标记之前，服务器崩溃恢复后该事务的状态是什么？","options":["A) 事务回滚，Binlog 中的记录被清除","B) 事务自动提交，恢复时重做 Redo Log 中已 prepare 的事务","C) 事务保持 prepare 状态，需要人工介入处理","D) 崩溃恢复时判断 Binlog 已写入则事务提交，否则回滚"],"answer":"答案：D) 崩溃恢复时判断 Binlog 已写入则事务提交，否则回滚\n\n解析：MySQL 两阶段提交的核心目的是保证 Redo Log 和 Binlog 的一致性。崩溃恢复时的判断逻辑：1）如果 Redo Log 中事务的状态是 COMMIT（已提交）——直接提交。2）如果 Redo Log 中事务的状态是 PREPARE（已准备）——检查对应的 Binlog 是否完整写入：Binlog 已写入 → 事务提交（因为 Binlog 已持久化，从库可能已经同步）；Binlog 未写入或写入不完整 → 事务回滚（保证主从数据一致）。\n\n扩展延伸：两阶段提交流程：① 事务执行阶段（写入 Redo Log 但未刷盘）。② Prepare 阶段（Redo Log 刷盘，状态标记为 PREPARE）。③ 写入 Binlog（Binlog 刷盘）。④ Commit 阶段（Redo Log 状态标记为 COMMIT）。崩溃可能发生在任何一步，但通过 Redo Log 和 Binlog 的交叉比对，总能恢复到一致状态。Binlog 有 XID event（事务 ID），用于与 Redo Log 中的事务对应。这个机制保证了即使主库崩溃，从库通过 Binlog 同步数据也不会出现不一致。","hints":["两阶段提交的四个步骤顺序","崩溃恢复时如何判断事务是否提交"],"tags":["MySQL","事务","崩溃恢复"],"id":1424},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL Buffer Pool 优化策略","content":"InnoDB Buffer Pool 是如何工作的？什么是冷热分离（LRU 链表分区）？Buffer Pool 过大或过小各有什么问题？如何监控 Buffer Pool 的命中率？","answer":"答案：Buffer Pool 是 InnoDB 在内存中缓存数据和索引的区域，是 MySQL 性能的核心。InnoDB 将 Buffer Pool 中的 LRU 链表分为两个区域：旧（Old）区域占 3/8，新（New）区域占 5/8。新读取的页先放入 Old 区域的 midpoint，只有当页在 Old 区域存活超过 innodb_old_blocks_time（默认 1000ms）且再次被访问时才移到 New 区域（LRU 头部）。这种冷热分离设计防止全表扫描等一次性大量读取冲掉热点数据。\n\n解析：Buffer Pool 过小：磁盘 I/O 频繁，查询性能差。Buffer Pool 过大：占用过多内存导致系统内存不足（触发 swap 或 OOM）。经验值：专用 MySQL 服务器上 Buffer Pool = 物理内存的 60-80%（加上 Redo Log 和操作系统缓存），云服务器上建议不超过可用内存的 70%。监控命令：SHOW ENGINE INNODB STATUS 中的 Buffer pool hit rate —— 如果 < 99% 说明 Buffer Pool 太小或需要优化查询减少读取量。\n\n扩展延伸：MySQL 8.0 的 Buffer Pool 增强：1）Buffer Pool 支持动态调整大小（INNODB_BUFFER_POOL_RESIZE_STATUS 监控）。2）多个 Buffer Pool Instance（innodb_buffer_pool_instances）减少并发竞争——当 Buffer Pool > 1GB 时建议设置多实例（默认 8）。3）Buffer Pool 预热：MySQL 8.0 支持在服务重启后自动预热（从 Redo Log 和 Doublewrite Buffer 恢复），或通过 SELECT ... INTO OUTFILE / LOAD DATA 预加载到 Buffer Pool。监控指标：Innodb_buffer_pool_read_requests（总读请求数）、Innodb_buffer_pool_reads（从磁盘读取次数，非命中），命中率 = (1 - buffer_pool_reads / buffer_pool_read_requests) * 100%。","hints":["Buffer Pool 冷热分离如何防止全表扫描冲掉热点数据","SHOW ENGINE INNODB STATUS 中哪些指标反映 Buffer Pool 健康度"],"tags":["MySQL","Buffer Pool","InnoDB","性能优化"],"id":1425},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL Metadata Lock 元数据锁机制","content":"关于 MySQL 元数据锁（Metadata Lock，MDL）的说法，以下哪个是正确的？","answer":"答案：D) MDL 在 5.5 版本引入，任何表操作前都需要获取，且 DDL 等待 MDL 会阻塞后续所有该表的请求\n\n解析：MySQL 5.5 引入了元数据锁机制，在执行任何表操作（SELECT、INSERT、DML、DDL）前都会获取 MDL。MDL 的等待队列有优先级——写锁（如 DDL）优先级高于读锁。当一个 DDL 等待 MDL 时，后续所有对该表的读操作都会被阻塞，这是线上 DDL 引发「连坐」阻塞的常见原因。\n\n扩展延伸：MDL 的等待超时由 lock_wait_timeout（默认 31536000 秒即 1 年）控制，实际生产中出现 MDL 阻塞应通过 performance_schema.metadata_locks 表定位源头会话。","options":["A) MDL 只在 DDL 执行时获取，DML 不会触发 MDL","B) MDL 的锁类型只有共享锁一种","C) MDL 等待队列中，读锁请求优先级高于写锁请求","D) MDL 在 5.5 版本引入，任何表操作前都需要获取，且 DDL 等待 MDL 会阻塞后续所有该表的请求"],"hints":["MDL 是在 MySQL 哪个版本引入的","DDL 等待 MDL 时为什么会导致连锁阻塞"],"tags":["MySQL","Metadata Lock","DDL","锁机制"],"id":1426},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Clone Plugin 克隆插件实现原理","content":"MySQL 8.0.17 引入了 Clone Plugin，请说明其工作原理：克隆的三种模式（本地克隆、远程克隆、捐赠者模式）各有什么特点？它如何实现一致性快照？与传统备份工具相比有哪些优势？","answer":"答案：Clone Plugin 利用 InnoDB 的 page copy-on-write 机制，通过后台线程以 page 为单位复制数据文件，同时跟踪复制过程中修改的 page（通过 redo log 的 adjusted LSN 追踪）。\n\n解析：三种模式：1）本地克隆（CLONE LOCAL DATA DIRECTORY）：在本地创建实例的数据目录快照。2）远程克隆（CLONE INSTANCE FROM donor）：从捐赠者实例拉取数据。3）捐赠者模式：被克隆方无需额外配置。克隆过程分三个阶段：INIT（初始化克隆上下文和权限校验）、FILE COPY（逐 page 复制数据文件，跟踪增量变化）、PAGE COPY（复制增量变化的 page）、REDO COPY（复制剩余的 redo log）、DONE（完成并重启目标实例）。\n\n扩展延伸：Clone Plugin 相比备份+恢复添加从库的优势：全自动化、GTID 位置自动同步、更快的速度（物理 page 级复制 vs 逻辑导出）。限制：源和目标 InnoDB page size 必须相同、不支持部分数据库选择。","hints":["Clone Plugin 如何保证文件复制过程中的一致性","克隆的三个阶段分别做了什么"],"tags":["MySQL","Clone Plugin","备份","InnoDB"],"id":1427},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Group Replication 认证与冲突检测机制","content":"MySQL Group Replication（MGR）在多主模式下如何检测和解决事务冲突？请说明认证阶段（Certification）的工作原理，以及 conflict detection 的判定依据。","answer":"答案：MGR 每个成员独立执行事务，在提交前将事务的写集（Write Set）通过 Group Communication 广播给所有成员，由每个成员独立运行认证过程。\n\n解析：认证阶段核心流程：1）事务提交时生成 Write Set（记录每行修改的主键 ID 和对应的事务快照）。2）通过 Paxos 协议广播到组内所有节点。3）每个节点独立运行 certifier：检查 incoming transaction 的 Write Set 与本地已认证事务的 Write Set 是否存在 key 冲突。4）冲突判定：若新事务的写集与已认证的写集有交集且事务时间戳冲突，则标记为冲突，回滚该事务（仅回滚在多主模式下检测到的写冲突，读不冲突）。5）certified 的事务才允许应用和提交。\n\n扩展延伸：冲突检测粒度是行级（通过主键/唯一键的 hash 值）。单主模式下不存在冲突认证（所有写操作在主节点）。多主模式建议避免同时对同一行进行操作，否则事务吞吐量会因回滚大幅下降。","hints":["Certification 基于什么粒度进行冲突检测","单主和多主模式在冲突检测上的区别"],"tags":["MySQL","Group Replication","冲突检测","认证","MGR"],"id":1428},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 8.0 Resource Group 资源组管理","content":"MySQL 8.0 引入了 Resource Group 功能，它能做什么？如何创建和管理资源组？资源组对线程的 CPU 和优先级控制的具体实现机制是什么？","answer":"答案：Resource Group 允许 DBA 将运行中的 MySQL 线程分组，并为每组分配不同的 CPU 核心和优先级，实现对查询的精细化资源管控。\n\n解析：资源组分为两类：system_group（系统内部线程，如 IO 线程）和 user_group（用户会话/查询线程）。创建语法：CREATE RESOURCE GROUP rg_name TYPE = USER VCPU = 0-3 THREAD_PRIORITY = -10；通过 RESOURCE_GROUP 会话变量或 SET RESOURCE GROUP 分配线程。VCPU 绑定通过 Linux sched_setaffinity 实现，线程优先级在 Linux 下映射为 nice 值（-20 到 0 之间，仅 USER 类型支持）。\n\n扩展延伸：典型场景——将慢查询自动路由到低优先级的资源组，避免影响 OLTP 主路径。Resource Group 需要 CAP_SYS_NICE 权限（Linux），MySQL 8.0.23+ 支持 Windows Job Objects。Resource Group 对 IO 没有控制能力，仅限 CPU 和优先级。","hints":["Resource Group 控制的是 CPU 还是 IO 还是内存","如何将查询自动分配到指定资源组"],"tags":["MySQL","Resource Group","性能优化","资源管理"],"id":1429},{"category":"database","difficulty":"hard","type":"true_false","title":"MySQL 8.0 EXPLAIN ANALYZE 实际执行时间","content":"MySQL 8.0.18 引入的 EXPLAIN ANALYZE 输出的实际执行时间（actual time）包含了锁等待和 IO 等待的时间。","answer":"答案：正确\n\n解析：EXPLAIN ANALYZE 在 MySQL 8.0.18+ 中通过实际执行查询并计时，输出每个迭代器的 actual startup time 和 actual total time。这些时间是基于 wall-clock 的测量值，包含该迭代器及其所有子迭代器中花费的全部时间——包括 CPU 执行时间、IO 等待时间、锁等待时间、以及行级锁等待。因此它反映的是真实执行时间而非优化器估算值，对于定位实际瓶颈非常有帮助。\n\n扩展延伸：EXPLAIN ANALYZE 执行实际查询（DML 会执行写操作），使用 FORMAT=TREE 输出树形执行计划。相比 EXPLAIN FORMAT=TREE（仅输出估算值），EXPLAIN ANALYZE 额外输出 actual rows 和 actual time。注意：EXPLAIN ANALYZE 会使查询实际运行，对于大表生产操作需谨慎。","options":["正确","错误"],"hints":["EXPLAIN ANALYZE 是基于实际执行还是估算","actual time 是 wall-clock 还是 CPU time"],"tags":["MySQL","EXPLAIN ANALYZE","查询优化","性能诊断"],"id":1430},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB 的 MVCC 与锁机制深度解析","content":"请深入分析 MySQL InnoDB 的 MVCC 和锁机制。包括 Undo Log 版本链与 Read View 的工作原理，当前读与快照读的区别，行锁/间隙锁/临键锁的加锁范围，INSERT 的隐式锁与锁升级机制。","answer":"答案：\nInnoDB 的 MVCC + 锁机制是事务隔离性的基石，理解它们需要区分「读」的两种模式。\n\n解析：\n1. Undo Log 版本链：每行记录有多个版本通过 DB_ROLL_PTR 指针链接。Read View 由 m_ids、min_trx_id、max_trx_id、creator_trx_id 组成。RC 级别每条语句前生成 Read View，RR 级别整个事务复用同一个 Read View。\n\n2. 当前读 vs 快照读：快照读（普通 SELECT）从 Read View 读取，不阻塞。当前读（SELECT FOR UPDATE / UPDATE / DELETE / INSERT）读取最新版本并加锁。\n\n3. Next-Key Lock = Record Lock + Gap Lock。RR 级别下 InnoDB 的默认锁是 Next-Key Lock，通过 Gap Lock 阻止新记录插入查询范围，部分解决幻读。RC 级别禁用 Gap Lock。\n\n4. INSERT 隐式锁：InnoDB 在聚簇索引中记录 trx_id，其他事务通过检查 trx_id 是否活跃来判断隐式锁。InnoDB 没有行锁升级到表锁的机制。","hints":["MVCC 的核心不是「保存多个副本」，而是「只保存增量差异（Undo Log）」，构建历史版本的成本很低","RC 下不可重复读的本质是每条语句新生成的 Read View 包含了新提交的事务"],"tags":["MySQL","InnoDB","MVCC","锁","事务"],"id":1431},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库索引设计策略","content":"请系统性地介绍关系数据库的索引设计策略。覆盖 B+ Tree 索引结构特点、联合索引的最左前缀原则、索引下推和覆盖索引的优化原理、索引选择性的概念。","answer":"答案：\n索引是数据库查询性能的核心——设计好的索引可以将查询从全表扫描降到索引查找。\n\n解析：\n1. B+ Tree：非叶子节点只存 key 和 pointer，每个节点可以存更多 key——树高度更矮（通常 3-4 层）。叶子节点形成有序双向链表支持范围查询。InnoDB 聚簇索引叶子节点直接存行数据，二级索引叶子节点存主键值（需回表）。\n\n2. 最左前缀原则：联合索引 (a, b, c) 等效于 (a)、(a, b)、(a, b, c)。查询必须包含最左列。B+ Tree 按联合索引的列顺序依次排序，跳过前导列 = 排序顺序不匹配。\n\n3. 索引下推（ICP, MySQL 5.6+）：在索引层级应用 WHERE 条件中索引列能判断的条件，减少回表次数。覆盖索引：查询的所有列都在二级索引中时不需要回表。\n\n4. 索引选择性 = Cardinality / 总行数。选择性越高，索引越有效。性别列 Cardinality = 2，选择性极低，不适合建索引。","hints":["最左前缀原则的本质是 B+ Tree 的排序方式决定的——它按联合索引的列顺序依次排序","覆盖索引是查询优化性价比最高的手段——不需要回表意味着减少一次或多次磁盘 I/O"],"tags":["MySQL","索引","B+ Tree","查询优化","数据库"],"id":1432},{"category":"database","difficulty":"hard","type":"short_answer","title":"分布式事务与一致性协议","content":"请系统性地介绍分布式事务的实现方案和一致性协议。包括 XA 两阶段提交的问题、TCC 模式的适用场景、Saga 模式的编排方式、最终一致性方案（本地消息表、事务消息）。","answer":"答案：\n分布式事务的核心矛盾是「一致性」和「可用性」的 trade-off——没有万能的方案。\n\n解析：\n1. XA 2PC：阶段 1 Prepare（参与者执行但不提交），阶段 2 Commit/Rollback。问题：同步阻塞（Prepare 后锁资源等待协调器），协调器单点，脑裂。\n\n2. TCC：Try（预留资源）、Confirm（真正执行）、Cancel（回滚）。Confirm 和 Cancel 必须幂等。业务侵入性强，但不持有数据库锁，并发性能比 2PC 好。\n\n3. Saga：长事务拆分为多个本地事务，每个有补偿操作。Choreography（事件驱动，去中心化）vs Orchestration（中心化协调，流程可视化）。适用长周期业务（如旅游预订）。\n\n4. 最终一致性方案：本地消息表（业务操作 + 消息同 DB 事务写入，后台轮询发送）。RocketMQ 事务消息（Producer 发 Half 消息 -> 执行本地事务 -> Commit/Rollback + 宕机回查）。","hints":["XA 2PC 存在的问题不是「慢」而是「不可靠」——协调器宕机导致所有参与者被阻塞","事务消息相对本地消息表的优势：不需要业务方维护表结构和轮询任务"],"tags":["分布式事务","2PC","TCC","Saga","事务消息"],"id":1433},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库高可用架构设计","content":"请设计一个关系数据库的高可用架构方案。覆盖主从复制原理、自动故障转移机制、读写分离的挑战、备份与恢复策略。","answer":"答案：\n数据库高可用不是「挂了有人接」就够了——需要保证 RPO 和 RTO 在业务能接受的范围内。\n\n解析：\n1. 复制方案：异步复制（性能好，RPO > 0），半同步复制（等待至少一个从库确认，RPO = 0），组复制 MGR（Paxos 共识，强一致性但要求所有表有主键）。\n\n2. 故障转移：MHA（传统，RTO 10-30s），Orchestrator（基于 Raft，拓扑可视化），MySQL InnoDB Cluster（MGR + MySQL Router，官方方案，RTO < 5s）。\n\n3. 读写分离挑战：主从延迟（从库 apply 慢、大事务）。应对策略——强制读主（实时性要求高）、延迟感知路由（Proxy 监控延迟）、缓存补偿。\n\n4. 备份：逻辑备份（mysqldump，可读可选择性恢复，适合小库）。物理备份（XtraBackup，直接拷贝数据文件，备份恢复快，适合大库）。全量 + binlog 实时 + 定期恢复验证。","hints":["半同步复制的「不丢数据」是有条件的——主库和从库同时宕机且从库的 relay log 也丢失时仍会丢数据","物理备份（XtraBackup）的备份速度远快于逻辑备份（mysqldump）"],"tags":["MySQL","高可用","主从复制","备份恢复","故障转移"],"id":1434},{"category":"database","difficulty":"hard","type":"short_answer","title":"SQL 查询优化实战","content":"请分析大规模数据下的 SQL 查询优化策略。分析时间范围查询的性能问题、分页深度问题、JOIN 查询优化、OR 条件的索引使用问题。","answer":"答案：\n大规模数据下的 SQL 优化核心是「减少数据扫描量」。\n\n解析：\n1. 时间范围查询：WHERE created_at > '2026-01-01' ORDER BY created_at LIMIT 100 会扫描大量匹配记录。优化：用 (created_at, id) 联合索引，或游标分页（Keyset Pagination）。\n\n2. 分页深度：LIMIT 100000, 100 等价于读取 100100 行后丢弃前 100000 行。优化：游标分页（WHERE id > :last_id LIMIT 100），或延迟关联（先查覆盖索引的主键再 JOIN 回原表）。\n\n3. JOIN 查询：先 JOIN 再 GROUP BY 会产生极大中间结果。优化：先聚合再 JOIN，子查询先过滤和聚合，减少 Join 的数据量。\n\n4. OR 条件：WHERE status = 'PAID' OR status = 'REFUND' 可能不走索引。改写为 IN 或 UNION ALL。","hints":["LIMIT + OFFSET 的深度分页问题是 MySQL 读取了 N 行后丢弃前 N-M 行——不是从第 N 行开始读","OR 改 IN 不是 SQL 语法糖——两种写法在优化器中的执行路径可能完全不同"],"tags":["MySQL","SQL优化","索引","慢查询","性能调优"],"id":1435},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL MVCC 实现原理","content":"MySQL InnoDB 如何通过 MVCC 实现可重复读隔离级别？MVCC 依赖哪些核心数据结构？","answer":"答案：MVCC（多版本并发控制）通过每行记录维护多个版本实现读不阻塞写、写不阻塞读。\n\n解析：InnoDB 在每行记录后隐藏两个字段：DB_TRX_ID（最近修改的事务 ID）和 DB_ROLL_PTR（回滚指针，指向 undo log 中上一个版本）。事务启动时生成 ReadView（活跃事务 ID 列表），通过比较事务 ID 与 ReadView 判断哪个版本可见。可重复读级别下，ReadView 在事务第一次读时创建并复用，保证同事务多次读结果一致。\n\n扩展延伸：READ COMMITTED 与 REPEATABLE READ 的区别在于 ReadView 的创建时机——RC 每次读都重新生成，RR 只在第一次读时生成。MVCC 只在 READ COMMITTED 和 REPEATABLE READ 级别生效，READ UNCOMMITTED 总是读最新版本，SERIALIZABLE 全部加锁。","hints":["每行记录的隐藏字段是什么","ReadView 在 RC 和 RR 下的区别"],"tags":["MySQL","MVCC","事务","InnoDB"],"id":1436},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL B+ Tree 索引结构详解","content":"为什么 MySQL InnoDB 选择 B+ Tree 而不是 B Tree 或红黑树作为索引结构？B+ Tree 相比 B Tree 有哪些优势？","answer":"答案：B+ Tree 比 B Tree 更适合磁盘 I/O 场景，因为非叶子节点不存数据，单节点能存更多索引键。\n\n解析：B+ Tree 核心优势：1）非叶子节点只存索引键（不存数据），扇出高，树矮（3-4 层即可存千万级数据），减少磁盘 I/O 次数。2）叶子节点通过双向链表连接，支持范围查询（B Tree 需要中序遍历，B+ Tree 直接遍历叶子链表）。3）所有数据都在叶子节点，查询复杂度稳定。对比红黑树：红黑树高度 O(log n) 约为 20+ 层，磁盘 I/O 次数多 5-10 倍。\n\n扩展延伸：InnoDB 的页大小默认 16KB。假设主键为 BIGINT（8 字节）+ 指针（6 字节），每页可存约 1170 个索引键。三层 B+ Tree 可存 1170 × 1170 × 16 ≈ 2190 万条记录。","hints":["B+ Tree 非叶子节点和叶子节点各存什么","为什么范围查询 B+ Tree 比 B Tree 快"],"tags":["MySQL","索引","B+ Tree","InnoDB"],"id":1437},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库索引失效的场景","content":"哪些情况下 MySQL 索引会失效？请列举至少 5 种常见场景并解释原因。","answer":"答案：常见索引失效场景包括：\n\n1）最左前缀原则不满足——联合索引 (a, b, c) 中跳过了第一列直接查 b。\n2）对索引列使用函数——WHERE LENGTH(name) = 5，索引列参与运算。\n3）隐式类型转换——列是 VARCHAR，条件给整数，MySQL 会加隐式 CAST 函数。\n4）LIKE 以 % 开头——WHERE name LIKE '%关键词'，无法利用索引。\n5）OR 条件中存在非索引列——WHERE id = 1 OR status = 'active'，status 无索引。\n6）索引列参与计算——WHERE age + 1 = 20。\n\n解析：索引本质是排序后的数据结构。对索引列做函数/运算后，排序结构被破坏，数据库只能全表扫描。最左前缀反映了联合索引按顺序构建的层级结构。\n\n扩展延伸：检查索引是否使用使用 EXPLAIN 查看 type 和 key 字段。Extra 中的 Using index 表示索引覆盖（无需回表），Using filesort 需要优化排序。","hints":["EXPLAIN 中 type 字段的常见值含义","索引覆盖（Covering Index）和回表的区别"],"tags":["MySQL","索引","SQL优化"],"id":1438},{"category":"database","difficulty":"easy","type":"short_answer","title":"SQL 数据库三大范式","content":"数据库设计中的三大范式是什么？为什么有时会违反范式（反范式化）？","answer":"答案：第一范式（1NF）：列不可再分（原子性）。第二范式（2NF）：在 1NF 基础上，非主键列完全依赖于主键（消除部分依赖）。第三范式（3NF）：在 2NF 基础上，非主键列不传递依赖于主键（消除传递依赖）。\n\n解析：范式化减少数据冗余、避免更新异常。但实际应用中常做反范式化——在表中冗余存储某些字段以减少 JOIN 查询。例如订单表直接存用户名而不是用户 ID，省去每次查询 JOIN 用户表。\n\n扩展延伸：工程中通常设计到 3NF，然后在性能瓶颈处用反范式化优化。过度范式化导致几十个表的复杂 JOIN，过度反范式化导致数据不一致风险。需要权衡。","hints":["部分依赖和传递依赖的区别","反范式化在什么场景下收益最大"],"tags":["数据库","范式","设计"],"id":1439},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 主从复制原理","content":"MySQL 主从复制是如何工作的？有哪几种复制模式？","answer":"答案：主从复制基于 binlog（二进制日志），分为三个步骤：\n1）主库将数据变更写入 binlog。\n2）从库的 I/O 线程读取主库 binlog 并写入 relay log（中继日志）。\n3）从库的 SQL 线程重放 relay log 中的数据变更。\n\n解析：复制模式有三种：1）异步复制（默认）——主库不等待从库确认，性能最好但可能丢数据。2）半同步复制——主库等待至少一个从库写入 relay log 后才返回，兼顾性能和数据安全。3）全同步复制——所有从库都写入后才返回，数据最安全但最慢。\n\n扩展延伸：主从延迟是常见问题——从库查询读到旧数据。解决方案：1）强制主库读（读写分离中间件）。2）缓存预热。3）并行复制（MySQL 5.7+ 支持多线程复制）。","hints":["半同步复制和异步复制的区别","主从延迟通常由哪些原因造成"],"tags":["MySQL","主从复制","架构"],"id":1440},{"category":"database","difficulty":"easy","type":"short_answer","title":"SQL vs NoSQL 的区别与选择","content":"关系型数据库（SQL）和非关系型数据库（NoSQL）有什么区别？各自适用什么场景？","answer":"答案：SQL 数据库使用结构化表模式和数据关系，支持 ACID 事务；NoSQL 数据库更灵活，支持多种数据模型（文档、键值、列族、图），通常牺牲强一致性换取性能和扩展性。\n\n解析：SQL 数据库强项是复杂的关联查询和事务完整性，适合金融、ERP 等系统。NoSQL 各类别适用场景不同：文档型（MongoDB）适合灵活 Schema、快速迭代；键值型（Redis）适合缓存、会话管理；列族型（HBase、Cassandra）适合宽表、时序数据；图数据库（Neo4j）适合社交关系、推荐系统。\n\n扩展延伸：现代架构普遍使用混合持久化（Polyglot Persistence）——MySQL 做核心事务 + Redis 做缓存 + Elasticsearch 做搜索，各取所长。","hints":["CAP 定理在 SQL 和 NoSQL 选择中的作用","BASE 理论和 ACID 的区别"],"tags":["数据库","NoSQL","架构"],"id":1441},{"category":"database","difficulty":"hard","type":"choice","title":"InnoDB 页分裂与页合并","content":"关于 InnoDB B+ Tree 的页分裂和页合并，以下说法正确的是？","answer":"答案：C) 页分裂发生在插入时，页合并发生在删除后利用率低于阈值时\n\n解析：页分裂：当插入的数据导致叶子页满时，InnoDB 会分配新页并将原页一半记录移到新页。页合并：删除数据后页利用率低于 MERGE_THRESHOLD（默认 50%）时，尝试与相邻页合并。两者的根本原因都是 B+ Tree 的有序性要求。","hints":[],"tags":["MySQL","InnoDB","索引"],"options":["A) 页分裂和页合并都只在插入时发生","B) 页分裂是删除数据时触发的，页合并在插入时触发","C) 页分裂发生在插入时，页合并发生在删除后利用率低于阈值时","D) 页分裂和页合并都是主动触发，与数据操作无关"],"id":1442},{"category":"database","difficulty":"medium","type":"choice","title":"数据库隔离级别解决的问题","content":"以下哪种隔离级别可以解决幻读（Phantom Read）问题？","answer":"答案：B) Serializable 和 InnoDB 的 RR 级别（通过间隙锁）。\n\n解析：幻读指同一个事务内两次查询结果集的行数不同（新插入的行）。InnoDB 的 REPEATABLE READ 级别通过间隙锁（Gap Lock）和临键锁（Next-Key Lock）在 MVCC 基础上解决了幻读问题。SQL 标准定义的 RR 不解决幻读，但 InnoDB 实现了比标准更强的 RR。","hints":[],"tags":["MySQL","事务","隔离级别"],"options":["A) Read Committed 和 Repeatable Read","B) Serializable 和 InnoDB 的 RR 级别（通过间隙锁）","C) 只有 Serializable","D) Read Uncommitted 和 Read Committed"],"id":1443},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 底层数据结构","content":"Redis 中哪些数据类型底层使用跳跃表（skiplist）实现？","answer":"答案：C) Zset（有序集合）\n\n解析：Redis 的 Zset 在元素较多或字符串较长时使用字典 + 跳跃表的组合实现。跳跃表支持 O(log n) 的插入、删除和范围查询。List 使用压缩列表或 quicklist，Hash 使用压缩列表或字典，Set 使用整数集合或字典。","hints":[],"tags":["Redis","数据结构"],"options":["A) List 和 Set","B) Hash 和 List","C) Zset（有序集合）","D) 所有 Redis 数据类型都使用跳跃表"],"id":1444},{"category":"database","difficulty":"easy","type":"true_false","title":"MySQL 中 COUNT(*) 与 COUNT(1) 的区别","content":"MySQL 中 COUNT(*) 比 COUNT(1) 慢，因为 COUNT(*) 需要读取所有列。","answer":"错误。解析：MySQL 中 COUNT(*) 和 COUNT(1) 没有性能差异。COUNT(*) 不会展开所有列，而是选择最小的二级索引或聚簇索引进行计数（如果有二级索引优先用二级索引，因为大小更小）。性能差异的关键在于是否走了索引，而不是括号内的内容。特殊地，COUNT(列名) 会排除该列为 NULL 的行，所以语义不同。","tags":["MySQL","SQL优化"],"options":["正确","错误"],"id":1445},{"category":"database","difficulty":"medium","type":"true_false","title":"Redis 的 SETNX 作为分布式锁","content":"只用 Redis 的 SETNX 命令实现分布式锁是足够安全的。","answer":"错误。解析：只用 SETNX 存在问题：1）没有设置过期时间时，获得锁的进程崩溃会导致死锁。2）即使 SETNX + EXPIRE 分开设置也不是原子的，EXPIRE 可能执行失败。3）锁可能被其他进程误释放（没有唯一标识）。4）无法处理时钟漂移。正确实现方案：使用 Redis Redlock 算法或 SET key value NX EX seconds 单原子命令 + 随机 value 做锁校验 + Lua 脚本保证释放的原子性。","tags":["Redis","分布式锁"],"options":["正确","错误"],"id":1446},{"category":"database","difficulty":"hard","type":"fill_in_blank","title":"Redis 持久化方式","content":"Redis 提供两种持久化方式：___（定时将内存快照写入磁盘）和 ___（记录每次写操作的日志）。前者适合___场景，后者数据安全性更高但___更大。","answer":"{\"correct\":[[\"RDB\",\"RDB 快照\"],[\"AOF\"],[\"备份\",\"全量恢复\"],[\"文件体积\",\"AOF 文件\"]],\"distractors\":[\"LDB\",\"日志\",\"主从\",\"内存占用\"]}","hints":["RDB 触发时机：save 命令、bgsave 命令、配置策略","AOF 的重写机制是什么"],"tags":["Redis","持久化"],"id":1447},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL 中 VARCHAR 和 CHAR 的区别","content":"关于 MySQL 中 VARCHAR 和 CHAR 类型，以下说法正确的是？","answer":"答案：B) VARCHAR 是变长字符串，CHAR 是定长字符串\n\n解析：VARCHAR 存储变长字符串，额外用 1-2 字节记录长度，适合长度差异大的列。CHAR 固定分配指定长度，适合长度固定的列（如手机号、身份证号）。VARCHAR(255) 和 VARCHAR(256) 的区别在于 255 以内只需 1 字节记录长度，256 以上需要 2 字节。此外，CHAR 在检索时会去掉末尾空格，VARCHAR 保留。","hints":[],"tags":["MySQL","数据类型"],"options":["A) VARCHAR 比 CHAR 更适合存储密码哈希值","B) VARCHAR 是变长字符串，CHAR 是定长字符串","C) VARCHAR 最多只能存储 255 个字符","D) CHAR 存储空间比 VARCHAR 总是更小"],"id":1448},{"category":"database","difficulty":"medium","type":"short_answer","title":"Elasticsearch 倒排索引原理","content":"Elasticsearch 的倒排索引是什么？全文搜索为什么比 LIKE 快那么多？","answer":"答案：倒排索引是词（Term）到文档（Document）的映射表，记录每个词出现在哪些文档中、什么位置。\n\n解析：MySQL LIKE '%关键词%' 走全表扫描，逐行匹配字符串。ES 在写入时预先分词、构建倒排索引，查询时直接通过词找到对应文档。以搜索”数据库优化”为例，ES 分词为”数据库”和”优化”，在倒排表中是两次 O(1) 查找，复杂度与文档总数无关，只与词频有关。\n\n扩展延伸：ES 的索引流程：文本 → 字符过滤 → 分词器（Tokenizer）→ 词项过滤（小写化、停用词、同义词）→ 写入倒排表。查询时默认使用 BM25 算法（Okapi BM25，基于 TF-IDF 改进）计算相关性评分。","hints":["正排索引和倒排索引的区别","ES 中的分片（Shard）和副本（Replica）是什么"],"tags":["Elasticsearch","搜索引擎","索引"],"id":1449},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库连接池的作用与配置","content":"数据库连接池有什么作用？连接池的常见参数（如最小连接数、最大连接数、连接超时）如何配置？","answer":"答案：数据库连接池复用 TCP 连接，避免每次数据库操作都经历 TCP 建连、MySQL 认证、TCP 断连的开销。\n\n解析：建连数据库通常需要 1-3ms（局域网）+ MySQL 认证，高频场景下不可忽略。连接池的关键参数：最小空闲连接数（保活，应对突发流量）、最大连接数（防止耗尽数据库资源）、连接超时（等待连接的最大时间）、空闲回收时间（超过此时间的空闲连接被关闭）。\n\n扩展延伸：HikariCP（Spring Boot 默认）推荐配置：maximumPoolSize = (core_count * 2) + effective_spindle_count。连接池不是越大越好——数据库侧每个连接消耗线程和内存（PostgreSQL 约 5MB/连接），过大的连接池反而导致上下文切换加剧。","hints":["连接池大小为什么不是越大越好","如何监控连接池的健康状态"],"tags":["数据库","连接池","性能"],"id":1450},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 死锁分析与排查","content":"MySQL InnoDB 中死锁（Deadlock）是如何产生的？如何查看和分析死锁？有哪些预防措施？","answer":"答案：死锁是两个或多个事务相互等待对方释放锁导致的循环等待。InnoDB 通过死锁检测（wait-for graph）自动发现并回滚代价较小的事务（持有锁较少或回滚代价低的事务）。\n\n解析：死锁产生条件（与操作系统死锁条件一致）：互斥、持有并等待、不可剥夺、循环等待。MySQL 中典型的死锁场景：事务 A 锁了行 1 想锁行 2，事务 B 锁了行 2 想锁行 1。或者间隙锁导致的死锁——两个事务的 INSERT 操作在相邻间隙上相互阻塞。查看最近死锁：SHOW ENGINE INNODB STATUS；查看输出的 LATEST DETECTED DEADLOCK 部分，包含涉及的事务和 SQL、持有的锁、等待的锁。MySQL 5.6+ 启用 innodb_print_all_deadlocks 可将所有死锁记录到错误日志。\n\n扩展延伸：频繁死锁时应该分析的几个方向：1）SQL 执行顺序——确保多个事务访问多个表的顺序一致（如都按 A→B 的顺序加锁）。2）索引——检查 SQL 是否使用了正确的索引（全表扫描会锁大量行，增加死锁概率）。3）降低隔离级别——从 RR 降到 RC（减少间隙锁）。4）缩短事务——事务保持时间越短，死锁概率越低。5）重试机制——在应用层捕获死锁异常（MySQL 错误码 1213）并重试。注意：死锁不是 bug——它是事务并发下的正常现象。合理的策略是检测 + 重试，而非消除所有死锁可能。","hints":["SHOW ENGINE INNODB STATUS 中哪个部分显示死锁信息","为什么降低隔离级别可以减少死锁"],"tags":["MySQL","死锁","事务","InnoDB"],"id":1451},{"category":"database","difficulty":"medium","type":"short_answer","title":"乐观锁与悲观锁","content":"乐观锁和悲观锁在数据库中的应用场景是什么？各自如何实现？什么场景下选择哪一种？","answer":"答案：悲观锁假设并发冲突很频繁，每次操作数据前都加锁（SELECT … FOR UPDATE）。乐观锁假设冲突很少发生，只在提交时检查数据是否被修改过（通过版本号或时间戳）。\n\n解析：悲观锁——通过数据库的锁机制（行锁、表锁）保证并发安全。适用场景：写冲突频繁、数据一致性要求极高的场景（如库存扣减、金融转账）。缺点：锁等待降低并发度，可能死锁。乐观锁——不锁数据库，通过应用层控制。常见实现方式：1）版本号（version）——读取时获取 version，更新时 SET version = version + 1 WHERE version = old_version。如果 affected_rows = 0 说明其他人已经修改过，重试。2）CAS（Check-And-Set）——WHERE status = old_status 或者 WHERE stock >= required 等条件判断。适用场景：读多写少、并发冲突概率低的场景（如文章更新、用户资料修改）。缺点：冲突频繁时重试开销大。\n\n扩展延伸：悲观锁的 select … for update 注意事项：1）必须在事务中执行。2）只在 InnoDB 的行锁级别生效（无索引会升级为表锁）。3）需要配合索引使用。乐观锁在分布式系统中的变体：1）Redis 的 WATCH 命令（乐观锁 CAS）。2）ETCD 的 Revision 机制。3）ZooKeeper 的版本号。选型总结：高并发写入、冲突频繁 → 悲观锁（或分布式锁）；低冲突概率、读多写少 → 乐观锁；一致性 > 性能 → 悲观锁；性能 > 强一致 → 乐观锁。","hints":["SELECT … FOR UPDATE 在索引失效时可能变成表锁","乐观锁 version 和 CAS 两种实现方式哪个更好"],"tags":["数据库","乐观锁","悲观锁","并发"],"id":1452},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB 行格式（Row Format）","content":"MySQL InnoDB 支持哪几种行格式？COMPACT、DYNAMIC、COMPRESSED 之间有什么区别？溢出页（Overflow Page）是如何工作的？","answer":"答案：InnoDB 行格式有四种：REDUNDANT（旧格式，基本淘汰）、COMPACT（MySQL 5.0 引入）、DYNAMIC（MySQL 5.7 默认）、COMPRESSED（在 DYNAMIC 基础上支持页压缩）。DYNAMIC 和 COMPRESSED 会将长字段（TEXT/BLOB）存储在溢出页，行内只保留 20 字节指针。\n\n解析：COMPACT 格式——行数据包含变长字段长度列表、NULL 标志位、记录头信息、RowID（无主键时）、事务 ID、回滚指针、各列数据。当一行数据超过一个页（16KB）时，部分数据存储到溢出页（off-page storage），行内用 768 字节前缀 + 20 字节指针。缺点：大字段的 768 字节前缀占用了行内空间，可能导致行总长度过大。DYNAMIC 格式（MySQL 5.7 默认）——优化了大字段的存储：不再存储 768 字节前缀，行内只保留 20 字节溢出页指针。完全的行外存储减少了行大小，提高 B+ Tree 的扇出（一页能存更多行），改善范围扫描性能。\n\n扩展延伸：COMPRESSED 格式——同 DYNAMIC 的溢出机制，但页级别使用 zlib 压缩。优点：减少磁盘 I/O 和内存占用（压缩页在 buffer pool 中以压缩形式存在）。缺点：压缩/解压消耗 CPU。适用场景：存储日志、文本等可压缩比高的数据。注意：COMPRESSED 格式的性能取决于 CPU 和 I/O 的平衡——IO 密集且数据压缩比高时收益大；CPU 密集时可能得不偿失。查看行格式：SHOW TABLE STATUS LIKE 'table_name'; 或 INFORMATION_SCHEMA.TABLES。","hints":["为什么 DYNAMIC 格式比 COMPACT 更适合大字段表","COMPRESSED 行格式在什么场景下收益最大"],"tags":["MySQL","InnoDB","行格式","存储"],"id":1453},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB 自适应哈希索引（AHI）","content":"什么是 InnoDB 的自适应哈希索引（Adaptive Hash Index）？它是如何工作的？什么情况下 AHI 可能成为瓶颈？","answer":"答案：自适应哈希索引（AHI）是 InnoDB 在内存中自动构建的哈希索引，加速 buffer pool 中频繁访问的索引页的等值查询（如 WHERE id = ?）。\n\n解析：AHI 的构建条件——InnoDB 监控对 B+ Tree 索引页的访问模式，如果某个索引页频繁通过等值条件访问（而不是范围扫描），且满足一定的访问频率阈值，InnoDB 会为该页构建 AHI 哈希索引。AHI 的数据结构是一个散列表，key 为（space_id + page_no），value 为哈希值。查询时先根据 space_id + page_no 查 AHI 找到页在 buffer pool 的位置，直接定位而无需遍历 B+ Tree 的多个层级。特点是完全自动、无需人工配置、内存分配来源于 buffer pool（通过 innodb_adaptive_hash_index_parts 控制分区数）。\n\n扩展延伸：AHI 可能成为瓶颈的场景：1）高并发写入时——AHI 需要维护自身的哈希表（split/merge），加锁操作（btr_search_latch）成为全局竞争热点（SX-latch contention）。2）MySQL 5.7 及之前版本中 AHI 使用单一的全局锁（search_latch），高并发 INSERT 场景下出现明显的等待（btr_search_latch 竞争）。3）MySQL 8.0 通过将 AHI 分区（innodb_adaptive_hash_index_parts，默认 8 分区）缓解了这个问题。AHI 支持开关控制：innodb_adaptive_hash_index=ON/OFF。关闭建议：如果 SHOW ENGINE INNODB STATUS 中 SEMAPHORES 部分显示大量 btr_search_latch 等待。AHI 只在等值查询上有效，对范围查询（>、<、BETWEEN）无帮助（B+ Tree 的叶子链表更优）。","hints":["btr_search_latch 竞争在什么场景下会出现","AHI 为什么对范围查询没有加速效果"],"tags":["MySQL","InnoDB","自适应哈希索引","性能"],"id":1454},{"category":"database","difficulty":"medium","type":"short_answer","title":"索引覆盖（Covering Index）与回表","content":"什么是索引覆盖（Covering Index）？什么是回表查询（Bookmark Lookup）？为什么要尽量使用索引覆盖？如何通过 EXPLAIN 判断？","answer":"答案：索引覆盖指查询所需的所有列都在索引树中（无需回表访问主键数据页）。回表指通过二级索引找到主键值后，再到聚簇索引中读取完整行数据。覆盖索引避免回表，减少磁盘 I/O。\n\n解析：InnoDB 的聚簇索引（Clustered Index）——表数据按主键顺序存储在 B+ Tree 的叶子节点（主键=数据行）。二级索引（Secondary Index）——叶子节点存储索引列的值 + 主键值（不是数据行本身）。所以二级索引找到记录后还需通过主键回表（一次额外 B+ Tree 搜索）读取完整数据。覆盖索引：如果 SELECT 的列都在二级索引中（如 SELECT id, name FROM user WHERE name = '...'，而 (name, id) 是联合索引），则二级索引的叶子节点已包含所有需要的数据，无需回表。\n\n扩展延伸：EXPLAIN 中 Extra 字段出现 Using index 表示使用了覆盖索引（无需回表）。出现 Using index condition 表示索引下推（虽然用了索引但需要回表）。没有 Using index 说明走了二级索引 + 回表。覆盖索引的设计策略：将高频查询的字段加入到已有索引的最右端（不影响最左前缀匹配），或者为高频查询专门设计索引。如：某个查询频繁根据 status 查 id 和 create_time，可以建索引 (status, create_time, id) 实现覆盖。注意：不要过度设计覆盖索引——索引也是有维护成本的（插入/更新需更新所有索引）。覆盖索引的主要收益在于减少磁盘 I/O 和减少对聚簇索引的访问压力。","hints":["EXPLAIN 中 Extra 字段的 Using index 和 Using index condition 的区别","覆盖索引和联合索引的关系是什么"],"tags":["MySQL","索引","覆盖索引","回表","SQL优化"],"id":1455},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB Change Buffer","content":"InnoDB 的 Change Buffer（变更缓冲区，旧称 Insert Buffer）的作用是什么？它如何提升性能？Change Buffer 在 MySQL 8.0 之后有什么变化？","answer":"答案：Change Buffer 用于缓存对二级索引页的变更操作（INSERT/UPDATE/DELETE），当目标索引页不在 buffer pool 中时，先将变更记录到 Change Buffer，等该页被读入 buffer pool 时再合并（Merge），减少磁盘随机 I/O。\n\n解析：二级索引的写入问题——InnoDB 的二级索引通常不是顺序的（相对于聚簇索引）。当 INSERT 一行数据时：聚簇索引写入（主键顺序，基本顺序写），但所有二级索引的更新需要随机 I/O。如果不做 Change Buffer，每次二级索引插入都需要磁盘随机读将目标页加载到 buffer pool。Change Buffer 的优化：1）变更操作写入 Change Buffer（内存 + 磁盘持久化）。2）当目标页被其他操作读入 buffer pool 时，触发 Change Buffer 的合并。3）Merge 批量化地应用变更到目标页。\n\n扩展延伸：Change Buffer 的配置——innodb_change_buffering 参数可设：none、inserts（只缓存 INSERT）、deletes、changes（inserts + deletes）、purges、all（默认值）。innodb_change_buffer_max_size（默认 25）——Change Buffer 最多占用 buffer pool 的 25%。MySQL 8.0 的改进：Change Buffer 从单一的 Insert Buffer 扩展到支持 INSERT/UPDATE/DELETE 三类变更。Change Buffer 的局限性——只对非唯一的二级索引有效（唯一索引需要立即检查唯一性约束，不能延迟合并）。对写密集场景也有副作用：如果二级索引页很少被读取，Change Buffer 会无限增长。","hints":["为什么 Change Buffer 对唯一索引无效","Change Buffer 在什么场景下反而可能成为性能瓶颈"],"tags":["MySQL","InnoDB","Change Buffer","性能优化"],"id":1456},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB Doublewrite Buffer","content":"什么是 InnoDB 的 Doublewrite Buffer（双写缓冲区）？它解决什么问题？为什么需要它而不仅仅依赖 Redo Log？","answer":"答案：Doublewrite Buffer 是 InnoDB 在写入数据页前的双重写入机制——先将页的副本写入 Doublewrite Buffer（顺序写），再写入实际数据文件（随机写）。解决部分写失效（Partial Page Write）问题——当数据库在写入 16KB 页的过程中崩溃，可能导致只有部分页写入磁盘（例如只写了 4KB），页数据损坏且 Redo Log 无法恢复。\n\n解析：部分写问题——InnoDB 数据页默认 16KB，而 OS 的磁盘写入单位通常为 512 字节（扇区）或 4KB。如果数据库在写 16KB 数据页到磁盘的过程中崩溃（如断电），可能只写入了部分内容，造成页损坏。此时该页的 LSN 无法正常识别，Redo Log 无法安全地应用到该页上。Doublewrite Buffer 的机制——1）写数据页到 Doublewrite Buffer（2MB 连续空间，顺序写）。2）将整个 Doublewrite Buffer 刷到磁盘（一次 fsync）。3）再从 Doublewrite Buffer 将数据页复制到各自的最终位置（随机写）。崩溃恢复时——如果在第一步或第二步崩溃，磁盘上的原始页是好的，Redo Log 可以正常恢复。如果在第三步崩溃，InnoDB 可以从 Doublewrite Buffer 找到页的完好副本恢复。\n\n扩展延伸：Doublewrite Buffer 的性能影响——写量翻倍，但实际影响不大：因为 Doublewrite Buffer 写入是顺序的，真正的数据写入才是随机 I/O。Doublewrite Buffer 默认开启（innodb_doublewrite=ON），建议一直保持开启。特殊场景——某些文件系统（如 ZFS）和存储系统（支持原子写 16KB 的硬件）本身已经解决部分写问题，可以关闭。MySQL 8.0.20+ 将 Doublewrite Buffer 从 system tablespace 迁移到独立文件，支持并发写入。","hints":["为什么部分写失效后 Redo Log 无法恢复","Doublewrite Buffer 在 SSD 上是否仍然必要"],"tags":["MySQL","InnoDB","Doublewrite","数据完整性"],"id":1457},{"category":"database","difficulty":"medium","type":"short_answer","title":"InnoDB Redo Log 与 Undo Log","content":"InnoDB 的 Redo Log 和 Undo Log 分别是什么？它们如何配合实现事务的 ACID 特性？","answer":"答案：Redo Log 记录事务对数据页的物理修改，用于保证事务的持久性（Durability，D）。Undo Log 记录事务修改前的数据状态，用于支持事务回滚（Atomicity，A）和 MVCC（一致性读，I）。两者配合实现 Crash Recovery 和 ACID。\n\n解析：Redo Log——记录页级别的物理修改，如「将 page 5 的 offset 100 处的值改为 200」。顺序写入（环形写入，循环覆盖旧的 log 文件），写入速度快。WAL（Write Ahead Logging）——事务提交时必须先将 Redo Log 刷盘（fsync 保证落盘），然后才将数据页写入磁盘。这就是 Redo Log 能保证持久性的原因：即使数据页还没写盘就崩溃，恢复时通过 Redo Log 重放所有已提交事务的修改。Undo Log——记录逻辑层面的反向操作，存储在 rollback segment 中（system tablespace 或 undo tablespace）。回滚时顺序读取 Undo Log 逐条执行反向操作。MVCC——Undo Log 还用于构建一致性读，通过 Undo Log 链表可以读到事务开始前的旧版本数据。\n\n扩展延伸：Crash Recovery 三阶段：1）Redo Phase（前滚）——从 checkpoint 位置开始扫描 Redo Log，重放所有未刷盘的修改（不管事务是否提交）。2）Undo Phase（回滚）——对 Redo Phase 后仍未提交的事务回滚其修改。3）Cleanup——清理未完成的事务和锁。参数优化：innodb_log_file_size——控制 Redo Log 总大小（MySQL 8.0+ 推荐 2-4GB，原默认 48MB 对写密集场景过小）。如果 Redo Log 太小，频繁的 checkpoint 导致性能抖动。MySQL 8.0 引入了 Redo Log 的自动调优。","hints":["WAL（Write Ahead Logging）保证持久性的原理是什么","为什么 Redo Log 是物理日志而 Undo Log 是逻辑日志"],"tags":["MySQL","InnoDB","Redo Log","Undo Log","事务"],"id":1458},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 索引下推（ICP）","content":"什么是 MySQL 的索引下推（Index Condition Pushdown，ICP）？它如何减少回表次数？什么时候 ICP 不能生效？","answer":"答案：索引下推是 MySQL 5.6 引入的优化，将 WHERE 条件中可以用索引筛选的部分「下推」到存储引擎层，在索引遍历过程中提前过滤不满足条件的记录，减少回表次数和 Server 层的数据处理量。\n\n解析：没有 ICP 时——存储引擎通过索引找到满足最左前缀条件的行（主键值），回表读取完整行数据，返回给 Server 层过滤。所有索引命中的行都要回表，即使它们最终被 WHERE 条件过滤掉了。有了 ICP 后——如果 WHERE 中的列虽然不在索引的最左前缀中，但属于索引的一部分（覆盖索引的中间或末尾列），存储引擎可以在索引遍历时直接判断该条件，不满足则直接跳过，不回表。示例：索引 (city, age)，查询 WHERE city='Beijing' AND age > 25。没有 ICP：通过 city='Beijing' 找到所有行，回表过滤 age > 25。有 ICP：在索引遍历时直接判断 age > 25，不满足跳过。\n\n扩展延伸：ICP 的使用条件——1）只适用于二级索引（不适用于聚簇索引）。2）只适用于 Range、Ref、Eq_Ref、Ref_Or_Null 访问方法。3）不支持子查询条件。4）不支持存储函数或触发器。查看 ICP 是否生效——EXPLAIN 输出中 Extra 列显示 Using index condition。ICP 默认开启（optimizer_switch 中的 index_condition_pushdown=on）。主要收益在于减少回表的 I/O 次数。","hints":["EXPLAIN 中 Extra 列的 Using index condition 表示 ICP 生效","ICP 为什么只对二级索引有效"],"tags":["MySQL","索引下推","ICP","SQL优化"],"id":1459},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL Group Commit（组提交）","content":"什么是 MySQL 的 Group Commit（组提交）？它解决了什么问题？在 MySQL 8.0 中是如何实现的？","answer":"答案：Group Commit 将多个事务的 Redo Log 刷盘操作合并成一次 fsync 调用，减少磁盘 I/O 次数，显著提高高并发场景下的事务处理吞吐量。\n\n解析：问题背景——事务提交时 Redo Log 需要 fsync 刷盘。fsync 是昂贵的磁盘 I/O 操作（SSD 上约 10-100 微秒，HDD 上 5-10 毫秒）。如果每个事务提交都做一次 fsync，TPS 上限受限于 fsync 的延迟。Group Commit 的原理——多个事务同时提交时，它们进入队列。队列中第一个事务（Leader）负责为整个组执行 Redo Log 刷盘操作。其他事务（Follower）在 Leader 完成刷盘后直接从提交队列返回。一次 fsync 服务多个事务，大幅提升吞吐量。\n\n扩展延伸：MySQL 8.0 的 Group Commit 三个阶段（由 binlog_group_commit_sync_delay 和 binlog_group_commit_sync_no_delay_count 控制）：1）FLUSH 阶段——将每个事务的 binlog 写入内存缓冲区，Leader 等待达到 count 或 delay 阈值。2）SYNC 阶段——Leader 调用 fsync 将 binlog 刷盘。3）COMMIT 阶段——在存储引擎层提交事务。优化参数：binlog_group_commit_sync_delay（微秒）——Leader 等待更多事务加入组的时间（建议 500-1000μs）。binlog_group_commit_sync_no_delay_count——组内事务数达到此值立即提交。注意：如果关闭了 binlog，Group Commit 在 InnoDB 层通过 log_flusher 线程实现。","hints":["为什么 Group Commit 能显著提升高并发下的 TPS","binlog_group_commit_sync_delay 和 sync_no_delay_count 如何配合使用"],"tags":["MySQL","Group Commit","事务","性能优化"],"id":1460},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 执行计划分析：filesort 与临时表优化","content":"EXPLAIN 输出中 Extra 字段出现 Using filesort 或 Using temporary 表示什么？如何通过索引优化避免这两种情况？","answer":"答案：Using filesort 表示 MySQL 需要额外的排序操作（使用文件排序或在内存中排序），Using temporary 表示 MySQL 需要使用临时表来处理查询。两者都表示查询性能可能存在问题，通常可以通过创建合适的复合索引来避免。\n\n解析：Using filesort——当 ORDER BY 的列与 WHERE 条件使用的索引不一致时，MySQL 无法利用索引有序性获得排序结果，需要自己排序。排序方式：内存排序（sort_buffer_size 足够时）或文件排序（数据量大时使用磁盘临时文件）。优化：创建包含 WHERE 条件和 ORDER BY 列的复合索引（利用索引本身就是有序的）。如 SELECT * FROM t WHERE a=1 ORDER BY b，可以创建索引 (a,b)，这样数据按 a 过滤后自然按 b 有序，不需要额外排序。Using temporary——当查询需要去重（DISTINCT）、分组（GROUP BY）或需要子查询结果时，MySQL 需要创建临时表。优化：同样通过合适的索引减少临时表的需求。GROUP BY 走索引可以减少临时表。\n\n扩展延伸：避免 filesort 和 temporary 的最佳实践：1）最左前缀原则：组合索引的顺序需要匹配 WHERE + ORDER BY 的列顺序。2）ORDER BY 列需要和 WHERE 条件中的索引列形成最左前缀（如索引 (a,b,c)，WHERE a=1 ORDER BY b → 利用索引；WHERE a=1 ORDER BY c → 无法利用索引的 b → 需要 filesort）。3）GROUP BY 优化：GROUP BY 的列如果是索引的一部分并且满足最左前缀，可以避免临时表。4）尽量减少 ORDER BY 和 GROUP BY 的列宽。5）适当增大 sort_buffer_size 避免磁盘排序。注意：不要指望完全消除 filesort——当查询结果集很大或排序需求复杂时，filesort 是必要的。关键是从全表扫描 + 磁盘排序优化为索引扫描 + 内存排序或免排序。","hints":["Using filesort 为什么通常意味着需要优化","复合索引的列顺序如何影响 ORDER BY 的优化"],"tags":["MySQL","SQL优化","filesort","执行计划"],"id":1461},{"category":"database","difficulty":"medium","type":"short_answer","title":"NoSQL 数据库选型：Redis、MongoDB、HBase、Cassandra","content":"请比较 Redis、MongoDB、HBase、Cassandra 这四种 NoSQL 数据库的核心特性和适用场景。什么场景下应该使用 NoSQL 而不是关系型数据库？","answer":"答案：Redis——内存键值数据库，支持丰富的数据结构，适合缓存和实时数据。MongoDB——文档数据库，灵活的 Schema，适合快速原型和内容管理。HBase——列族数据库，基于 HDFS，适合海量数据实时读写。Cassandra——宽列存储，去中心化架构，适合全球多活部署。\n\n解析：1）Redis——全内存 + 可持久化，单线程处理命令（原子性），支持 String/Hash/List/Set/Sorted Set/Bitmap/HyperLogLog，支持事务和 Lua 脚本，发布订阅，主从+哨兵+集群。延迟通常在微秒级。适合：缓存、Session 存储、实时排行榜、分布式锁、消息队列。不适合：数据量超过内存的场景、需要复杂查询（多条件过滤）的场景。2）MongoDB——BSON 文档存储，支持二级索引和聚合管道，分片（水平扩展），无 Schema 约束（集合中的文档结构可以不统一）。适合：内容管理（CMS）、实时分析、IoT 数据采集、快速原型开发。不适合：强事务（ACID）要求、多表 JOIN 频繁、大量数据更新操作。\n\n扩展延伸：3）HBase——列族（Column Family）存储，按 Row Key 排序。Region Server 自动分片，强一致性（CP，基于 ZK）。适合：海量数据的实时随机读写（每秒百万级请求）、时序数据（监控指标）、大表（数十亿行×数百万列）。不适合：关系型查询模式、数据量小（HDFS 最小块 128MB，小数据量场景浪费空间）。4）Cassandra——分区键 + 聚类列，无主节点（所有节点平等），最终一致性（AP，可调一致性级别），Gossip 协议 + 去中心化。Write 性能极高（追加写入 CommitLog + MemTable）。适合：物联网设备数据、时序数据、全球多活（Multi-DC 同步）、写多读少的场景。不适合：强事务和复杂查询、数据一致性要求高于可用性。NoSQL 不是银弹——大多数业务场景的最佳选择是 MySQL（关系型）为主 + Redis（缓存）为辅。只在特定场景（海量数据、灵活 Schema、极高并发）才考虑 MongoDB/HBase/Cassandra。","hints":["什么场景应该用 Redis、MongoDB、HBase 或 Cassandra","CAP 定理如何指导 NoSQL 数据库选型"],"tags":["NoSQL","Redis","MongoDB","HBase","Cassandra"],"id":1462},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库事务隔离级别与实现","content":"请详细解释 SQL 标准定义的四种事务隔离级别：读未提交（RU）、读已提交（RC）、可重复读（RR）、串行化（Serializable）。MySQL InnoDB 如何实现这些隔离级别？Oracle 和 PostgreSQL 的默认隔离级别是什么？","answer":"答案：四种隔离级别分别解决不同的并发问题：RU（脏读）、RC（不可重复读）、RR（可重复读）、Serializable（幻读）。InnoDB 默认 RR 级别，通过 MVCC + Next-Key Lock 实现。Oracle 默认 RC，PostgreSQL 默认 RC。\n\n解析：1）脏读——事务 A 读取了事务 B 未提交的数据，事务 B 回滚后导致 A 读到了脏数据。RU 级别可以发生脏读，RC 及以上级别通过读取已经提交的快照避免脏读。2）不可重复读——事务 A 内两次读取同一行数据，在两次读取之间事务 B 修改并提交了该行，导致 A 两次读取结果不同。RC 级别不可重复读，RR 级别通过在事务开始创建一致性快照（MVCC，多个版本并发控制）实现可重复读。3）幻读——事务 A 内两次范围查询，事务 B 在 A 两次查询期间插入了新行，导致 A 第二次多出了一行。RR 级别在 InnoDB 中通过间隙锁（Gap Lock）和 Next-Key Lock 防止幻读（但仅对当前读有效，快照读不受幻读影响）。Serializable 级别通过对所有读加锁强制串行。\n\n扩展延伸：实现机制——1）MVCC（多版本并发控制）：每行数据有多个版本（通过 Undo Log 维护），每行记录创建的事务 ID 和删除的事务 ID。事务开始时获取一个 Read View（活跃事务列表），通过可见性规则判断应该读哪个版本。快照读（普通的 SELECT）不加锁，通过 MVCC 获得一致快照。当前读（SELECT ... FOR UPDATE / UPDATE / DELETE）需要加锁。2）Next-Key Lock = 行锁 + 间隙锁，是 InnoDB RR 级别防止幻读的关键——锁住行以及行之间的间隙，阻止其他事务在间隙中插入新行。3）不同 DB 的默认隔离级别：MySQL InnoDB 默认 RR（可重复读），Oracle 默认 RC（读已提交），PostgreSQL 默认 RC（读已提交），SQL Server 默认 RC（读已提交）。MySQL 选择 RR 作为默认是为了兼容 binlog 基于 statement 格式时的复制安全——但现在推荐使用 ROW 格式+RC 级别。","hints":["MVCC 如何实现读不阻塞写、写不阻塞读","为什么 MySQL InnoDB 使用 RR 作为默认隔离级别而 Oracle 却用 RC"],"tags":["数据库","事务","隔离级别","MVCC"],"id":1463},{"category":"database","difficulty":"hard","type":"short_answer","title":"数据库连接池连接数优化","content":"数据库连接池的最大连接数设置为多少合适？为什么不是越多越好？如何根据应用类型（OLTP vs OLAP）调整连接池参数？","answer":"答案：连接池的最大连接数不是越多越好——过大的连接数会导致数据库端上下文切换增加、资源竞争加剧，反而降低吞吐量。OLTP（在线事务处理）适合小连接数，OLAP（在线分析处理）可能需要大连接数但场景相对孤立。建议最大连接数 = CPU 核心数 × 2 + 磁盘数量的小公式作为起点。\n\n解析：1）连接不是越多越好——每个数据库连接都消耗资源（MySQL 每个连接一个线程，占用内存和 CPU 上下文切换）。当活跃连接数超过 CPU 核心数时，线程切换成本急剧增加。大量连接竞争 InnoDB 的行锁会导致锁等待加剧。2）HikariCP（Spring Boot 默认）的推荐公式：maximumPoolSize = ((core_count × 2) + effective_spindle_count)。其中 effective_spindle_count 是磁盘数量（SSD 视为 1，HDD 可设更高）。这个公式的前提是数据库和应用在同一台机器或同机房低延迟网络。对于 OLTP 应用（简短快速的事务），5-10 个连接通常足够。超过这个数字后，数据库更多是在处理锁竞争和线程切换而不是实际工作。\n\n扩展延伸：3）连接池参数调整——不同负载类型：OLTP（高并发、短查询、低延迟要求）：小连接池（10-20）、短超时（3-5 秒）、最小空闲连接保持 5-10。OLAP（复杂查询、数据量大、单个查询时间长）：可能需要更大的连接池或单独配置连接到分析库。混用场景（OLTP + 少量 OLAP）：分别配置两个数据源（一个给 OLTP 用小连接池，一个给 OLAP 用大连接池）。4）监控连接池：活跃连接数（active）、空闲连接数（idle）、等待获取连接的线程数（pending）。如果 pending > 0 持续上升，说明连接池过小；如果 active 一直远小于 maximum，说明连接池过大。5）数据库端上限：MySQL 的 max_connections（默认 151）需要大于所有应用实例连接池大小的总和。","hints":["为什么 CPU 核心数 × 2 + 磁盘数 是一个连接池大小参考公式","OLTP 应用连接池为什么不宜超过 CPU 核心数的 2-3 倍"],"tags":["MySQL","连接池","性能","OLTP"],"id":1464},{"category":"database","difficulty":"medium","type":"short_answer","title":"ShardingSphere 与数据库分片中间件","content":"请介绍数据库分片（Sharding）的几种策略。ShardingSphere、MyCAT 等分片中间件的工作原理是什么？分片后有哪些常见问题和挑战？","answer":"答案：数据库分片将数据水平拆分到多个数据库实例上，以突破单机存储和性能上限。分片策略包括：哈希分片（取模/一致性哈希）、范围分片（按 ID 或时间范围）、映射表（维护分片路由关系）。ShardingSphere 作为分片中间件，基于数据库协议层做 SQL 解析→路由→改写→执行→结果归并。\n\n解析：1）分片策略——哈希分片：对分片键取模（如 user_id % 16）→ 映射到 16 个库。数据分布均匀，但扩缩容需要重新分布数据（一致性哈希可减少迁移量）。范围分片：按分片键的范围映射到不同库（如 user_id 1-1000 万在库1，1000万-2000万在库2）。扩缩容容易（加新范围即可），但可能出现数据倾斜（活跃用户集中在某一范围）。映射表：维护分片键到数据库的映射关系。路由最灵活但需要查表（额外性能开销）。2）分片中间件——客户端模式（ShardingSphere-JDBC）：在 JDBC 层嵌入，应用直连数据库，无网络代理。优点：部署简单、性能高。缺点：每个应用都需要集成。代理模式（ShardingSphere-Proxy / MyCAT / DBLE）：独立的代理服务器，应用连接代理像连接数据库一样。\n\n扩展延伸：分片后的挑战和解决方案——1）跨分片查询：跨多个数据库的 JOIN 和排序效率低。解决：尽量按分片键查询（避免跨分片）；用 ES 做宽表冗余；应用层聚合。2）分布式事务：跨分片的事务需要分布式事务支持（Seata、XA、TCC）。尽量避免跨分片事务，或者通过最终一致性+补偿机制处理。3）全局主键：自增 ID 在分片下不适用。解决：雪花算法（Snowflake ID）、UUID、号段模式（Leaf/美团分布式ID）。4）分片键选择：必须根据查询模式选择分片键。如果分片键选错了，很多查询需要广播到所有分片。5）数据迁移：分片扩容（从 8 分片扩到 16）需要重新分布数据——停机迁移或双写迁移。一致性哈希可以最小化迁移量。分片是最后的优化手段——在分片前先尝试读写分离、缓存、分区表等更简单的方案。","hints":["分片后跨分片查询和分布式事务是最难解决的问题","为什么一致性哈希在分片扩容时比简单取模更好"],"tags":["数据库","分片","ShardingSphere","分布式"],"id":1465},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 主键选择与自增 ID 优化","content":"为什么 InnoDB 建议使用自增 ID 作为主键？UUID 作为主键有什么问题？雪花算法（Snowflake）ID 生成器的原理？主键选择对 B+ Tree 性能的影响？","answer":"答案：自增 ID 作为主键是最优选择——新记录插入时只在 B+ Tree 的末尾追加（页分裂最少）。UUID 作为主键会随机插入（大量页分裂和碎片化），且主键更长导致二级索引更大。雪花算法生成全局唯一分布式 ID（时间戳 + 机器 ID + 序列号）。\n\n解析：自增 ID 的优势——1）B+ Tree 的聚簇索引按主键顺序存储，自增 ID 新记录总是在最后插入，Page 利用率最高。2）UUID 作为主键时新记录的插入位置随机，导致大量页分裂（Page Split）、B+ Tree 频繁调整。3）自增 ID（4-8 bytes）比 UUID（16 bytes 或 36 bytes 字符串）小，主键越小二级索引越小（所有二级索引都包含主键）。\n\n扩展延伸：自增 ID 的局限——1）分库分表场景：不同库的自增 ID 会重复，需要全局唯一 ID。2）数据迁移时 ID 可能冲突。3）批量插入时自增锁（AUTO-INC Lock）可能成为瓶颈（InnoDB 可用轻量级 mutex 优化）。雪花算法——1）结构：1bit 符号位（固定 0）+ 41bit 时间戳（ms 级精度，可用 69 年）+ 10bit 机器 ID（最多 1024 台）+ 12bit 序列号（每 ms 最多 4096 个 ID）。2）时钟回拨问题：如果机器时间回拨，可能产生重复 ID。解决方案：记录上次生成时间戳，回拨时等待或使用备用序列号段。替代方案——分布式 ID——UUID（不推荐做 DB 主键）、Snowflake（最常用）、Leaf（美团）、Tinyid（滴滴）、Redis INCR + 号段模式。","hints":["UUID 做主键的三大问题——随机插入导致页分裂、16byte 比 4byte 大得多、二级索引膨胀","雪花算法的时钟回拨问题——时间回拨毫秒内可能生成重复 ID，需要容错机制"],"tags":["数据库","MySQL","主键","分布式ID"],"id":1466},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 备份恢复策略","content":"MySQL 有哪些备份方式？逻辑备份（mysqldump）和物理备份（XtraBackup）的区别？全量备份+增量备份+binlog 的恢复策略如何设计？","answer":"答案：MySQL 备份分为逻辑备份（mysqldump/mydumper 导出 SQL）和物理备份（直接拷贝数据文件，XtraBackup）。逻辑备份灵活但速度慢，物理备份速度快但跨版本兼容性差。最佳实践：全量备份（每周）+ 增量备份（每天）+ binlog 实时归档（点到点恢复）。\n\n解析：备份方式对比——1）mysqldump：导出 SQL 语句恢复数据库。优点：可跨版本、可选择单表、结果可读。缺点：速度慢（逐行导出）、导入慢（逐条执行 SQL）、锁表（--single-transaction 可避免 InnoDB 锁表）。大数据库（100GB+）不适用。2）XtraBackup（Percona）：物理备份，直接拷贝 InnoDB 数据文件。优点：速度快、不影响线上读写、支持增量备份。缺点：备份文件只能恢复同版本 MySQL。3）mydumper/myloader：多线程逻辑备份，比 mysqldump 快 3-5 倍。\n\n扩展延伸：恢复策略——1）RPO（Recovery Point Objective，最多丢失多少数据）和 RTO（Recovery Time Objective，恢复目标时间）决定备份策略。RPO=1 小时 → 每 1 小时 binlog 备份一次。RTO=4 小时 → 选择恢复速度快的物理备份方式。2）恢复步骤：恢复最近的全量备份 → 叠加增量备份 → 应用 binlog 到崩溃前的时间点（point-in-time recovery）。3）定期演练：备份不做恢复验证等于没有备份。每月至少一次恢复演练。延迟复制的用途——在误操作时从延迟复制（delayed replica）恢复数据。","hints":["mysqldump 适合小库（<50GB），XtraBackup 适合大库——物理备份速度远快于逻辑备份","备份恢复演练比备份本身更重要——没有验证过的备份可能在真正需要时不可用"],"tags":["数据库","MySQL","备份","恢复"],"id":1467},{"category":"database","difficulty":"medium","type":"choice","title":"MySQL 覆盖索引","content":"以下关于 MySQL 覆盖索引（Covering Index）的描述中，哪一个是正确的？","options":["A) 覆盖索引是指索引包含所有列，不需要回表查询","B) 覆盖索引一定会比非覆盖索引快","C) 覆盖索引只能用于主键查询","D) 覆盖索引在 EXPLAIN 中显示为 Using where"],"answer":"答案：A) 覆盖索引是指索引包含所有列，不需要回表查询\n\n解析：覆盖索引指查询所需的所有列都包含在索引中，不需要通过主键回表查询聚簇索引中的完整行。EXPLAIN 中的 Extra 显示为 Using index（区别于 Using where）。覆盖索引减少磁盘 I/O（只访问索引 B+ Tree 即可返回查询结果，无需回表），在高频查询中效果显著。\n\n扩展延伸：覆盖索引设计——1）SELECT 子句中的列和 WHERE 条件列都应包含在索引中。但如果索引列太多（覆盖全部列）反而不如回表（索引变大 → B+ Tree 变高 → 查询变慢）。2）不要为了覆盖索引添加过多列——只在高频查询上使用覆盖索引优化。3）回表（Secondary Index Lookup）：二级索引查到主键后，再通过主键到聚簇索引中查找完整行记录。覆盖索引避免了这一过程。4）Extra 的 Using index vs Using where：Using index 表示使用了覆盖索引（不需要回表）；Using where 表示 Server 层在存储引擎返回记录后进行了过滤。两者可以同时出现。","hints":["覆盖索引的 EXPLAIN 标志——Extra 显示 Using index 表示不需要回表","覆盖索引不是列越多越好——索引列越多 B+ Tree 越大，需要权衡"],"tags":["数据库","MySQL","覆盖索引","优化"],"id":1468},{"category":"database","difficulty":"easy","type":"true_false","title":"MySQL 数据库连接池","content":"数据库连接池中的连接数量越多越好。如果系统需要处理 1000 个并发请求，应该配置 1000 个数据库连接来确保每个请求都有独立的数据库连接可用。","options":["正确","错误"],"answer":"答案：错误。\n\n解析：数据库连接数并非越多越好。过多的连接会导致数据库服务器切换上下文频繁，反而降低吞吐量。PostgreSQL 和 MySQL 官方建议的活跃连接数 = 2 * CPU 核数 + 有效磁盘数（通常几十到几百就足够）。HikariCP（Spring Boot 默认连接池）作者指出：连接数过多时数据库的瓶颈从 CPU 变为上下文切换和锁竞争。\n\n扩展延伸：连接池配置原则——1）连接池大小不是并发请求数，而是「数据库能同时高效处理的活跃连接数」。CPU 密集型查询：core_count * 2 + 1。IO 密集型查询：可适当增加但也不宜过大。2）等待队列：请求从连接池获取连接时如果连接用尽，应该排队等待（而非立即创建新连接）。HikariCP 的 maximumPoolSize 和 minimumIdle 配置。3）连接池监控：活跃连接数、等待超时次数、连接创建/销毁频率。如果连接池设置过大（如 200+），在数据库端观察 Threads_running 指标会很高，CPU 的 context switch 大幅增加，吞吐量反而下降。4）经验值：4 核数据库 → 活跃连接 10-20。16 核 → 50-100。应用层连接池通常 10-50 就足够。","hints":["连接数过多导致数据库上下文切换频繁——HikariCP 推荐的活跃连接数 = 2 * CPU 核数 + 有效磁盘数","1000 个连接 ≠ 1000 个并行查询——数据库的并行度受 CPU 核数限制"],"tags":["数据库","连接池","MySQL","性能"],"id":1469},{"category":"database","difficulty":"medium","type":"fill_in_blank","title":"MySQL Redo Log 写入流程","content":"InnoDB 的 Redo Log 采用{{____}}写入方式，数据先写入{{____}}（内存缓冲区），由{{____}}线程定期刷盘。写入时遵循{{____}}原则（日志先行），确保事务的{{____}}性。Redo Log 是{{____}}日志，记录的是{{____}}的物理修改。","answer":"{\"correct\":[[\"循环\"],[\"redo log buffer\"],[\"log writer\"],[\"WAL（Write-Ahead Logging）\"],[\"持久\"],[\"物理\"],[\"数据页\"]],\"distractors\":[[\"顺序\",\"随机\",\"追加\"],[\"buffer pool\",\"log cache\",\"数据缓冲区\"],[\"page cleaner\",\"checkpoint\",\"master\"],[\"ACID\",\"MVCC\",\"两阶段提交\"],[\"一致\",\"隔离\",\"原子\"],[\"逻辑\",\"混合\",\"事务\"],[\"行记录\",\"表结构\",\"索引\"]]}","hints":["WAL（Write-Ahead Logging）——在修改数据页之前先把 Redo Log 写入磁盘，保证 Crash Recovery","Redo Log 是物理日志（记录对数据页的修改），Undo Log 是逻辑日志（记录数据修改前的状态）"],"tags":["数据库","MySQL","Redo Log","InnoDB"],"id":1470},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库分片策略与分布式主键","content":"常见的数据库分片策略有哪些？如何选择分片键？分布式场景下全局唯一主键如何生成？","answer":"答案：常见分片策略包括范围分片、哈希分片、一致性哈希分片。分片键选择需保证数据均匀分布，常用用户ID、订单ID等高频查询字段。分布式主键方案包括UUID、雪花算法（Snowflake）、数据库分段（segment）、Redis incr。\n\n解析：1）范围分片（Range Sharding）——按连续范围划分数据，如按时间或ID范围。优点：范围查询友好，扩展时只需新增分片。缺点：热点问题——最新数据集中在最后一个分片。2）哈希分片（Hash Sharding）——对分片键取模或一致性哈希。优点：数据分布均匀，写压力分散。缺点：扩缩容需要数据迁移（一致性哈希可缓解范围变化），跨分片范围查询性能差。3）键值映射分片——维护分片键到分片的映射表。优点：灵活调整。缺点：映射表成为瓶颈和单点风险。分布式主键方案：UUID简单但128位过长且无序（影响B+树写入性能）。雪花算法（Snowflake）64位长整型——1bit符号+41bit毫秒时间戳+10bit机器ID+12bit序列号，有序递增、高性能、无中心化依赖。\n\n扩展延伸：分片后的实践挑战——跨分片事务需要分布式事务方案（XA、TCC、Saga）。跨分片查询的聚合问题——全局排序需归并排序、分页需各分片取回再合并、多维度查询需辅助索引（ES）。ShardingSphere 的 Hint 分片支持强制路由到指定分片。生产建议：分片键选择高频等值查询字段，避免使用 JOIN 跨分片，单表数据量超过 2000 万行再考虑分片。","hints":["一致性哈希如何减少扩缩容时的数据迁移量","雪花算法在时钟回拨场景下怎么处理"],"tags":["数据库分片","分片策略","分布式主键","雪花算法"],"id":1471},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL 组复制（MGR）原理","content":"MySQL Group Replication（MGR）如何实现高可用？与异步复制和半同步复制的核心区别是什么？","answer":"答案：MGR 基于 Paxos 协议的组通信系统实现多节点强一致性复制。所有节点组成复制组，事务需经组内多数节点同意才能提交。与异步复制（主无条件提交，不等待从库确认）和半同步复制（至少一个从库确认）不同，MGR 要求多数节点确认提交，提供更强的一致性保证。\n\n解析：MGR 采用全连接网状拓扑，节点之间通过 Group Communication System（基于 Paxos）通信。事务提交流程：1）事务在本地执行。2）提交时广播到组内所有节点。3）多数节点 certify 通过后本地提交。4）其余节点异步回放。冲突检测——MGR 对行级并行执行，使用维向量（version vector）检测写冲突。两种模式：单主模式（single-primary）——只有主节点可写，其余为只读节点，简化冲突处理。多主模式（multi-primary）——所有节点可写，但需要应用层处理写冲突。与异步复制区别：异步复制中主机宕机可能丢数据。半同步复制至少保证一个从机确认，但一致性仍弱于 MGR。MGR 保证多数节点有数据，自动故障切换。\n\n扩展延伸：MGR 的限制——写性能受组内最慢节点影响，组内节点数建议 3-5 个（奇数避免平局），不支持级联复制。MGR vs InnoDB Cluster——MGR 是核心组件，InnoDB Cluster 是 MGR + MySQL Router + MySQL Shell 的完整高可用方案。生产建议：使用单主模式 + 3 节点 + MySQL Router 自动读写分离。","hints":["单主模式和多主模式下写冲突处理的差异","为什么 MGR 建议用奇数个节点"],"tags":["MySQL","MGR","组复制","高可用"],"id":1472},{"category":"database","difficulty":"medium","type":"short_answer","title":"NoSQL 数据建模核心原则","content":"NoSQL 数据建模与关系型数据库有哪些根本区别？如何根据不同 NoSQL 类型（键值、文档、列族、图）设计数据模型？","answer":"答案：NoSQL 数据建模的核心原则是「查询驱动设计」（Query-Driven Design）——先确定查询模式再设计数据模型（RDBMS 反之：先设计数据模型再写查询）。遵循反范式化、聚合导向、避免 JOIN 三大原则。\n\n解析：四种 NoSQL 类型的数据建模特点：1）键值存储（Redis/Memcached）——建模为 Key→Value 映射，无模式约束。Key 命名规范用冒号分隔（user:123:profile），Value 结构根据访问模式选择（JSON 字符串、Hash、Set）。适用：缓存、Session、计数器。2）文档数据库（MongoDB）——建模为 Collection → Document → Field。反范式化嵌入关联数据（Embedding）减少查询次数。设计关键：Embedding vs Referencing——嵌入性能好但有 16MB 文档上限，引用减少冗余但需应用层聚合。3）列族数据库（HBase/Cassandra）——RowKey 设计最重要（影响数据分布和访问效率）。Cassandra 要求先定义查询模式再建表（CQL 表设计以查询为中心）。4）图数据库（Neo4j）——建模为 Node → Relationship → Property。适合社交关系、推荐、知识图谱的深度遍历查询。\n\n扩展延伸：NoSQL 建模的反模式——在文档数据库中做应用层 JOIN（N+1 查询问题）、在 Cassandra 中建过多二级索引（每表不超过 2 个）、在 Redis 中存大 Key（影响集群重新分片和内存管理）。选型建议：支付宝用 OceanBase（NewSQL），微博用 Redis + MySQL，Facebook 用 Cassandra，Google 用 Spanner/Bigtable。","hints":["文档数据库中的 Embedding 和 Referencing 如何取舍","Cassandra 的数据模型设计为什么从查询开始"],"tags":["NoSQL","数据建模","MongoDB","Cassandra","Redis"],"id":1473},{"category":"database","difficulty":"hard","type":"short_answer","title":"NewSQL 数据库架构与 TiDB 实践","content":"NewSQL 数据库（如 TiDB、CockroachDB、OceanBase）如何同时保证 ACID 事务和水平扩展？与传统分库分表方案相比有哪些核心优势？","answer":"答案：NewSQL 采用分布式 SQL 引擎 + 自动分片 + 共识协议（Raft/Paxos）的架构，在保持 SQL 和 ACID 事务的同时实现水平扩展。相比传统分库分表：业务无侵入（无需配置分片键）、跨分片查询透明、数据自动 rebalance、强一致性内置。\n\n解析：以 TiDB 为例——1）TiDB Server：无状态 SQL 层，解析 SQL、生成执行计划、下推算子到存储节点。兼容 MySQL 协议，可直接用 MySQL 客户端连接。2）TiKV Server：分布式 KV 存储引擎，数据按 Range 自动分片为 Region（默认 96MB）。每个 Region 通过 Raft 协议复制到 3 个节点，保证强一致性。Region 自动分裂和合并。3）PD（Placement Driver）：管理 Region 元数据，调度 Region 在节点间均衡分布，监控集群状态。传统分库分表痛点：分片键变更困难、跨分片查询/排序/分页复杂、分布式事务依赖 XA 性能差、扩缩容需迁移数据并配合业务停机。NewSQL 在 SQL 层自动完成分区路由和下推聚合，对应用完全透明。\n\n扩展延伸：主流 NewSQL 产品对比——TiDB（开源，MySQL 兼容，HTAP）、CockroachDB（开源，PostgreSQL 兼容，全球部署能力）、OceanBase（闭源，Oracle 兼容，蚂蚁集团核心系统）、Google Spanner（TrueTime API + 全球强一致）。HTAP（Hybrid Transactional/Analytical Processing）是 NewSQL 发展方向——同一系统同时支持 OLTP 和 OLAP，通过行列混合存储实现（TiDB 的 TiFlash 列存引擎）。","hints":["TiDB 中 SQL 层如何将查询下推到存储层","Raft 协议在 TiKV 中如何保证 Region 内数据一致性"],"tags":["NewSQL","TiDB","分布式数据库","Raft","HTAP"],"id":1474},{"category":"database","difficulty":"medium","type":"short_answer","title":"读写分离架构与主从延迟处理","content":"MySQL 读写分离架构如何实现？主从同步延迟会导致哪些问题？有哪些应对策略？","answer":"答案：读写分离通过将写操作路由到主库、读操作路由到从库实现。核心组件包括中间代理层（Proxy/MaxScale/ProxySQL）或客户端路由（ShardingSphere/Spring @Transactional(readOnly=true)）。主从延迟导致「读到脏数据」——写入后立即读取到的是旧数据。应对策略包括强制读主、延迟容忍、缓存辅助、并行复制。\n\n解析：两种实现模式——1）中间代理层：应用程序连接代理，代理自动路由读写（如 MySQL Router、MaxScale、ProxySQL）。优点：对应用透明。缺点：增加网络一跳，代理成为性能瓶颈和高可用关注点。2）客户端路由：通过数据源框架实现（如 ShardingSphere 读写分离功能、Spring @Transactional(readOnly=true)）。优点：无需额外组件。缺点：每个应用都要配置。主从延迟根因：主库 binlog → 网络传输 → 从库 relay log → SQL 线程回放。延迟触发：从库硬件弱于主库、从库同时服务读请求、大事务（大量 binlog）、DDL 操作。\n\n扩展延伸：应对方案详解——1）强制读主：一致性敏感的请求（支付结果、刚创建的记录）强制路由到主库。2）延迟标记：监控从库延迟（Seconds_Behind_Master），超过阈值自动摘除该从库的读流量。3）缓存辅助：写入后同步更新 Redis 缓存，优先读缓存。4）数据库层面优化：半同步复制（等待至少一个从库确认）、启用并行复制（MySQL 5.7+ 多线程回放，slave_parallel_workers）。5）业务妥协：客户端写入后延迟 100ms 再读。监控：SHOW SLAVE STATUS 的 Seconds_Behind_Master，Percona Monitoring Plugins。建议：一主三从常见配置，从库数建议不超过 5 个。","hints":["半同步复制如何平衡一致性和性能","为什么从库数量不建议超过 5 个"],"tags":["读写分离","主从延迟","MySQL","高可用"],"id":1475},{"category":"database","difficulty":"medium","type":"short_answer","title":"时序数据库与关系数据库的区别","content":"时序数据库（如 InfluxDB、Prometheus、TimescaleDB）与关系数据库在数据模型、存储结构、查询方式上有什么核心区别？时序数据库适合什么场景？","answer":"答案：时序数据库专为时间序列数据优化，以时间戳+标签+值的数据模型存储，写入吞吐高、压缩比大，适合监控、IoT、金融行情等场景。\n\n解析：时序数据库的核心特性：1）数据模型——每条数据由时间戳（Timestamp）、标签（Tag，如 host=server1, region=cn-beijing）和字段值（Field）组成。Tag 用于过滤和分组，Field 用于聚合计算。2）写入优化——时序数据写入频繁但很少修改，时序数据库针对 append-only 写入模式优化，写入吞吐可达百万点/秒。3）存储优化——使用列式压缩（差值编码、游程编码、浮点数 XOR 压缩），压缩比可达 10:1 到 50:1。4）查询模式——按时间范围聚合（降采样）、按标签过滤，支持连续查询（Continuous Query）自动聚合。\n\n扩展延伸：关系数据库（如 PostgreSQL + TimescaleDB 插件）也可以存储时序数据，但写入吞吐和压缩比不如专用时序数据库。时序数据库的局限性：不适合复杂 JOIN、事务型场景。选型建议：监控指标用 Prometheus，IoT 设备用 InfluxDB，需要 SQL 兼容用 TimescaleDB。","hints":["时序数据的写入模式有什么特点","时序数据库为什么压缩比高"],"tags":["时序数据库","InfluxDB","Prometheus","监控"],"id":1476},{"category":"database","difficulty":"medium","type":"short_answer","title":"图数据库的核心概念与应用场景","content":"什么是图数据库？Neo4j 等图数据库的核心概念（节点、关系、属性、遍历）是什么？图数据库适合解决什么问题？","answer":"答案：图数据库以图结构（节点+边+属性）存储数据，核心概念包括节点（实体）、关系（边）、属性（KV 对）、标签和遍历。擅长处理复杂关联关系和深层次路径查询。\n\n解析：图数据库的核心特性：1）数据模型——节点（Node）代表实体（如人、公司），关系（Relationship）代表实体间的连接（如「任职」「投资」），属性和标签附加在节点和关系上。2）查询语言——Cypher（Neo4j）或 Gremlin，用模式匹配表达图遍历，如 MATCH (a:Person)-[:WORKS_FOR]->(b:Company) WHERE a.name = '张三' RETURN b。关系数据库需要多层 JOIN 才能表达的查询，图数据库一行 Cypher 即可。3）性能优势——关联查询的复杂度与遍历深度相关，与数据总量无关。关系数据库 JOIN 多张千万级表时性能急剧下降，图数据库在深度关联场景快几个数量级。4）存储结构——使用邻接表或邻接矩阵的变体，节点和关系物理上指向相邻节点，无需索引即可快速遍历。\n\n扩展延伸：图数据库的典型场景——社交网络（好友推荐、影响力分析）、反欺诈（异常交易链路检测）、知识图谱（实体关系推理）、推荐系统（协同过滤的图路径计算）。不适用场景：大量聚合统计（如 SUM/COUNT）、全文搜索、OLTP 事务场景。","hints":["图数据库为什么在深度关联查询中比关系数据库快","Cypher 查询语言和 SQL 有什么本质区别"],"tags":["图数据库","Neo4j","知识图谱"],"id":1477},{"category":"database","difficulty":"medium","type":"short_answer","title":"列式存储与行式存储的区别","content":"列式存储（如 ClickHouse、Parquet、ORC）和行式存储（如 MySQL InnoDB）的存储结构和查询性能有什么核心区别？列存为什么在 OLAP 场景中表现更好？","answer":"答案：行式存储按行组织数据（一行连续存储），适合 OLTP 的点查和更新。列式存储按列组织数据（一列连续存储），适合 OLAP 的大规模聚合和扫描查询。\n\n解析：列式存储的核心优势：1）按需读取——查询只需要少数列时，列存只读取相关列的数据，减少 I/O。行存即使只查一列也要读整行数据。2）压缩率高——同一列的数据类型相同、值分布有规律（如日期列、枚举列），可以使用差值编码、游程编码、字典编码等高效压缩算法。列存压缩比通常为 5:1 到 20:1。3）向量化执行——列存天然适合 SIMD 向量化处理，单条指令可处理多列值。4）编码优化——数据排序后存储可以进一步压缩，如稀疏列可转为位图（Bitmap）存储。\n\n扩展延伸：行式存储 vs 列式存储的工程实践：1）数据更新——列存修改单行开销大（涉及多列文件改写），行存更新高效。2）OLTP（如订单系统）用行存，OLAP（如报表分析）用列存。3）HTAP 数据库（如 TiDB、StarRocks）同时支持行存和列存两种引擎。4）列存的代价：查询少量行时延迟高（需要扫描大量数据才能找到目标行），不适合点查场景。","hints":["为什么同一列的数据更容易压缩","列存为什么不适合频繁更新的场景"],"tags":["列式存储","ClickHouse","Parquet","OLAP"],"id":1478},{"category":"database","difficulty":"hard","type":"short_answer","title":"HTAP 数据库的原理与挑战","content":"什么是 HTAP（Hybrid Transactional/Analytical Processing）？它解决了什么问题？HTAP 数据库在一份数据上同时支持 TP 和 AP 的核心技术挑战是什么？","answer":"答案：HTAP 指在同一数据库引擎中同时支持 OLTP 事务处理和 OLAP 分析查询，避免传统架构中 TP 库和 AP 库之间的数据搬运（ETL）。核心挑战在于如何在一份数据上同时满足 TP 的低延迟更新和 AP 的高吞吐扫描。\n\n解析：HTAP 的核心技术架构：1）行列混合存储——同时维护行存（高效点查和更新）和列存（高效聚合分析），通过分布式一致性协议（如 Raft）同步数据。写入走行存，分析查询走列存，两套引擎共享同一份最新数据（TiDB 的 TiFlash、MySQL HeatWave）。2）计算存储分离——计算节点无状态可弹性伸缩，存储节点按数据分片存储。TP 查询走计算节点的行存引擎，AP 查询走列存引擎（通过列存副本）。3）实时一致性——列存引擎通过 Raft Learner 或异步复制实时同步行存的数据变更，保证 AP 查询读取的是近实时数据（秒级延迟）。\n\n扩展延伸：主流 HTAP 方案对比——TiDB：行存（TiKV）+ 列存（TiFlash），Raft 同步。StarRocks：三种表模型（明细/聚合/更新），列式存储引擎同时支持 TP 和 AP。Snowflake：计算和存储分离，自动聚类和物化视图优化 AP 性能。ClickHouse：纯列存，通过 CollapsingMergeTree/ReplacingMergeTree 支持轻量级更新。HTAP 的局限：同一份数据难以同时在 TP 延迟和 AP 吞吐上都达到极致，通常是一种折中方案。","hints":["HTAP 如何解决 TP 和 AP 之间的数据同步延迟问题","行列混合存储中的列存副本是怎样实时同步的"],"tags":["HTAP","TiDB","StarRocks","行列混合"],"id":1479},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库中间件的核心作用","content":"数据库中间件（如 ShardingSphere、MyCAT、Vitess）在分布式数据库架构中起什么作用？它们解决了哪些问题？有哪些常见的功能分层？","answer":"答案：数据库中间件位于应用和数据库之间，提供分库分表、读写分离、分布式事务、数据迁移等能力，让业务像访问单库一样访问分布式数据库集群。\n\n解析：数据库中间件的核心功能：1）分库分表（Sharding）——按分片键（Sharding Key）将数据路由到不同的数据库实例或表。策略包括：取模分片、范围分片、一致性哈希分片。对应用透明，SQL 层自动改写和路由。2）读写分离——将 SELECT 请求路由到只读从库，INSERT/UPDATE/DELETE 路由到主库。解决读写分离场景下从库的负载均衡和延迟感知问题。3）分布式事务——支持 XA 事务（两阶段提交）、SEATA（AT/TCC/Saga）等分布式事务方案，保证跨库事务的一致性。4）数据迁移和治理——在线数据迁移、分片策略动态调整、影子库压测、SQL 审计和限流。\n\n扩展延伸：数据库中间件的演进方向——从 Proxy 模式（如 MyCAT、Vitess，独立部署代理层）到 SDK 模式（如 ShardingSphere-JDBC，嵌入应用进程），再到云原生 DBaaS（直接提供分布式数据库实例）。Proxy 模式优势是跨语言兼容，劣势是多一层网络跳转。SDK 模式优势是低延迟（无中间层），劣势是仅 Java 生态。选型建议：小团队用 ShardingSphere-JDBC，大团队/多语言用 ShardingSphere-Proxy 或 Vitess。","hints":["Proxy 模式和 SDK 模式各有什么优缺点","分片键选择不当会导致什么问题"],"tags":["数据库中间件","ShardingSphere","分库分表","Vitess"],"id":1480},{"category":"database","difficulty":"hard","type":"short_answer","title":"TiDB TiKV/TiFlash 存储引擎架构深度剖析","content":"请深入分析 TiDB 的存储引擎层 TiKV 和 TiFlash 的架构设计，包括 TiKV 的 Raft 复制、Region 调度、MVCC 实现，以及 TiFlash 的列式存储和 Raft Learner 角色。","answer":"答案：TiDB 是 NewSQL 数据库，采用计算与存储分离的架构。TiKV 是其行式存储引擎，基于 RocksDB（LSM-Tree）本地存储，通过 Raft 共识协议实现多副本强一致性。TiFlash 是 TiKV 的列式存储扩展（Raft Learner），异步复制数据后以列式格式存储，专为 OLAP 查询优化。两者在同一个集群中共存，实现 HTAP 能力。\n\n解析：TiKV 的核心设计：1) 数据以 Region 为单位管理（默认 96MB），每个 Region 有多个副本（通常是 3 副本），副本之间通过 Raft 协议同步写入。Region 是数据调度和负载均衡的基本单元。2) PD（Placement Driver）负责全局元数据管理和 Region 调度 —— 自动拆分/合并 Region、在节点间移动 Region 均衡负载、管理 Raft group 的 Leader 分布。3) MVCC 通过 Key 追加时间戳实现（_key_version），读请求使用 snapshot read 在特定时间戳上执行。TiFlash 的处理：作为 Raft Learner 从 TiKV Raft Group 异步复制数据，不参与 Raft 投票，因此不会影响 TiKV 的写入性能。数据以列式格式存储（Delta Tree 引擎），支持向量化计算。\n\n扩展延伸：TiDB 的适用场景：1) 需要 MySQL 兼容性但数据量超出单机（>1TB）的场景 —— 可直接替代 MySQL，分库分表方案不再必要；2) HTAP 场景 —— 一份数据同时支持 OLTP 和 OLAP，TiFlash 处理分析型查询不影响 TiKV 的 TP 负载；3) 弹性扩展 —— 在线扩容/缩容，Region 自动迁移。限制与注意事项：1) 事务冲突严重的场景性能不佳（乐观事务模型有 conflict 回滚开销）；2) 小表（< 1TB）场景下 TiDB 的分布式开销 > MySQL 单机；3) TiFlash 数据同步有秒级延迟，不适合对实时性要求极高的分析场景。","hints":["Region 是 TiKV 数据管理的最小单元，通过 Raft 在多个 TiKV 节点间复制","PD 负责全局调度，决定 Region 分布在哪些节点上","TiFlash 是 Raft Learner，不参与写入投票，异步接收数据"],"tags":["TiDB","TiKV","TiFlash","NewSQL","HTAP"],"id":1481},{"category":"database","difficulty":"hard","type":"short_answer","title":"CockroachDB 架构与分布式事务","content":"请介绍 CockroachDB 的架构设计，包括其 Range 分片机制、Raft 复制、以及基于混合逻辑时钟（HLC）和 Serializable Snapshot Isolation（SSI）的分布式事务实现。","answer":"答案：CockroachDB 是 Google Spanner 思想的开源实现（但不等同），使用 Range（默认 64MB）自动分片数据。每个 Range 有 3 副本（默认），副本间通过 Raft 共识协议保持一致性。Gossip 协议用于节点发现和元数据分布，无需外部协调服务（对比 TiDB 依赖 PD）。分布式事务基于混合逻辑时钟（Hybrid Logical Clock，HLC）实现 Serializable Snapshot Isolation（SSI）。\n\n解析：CockroachDB 的核心机制：1) Range 分裂与合并 —— 当 Range 超过目标大小时自动分裂成两个 Range；当数据被删除导致 Range 过小时自动合并。分裂/合并不影响集群可用性。2) 事务机制 —— 通过 TCO（Transaction Coordinator Orchestrator）协调分布式事务，使用写入意向（Write Intent，类似锁）标记未提交数据。SSI 通过冲突检测和串行化保证 Serializable 隔离级别。写写冲突通过 Read-Committed 重试机制处理（自动回滚和重试）。3) 时钟 —— HLC 结合物理时钟和逻辑计数器，提供全局序而不依赖物理时钟同步精度（相比 Spanner 的 TrueTime 需要原子钟/GPS）。CockroachDB 默认最大时钟偏移为 500ms，通过 Clock Synchronization 检测防止偏离过大。\n\n扩展延伸：CockroachDB vs TiDB：1) 元数据管理 —— CockroachDB 使用 Gossip 协议，TiDB 使用 PD（中心化），两者各有优劣，Gossip 避免了单点但元数据变更收敛慢；2) 事务隔离 —— CockroachDB 默认 Serializable，TiDB 默认 Snapshot Isolation（SI），SI 在并发写入冲突下有 Write Skew 问题；3) 部署复杂度 —— CockroachDB 单二进制部署更简单，TiDB 需要 TiDB Server、PD、TiKV、TiFlash 四个组件；4) 监控成熟度 —— TiDB 的 Dashboard 和 Grafana 开箱即用更丰富；5) 生态兼容 —— TiDB 兼容 MySQL 协议，CockroachDB 兼容 PostgreSQL 协议。","hints":["CockroachDB 使用 Gossip 协议而非中心化元数据服务","HLC 提供线性一致性而不依赖高精度时钟同步","Write Intent 是 CockroachDB 的锁机制且支持死锁检测"],"tags":["CockroachDB","分布式数据库","Raft","NewSQL"],"id":1482},{"category":"database","difficulty":"medium","type":"short_answer","title":"MongoDB 聚合管道（Aggregation Pipeline）详解","content":"请详细说明 MongoDB 聚合管道的设计原理、常用阶段操作符（$match、$group、$project、$lookup、$unwind 等）以及性能优化策略。","answer":"答案：MongoDB 聚合管道（Aggregation Pipeline）是一个数据处理框架，文档依次经过多个阶段（Stage）处理，每个阶段对输入文档执行变换（过滤、分组、投影、关联等），输出结果传递给下一阶段。它基于流式处理模型 —— 阶段之间通过内存或临时文件传递数据，支持大规模文档的批量处理，比 MapReduce 更高效。\n\n解析：常用阶段操作符及作用：1) $match —— 过滤文档，应尽量放在管道前端以减少后续阶段处理量；2) $project —— 投影（保留/排除/重命名字段、添加计算字段）；3) $group —— 按指定键分组聚合（支持 SUM、AVG、MAX、MIN、$push 等累加器）；4) $sort —— 排序，如果在大数据量上排序建议在分组之后做；5) $lookup —— 左外连接（类似 SQL LEFT JOIN），从另一集合关联文档；6) $unwind —— 将数组字段展开为多条文档；7) $bucket —— 分桶聚合（如按年龄分段统计）；8) $facet —— 多维度统计，一次管道输出多个聚合结果；9) $addFields —— 添加计算字段不改变其他字段。\n\n扩展延伸：性能优化：1) 索引利用 —— $match 和 $sort 如果在管道最前面且字段有索引，可以利用索引加速。$lookup 关联的字段（foreignField）应有索引。2) 内存限制 —— 每个阶段默认使用 100MB 内存，超出写入临时文件（allowDiskUse: true 开启允许磁盘）。$group、$bucket、$sort 等有状态阶段消耗内存最多。3) 管道顺序优化 —— 将 $match 和 $limit 尽量前移，尽早减少数据量；4) 避免过大的 $unwind —— 展开大数组会放大数据量数倍，可考虑将 $unwind 后的 $match 合并到前面的阶段；5) 使用 cursor 返回聚合结果而非单个文档（allowDiskUse + batchSize 优化大结果集输出）。","hints":["$match 放在管道最前面能利用索引并尽早减少数据量","$lookup 在 MongoDB 5.1+ 支持关联条件索引自动选择","面向磁盘的聚合使用 allowDiskUse: true 可突破 100MB 内存限制"],"tags":["MongoDB","聚合管道","Aggregation","NoSQL"],"id":1483},{"category":"database","difficulty":"hard","type":"short_answer","title":"HBase Region 分裂与合并机制详解","content":"请详细说明 HBase 的 Region 分裂（Split）和合并（Merge）机制，包括 Split 策略（ConstantSizeRegionSplitPolicy、IncreasingToUpperBoundRegionSplitPolicy、SteppingSplitPolicy）、分裂步骤，以及合并的触发条件和影响。","answer":"答案：HBase 的 Region 是表水平分片的基本单元。当 Region 大小超过阈值时触发 Split（自动分裂为两个子 Region），保证数据分布均匀和查询性能。HBase 提供了多种 Split 策略：1) ConstantSizeRegionSplitPolicy —— Region 大小超过 hbase.hregion.max.filesize（默认 10GB）时分裂；2) IncreasingToUpperBoundRegionSplitPolicy（0.94+ 默认）—— 初始阈值随表 Region 数量增加而提高（min(10GB, 2*R^3 * hbase.hregion.memstore.flush.size)）)；3) SteppingSplitPolicy（2.0+ 默认）—— 改进版，初始分裂阈值较小（256MB * 2），随分裂次数递增到 max.filesize，适合初始数据量小的表。\n\n解析：Region 分裂分为三个步骤：1) 在 Zookeeper 中创建分裂 znode 标记 Region 为分裂中（SPLITTING）；2) 父 Region 停止服务，将 Store 中的数据划分为两个子 Region（通过 split key 确定分界点）。HFile 引用机制 —— 子 Region 通过引用文件指向父 Region 的数据文件，直到 Compaction 时再读取实际数据；3) 将子 Region 上线到 RegionServer，更新 META 表记录。合并（Region Merge）是分裂的逆操作，将相邻的两个 Region 合并成一个，通常在大量数据删除后 Region 过小时触发 —— 可手动触发（merge_region CLI）或通过 RegionMerger 自动执行（hbase.region.merging.enabled 启用）。\n\n扩展延伸：生产实践建议：1) Region 数量管理 —— 单 RegionServer 建议 100-200 个 Region，避免过多 Region 导致 RegionServer 元数据膨胀和内存压力；2) 预分裂（Pre-splitting）—— 创建表时根据 rowkey 分布预分 Region，避免刚创建时所有写入集中在单个 Region 上；3) Split 后的 Compaction 风暴 —— 大量 Region 同时分裂后，子 Region 的引用文件触发多次合并，可能产生写放大，建议错峰建表或调整 split 策略；4) Region Hotspot（热点）—— 单调递增 rowkey 导致所有写入集中在最后一个 Region，可通过反转 rowkey 或加盐（salting）解决。","hints":["HFile 引用机制使 Split 不涉及实际数据移动，速度快","预分裂可以避免初始阶段写入集中在单 Region","单调递增 rowkey 是 Region 热点的最常见原因"],"tags":["HBase","Region","Split","Merge"],"id":1484},{"category":"database","difficulty":"medium","type":"short_answer","title":"Cassandra 分区键与数据分布策略","content":"请介绍 Apache Cassandra 的数据分布机制，包括分区键（Partition Key）和集群键（Clustering Key）的设计原则、分片与复制策略（Partitioners、Replication Strategy）、以及查询优化（二级索引、物化视图、SASI 索引）的最佳实践。","answer":"答案：Cassandra 是分布式 NoSQL 数据库，使用一致性哈希环进行数据分布。每个表必须有主键，主键的第一部分（Partition Key）决定数据存储在哪个节点（通过哈希计算 token），后续列是 Clustering Key 决定同一分区内的排序顺序。查询时必须包含 Partition Key（WHERE 子句中 = 或 IN），否则需要全集群扫描。\n\n解析：数据分布的核心组件：1) Partitioner —— 计算 Partition Key 的哈希值（Murmur3Partitioner，默认）决定数据在环上的位置。Token 范围环上的每个节点负责一段连续的 token 范围。2) Replication Strategy —— SimpleStrategy（单数据中心，测试用）和 NetworkTopologyStrategy（生产用，可指定每个机架的副本数，机架感知）。3) Snitch —— 感知网络拓扑（机架和数据中心），决定副本放置位置（如 Ec2Snitch、GossipingPropertyFileSnitch）。查询优化策略：二级索引适用于低基数（区分度高的列）且返回结果少（< 100 条）的查询；物化视图（Materialized View）自动维护基于不同列排序的视图；SASI 索引（SSTable Attached Secondary Index）支持全文搜索和范围查询。\n\n扩展延伸：Cassandra 数据建模原则：1) 按查询建表 —— 先分析查询模式再设计表结构，不要试图用 JOIN 或子查询（不支持）；2) 避免大分区 —— 单个分区的数据不宜超过 100MB（否则查询和写入性能都会下降）。分区键应选取区分度高的列，避免\"热点分区\"；3) 删除操作 —— Cassandra 的删除是 tombstone 标记（标记删除），Compaction 时真正清理。大量删除导致 tombstone 过多会降低查询性能；4) 内存和磁盘 —— Cassandra 依赖 OS Page Cache，建议 SSD + 大内存配置，调优 heap 大小和 GC 参数。注意 cqlsh 的 tracing 功能可分析查询性能瓶颈。","hints":["Partition Key 的基数（Cardinality）直接决定了数据分布是否均匀","Cassandra 按查询建表，非按关系建模","Tombstone 过多（大量删除）是查询性能下降的常见原因"],"tags":["Cassandra","NoSQL","分区键","一致性哈希"],"id":1485},{"category":"database","difficulty":"medium","type":"short_answer","title":"TiDB 架构","content":"请介绍 TiDB 的 NewSQL 架构。TiDB 如何通过计算存储分离实现水平扩展？TiKV 的 Raft 分区和 Percolator 事务模型如何工作？","answer":"答案：TiDB 是分布式 NewSQL 数据库，兼容 MySQL 协议，支持在线水平扩展和强一致性。\n\nTiDB 三层架构：\n1. TiDB Server（计算层）：\n   - 无状态 SQL 引擎（解析 SQL、生成执行计划、下推计算到 TiKV）\n   - 兼容 MySQL 协议（客户端可像连接 MySQL 一样连接 TiDB）\n   - 水平扩展：增加 TiDB Server 节点提升并发处理能力\n2. TiKV Server（存储层）：\n   - 分布式 KV 存储引擎（基于 RocksDB，LSM-Tree）\n   - 数据按 Range 分为 Region（默认 96MB），每个 Region 有 Leader 和 Follower\n   - Region 通过 Raft 协议复制（强一致性）\n   - 水平扩展：增加 TiKV 节点，Region 自动迁移到新节点\n3. PD Server（调度层）：\n   - 基于 etcd（Raft 一致性），管理 Region 元数据和调度\n   - 调度决策：Leader 均衡、Region 分裂/合并、故障转移\n\nTiKV 的 Raft 分区：\n- 数据分为多个 Region（每个 Region 一个 Raft Group）\n- 每个 Region 有 Leader（读写）+ 多个 Follower（只读+复制）\n- 读走 Leader（强一致），也支持 Follower Read（弱一致）\n- Region 分裂：超过 96MB 时自动分裂为两个 Region\n\nPercolator 事务模型：\n- TiDB 使用 Google Percolator 的分布式事务模型\n- 基于 Primary Key + 时间戳（TSO）的乐观事务\n- 事务流程：\n  1. Prewrite：写入所有 key 的锁和数据（携带时间戳）\n  2. Commit：提交 Primary Key（成功后事务即提交）\n  3. 异步提交（Async Commit / 1PC）优化——减少两阶段提交的开销\n\n扩展延伸：TiDB vs CockroachDB——类似架构但事务模型不同（CRDB 使用混合逻辑时钟 HLC，不依赖 TSO 全局时钟）。TiDB 适合 OLTP + 轻量 OLAP 场景（HTAP）。TiFlash——列存引擎（Raft Learner），用于分析型查询。","hints":["TiDB = TiDB（无状态 SQL 引擎）+ TiKV（Raft + Region 分片）+ PD（元数据调度）","Percolator 事务 = 乐观两阶段提交（Prewrite + Commit），基于 TSO 全局时间戳"],"tags":["数据库","TiDB","NewSQL","分布式事务"],"id":1491},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据分片策略","content":"请介绍数据库数据分片（Sharding）的策略和挑战。范围分片和哈希分片各有什么优缺点？分片后的跨节点查询和分布式事务如何处理？","answer":"答案：数据分片将大表水平切分到多个数据库节点（Shard），解决单机存储和性能瓶颈。\n\n分片策略：\n1. 范围分片（Range Sharding）：\n   - 按分片键的范围分配：Shard 1（id 1-1000000）、Shard 2（id 1000001-2000000）\n   - 优点：范围查询友好（连续范围通常在同一节点），支持分片键的范围扫描\n   - 缺点：数据倾斜（热点——最新数据集中在尾部分片），重新分片时需要移动大量数据\n2. 哈希分片（Hash Sharding）：\n   - 对分片键哈希取模：shard_id = hash(shard_key) % N\n   - 优点：数据分布均匀（无热点），写入负载均衡\n   - 缺点：范围查询需要广播到所有分片，增加分片需要迁移数据（一致性哈希可缓解）\n3. 一致性哈希（Consistent Hashing）：\n   - 哈希环 + 虚拟节点——增加/减少节点时只影响相邻节点\n   - 需要迁移的数据量约为 1/N（N = 节点数）\n   - 适合分片数频繁变化的场景\n\n分片键选择：\n- 选择访问频率最高、分布最均匀的字段（如 user_id、order_id）\n- 避免单调递增的字段（范围分片时产生热点）\n- 考虑业务查询模式——尽量让同一业务的数据在同一分片\n\n分片后的挑战：\n1. 跨节点查询：跨分片的查询需要广播到所有分片 → 聚合结果\n2. 分布式事务：分片后跨越多个节点的事务（2PC/SAGA/TCC）\n3. 全局主键：分片后不能使用数据库自增，需要分布式 ID（Snowflake）\n4. 分片键变更：极难在线变更（需要重新分布数据）\n\n扩展延伸：分片中间件——ShardingSphere（JDBC + Proxy 两种模式，功能丰富）、Vitess（YouTube 开源的 K8s 原生分片方案，支撑 CloudSQL）、MyCat（基于 Proxy 的 MySQL 分片代理）。分片 vs NoSQL——MongoDB 原生分片、Cassandra 的 Partition 设计。","hints":["范围分片（连续/范围查询友好/热点问题）vs 哈希分片（均匀分布/范围查询需广播）","分片挑战：跨节点查询 + 分布式事务 + 全局主键 + 分片键难变更"],"tags":["数据库","分片","Sharding","水平扩展"],"id":1492},{"category":"database","difficulty":"medium","type":"short_answer","title":"SQL 慢查询优化方法论","content":"请介绍 SQL 慢查询的优化方法论。如何通过 EXPLAIN 分析查询性能？常见的慢查询原因和对应的优化手段有哪些？","answer":"答案：SQL 慢查询优化遵循\"先定位、再分析、后优化\"的流程。\n\n定位慢查询：\n- 慢查询日志（slow_query_log）：记录执行时间超过 long_query_time 的 SQL\n- performance_schema：更详细的信息（锁等待、IO、事务等）\n- 实时监控：信息_schema.PROCESSLIST 查看当前正在执行的查询\n\nEXPLAIN 分析（重要字段）：\n- type（访问类型）：system > const > eq_ref > ref > range > index > ALL（全表扫描）\n  - 目标：至少达到 range（范围扫描），最好 ref（等值引用）或 const（主键查询）\n- possible_keys / key：可能使用的索引 / 实际使用的索引\n- rows：预估扫描的行数（越小越好）\n- Extra：Using index（覆盖索引）、Using index condition（索引下推）、Using filesort（文件排序，要优化）、Using temporary（临时表，要优化）\n- key_len：使用的索引长度（越长说明索引覆盖的列越多）\n\n常见原因与优化：\n1. 全表扫描（ALL）：确认查询条件是否有索引，添加合适的索引\n2. 索引失效：\n   - 对索引列使用函数：WHERE UPPER(name) = 'ABC' → 改为 name = 'abc'\n   - 隐式类型转换：WHERE phone = 123（phone 是 varchar）→ 改为 '123'\n   - 最左前缀不满足：索引 (a,b,c) 但查询没有 a\n   - LIKE '%xxx'：以通配符开头会导致索引失效\n3. 排序和分组慢（Using filesort/Using temporary）：\n   - 确保排序列有索引（覆盖索引的列顺序匹配排序顺序）\n   - 分组字段建立索引可以减少临时表\n4. JOIN 慢：确保 JOIN 字段在驱动表和被驱动表上都有索引\n5. 分页慢（深分页 LIMIT 100000, 10）：\n   - 使用游标分页（WHERE id > last_id LIMIT 10）\n   - 或子查询延迟关联（先查出主键再关联原表）\n\n扩展延伸：覆盖索引优化——SELECT 只查索引包含的字段（不回表）。索引选择性（Cardinality）——区分度越高的列越适合建索引。不要对性别/状态这类低区分度列建单列索引（但可以加入联合索引）。MySQL 优化器的选择——即使有索引也可能选择全表扫描（估算扫描行数过大时）。","hints":["EXPLAIN 关键字段：type（const>ref>range>index>ALL）+ Extra（Using filesort/temporary=要优化）","索引失效：函数/隐式转换/最左前缀不满足/LIKE 前置通配符"],"tags":["数据库","慢查询","EXPLAIN","索引优化"],"id":1493},{"category":"database","difficulty":"easy","type":"short_answer","title":"数据库连接池","content":"请介绍数据库连接池（Connection Pool）的原理和配置策略。为什么要使用连接池而不是每次创建新连接？连接池的常用参数（最小连接数/最大连接数/超时时间）如何配置？","answer":"答案：连接池维护一组数据库连接，应用程序重复使用它们，避免频繁创建和销毁连接的开销。\n\n为什么用连接池：\n- 创建连接的开销大：TCP 三次握手 + 数据库认证（几十到几百毫秒）\n- 数据库对连接数有限制（MySQL 默认 max_connections = 151）\n- 连接池复用连接——连接建立一次，后续请求复用已建立的连接\n- 连接池还提供连接管理（超时断开、健康检查、自动恢复）\n\n关键参数配置：\n1. 最小连接数（minimumIdle / minPoolSize）：\n   - 连接池保持的最小空闲连接数\n   - 推荐：根据业务低谷的 QPS 估算，保留少量空闲连接\n   - 太小 = 流量突发时创建连接的延迟\n2. 最大连接数（maximumPoolSize）：\n   - 连接池允许的最大活跃连接数\n   - 不是越大越好！数据库的 CPU/IO 限制了并行度\n   - 经验公式：CPU 核数 × 2 + 有效磁盘数（HDD 1-2，SSD 2-4）\n   - 常见配置：20-50（中等服务器），100-200（高性能服务器）\n   - HikariCP 作者建议：单节点 10-15 个连接已足够高吞吐\n3. 连接超时（connectionTimeout）：\n   - 等待连接的最大时间。超过则抛出异常\n   - 推荐：1000-5000ms（太长导致请求堆积，太短容易误判流量毛刺）\n4. 空闲超时（idleTimeout）：空闲连接的最大存活时间\n5. 最大生命周期（maxLifetime）：连接存活时间上限（建议小于数据库的 wait_timeout）\n\n连接池产品：\n- HikariCP（Java，最推荐）：性能极高，字节码优化，生产验证\n- Druid（Java，阿里）：功能最丰富（监控/SQL 审计/防 SQL 注入/慢查询日志）\n- DBCP/C3P0（Java，旧）：不再推荐（性能差，有坑）\n- SQLAlchemy（Python）：ORM 自带的连接池\n\n扩展延伸：连接泄露——应用中未关闭连接导致连接池耗尽。预防：try-with-resources（Java）/ with 语句（Python）。数据库侧的连接管理——wait_timeout（MySQL 默认 8 小时）。连接池大小与 PSCache（Prepared Statement Cache）的关系——缓存预编译的 SQL 计划，减少 SQL 解析开销，但占用连接池内存。","hints":["连接池复用连接（避免 TCP 握手 + 认证开销），最大连接数不是越大越好","经验：最大连接数 = CPU核数 × 2（SSD），HikariCP 推荐单节点 10-15 连接"],"tags":["数据库","连接池","HikariCP","优化"],"id":1494},{"category":"database","difficulty":"medium","type":"short_answer","title":"查询计划与优化器","content":"请介绍数据库查询优化器（Query Optimizer）的工作原理。优化器如何选择索引？基于成本的优化（CBO）和基于规则的优化（RBO）的区别是什么？","answer":"答案：查询优化器将 SQL 语句转换为最高效的执行计划。\n\n优化器的工作流程：\n1. 解析器：SQL → 抽象语法树（AST）\n2. 预处理器：语义检查（表/列是否存在）、视图展开\n3. 优化器：生成多个执行计划（Join 顺序、索引选择、访问方式），选择成本最低的\n4. 执行器：按照执行计划执行\n\nRBO（基于规则的优化）：\n- 使用固定的规则进行优化（如\"WHERE 条件优先执行\"、\"子查询展开\"）\n- 规则是硬编码的经验法则\n- 优点：实现简单，执行计划可控\n- 缺点：不根据实际数据量调整，选择的计划不一定最优\n- 早期数据库（如 Oracle RBO）使用\n\nCBO（基于成本的优化）：\n- 根据统计信息估算每种执行计划的成本（IO + CPU + 网络）\n- 统计信息：表的行数、列的基数（Cardinality）、数据分布直方图\n- 优化器计算每种计划的成本，选择成本最低的\n- 缺点：统计信息过时时，优化器可能选择次优计划\n\nMySQL 的优化器：\n- 默认使用 CBO（MySQL 5.6+）\n- 通过 ANALYZE TABLE 更新统计信息\n- 使用 FORCE INDEX / USE INDEX / IGNORE INDEX 提示影响优化器选择\n- 优化器会考虑：全表扫描（ALL）、索引扫描（index/range/ref）、索引合并（Index Merge）、MRR（Multi-Range Read）\n\n扩展延伸：执行计划的查看——EXPLAIN（计划）+ EXPLAIN ANALYZE（MySQL 8.0，执行并输出实际耗时和行数）。优化器的局限——复杂的 JOIN 查询中，JOIN 顺序的选择是指数级的（N!），优化器通常使用启发式算法（贪心/动态规划）剪枝。统计信息的维护——自动更新 vs 手动更新，采样率设置。","hints":["RBO = 规则硬编码（实现简单，不根据数据量调整）→ CBO = 基于统计信息估算成本（IO+CPU+网络）","MySQL 使用 CBO，统计信息过时会导致优化器选错索引"],"tags":["数据库","优化器","CBO","执行计划"],"id":1495},{"category":"database","difficulty":"hard","type":"short_answer","title":"数据库分片（Sharding）与分区（Partitioning）设计对比","content":"数据库分片（Sharding）和分区（Partitioning）都是将数据拆分的技术。它们的核心区别是什么？在架构设计中如何选择？两者可以共存吗？","answer":"答案：分区（Partitioning）是在同一数据库实例内将表物理拆分为多个文件（对应用透明），分片（Sharding）是将数据分布到多个独立数据库实例（应用需感知路由规则）。分区解决单表过大问题，分片解决单机容量和性能上限问题。\n\n解析：核心区别——1）分区：MySQL 分区表或 PostgreSQL 表继承/分区表，数据仍然在同一数据库实例中，只是底层存储文件分开（如按时间分区的历史数据归档）。对应用完全透明，不需要修改 SQL。分区能改善查询性能（分区裁剪）和管理便利（删除分区比 DELETE 快）。但分区不能突破单机资源限制（CPU、内存、磁盘 IO 共享）。2）分片：数据分布到多台机器，每台机器有独立的计算和存储资源。需要分片中间件（ShardingSphere/MyCAT）或应用层路由。分片可以线性扩展（加机器 = 加性能），但带来分布式事务、跨分片查询、数据迁移等复杂问题。\n\n扩展延伸：3）两者共存——可以。先分区再分片：每个分片上的表使用分区表。如订单表按用户 ID 分片到 16 个库，每个库内的订单表按月分区。这样既实现了水平扩展又便于历史数据管理。4）选择原则——单表超千万行且查询通过索引能优化 -> 分区（更简单）。单表超亿行或总数据量超单机承载 -> 分片（必须突破单机限制）。5）替代方案——在考虑分片之前，先尝试：索引优化 + 读写分离 + 缓存 + 分区表 + 冷热分离。如果这些都无法满足，再考虑分片。","hints":["分区和分片最本质的区别在于是否跨数据库实例","为什么分区不能替代分片来解决单机瓶颈"],"tags":["数据库","分片","分区","架构设计"],"id":1506},{"category":"database","difficulty":"hard","type":"short_answer","title":"InnoDB 缓冲池（Buffer Pool）管理与 LRU 优化","content":"InnoDB 的缓冲池（Buffer Pool）是如何管理的？InnoDB 对传统 LRU 算法做了哪些优化来防止缓冲池被污染（Buffer Pool Pollution）？如何监控 Buffer Pool 的健康状态？","answer":"答案：InnoDB Buffer Pool 是 InnoDB 在内存中缓存数据页和索引页的区域（默认 128MB，通常设为物理内存的 60-80%）。InnoDB 使用改进的 LRU 算法——将 LRU 链表分为年轻代（New Sublist，约 5/8）和老年代（Old Sublist，约 3/8），新读取的页先插入 Old Sublist 的 midpoint，避免一次全表扫描将热点数据全部挤出。\n\n解析：Buffer Pool 管理机制——1）LRU 链表分为两部分：New Sublist（5/8）存储热点数据页，Old Sublist（3/8）存储冷数据页。新读取的页插入到 Old Sublist 的头部，只有在 Old Sublist 中存活超过 innodb_old_blocks_time（默认 1000ms）且被再次访问时才移到 New Sublist。2）这种改进解决了缓冲池污染问题——全表扫描或索引扫描一次性读取大量页，如果不做分代，这些只读一次的冷数据会把真正的热点数据全部挤出 Buffer Pool。\n\n扩展延伸：3）Buffer Pool 配置——innodb_buffer_pool_size：建议设为物理内存的 60-80%（MySQL 8.0 可在线调整）。innodb_buffer_pool_instances：将 Buffer Pool 拆分为多个实例减少锁竞争。innodb_old_blocks_time：冷数据在 Old Sublist 的存活时间。4）监控——SHOW ENGINE INNODB STATUS 的 BUFFER POOL AND MEMORY 部分：Buffer pool hit rate（命中率，>99% 为健康）、Free buffers（空闲页数）。5）Buffer Pool 预热——MySQL 5.7+ 支持 SHUTDOWN 时将 Buffer Pool 状态保存到磁盘（innodb_buffer_pool_dump_at_shutdown=ON），启动时加载（innodb_buffer_pool_load_at_startup=ON），避免重启后命中率从 0% 开始爬坡。","hints":["InnoDB 的 LRU 为什么分为 young 和 old 两个 sublist","innodb_old_blocks_time 参数对 SSD 和 HDD 场景的不同影响"],"tags":["MySQL","InnoDB","Buffer Pool","LRU"],"id":1507},{"category":"database","difficulty":"medium","type":"short_answer","title":"数据库连接池容量计算公式与最佳实践","content":"数据库连接池的容量（最大连接数）应该如何计算？连接池大小的确定公式是什么？连接数过多或过少分别有什么影响？","answer":"答案：连接池最大连接数没有万能公式，但有一个广泛引用的经验起点：maximumPoolSize = Tn × (C - 1) + 1，其中 Tn = CPU 核心数，C = 单个连接处理的并发请求数。更简化的公式：核心数 × 2 + 磁盘数。核心原则：连接池大小应以数据库能有效处理的并行请求数为上限。\n\n解析：1）理论推导——连接池的本质是复用 TCP 连接。假设单个数据库连接的处理能力是 C 个请求/秒，CPU 核心数为 Tn，则数据库能处理的 TPS 上限 ≈ Tn × C。当连接数超过 Tn × C 时，增加连接只会增加上下文切换而不增加吞吐。2）实践经验——OLTP 场景（短查询，每次 1-5ms）：4 核机器建议 8-16 个连接，8 核机器建议 16-32 个连接。N 个应用实例 × 每个实例的连接池大小不应超过数据库 max_connections。3）过大的影响——CPU 上下文切换加剧，锁竞争增加（InnoDB 的行锁/间隙锁），数据库内存消耗增加（每个连接约 2-5MB），TPS 反而下降（拐点效应）。\n\n扩展延伸：4）HikariCP 的设计哲学——作者认为连接池不是越大越好，10 个连接通常比 100 个连接更快（因为避免了大量上下文切换）。5）不同负载类型的调整——OLTP（短事务）：池小（10-20）。批处理（长事务）：池可适度增大（50-100），单连接处理一条长 SQL。混合负载：拆分数据源，OLTP 用小池，分析类用大池。6）监控指标——活跃连接数（active）、等待线程数（pending）、连接获取超时次数（timeout）。active 持续接近 maximumPoolSize 且 pending > 0 说明连接池不够或 SQL 需要优化。","hints":["为什么连接池最大连接数不应该超过 CPU 核心数的 2-3 倍","如何通过监控指标判断连接池是否过小"],"tags":["数据库","连接池","容量规划","HikariCP"],"id":1508},{"category":"database","difficulty":"medium","type":"short_answer","title":"覆盖索引与仅索引扫描（Index-Only Scan）对比","content":"覆盖索引（Covering Index）和仅索引扫描（Index-Only Scan）在 MySQL 和 PostgreSQL 中的实现有何不同？什么是 PostgreSQL 中的 Visibility Map？为什么 MySQL 的覆盖索引不需要 Visibility Map？","answer":"答案：覆盖索引指查询所需的所有列都包含在索引中，无需回表（MySQL 的 Extra=Using index）。PostgreSQL 的 Index-Only Scan 类似但需要 Visibility Map 辅助来判断可见性——因为 PostgreSQL 的 MVCC 将死元组保留在数据页中，索引项可能指向不可见的元组，需要通过 Visibility Map 跳过不可见行。MySQL InnoDB 的二级索引只包含主键，通过 MVCC 的 Undo Log 判断可见性，不存在此问题。\n\n解析：MySQL 覆盖索引——InnoDB 的二级索引叶子节点包含索引列值 + 主键值。如果查询所需的列全部在索引中（SELECT 和 WHERE 列都是索引的一部分），则无需回表访问聚簇索引。Extra=Using index 表示使用了覆盖索引。条件是索引必须包含所有 SELECT 列和 WHERE 列（即索引覆盖了查询）。\n\nPostgreSQL Index-Only Scan——PG 的索引不包含 TID（Tuple ID）之外的可见性信息。如果索引项指向的元组已经更新（新元组可能在不同页面），需要回表检查可见性。PG 通过 Visibility Map（每个数据页的可见性位图）来加速——如果数据页的全部元组对当前所有事务都可见，则直接从索引返回，不需要回表。Visibility Map 由 VACUUM 维护。\n\n扩展延伸：3）性能对比——MySQL 的覆盖索引本质上是在索引中「冗余」存储数据列，索引体积可能更大但免去了回表 IO。PG 的 Index-Only Scan 无需冗余存储，但依赖 VACUUM 及时更新 Visibility Map。4）设计策略——MySQL：将高频查询的列加入索引以形成覆盖索引。PG：通过 VACUUM 及时清理死元组，保持 Visibility Map 的有效性。5）适用场景——MySQL 覆盖索引适合查询列集相对固定的场景。PG 的 Index-Only Scan 适合数据更新不频繁、VACUUM 及时的场景（频繁更新导致 Visibility Map 有效性下降）。","hints":["PostgreSQL 为什么需要 Visibility Map 来实现 Index-Only Scan","MySQL 的覆盖索引和 PostgreSQL 的 Index-Only Scan 在索引设计上有何不同"],"tags":["覆盖索引","Index-Only Scan","MySQL","PostgreSQL"],"id":1509},{"category":"database","difficulty":"hard","type":"short_answer","title":"快照隔离（Snapshot Isolation）与可串行化隔离级别实现","content":"快照隔离（Snapshot Isolation）是数据库多版本并发控制的一种实现。它和可串行化（Serializable）隔离级别有什么区别？为什么快照隔离不保证可串行化？写偏斜（Write Skew）问题是什么？","answer":"答案：快照隔离（SI）保证事务读取的是事务开始时刻的一致性快照（解决了脏读、不可重复读、幻读），但不保证可串行化。SI 可能出现写偏斜（Write Skew）问题——两个并发事务读取同一组数据但更新不同子集时，各自基于旧快照做决策，导致违反业务约束。可串行化隔离级别（如 PostgreSQL 的 Serializable Snapshot Isolation, SSI）通过检测读写冲突避免写偏斜。\n\n解析：1）快照隔离的保证——事务读取的是提交时的一致性快照。写操作采用 First-Committer-Wins 规则：两个并发事务写同一行时，先提交者成功，后提交者回滚。SI 被许多数据库作为默认或高级隔离级别使用（Oracle 的默认 RC 实际上是一种 SI，PostgreSQL 的 RC 和 RR 都基于 SI）。\n\n2）写偏斜（Write Skew）——经典例子：医生值班系统，要求至少有一位医生值班。事务 A：检查值班医生数 >= 2 后更新自己「不值」。事务 B：检查值班医生数 >= 2 后更新自己「不值」。两个事务基于相同的快照看到值班医生数为 2，都认为自己可以离开，各自更新自己的状态。结果：值班医生从 2 变成 0，违反业务规则。这个场景在 Serializable 级别下会被阻止（因为 SSI 检测到了读写冲突并回滚其中一个事务）。\n\n扩展延伸：3）PostgreSQL SSI（Serializable Snapshot Isolation, PG 9.1+）——在 SI 基础上增加读写冲突检测（SIREAD 锁），通过等待图异常检测来判断是否存在写偏斜风险。检测到潜在的可串行化冲突时回滚一个事务让另一个成功。4）MySQL Serializable——通过将所有 SELECT 隐式转换为 SELECT ... FOR SHARE（共享锁），完全使用锁机制而非 SI。可串行化但并发性能远低于 SSI。5）其他 SI 变体——Microsoft SQL Server 的 SNAPSHOT 隔离级别是 SI（需要单独启用 ALLOW_SNAPSHOT_ISOLATION）。MySQL InnoDB 的 REPEATABLE READ 也是基于 SI（同时使用 Next-Key Lock 减少了幻读和部分写偏斜）。","hints":["写偏斜（Write Skew）与脏写（Dirty Write）有什么区别","PostgreSQL 的 SSI 如何在不使用全表锁的情况下检测写偏斜"],"tags":["快照隔离","可串行化","写偏斜","SSI","PostgreSQL"],"id":1510},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 死锁分析与全局锁排查","content":"线上 MySQL 发生死锁时，如何快速定位死锁根因？InnoDB 的全局锁（LOCK TABLES 和 MDL）导致的死锁与行级死锁有什么不同？如何从应用层面系统性地预防死锁？","answer":"答案：SHOW ENGINE INNODB STATUS 查看 LATEST DETECTED DEADLOCK；全局锁死锁通常涉及表锁或元数据锁（MDL），行级死锁涉及记录锁和间隙锁。\n\n解析：排查步骤：1）执行 SHOW ENGINE INNODB STATUS\\G 找到 LATEST DETECTED DEADLOCK 段，查看事务 1 和事务 2 的 SQL、等待的锁（WAITING FOR THIS LOCK TO BE GRANTED）和当前持有的锁（HOLDS THE LOCK）。2）ROW LEVEL DEADLOCK 常见于两个事务加锁顺序相反，或二级索引与聚簇索引加锁顺序差异。3）MDL（元数据锁）死锁——ALTER TABLE 等待 DDL，DDL 被正在执行查询的事务阻塞。排查：performance_schema.metadata_locks 表看 MDL 等待链。\n\n扩展延伸：系统性预防策略：1）确保所有事务按相同的顺序访问表和行。2）保持事务短小（快速提交/回滚），减少锁持有时间。3）对高并发更新的表使用 READ COMMITTED 级别（无 Gap Lock 减少冲突）。4）合理设计索引——避免大范围锁扫描。5）SQL 语句使用明确的 ORDER BY 保证加锁顺序一致。6）设置 innodb_lock_wait_timeout（默认 50s）避免无限等待，设置较短的超时（如 5s）快速失败重试。7）兜底：应用层重试机制（捕获 DeadlockException 后 sleep 随机时间重试）。","hints":["SHOW ENGINE INNODB STATUS 中如何解读 LOCK WAIT 和 DEADLOCK 信息","MDL 死锁在什么场景下最容易出现——DDL 与长查询并发"],"tags":["MySQL","死锁","MDL","行锁","排查"],"id":1521},{"category":"database","difficulty":"medium","type":"choice","title":"联合索引最左前缀与 Skip Scan","content":"表 t 上有联合索引 (a, b, c)，以下哪个查询能最充分利用该索引的三列进行索引扫描？","options":["A) WHERE b = 1 AND c = 2","B) WHERE a = 1 AND c = 2","C) WHERE a = 1 AND b = 2 AND c = 3","D) WHERE a > 1 AND b = 2"],"answer":"答案：C)。解析：最左前缀原则要求从索引最左列开始匹配且不能跳过中间列。C) 完全匹配三列，三列都走索引（ref 访问）。A) 没有 a 列，索引完全失效（除非 MySQL 8.0 Skip Scan 能优化）。B) 跳过了 b 列，a 列用索引但 c 列无法直接利用（可能通过 ICP 下推过滤）。D) a > 1 是范围查询，a 范围扫描后 b 列无法利用排序（range 之后所有列失效）。注意：MySQL 8.0.13+ 的 Skip Scan 优化可以在特定条件下跳过最左列直接使用非首列——条件是优化器判断 a 列不同值较少且 b 列过滤性好。","hints":["范围查询（>, <, BETWEEN）后的索引列为什么失效——B+ 树的有序性被破坏","MySQL 8.0 Skip Scan 在什么条件下才能触发——a 列 distinct 值少 + b 列过滤性好"],"tags":["MySQL","索引","最左前缀","Skip Scan","ICP"],"id":1522},{"category":"database","difficulty":"hard","type":"fill_in_blank","title":"MySQL WAL 两阶段提交步骤","content":"MySQL 两阶段提交确保 redo log 和 binlog 一致：第一阶段 InnoDB 将 redo log 写入磁盘并标记为___状态。第二阶段 Server 层将 binlog 写入磁盘后，InnoDB 将 redo log 标记为___状态。如果在 prepare 完成后写入 binlog 前发生崩溃，___机制会回滚该事务；如果 binlog 已写完但 redo log 尚未标记完成时崩溃，重启后会自动___该事务。","answer":"{\"correct\": [[\"prepare\", \"准备\"], [\"commit\", \"提交\"], [\"崩溃恢复\", \"crash recovery\"], [\"提交\", \"commit\"]], \"distractors\": [\"undo\", \"rollback\", \"checkpoint\", \"purge\"]}","hints":["为什么必须先写 redo log 再写 binlog——崩溃恢复时以 binlog 为准","崩溃恢复时如果 redo log 处于 prepare 且 binlog 完整，事务应该提交还是回滚"],"tags":["MySQL","WAL","两阶段提交","崩溃恢复","redo log"],"id":1523},{"category":"database","difficulty":"medium","type":"short_answer","title":"MySQL JOIN 算法演进与优化","content":"MySQL 执行 JOIN 查询时有哪几种连接算法？各自在什么场景下被优化器选择？如何通过索引设计和参数调优优化 JOIN 性能？","answer":"答案：三种算法：Nested Loop Join（有索引）、Block Nested Loop Join（无索引、MySQL 5.6+）、Hash Join（等值连接、MySQL 8.0.18+）。\n\n解析：1）Nested Loop Join（NLJ）——驱动表遍历每条记录，在被驱动表上用索引查找匹配，复杂度 O(N × logM)。最优方案但要求被驱动表有有效索引。2）Block Nested Loop Join（BNL）——驱动表一批记录（join_buffer_size 控制）缓存到 join buffer，一次批量匹配被驱动表全表扫描，减少 IO 次数。无索引时的次优方案。3）Hash Join——驱动表构建哈希表（内存），被驱动表逐条探测。等值 JOIN、两表均无索引时性能最好（比 BNL 快很多）。\n\n扩展延伸：优化策略：1）被驱动表 JOIN 列加索引——让优化器选择 NLJ 而非 BNL，这是最重要的优化。2）调整 join_buffer_size（默认 256KB）——BNL 时一次缓存更多驱动表记录，减少被驱动表扫描次数。但不要设过大（全局共享，过大浪费内存）。3）小表驱动大表——驱动表越小，被驱动表的索引查找次数越少。4）EXPLAIN 中 Extra 出现「Using join buffer (Block Nested Loop)」就是优化信号——需要检查被驱动表索引。","hints":["为什么被驱动表加索引对 JOIN 性能影响最大——NLJ 将全表扫描变为索引查找","Hash Join 为什么只适用于等值连接——哈希探测需要精确匹配"],"tags":["MySQL","JOIN","NLJ","Hash Join","优化"],"id":1524},{"category":"database","difficulty":"hard","type":"true_false","title":"MySQL 临时表的存储位置","content":"MySQL 在执行包含 DISTINCT、GROUP BY 或 UNION 的查询时，如果发现无法使用索引完成操作，会在 Extra 中显示「Using temporary」。这些临时表一定创建在磁盘上，会触发大量磁盘 IO 导致查询变慢。","options":["A) 正确","B) 错误"],"answer":"B","hints":["MySQL 临时表优先使用 MEMORY 引擎存放在内存中","tmp_table_size 和 max_heap_table_size 参数控制了内存临时表的最大大小"],"tags":["MySQL","临时表","Using temporary","MEMORY引擎"],"id":1525},{"category":"database","difficulty":"hard","type":"short_answer","title":"MySQL 子查询优化：半连接与物化策略","content":"MySQL 优化器如何处理 IN 和 EXISTS 子查询？什么是半连接（Semi-join）和物化（Materialization）？","answer":"答案：MySQL 优化器对 IN/EXISTS 子查询有多种优化策略。半连接（Semi-join）将子查询转换为类似 JOIN 的形式（但只返回外表匹配的行，每个内表行只匹配一次），物化（Materialization）将子查询的结果集先物化为临时表再进行 JOIN。\n\n解析：半连接优化（MySQL 5.6+）：1）Duplicate Weedout——通过临时表消除子查询结果的重复值，外表 JOIN 内表结果集，确保外表行只返回一次。2）First Match——对每个外表行，一旦在内表中找到第一个匹配就停止扫描并返回该外表行。3）Loose Scan——利用索引跳过重复的匹配值。4）Materialization-Lookup——将子查询结果物化为临时表，建索引后用外表行去探测。\n\n扩展延伸：Semi-join 不生效的情况：子查询中使用了 GROUP BY/LIMIT/聚合函数，或子查询过于复杂时优化器退化为 EXISTS 执行方式。NOT IN/NOT EXISTS 与 Anti-join——MySQL 5.6+ 对 NOT IN/NOT EXISTS 也有反连接（Anti-join）优化。判断是半连接还是物化：EXPLAIN 中 select_type 出现 MATERIALIZED（子查询物化）或 DEPENDENT SUBQUERY（依赖子查询，逐行执行，性能差）。SUBQUERY（非依赖子查询，执行一次）。生产实战：IN (SELECT id FROM t2) 在 t2 表数据量小时优先用半连接，数据量大时物化更优。如果子查询表有索引优先用 Semi-join，否则物化可能更好。","hints":["EXPLAIN 中 MATERIALIZED、DEPENDENT SUBQUERY、SUBQUERY 的区别","为什么 NOT IN 比 NOT EXISTS 更容易产生性能问题"],"tags":["MySQL","子查询","优化器","半连接"],"id":1526},{"category":"database","difficulty":"medium","type":"fill_in_blank","title":"MySQL 主从复制的三种模式","content":"MySQL 主从复制有三种模式：___（主库提交后立即返回，不等待从库确认），___（至少一个从库写入 relay log 后主库才返回），以及___（基于 Paxos 协议的多主写入模式）。","answer":"{\"correct\":[[\"异步复制\"],[\"半同步复制\"],[\"组复制（MGR）\"]],\"distractors\":[[\"同步复制\",\"全同步复制\"],[\"全同步复制\",\"强同步复制\"],[\"Galera Cluster\",\"InnoDB Cluster\",\"NDB Cluster\"]]}","hints":["半同步复制在超时后会退化为什么模式","MGR 与半同步复制的核心差异是什么"],"tags":["MySQL","主从复制","高可用"],"id":1527},{"category":"database","difficulty":"medium","type":"true_false","title":"MySQL 派生表合并优化","content":"MySQL 优化器可以将派生表（Derived Table）合并到外层查询中，避免物化派生表。但在派生表中包含 LIMIT、ORDER BY 或聚合函数时，优化器无法合并派生表。","options":["正确","错误"],"answer":"答案：正确\n\n解析：派生表合并（Derived Table Merging）是 MySQL 5.7+ 引入的优化，优化器将 FROM 子句中的子查询（派生表）合并到外层查询中，直接访问基表的索引，避免创建和扫描临时表。但以下场景中派生表无法合并：派生表使用 LIMIT（限制行数后语义可能改变）、派生表使用 ORDER BY（外层查询的排序需求可能不同）、派生表包含聚合函数（GROUP BY/MIN/MAX/SUM 等，合并后外层 GROUP BY 可能影响内层结果）、派生表是 UNION 的结果集、派生表使用了聚合函数或 DISTINCT。\n\n扩展延伸：无法合并时，MySQL 5.6+ 会派生表物化（Materialization），将派生表结果写入临时表，再进行外层查询。如果派生表的数据量不大，派生表合并的效果显著（省去了临时表的创建和销毁）。开发者可通过优化派生表的使用来提升性能：尽量将过滤条件下推到派生表内部（WHERE 条件越早过滤越好），避免在派生表中使用 LIMIT/ORDER BY 导致无法合并。EXPLAIN 中 select_type 为 DERIVED 表示派生表被物化。MySQL 8.0.14+ 进一步支持 Lateral Derived Table（LATERAL 关键字），允许派生表引用前面表的值。","hints":["为什么 LIMIT 会导致派生表无法合并","EXPLAIN 中 DERIVED 表示什么"],"tags":["MySQL","派生表","优化器"],"id":1528},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 7.0 新特性与功能增强","content":"Redis 7.0 引入了哪些重大新特性？对现有功能做了哪些改进？","answer":"答案：Redis 7.0（2022 年发布）是 Redis 史上最大的版本之一，引入和改进了多项核心功能：AOF 增强（Multi-Part AOF）、函数（Redis Functions）、集群改进（Sharded Pub/Sub、ACL V2、集群链路优化）、内存效率提升（listpack 全面替代 ziplist）、自动 AOF 重写等。\n\n解析：1）Multi-Part AOF——将单个 AOF 文件拆分为 Base（基础 RDB 格式）+ Incremental（增量日志）+ Manifest（清单文件）三部分。解决了 AOF 重写期间的磁盘双倍占用问题，提高了 AOF 重写的稳定性。2）Redis Functions——替代 EVAL/EVALSHA，将 Lua 脚本作为一等公民管理。支持函数库（Library）、命名空间、版本管理，可以在服务端预加载管理，减少客户端传输脚本的带宽开销。3）Sharded Pub/Sub——在 Redis Cluster 中，Pub/Sub 消息不再广播到所有节点，而是限制在 hash slot 范围内（SSUBSCRIBE/SPUBLISH），解决了 Cluster 模式下 Pub/Sub 广播的带宽浪费问题。\n\n扩展延伸：4）Listpack 全面替代 Ziplist——Redis 7.0 用 listpack 替代了 ziplist 的所有使用场景（Hash Listpack、ZSet Listpack、List Quicklist 节点）。listpack 的每个元素记录自身长度而不是前一个元素的长度，解决了 ziplist 的连锁更新问题。5）ACL V2——支持 key-based 权限通配符（~* 和 %* 分别控制读写模式）。6）集群改进——Cluster 集群支持节点间更高效的故障检测（Faster Failure Detection）、集群迁移更少的阻塞时间。7）ROLE 命令增强、INFO 命令改进、内存报告更精确。需要注意的是：Redis 7.2 和 7.4 已发布，7.0 是重要的功能里程碑版本，标志着 Redis 在函数式管理和集群可扩展性上的大幅提升。","hints":["Multi-Part AOF 如何解决 AOF 重写的磁盘双倍占用","Redis Functions 相比 EVAL/EVALSHA 的优势"],"tags":["Redis","7.0","新特性"],"id":1529},{"category":"database","difficulty":"medium","type":"choice","title":"Redis SCAN 命令与 KEYS 的区别","content":"关于 Redis 的 SCAN 命令和 KEYS 命令，以下说法正确的是？","options":["A) SCAN 和 KEYS 都会阻塞 Redis 主线程，性能相同","B) SCAN 是阻塞命令，但每次只返回部分结果，减少阻塞时间","C) SCAN 是非阻塞命令，通过游标分批遍历，每次返回有限数量的 key，不会长时间阻塞 Redis","D) KEYS 命令在 Redis 6.0 后已经被废弃，应始终使用 SCAN"],"answer":"答案：C) SCAN 是非阻塞命令，通过游标分批遍历，每次返回有限数量的 key，不会长时间阻塞 Redis\n\n解析：KEYS * 命令是 O(N) 操作，在 Redis 单线程模型下执行时阻塞所有其他操作（包括读写请求），如果 key 数量很大（数百万个），可能阻塞数秒到数十秒。SCAN 命令通过游标（cursor）机制分批遍历，每次返回 COUNT 个（默认 10）key，遍历之间可以穿插执行其他命令。每次 SCAN 的时间复杂度约为 O(1)（返回一小批），整体遍历完仍然是 O(N) 但分摊到多次调用。\n\n扩展延伸：SCAN 命令的特点：1）每次返回的 key 数量不保证精确等于 COUNT（可能多可能少）。2）遍历过程中新增或删除的 key 不一定被返回（不提供完整一致性）。3）遍历过程中 key 可能被返回多次（客户端需要去重）。4）同一 Session 中 SCAN 的 cursor 有效，但长间隔可能导致 cursor 失效。5）SCAN 同样支持 SSCAN（Set）、HSCAN（Hash）、ZSCAN（ZSet）等类型特定的遍历。生产最佳实践：永远不要在生产环境使用 KEYS * 命令。使用 SCAN + COUNT 控制每次扫描量（建议 COUNT 100-1000），在低峰期执行。\n\n","hints":["为什么 KEYS * 命令在高 QPS 场景下特别危险","SCAN 命令的游标机制如何避免阻塞"],"tags":["Redis","SCAN","KEYS","性能"],"id":1530},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 主从复制原理","content":"Redis 主从复制是如何工作的？psync2 和部分重同步的原理是什么？","answer":"答案：Redis 主从复制通过 PSYNC 命令实现，支持完整重同步和部分重同步（psync2）。全量同步时主节点 fork 子进程做 RDB 快照 + 增量缓冲；部分同步通过 replication ID 和 offset 在 backlog 中追回增量数据。\n\n解析：1）完整重同步——从节点向主节点发送 PSYNC ? -1（首次），主节点执行 BGSAVE 生成 RDB，同时将后续写命令缓冲到 replication backlog。RDB 传完后继续发送缓冲的写命令。2）部分重同步（psync2，Redis 4.0+）——从节点断线重连后发送上次的 replication ID 和 offset，主节点检查 offset 是否仍在 backlog 内（由 repl-backlog-size 决定，默认 1MB），如果在则发增量数据，不在则触发全量同步。3）心跳机制——主节点每 10s ping 从节点检测存活。\n\n扩展延伸：Redis 7.0+ 支持 diskless replication（无盘复制），主节点直接将 RDB 通过 socket 发送给从节点，减少磁盘 IO。全量同步的代价：fork 子进程可能阻塞主进程（数据量大时几十毫秒到秒级），RDB 传输占用网络带宽。建议：主节点配置禁用持久化以提高性能，从节点开启持久化；repl-backlog-size 根据网络断连频率调整（如 64MB-512MB）。","hints":["PSYNC 中 replication ID 和 offset 的作用是什么","全量同步时主节点 fork 子进程会有哪些影响"],"tags":["Redis","主从复制","高可用"],"id":4057},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 哨兵模式","content":"Redis Sentinel（哨兵）是如何实现高可用的？主节点宕机后故障转移的过程是什么？","answer":"答案：Sentinel 是一个独立进程，负责监控 Redis 节点状态、自动故障转移和通知客户端。当主节点宕机时，Sentinel 先判定主观下线（SDOWN）→ 达到 quorum 后判定客观下线（ODOWN）→ 选举 leader → 选新主节点 → 切换。\n\n解析：1）SDOWN（Subjective Down）——单个 Sentinel 检测到节点在一定时间内（down-after-milliseconds，默认 30s）没有响应 PING。2）ODOWN（Objective Down）——多个 Sentinel 都确认 SDOWN，达到 quorum（如 3 个 Sentinel 设 quorum=2）后判定 ODOWN。3）Leader 选举——Sentinel leader 通过 Raft 类算法选主（需要 N/2+1 投票），leader 负责执行故障转移。4）新主节点选择——优先选择 repl-priority 最小的从节点，然后选 replication offset 最大的（数据最新），最后选 runID 最小的（启动最早的）。5）故障转移——leader Sentinel 向新主节点发送 SLAVEOF NO ONE，其他从节点 SLAVEOF 新主节点，旧主恢复后降级为从节点。\n\n扩展延伸：Sentinel 客户端需要订阅 + channel（+switch-master）或定期 get-master-addr-by-name 获取最新主节点地址。Sentinel 集群最少部署 3 个实例（奇数，避免 split-brain 时无法选主）。生产建议：Sentinel 和 Redis 节点分开部署，避免同时宕机。","hints":["SDOWN 和 ODOWN 的区别是什么","为什么 Sentinel 集群建议部署奇数个节点"],"tags":["Redis","哨兵","高可用","Sentinel"],"id":4058},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Cluster 集群原理","content":"Redis Cluster 的数据分片和节点通信机制是什么？MOVED 和 ASK 重定向有什么区别？","answer":"答案：Redis Cluster 将数据分为 16384 个哈希槽（hash slot），每个节点负责一部分槽位。节点间通过 Gossip 协议通信。客户端访问时若槽位不在本节点，节点返回 MOVED/ASK 重定向给客户端。\n\n解析：1）哈希槽分配——计算 HASH_SLOT = CRC16(key) % 16384，将 key 映射到 0-16383 的槽位。支持 hash tag 机制：key 中 {…} 部分参与哈希，保证一批 key 落到同一节点，支持多 key 操作。2）MOVED 重定向——槽位已永久分配给其他节点时返回 MOVED ${slot} ${ip}:${port}，客户端直接跳转到新节点并刷新本地路由缓存。3）ASK 重定向——槽位正在迁移（迁移过程中）返回 ASK ${slot} ${ip}:${port}，客户端先向目标节点发 ASKING 命令再执行操作，仅单次生效（不刷新路由缓存）。4）Gossip 协议——节点间通过 PING/PONG 交换状态信息（包括其他节点的状态，称为 Gossip gossip），端口为 redis-port + 10000。\n\n扩展延伸：Cluster 限制：1）不支持多 key 操作（除非 key 在相同槽，通过 hash tag 实现）。2）事务操作涉及多 key 时也要求在同一节点。3）客户端需支持 Cluster 协议（如 JedisCluster、Lettuce）。集群规模建议：3 主 3 从起步（至少 3 主），节点数受 Gossip 通信量限制（官方建议 < 1000 节点）。节点扩容时需要 re-shard（slot 迁移），数据迁移过程中对客户端透明（通过 ASK 重定向）。","hints":["为什么 Redis Cluster 固定使用 16384 个槽而不是更多","hash tag 如何保证相关 key 落到同一节点"],"tags":["Redis","Cluster","分片","哈希槽"],"id":4059},{"category":"database","difficulty":"medium","type":"short_answer","title":"缓存一致性：Cache Aside 模式","content":"什么是 Cache Aside Pattern？先更新数据库还是先删除缓存？如何保证缓存和数据库的一致性？","answer":"答案：Cache Aside Pattern 是当前最常用的缓存策略：读时先查缓存（miss 则读 DB 再回写缓存），写时先写 DB 再删除缓存。删除缓存是最小化一致性风险的方案。\n\n解析：为什么先写 DB 再删缓存而不是先删缓存再写 DB？如果先删缓存再写 DB，期间有并发读请求会直接读 DB（因缓存已删）并将旧数据回写到缓存，导致缓存与 DB 不一致。先写 DB 再删缓存的风险：写 DB 完成后还没删缓存时，旧缓存被其他线程读到。删除缓存比更新缓存好的原因：更新缓存存在竞争条件——A 写 DB 后缓存更新为 A 的值，B 写 DB 后缓存更新为 B 的值，但可能先 B 后 A（网络延迟导致 A 的更新请求晚于 B 到达），导致缓存最终是旧值。\n\n扩展延伸：Cache Aside 仍有短暂的窗口不一致（写 DB 到删缓存之间）。更高一致性方案：1）延迟双删——先删缓存 → 写 DB → sleep N ms → 再删缓存。N 取经验值 500-1000ms（取决于读请求的响应时间）。2）Canal（阿里开源）——订阅 MySQL binlog，变更时异步删除或更新缓存。3）读写锁——写操作加写锁阻塞并发读，保证强一致但降低性能。生产建议：绝大多数业务接受最终一致性，Cache Aside + 延迟双删 + TTL 兜底已足够。","hints":["为什么更新缓存比删除缓存更容易出问题","延迟双删中 sleep 的时间如何确定"],"tags":["Redis","缓存","一致性","Cache Aside"],"id":4060},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 事务机制","content":"Redis 的事务机制（MULTI/EXEC）是如何工作的？它与关系型数据库事务的本质区别是什么？","answer":"答案：Redis 事务通过 MULTI 开启，后续命令加入队列，EXEC 时批量原子执行。但 Redis 事务**不支持回滚**（没有 rollback），且是隔离单线程执行而非 ACID。\n\n解析：执行流程：1）MULTI——开启事务。2）命令入队——后续命令不立即执行，而是排入队列返回 QUEUED。3）EXEC——按顺序执行队列中的命令，保证不被其他命令中断。特点：整个事务是原子执行的（单线程保证无并发插入），但部分失败不回滚。WATCH 命令——乐观锁实现 CAS：WATCH key 后如果 key 在事务执行前被其他客户端修改，EXEC 返回 nil（事务放弃）。\n\n扩展延伸：对比关系型数据库事务：1）隔离性——Redis 单线程执行，天然可串行化（Serializable），没有脏读/不可重复读/幻读。2）持久性——Redis 事务不保证持久性（取决于 AOF 配置，always 模式才保证）。3）回滚——Redis 不支持回滚。如果命令入队时语法错误，所有命令被丢弃；如果 EXEC 后运行时错误（如对 string 做 LPUSH），正确命令不受影响。设计哲学：Redis 的设计者认为事务回滚是数据库层的复杂功能，Redis 保持简单——开发者应确保命令正确，错误在应用层处理。","hints":["WATCH 如何实现乐观锁（CAS）","Redis 事务中语法错误和运行时错误的处理有什么不同"],"tags":["Redis","事务","MULTI","WATCH"],"id":4061},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis Pipeline 批量操作","content":"Redis Pipeline 是什么？它和事务的主要区别是什么？适用什么场景？","answer":"答案：Pipeline 将多条命令一次性批量发送到服务器，减少网络往返时间（RTT）。它与事务的本质区别：Pipeline 不保证原子性，只是批量网络传输优化。\n\n解析：单条命令的网络 RTT 在本地网络约 0.1-1ms，远程网络 10-50ms。如果用 Pipeline 将 100 条命令一次发送，RTT 从 100ms 降到 0.1-1ms。Pipeline 的工作方式：客户端将多个命令缓冲到队列（不等待每个响应），一次性 flush 到服务器，服务器依次执行并将响应全部返回。\n\n扩展延伸：Pipeline vs 事务：Pipeline 只是网络层面的优化，命令被服务器逐个执行，期间可能有其他客户端的命令插入。MULTI/EXEC 保证执行期间的原子性（中间不会有其他命令插入）。两者可以结合使用：在 Pipeline 中发送 MULTI → 命令 → EXEC，既获得网络批量传输的效率又获得原子执行保证。注意：Pipeline 缓冲的命令过多会导致客户端内存占用过大（需要缓存所有响应直到读取），建议控制每批 1000-5000 条命令。Pipeline 在 Redis Cluster 中使用时需要注意 key 的 hash tag 分配。","hints":["Pipeline 缓冲的命令过多会产生什么问题","Pipeline 和 MULTI/EXEC 能否一起使用"],"tags":["Redis","Pipeline","批量操作","RTT"],"id":4062},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Lua 脚本","content":"Redis 中 Lua 脚本（EVAL）的工作原理是什么？它在批量操作的原子性上有什么优势？","answer":"答案：Lua 脚本在 Redis 服务端原子执行，脚本中的多条命令作为一个整体执行，中间不插入任何其他命令。通过 EVAL/EVALSHA 调用，脚本被缓存到服务器。\n\n解析：1）EVAL——直接传入脚本内容，如 EVAL 'return redis.call(\"SET\", KEYS[1], ARGV[1])' 1 foo bar。KEYS[1] 和 ARGV[1] 用于传入 key 和参数，规范要求显式传入 key 列表（Cluster 模式下校验 key 是否在同一节点）。2）EVALSHA——通过 SHA1 指纹调用已缓存的脚本，避免重复传输脚本内容。SCRIPT LOAD 预加载脚本，SCRIPT FLUSH 清空缓存。3）原子性——Lua 脚本中的命令与其他客户端的命令绝对隔离（Redis 单线程执行 Lua）。相比事务的优势：脚本中可以包含逻辑控制（if/else、循环等），而事务只能按固定顺序执行。\n\n扩展延伸：脚本超时处理：默认 lua-time-limit 5000ms，超时后 Redis 记录脚本到慢查询日志并开始接受 other commands 的请求（但不会执行），允许 SCRIPT KILL。如果脚本已经执行了写命令则只能 SHUTDOWN NOSAVE 强制终止。实践：分布式锁的 Redisson Watch Dog 续期、秒杀库存扣减、限流器令牌桶的复杂操作——都是用 Lua 脚本保证原子性。注意：Lua 脚本中应避免毫秒级耗时操作（如 TIME、大集合遍历），避免阻塞 Redis。","hints":["EVALSHA 比 EVAL 好在哪","Lua 脚本超时后为什么可能只能 SHUTDOWN NOSAVE"],"tags":["Redis","Lua","原子性","EVAL"],"id":4063},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 底层数据结构详解","content":"Redis 五种数据类型的底层实现分别是什么？SDS、quicklist、listpack、dict、intset、skiplist 各自的特点是什么？","answer":"答案：String 底层用 SDS（Simple Dynamic String）；List 用 quicklist（双向链表节点 + listpack）；Hash 用 dict（字典）或 listpack；Set 用 intset（整数集合）或 dict；Zset 用 skiplist + dict 或 listpack。\n\n解析：1）SDS——头部分别存储 len（已用长度）和 alloc（总容量），通过预分配和惰性空间释放避免重复内存操作。相比 C 字符串：O(1) 获取长度、二进制安全（不依赖 null 终止符）、自动扩容。Redis 7.0 有五类 SDS：sdshdr5/8/16/32/64（flags 字段区分）。2）quicklist（Redis 3.2+）——双向链表，每个节点使用 listpack（Redis 7.0+ 替换了原来的 ziplist）存储数据，平衡了内存紧凑和读写性能。3）listpack——连续内存块，每个元素带 encoding + data + length，无需像 ziplist 那样在遍历时更新 prevlen，解决连锁更新问题。4）dict——散列表，使用渐进式 rehash（ht[0] + ht[1] 双表），rehashidx 标记迁移进度。5）intset——有序的整数数组，支持 INT16/32/64 自动升级。6）skiplist——多层链表，层高随机（幂律分布），Redis 7.0 最大层数 64（之前是 32）。\n\n扩展延伸：切换阈值：Hash 的 field 数少于 512 且 value 小于 64 字节时用 listpack，否则用 dict。Zset 元素少于 128 且元素大小小于 64 字节时用 listpack，否则用 skiplist + dict。注意：ziplist 在 Redis 7.0 中被 listpack 全面取代。","hints":["为什么 listpack 解决了 ziplist 的连锁更新问题","SDS 的预分配策略如何减少内存重分配次数"],"tags":["Redis","数据结构","SDS","listpack","skiplist"],"id":4064},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis big key 治理","content":"什么是 Redis big key？它有什么危害？如何发现和处理 big key？","answer":"答案：Big key 指单个 key 包含大量数据（如大 String 超过 10MB，或集合类型元素超过 5000 个）。危害包括阻塞命令、网络带宽拥塞、集群数据倾斜。发现使用 redis-cli --bigkeys 或 memory usage 命令。\n\n解析：危害：1）阻塞——对大集合执行 DEL/EXPIRE 等操作会阻塞 Redis（O(n) 复杂度），大量数据在一次响应中传输也阻塞网络。2）网络——每次操作 big key 都要传输大量数据，增加网络延迟和带宽。3）数据倾斜——Cluster 场景下 big key 所在节点负载远高于其他节点。\n\n发现方法：1）redis-cli --bigkeys（scan 逐个类型统计，生产安全）。2）命令 memory usage key（Redis 4.0+，返回 key 的精确内存占用）。3）通过 MONITOR 或慢查询日志定位访问量大且数据传输量大的 key。\n\n扩展延伸：处理方案：1）大 String——拆分为多个小 key：原本存 user:123 一个字段拆为 user:123:profile user:123:orders。2）大 Hash——用 hscan + hdel 分批清除无用字段。3）大 List——用 ltrim 裁剪。4）大 Set/Zset——用 sscan/zscan + srem/zrem 分批，或用 sunlink（异步删除，Redis 4.0+）替代 del——UNLINK 命令在后台线程回收内存，主线程 O(1) 立即返回。5）提前预防——控制集合大小分裂，设置合理过期时间。","hints":["redis-cli --bigkeys 为什么是生产安全的","UNLINK 和 DEL 删除大 key 的区别是什么"],"tags":["Redis","big key","性能","阻塞"],"id":4065},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis hot key 治理","content":"什么是 Redis hot key？如何发现热点 key？有哪些治理方案？","answer":"答案：Hot key 指某个 key 的访问量远超平均值，导致该 key 所在的 Redis 节点成为瓶颈，集群中其他节点空闲。发现方法包括客户端统计、代理层统计、Redis 监测命令。治理主要靠本地缓存、副本分摊、热点拆分。\n\n解析：发现方法：1）客户端统计——在 Jedis/Lettuce 拦截层对 key 访问计数。2）代理层——如果使用 Twemproxy/Codis/Redis Cluster proxy，可以在代理层统计。3）Redis 4.0+ 开启 LFU 淘汰策略后，用 OBJECT FREQ key 查看访问频率。4）redis-cli --hotkeys（Redis 4.0+，需启用 LFU）。不推荐生产环境使用 MONITOR 命令找 hot key（性能开销极大）。\n\n扩展延伸：治理方案：1）本地缓存——在服务层（Caffeine/Guava Cache）缓存热点 key，减少对 Redis 的访问。这是最简单有效的方案。2）副本分摊——Redis 4.0+ 支持从节点处理读请求（readonly），将热点 key 的读压力分散到多个从节点。注意从节点数据可能延迟。3）拆散 Hot key——将一个 key 拆为 N 个 key：hotkey_1, hotkey_2, …, hotkey_N（如 hash tag 打散 + 轮询读取），将访问分散到不同节点。4）限流——在网关层对热点 key 请求限流，保护后端 Redis。5）读写分离——让一部分读流量走从节点（Redis Cluster 从节点可处理读）。","hints":["为什么不能在生产环境用 MONITOR 命令找 hot key","本地缓存缓解 hot key 的核心风险是什么"],"tags":["Redis","hot key","热点","性能"],"id":4066},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 内存淘汰策略","content":"Redis 的 8 种内存淘汰策略分别是什么？如何选择？LRU 和 LFU 的区别是什么？","answer":"答案：8 种策略分为 2 大类：不淘汰（noeviction）和可淘汰。可淘汰中分为：作用于所有 key（allkeys-lru/allkeys-lfu/allkeys-random）和仅限设置了过期时间的 key（volatile-lru/volatile-lfu/volatile-random/volatile-ttl）。\n\n解析：1）noeviction（默认）——内存满时写入操作返回 OOM 错误。2）allkeys-lru——淘汰最近最少使用的 key（推荐，多数业务场景最佳选择）。3）allkeys-lfu（Redis 4.0+）——淘汰使用频率最低的 key。4）allkeys-random——随机淘汰。5）volatile-lru——从设置了过期时间的 key 中淘汰最近最少使用的。6）volatile-lfu——从设置了过期时间的 key 中淘汰使用频率最低的。7）volatile-random——从设置了过期时间的 key 中随机淘汰。8）volatile-ttl——淘汰剩余存活时间最短的 key。\n\n扩展延伸：LRU 与 LFU 的区别：LRU（Least Recently Used）按最近访问时间淘汰，问题是一键批量读取旧数据可能把原本高频的缓存数据挤掉（缓存污染）。LFU（Least Frequently Used）按访问频率淘汰，维护每个 key 的访问计数器（counter，有限的频度老化避免长期高频压制新热点）。LFU 的 counter 是一个 8 位的概率计数器（Morris counter，用概率递增），最大值 255。Redis 的近似 LRU：不是精确 LRU，因为精确 LRU 需要维护全量链表，内存开销大。Redis 采样池（pool）方式——从所有 key 中随机取 samples（默认 maxmemory-samples=5），淘汰其中最旧的。sample 数越大越接近精确 LRU。选择建议：通用缓存 → allkeys-lru；有明显冷热区分且热 key 变化少 → allkeys-lfu；需要兼顾 TTL 策略 → volatile-ttl；业务明确不需要淘汰 → noeviction + 监控告警。","hints":["LRU 的缓存污染问题是什么","LFU 的 counter 为什么用 Morris 计数器而不是整数"],"tags":["Redis","淘汰策略","LRU","LFU"],"id":4067},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redisson 看门狗 Watch Dog","content":"Redisson 分布式锁的 Watch Dog（看门狗）机制是什么？锁自动续期是如何实现的？","answer":"答案：Watch Dog 是 Redisson 在获取分布式锁后启动的后台线程，在锁接近过期时自动续期，防止业务未完成而锁提前释放。默认锁超时 30s，每 10s 续期一次。\n\n解析：Redisson 的 RLock 使用 Lua 脚本加锁（SET key uuid NX PX 30000），加锁成功后客户端启动一个后台定时任务：每 leaseTime/3（默认 10s）执行一次 Lua 脚本检查锁是否还存在，如果存在则重置过期时间为 30s。如果 Redisson 客户端宕机或关机，Watch Dog 线程不再续期，锁在 30s 后自动释放。\n\n扩展延伸：使用 Watch Dog 时业务代码不需关心锁过期：如果业务执行时间超过锁过期时间，Watch Dog 自动续期；如果业务代码异常退出，Watch Dog 随线程死亡不再续期，锁自动释放。自定义超时：lock(10, TimeUnit.SECONDS) 手动指定租约时间（此时不启动 Watch Dog，到期自动释放）。tryLock 带等待时间：tryLock(waitTime, leaseTime, unit) 控制获取锁的等待时间和锁持有时间。注意：Watch Dog 只对 Redisson 的 RLock 生效（基于 SET NX + Lua 续期），不是 Redis SETNX 原生的功能。生产建议：如果业务执行时间非常稳定且可预估，手动设置 leaseTime 避免 Watch Dog 开销；如果执行时间有波动，使用 Watch Dog 自动续期更安全。","hints":["Watch Dog 为什么每 10 秒续期一次而不是更频繁","锁自动续期和手动指定租约时间应如何选择"],"tags":["Redis","分布式锁","Redisson","Watch Dog"],"id":4068},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 发布订阅与 Stream","content":"Redis 的 PUB/SUB 和 Stream（5.0+）有什么区别？Stream 的消费者组（Consumer Group）机制是如何工作的？","answer":"答案：PUB/SUB 是即时消息广播（fire-and-forget），消息不持久化、没有 ACK 机制、离线客户端丢失消息。Stream 是持久化消息队列，支持消费组、ACK、消息回溯，类似 Kafka 在 Redis 中的实现。\n\n解析：PUB/SUB 的缺陷：1）消息不持久，publisher 发送后 subscriber 不在线则消息丢失。2）没有 ACK 确认机制。3）每个订阅者收到相同消息（广播模型，与 Kafka 消费组不同）。4）不支持消息回溯。适用：实时性要求高但允许丢失的场景（如 Sentinel 的状态变更通知）、系统内部信号通信。Redis Stream（5.0+，借鉴 Kafka）：每个 Stream 是一个仅追加的消息链表，每条消息有唯一 ID（时间戳 + 序列号）。支持 XADD 添加、XREAD 读取（支持阻塞读）、XRANGE 范围查询。\n\n扩展延伸：Stream 的 Consumer Group：通过 XGROUP CREATE 创建消费组，同一消费组内的消费者分摊消息（类似 Kafka 消费组），每条消息只能被组内一个消费者消费。机制：1）每个消费组有 last_delivered_id（类似 Kafka 的 offset），新消费者从该位置开始消费。2）消息用 XREADGROUP 读取后变为 pending 状态，消费者需用 XACK 确认。3）未确认的消息会一直 pending，通过 XPENDING 查看，用 XCLAIM 转移给其他消费者处理（类似 Kafka 的重平衡）。Redis 7.0+ 新增 XAUTOCLAIM 自动处理超时的 pending 消息。注意：Stream 将数据存在内存，消息堆积（大量待消费消息会占用 RAM），不像 Kafka 用磁盘持久化。适用建议：轻量级消息队列、任务队列、临时数据流处理。非轻量的 MQ 场景还是用 Kafka/RocketMQ。","hints":["Stream 和 Kafka 在消息堆积能力上有什么本质区别","Stream 消费组的 pending 列表中 XCLAIM 的用途是什么"],"tags":["Redis","Stream","PUB/SUB","消息队列"],"id":4069},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 内存优化与碎片管理","content":"Redis 内存碎片是如何产生的？如何查看和管理内存碎片？jemalloc 在 Redis 中的作用是什么？","answer":"答案：内存碎片是对象频繁创建和删除、key 大小变化导致的内存分配间隙。Redis 使用 jemalloc 内存分配器减少碎片，并通过 info memory 查看内存碎片率。碎片率过高（>1.5）时启用 active defrag 自动整理。\n\n解析：1）碎片产生原因——Redis 创建/删除对象、key 增长/过期淘汰、不同大小 key 混合存储导致 jemalloc 分配的内存块无法被后续新分配完全利用。2）查看指标——info memory 中的 used_memory_rss（物理内存占用）和 used_memory（逻辑占用），计算 mem_fragmentation_ratio = used_memory_rss / used_memory。碎片率 > 1.5 表示碎片较多（即 RSS 远大于逻辑占用），< 1 表示使用了 swap（危险信号）。3）jemalloc——Redis 默认使用 jemalloc 分配器（编译时指定，而不是 glibc 的 malloc），对多线程场景优化好，通过固定 size class 和 slab 分配减少小对象碎片。\n\n扩展延伸：active defrag（Redis 4.0+ 实验性，5.0+ 生产可用）：配置 activedefrag yes，Redis 在后台进程中做碎片整理（复制对象到新的连续内存区域后释放旧内存）。参数：active-defrag-ignore-bytes 100MB（碎片超过此值时触发）、active-defrag-threshold-lower 10（碎片率超过 10% 时触发）。注意：active defrag 会占用 CPU 资源，在线业务繁忙时可能影响性能。如果碎片率很高，可以考虑重启（主从切换、RDB 重加载后内存会重新连续排列）、升级 jemalloc 版本、合理规划 key 大小分布。","hints":["mem_fragmentation_ratio < 1 意味着什么","Redis 重启后为什么碎片率会显著下降"],"tags":["Redis","内存","碎片","jemalloc"],"id":4070},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 生产配置架构原则","content":"Redis 生产环境部署需要考虑哪些方面？做配置选型时应遵循什么原则？","answer":"答案：Redis 生产配置的核心原则是「根据业务场景做权衡」，主要考虑内存规划、持久化策略、高可用设计和安全基线，而非照搬参数清单。\n\n解析：1）内存规划——设置 maxmemory 预留 20-30% 余量给碎片和复制缓冲，结合业务访问特征选择淘汰策略（通用场景 allkeys-lru，有明显冷热区分选 allkeys-lfu）。2）持久化选型——权衡性能和数据安全：RDB（快照，适合缓存场景允许丢部分数据）、AOF everysec（每秒 fsync，适合数据敏感场景）、混合持久化（Redis 4.0+，兼顾重启速度和数据安全）。核心原则：允许丢数据 → 只用 RDB 或关持久化；不允许丢 → AOF + RDB 混合。3）高可用设计——主从 + Sentinel（自动故障转移）或 Cluster（自动分片），避免单点。Sentinel 至少 3 节点奇数部署。Cluster 至少 3 主 3 从起步。\n\n扩展延伸：监控和运维：1）关键指标监控——内存碎片率（mem_fragmentation_ratio > 1.5 需关注，< 1 说明用了 swap 危险）、命中率、慢查询、复制延迟。2）安全基线——requirepass、绑定内网 IP、rename-command 禁用作弊命令。3）OS 层面关注点——禁用透明大页（THP 可能导致 fork 延迟抖动）、合理配置 vm.overcommit、设置 swappiness 避免 swap。这些是操作系统常规优化，并非 Redis 特有的参数背诵。4）容器化注意——Redis fork 子进程在 CPU 受限的 K8s Pod 中耗时可能大幅增加，建议持久化由从节点承担。\n\n核心原则：先明确业务对数据安全、可用性、性能的要求，再做配置决策。没有通用的最佳配置，只有适合业务场景的配置。","hints":["Redis 内存碎片率过高时应如何处理","持久化选型时 RDB 和 AOF 应该如何权衡"],"tags":["Redis","配置","生产","调优"],"id":4071},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 6/7 多线程 I/O 模型","content":"Redis 6/7 引入了多线程 I/O，它优化了什么？Redis 的主线程和 I/O 线程各司什么职责？为什么 Redis 没有完全变成多线程？","answer":"答案：Redis 6 引入多线程处理网络 I/O（读写请求/响应数据），但命令执行仍然是单线程。多线程 I/O 解决了网络吞吐瓶颈——大量并发连接时单线程读取/写入 socket 的 CPU 开销过大。Redis 7 进一步优化了子线程效率和延迟稳定性。核心设计仍然是「多线程 I/O + 单线程命令执行」。\n\n解析：Redis 6 多线程 I/O 的工作方式：1）主线程负责 accept 新连接、分发读任务到 I/O 线程池。2）I/O 线程从 socket 中读取请求数据并解析。3）主线程等待所有 I/O 线程完成读后，单线程串行执行命令。4）执行完成后，主线程将响应数据分发给 I/O 线程写入 socket。I/O 线程数默认 3（读+写各 3），通过 io-threads 和 io-threads-do-reads 配置控制。\n\n扩展延伸：为什么 Redis 不改成全多线程？1）单线程模型是 Redis 高性能的核心基石——避免锁竞争、上下文切换和复杂的并发控制（Lua 脚本、事务、WATCH 的原子性都依赖单线程）。2）Redis 的瓶颈很少在 CPU——绝大多数场景下都是网络 I/O 和内存带宽受限。3）引入多线程执行命令会破坏现有数据结构的线程安全性，需要大量重构且收益不确定。Redis 6 的多线程 I/O 优化了「受限于网络带宽」而非「受限于 CPU」的场景——1Gbps+ 网络下，单线程处理网络 I/O 会成为瓶颈，多线程 I/O 显著提升吞吐。","hints":["Redis 6 的多线程 I/O 为什么不解锁命令执行也变多线程","io-threads-do-reads 配置对性能有什么影响"],"tags":["Redis","多线程","I/O","性能"],"id":4072},{"category":"database","difficulty":"medium","type":"short_answer","title":"RESP 协议","content":"Redis 序列化协议（RESP）是什么？RESP3（Redis 6+）相比 RESP2 有哪些改进？RESP 协议对 Redis 性能有什么影响？","answer":"答案：RESP（Redis Serialization Protocol）是 Redis 服务端和客户端之间通信的文本协议，将命令参数和结果编码为特定前缀的字符串。Redis 6 引入 RESP3 协议，新增了丰富的返回类型。\n\n解析：RESP 数据类型都用前缀标识：+ 简单字符串、- 错误、: 整数、$ 批量字符串（$5\\r\\nhello\\r\\n）、* 数组（*3\\r\\n...）。RESP 的设计原则是简单性和解析速度——前缀标识了类型和长度，解析器可以快速跳过不需要的数据。\n\nRESP2 vs RESP3：RESP2 只有 5 种类型（简单字符串、错误、整数、批量字符串、数组）。RESP3 新增加了 Map（有序映射）、Set（集合）、Bool（布尔值）、Double（浮点数）、Big Number（大数）、Null（空值）、Streamed types（流式类型）等 8 种新的数据类型。RESP3 的核心优势：客户端不再需要猜测服务端返回的数据是什么类型——Map 类型直接表示哈希结构，不需要解析为扁平数组。这大大简化和改进了客户端库的实现。\n\n扩展延伸：RESP 协议的性能考量：1）文本协议 vs 二进制协议——RESP 是文本协议，但效率并不低（没有 XML/JSON 的冗余）。大部分数据包很小（短 key 和整数），文本开销可忽略。2）Pipelining——RESP 天然支持管道传输（客户端不等待响应直接发送多个命令）。3）RESP3 支持服务器端推送（Push 类型），使客户端可以接收 Pub/Sub 消息、客户端断连通知等异步消息，无需轮询。4）RESP3 的流式类型支持从服务器获取大量数据（如一个大集合）时以流式传输，减少客户端内存压力。","hints":["RESP 协议为什么选择文本形式而不是二进制","RESP3 的 Push 类型对客户端实现有什么影响"],"tags":["Redis","RESP","协议","RESP3"],"id":4073},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 慢查询日志","content":"Redis 的慢查询日志（SLOWLOG）是如何工作的？如何通过慢查询日志定位性能问题？配置参数有哪些？","answer":"答案：Redis 的 SLOWLOG 记录执行时间超过指定阈值（slowlog-log-slower-than，单位微秒）的命令。日志保存在内存中，通过 SLOWLOG GET 查看。\n\n解析：配置参数：1）slowlog-log-slower-than——命令执行时间阈值，单位微秒（默认 10000，即 10ms）。设置为负值关闭慢查询日志，0 记录所有命令。2）slowlog-max-len——内存中保留的慢查询最大条数（默认 128）。超出时最早的记录被丢弃。与 MySQL 不同，Redis 的慢查询日志保存在内存（固定大小的队列），不会写文件，对性能影响极小。查看命令：SLOWLOG GET [count]——查看最近 N 条慢查询记录，每条包含：唯一 ID、时间戳、执行耗时（微秒）、命令及参数、客户端地址/端口。SLOWLOG LEN——查看当前慢查询数量。SLOWLOG RESET——清空慢查询日志。\n\n扩展延伸：通过慢查询定位问题的方法：1）慢查询日志显示执行时间长——首先检查命令的时间复杂度（O(N) 的 KEYS、SMEMBERS、HGETALL、LRANGE 可能在大集合上出问题）。2）排查 big key——慢查询中大量出现对大 key 的操作（DEL 大 key 也会阻塞）。3）排查慢查询对应的客户端——慢查询会记录客户端信息。4）注意 Redis 是单线程——一个慢查询会阻塞后续所有命令。如果观察到 QPS 下降，通常是有慢查询导致。优化建议：将 SLOWLOG 阈值设置为 1000-2000 微秒（1-2ms），这样可以看到对正常业务有实际影响的慢命令。避免使用 O(N) 命令，使用 SCAN 替代 KEYS、SSCAN 替代 SMEMBERS、HSCAN 替代 HGETALL。","hints":["Redis 的慢查询日志为什么不写磁盘而是存在内存","慢查询日志发现的大 key 怎么处理"],"tags":["Redis","慢查询","SLOWLOG","性能"],"id":4074},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 备份恢复策略","content":"Redis 的备份和恢复策略有哪些？RDB 和 AOF 的备份恢复场景各有什么不同？如何做异地容灾备份？","answer":"答案：Redis 的备份分为 RDB 备份（定时快照）和 AOF 备份（追加日志）。恢复时优先使用 AOF（数据更完整）。异地容灾通过主从复制、RDB 远程传输或云厂商跨地域复制实现。\n\n解析：RDB 备份——定期执行 BGSAVE 生成 .rdb 文件，Redis 4.0+ 可配置周期性自动触发（save 900 1 等）。备份方式：将 .rdb 文件 rsync/scp 到远程存储或云存储（S3/OSS）。RDB 适合全量备份和快速恢复，但可能丢失最后一次快照后的数据。AOF 备份——AOF 文件记录所有写操作，通过 rewrite（BGREWRITEAOF）控制文件大小。备份方式：定期复制 AOF 文件到远程存储。AOF 备份更安全（可设置 appendfsync everysec，最多丢 1 秒数据）。\n\n扩展延伸：恢复流程：1）将 RDB/AOF 文件放到 Redis 工作目录（dir 配置）。2）重启 Redis，自动加载 AOF 或 RDB（优先加载 AOF，如果没有 AOF 则加载 RDB）。3）验证数据完整性——用 redis-check-rdb 和 redis-check-aof 工具检查文件。异地容灾方案：1）主从复制跨机房——主节点在一个数据中心，从节点在其他数据中心。注意跨机房延迟。2）RDB 远程备份脚本——crontab 定期执行 BGSAVE，然后将 .rdb 用 rsync 同步到异地机器。3）云原生方案——AWS ElastiCache 跨区域复制（Global Datastore）、阿里云 Redis 跨地域复制。4）Sentinel/Cluster 的跨 AZ 部署——异常时切换到其他可用区。注意：AOF 也依赖 appendfsync 策略（always/everysec/no）。always 最安全但写入性能大幅下降（每次写入都 fsync）。生产建议：RDB + AOF 混合持久化 + AOF everysec + 定时异地 RDB 备份。","hints":["恢复时 Redis 为什么优先加载 AOF 而不是 RDB","Redis 异地容灾跨机房同步延迟问题如何解决"],"tags":["Redis","备份","恢复","容灾"],"id":4075},{"category":"database","difficulty":"easy","type":"short_answer","title":"redis-benchmark 性能压测","content":"redis-benchmark 是做什么的？如何使用它测试 Redis 性能？测试结果中的关键指标怎么解读？","answer":"答案：redis-benchmark 是 Redis 自带的性能基准测试工具，模拟指定数量的并发客户端发送命令，统计每秒完成的请求数（TPS/QPS）和响应延迟。\n\n解析：基本用法：redis-benchmark -h 127.0.0.1 -p 6379 -c 50 -n 10000。参数说明：-c 并发客户端数（默认 50）、-n 总请求数（默认 100000）、-d 数据大小（字节，默认 3）、-t 指定测试的命令（如 -t set,get,lpush）、-P 启用 Pipeline（管道批处理数量）。默认测试：依次测试 PING、SET、GET、INCR、LPUSH、RPUSH、LPOP、RPOP、SADD、SPOP、LPUSH（列表）、MSET（批量）等命令。\n\n扩展延伸：解读结果：每条命令输出类似 SET: 93545.23 requests per second——表示 1 秒内完成了约 9.3 万次 SET 操作。影响测试结果的因素：1）网络延迟——localhost 测试排除网络因素。2）CPU 频率和内存带宽——Redis 是 CPU 和内存敏感型。3）数据大小（-d 参数）——数据越大带宽消耗越大。4）Pipeline 批处理——Pipelining 可以大幅提升 TPS（减少 RTT）。高级测试技巧：1）redis-benchmark -c 20 -n 100000 -P 10——测试 Pipeline 10 批量时的性能。2）redis-benchmark -t set,get -q——仅输出简洁结果（requests per second）。3）对比不同参数：分别测试 -c 10/50/200/1000 观察并发与吞吐的变化曲线。4）注意——redis-benchmark 不模拟真实业务场景（真实场景各命令比例不同，数据大小分布不同）。真实压测建议用自己编写的压测脚本（如 wrk + Lua 脚本、go 压测工具）。","hints":["redis-benchmark 和真实流量压测的区别是什么","Pipeline 测试中 -P 参数对 TPS 的典型影响"],"tags":["Redis","性能","压测","benchmark"],"id":4076},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 持久化原理深入","content":"请详细解释 Redis RDB 和 AOF 持久化的底层实现机制。RDB 的 fork 时机会对主进程产生什么影响？","answer":"答案：RDB 通过 fork 子进程生成全量快照，AOF 通过追加日志记录每一条写命令。RDB 的 fork 时机由 save 配置和手动 BGSAVE 决定，fork 时主进程阻塞（耗时与内存量正相关）。\n\n解析：RDB 执行流程：主进程 fork → 子进程将内存数据写入临时 RDB 文件 → 写入完成后原子替换旧 RDB 文件。fork 采用写时复制（COW）——子进程共享父进程内存页，只有当父进程修改了某个内存页时才复制该页。fork 本身的耗时：Redis 实例 10GB 时 fork 约 300ms-1s（取决于服务器性能）。AOF 的三种 appendfsync 模式：1）always——每次写入都 fsync，最安全（最多丢 1 条命令）但性能最差（约数百 TPS）。2）everysec（默认）——每秒 fsync 一次，性能好（可维持 10 万+ TPS），最多丢 1 秒数据。3）no——由操作系统决定何时将缓冲区数据刷到磁盘（可能丢 30s+ 数据）。\n\n扩展延伸：混合持久化（Redis 4.0+，aof-use-rdb-preamble yes）：AOF 重写时先写 RDB 格式的全量数据，再追加增量 AOF 日志。恢复时先加载 RDB 快照再回放 AOF 增量——既快（RDB 恢复比纯 AOF 快数倍）又安全（AOF 保证增量不丢）。持久化对主进程的影响：RDB 的 fork 阻塞主进程，大实例（> 20GB）在低配机器上 fork 可能导致秒级卡顿；AOF 的 fsync 在磁盘压力大时可能阻塞主线程（Redis 的 fsync 由后台线程执行，但如果后台线程跟不上写入速度，主线程会被阻塞）。","hints":["RDB fork 时写时复制（COW）具体如何工作的","为什么 AOF 的 everysec 模式推荐用于生产"],"tags":["Redis","持久化","RDB","AOF","fork"],"id":4077},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis ACL 与安全配置","content":"Redis 6 引入的 ACL（访问控制列表）是什么？如何配置用户权限？","answer":"答案：ACL（Access Control List）是 Redis 6 引入的细粒度权限控制机制，允许为不同用户分配不同的命令权限和键空间访问范围。替代了传统的 requirepass 单一密码模式。\n\n解析：ACL 的核心命令：1）ACL LIST——查看所有用户及其权限。2）ACL SETUSER username on >password ~cached:* +@read -DEL——创建一个用户，设置密码，限制键空间（~cached:*），允许所有读命令（+@read）但禁止 DEL 命令（-DEL）。3）ACL CAT——查看所有命令分类（@read/@write/@admin/@dangerous 等）。4）ACL LOG——查看 ACL 拒绝日志（定位为什么某些用户的操作被拒绝）。默认用户（default）保留完全权限，用于向后兼容。\n\n扩展延伸：ACL 规则格式：1）身份验证——>password 设置密码（可设置多个），<password 移除密码。2）命令权限——+command 允许命令，-command 禁止，+@category 允许整个类别。3）键空间——~pattern 限制可访问的 key 模式（如 ~user:* 只允许操作 user: 前缀的 key）。4）通道——&pattern 限制 Pub/Sub 频道（Redis 7.0+）。生产建议：为不同应用创建独立 ACL 用户（如 order-service、user-service），只允许各自需要的命令和 key 前缀。ACL 配置持久化到 redis.conf 或通过 ACL SAVE/LOAD 管理。注意：ACL 不是网络安全机制——它不能替代防火墙和禁用危险命令（FLUSHALL/KEYS/CONFIG 应同时在 redis.conf 中 rename-command）。","hints":["ACL 的 +@read -DEL 这样的规则是如何组合生效的","ACL LOG 如何帮助排查权限问题"],"tags":["Redis","ACL","安全","权限"],"id":4078},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis 过期键删除策略","content":"Redis 的过期键是如何被删除的？惰性删除和定期删除分别是什么？如何避免过期 key 堆积？","answer":"答案：Redis 采用惰性删除（Lazy Deletion）配合定期删除（Active Expiration）两种策略的组合，既保证过期 key 被及时清理，又避免对 CPU 造成过大冲击。\n\n解析：1）惰性删除——当客户端访问某个 key 时，Redis 检查该 key 是否已过期，若已过期则立即删除并返回 nil。优势：CPU 友好（只删除被访问的过期 key）。问题：如果过期 key 未被访问，会一直占用内存（过期 key 堆积）。2）定期删除——Redis 每 100ms 执行一次主动扫描，从设置了过期时间的 key 集合（expires 字典）中随机取一批（默认 20 个）检查，删除其中过期的 key。如果本次扫描删除比例超过 25%（即有超过 5 个过期），则继续重复扫描（直到比例低于 25% 或超时 25ms）。\n\n扩展延伸：过期 key 对内存的潜在风险：如果大量 key 设置了相同的过期时间（如缓存同时过期），定期删除的随机采样可能无法及时清理所有过期 key，导致短时间内大量 key 过期但仍占用内存。解决：给缓存 key 的过期时间加随机偏移（如 TTL + random(0, 300) 秒）。过期 key 与淘汰策略的关系：淘汰策略（maxmemory-policy）针对的是内存不足时选择删除哪些 key，而过期删除针对的是已到期的 key——两者独立但可以配合使用。MAXMEMORY 秒杀场景：没设置过期时间的 key 也可能被淘汰策略选中删除（如 allkeys-lru）。注意：EXPIRE 命令对已经设置了过期时间的 key 会覆盖旧的 TTL。PERSIST 命令移除过期时间。","hints":["惰性删除和定期删除哪个对内存释放更重要","大量 key 同一时间过期为什么会造成延迟抖动"],"tags":["Redis","过期","删除","内存"],"id":4079},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis AOF 重写原理","content":"BGREWRITEAOF 命令触发 AOF 重写时，Redis 内部做了哪些工作？AOF 重写如何保证不丢失数据？","answer":"答案：AOF 重写通过 fork 子进程将内存数据转换为最小命令集写入新 AOF 文件，替换旧文件。重写期间主进程继续服务，新写入的命令通过重写缓冲区（rewrite buffer）记录，子进程完成后合并到新文件。\n\n解析：AOF 重写的目的：AOF 文件随着写入会越来越大——1 个 key 被反复 set 100 次，AOF 中会记录 100 条 SET 命令。重写后只剩下 1 条 SET（最新的值）。流程：1）主进程 fork 子进程，fork 瞬间的内存快照作为重写起点。2）子进程开始遍历 database，用最少的命令重建每个 key 的值（写操作合并）。3）同时，主进程开启一个 AOF 重写缓冲区（rewrite buffer），记录 fork 之后的所有写入命令。4）子进程完成重写后通知主进程。5）主进程将 rewrite buffer 中的增量命令追加到新 AOF 文件末尾（保证数据不丢失）。6）原子性地用新 AOF 文件替换旧文件。\n\n扩展延伸：自动 AOF 重写触发条件（redis.conf 配置）：1）auto-aof-rewrite-percentage 100——AOF 文件比上次重写时增长了 100%（即文件翻倍）。2）auto-aof-rewrite-min-size 64mb——AOF 文件至少达到 64MB 才触发（避免小文件反复重写）。手动触发：BGREWRITEAOF 命令。重写对性能的影响：fork 阻塞主进程 + 子进程遍历全量数据消耗 CPU 和内存（写时复制可能放大内存使用）。生产建议：在业务低峰期允许自动重写，大实例（> 30GB）先手动触发 RDB 子进程再手动 AOF 重写不要同时执行防止内存翻倍。","hints":["AOF 重写为什么需要 rewrite buffer 这个额外缓冲区","为什么 AOF 自动重写同时检查百分比和最小大小两个条件"],"tags":["Redis","AOF","重写","持久化"],"id":4080},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis 部署方案选型","content":"Redis 单机、哨兵（Sentinel）、Cluster 三种部署方案分别适用什么场景？如何选型？","answer":"答案：单机适合开发测试和允许丢数据的缓存场景；哨兵适合高可用但数据量可被单机承载的场景；Cluster 适合数据量超单机内存且需要水平扩展的场景。\n\n解析：1）单机模式——部署简单，延迟最低（无复制/集群开销）。缺点：单点故障，机器宕机后服务中断直到重启或恢复。适用：本地开发、测试环境、纯缓存业务（可以忍受短时间不可用）。2）哨兵模式——主从复制 + Sentinel 自动故障转移。读性能可水平扩展（从节点分担读请求），主节点故障时哨兵自动选新主。缺点：写性能受限于单主节点，数据量受单机内存限制。适用：大多数生产场景——数据可放入单机、需要高可用。3）Cluster 模式——数据自动分片到多节点（16384 个 slot），支持水平扩展。写性能随节点数线性提升，数据量可达 TB 级。\n\n扩展延伸：选型决策树：数据量 < 32GB 且能接受单点 → 哨兵（最简单可靠）。数据量 > 32GB 或需要写水平扩展 → Cluster。允许秒级数据丢失的纯缓存 → 单机关持久化。注意：哨兵模式下如果写 QPS 极高（> 10 万/s），考虑 Cluster 分散写压力（即使数据量不大）。三者的原生客户端支持：Jedis 支持所有模式，Lettuce 支持哨兵和 Cluster（异步驱动），Redisson 功能最全。迁移路径：单机 → 哨兵（改造小，加从节点+sentinels）→ Cluster（改造大，需支持 slot 和 MOVED 重定向）。","hints":["哨兵模式下读 QPS 如何扩展、写 QPS 遇到瓶颈怎么办","什么情况下需要从哨兵升级到 Cluster"],"tags":["Redis","部署","架构","选型"],"id":4081},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 持久化：RDB vs AOF","content":"Redis 的 RDB 和 AOF 两种持久化方式的原理、优劣和选型建议？RDB 的 fork 写时复制（COW）机制如何工作？AOF 重写（Rewrite）的目的是什么？","answer":"答案：RDB 是时间点快照（fork 子进程将全量数据写入磁盘），AOF 是追加写操作日志（每个写命令追加到文件）。RDB 文件小、恢复快但可能丢数据；AOF 数据更完整但文件大、恢复慢。两者可同时开启。\n\n解析：RDB——1）通过 fork() 创建子进程，子进程将数据写入临时 RDB 文件，完成后替换旧文件。2）写时复制（COW）：fork 后父子进程共享内存页，子进程写 RDB 时如果父进程修改了某页内存，内核复制该页给子进程（子进程看到的是 fork 时刻的数据快照）。3）配置：save 900 1（900 秒内至少 1 个 key 变化触发）。AOF——1）追加写命令到文件末尾（aof_buf → fsync 到磁盘）。2）fsync 策略：appendfsync always（每次写都 fsync，最安全但最慢）、everysec（每秒 fsync，推荐）、no（交给 OS，最快但不安全）。3）AOF 重写：子进程读取当前内存中的数据生成最小的写命令集合来重建数据集——解决 AOF 文件无限增长问题。4）混合持久化（Redis 4.0+）：RDB 快照 + AOF 增量日志。AOF 重写时先生成当前数据的 RDB，再追加增量写命令。加载时先加载 RDB 再回放 AOF 增量。\n\n扩展延伸：选型建议——1）允许丢少量数据 + 追求恢复速度 → RDB。2）不能丢数据 + 可以接受慢恢复 → AOF（everysec）。3）最佳实践：RDB + AOF 同时开启（混合持久化）。监控 AOF 文件大小和重写耗时。注意：RDB fork 的 COW 机制——如果 fork 后父进程大量写入（修改内存页），子进程需要复制更多内存页，内存使用翻倍（物理内存不足时使用 Swap 导致性能骤降）。需要预留一半内存给 COW。","hints":["RDB 的 fork COW 注意——写入量大的时候子进程复制页多，内存可能翻倍","AOF everysec 是最推荐的 fsync 策略的原因——最多丢 1 秒数据，性能影响小"],"tags":["Redis","持久化","RDB","AOF"],"id":4082},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 过期策略与内存淘汰","content":"Redis 的 key 过期删除策略有哪些？惰性删除和定期删除如何配合工作？内存淘汰（Eviction）策略有哪些？如何选择淘汰策略？","answer":"答案：过期删除策略——1）惰性删除：访问 key 时检查是否过期，过期则删除。优点：CPU 友好（只处理被访问的 key）。缺点：过期但不再访问的 key 永远不删除（内存泄漏）。2）定期删除：每 100ms 扫描一部分设置了过期时间的 key（随机抽样 + 过期则删除）。两者配合：定期删除兜底，惰性删除精准。\n\n解析：定期删除的细节——1）server.hz 控制扫描频率，默认 10（也就是每秒执行 10 次）。2）每次扫描 Redis 从设置了过期时间的 key 中随机取 20 个，删除其中过期的。如果超过 25% 过期则再随机取 20 个（循环上限 16ms）。3）续命机制：如果大量 key 同时过期，扫描会持续直到过期比例 < 25% 或耗时 > 16ms。\n\n扩展延伸：内存淘汰策略（maxmemory 配置）——1）noeviction（默认）：不淘汰，写入时报错（OOM 拒绝）。2）allkeys-lru：从所有 key 中选最近最少使用的淘汰。最常用。3）volatile-lru：从设置了过期时间的 key 中选 LRU 淘汰。4）allkeys-lfu：从所有 key 中选最不经常使用的淘汰（Redis 4.0+）。5）volatile-random/volatile-ttl：随机淘汰或按 ttl 淘汰。选型：缓存场景 → allkeys-lru（最均衡）。有 Session 场景 → volatile-lru（只淘汰可过期的，永不过期的 key 安全）。淘汰不是精确 LRU——Redis 的近似 LRU 通过随机采样 + 维护一个 LRU 时间戳实现（节省内存）。","hints":["为什么定期删除的随机抽样 + 过期比例检查比扫描所有 key 更高效——避免 O(N) 扫描","近似 LRU 和精确 LRU 的差异——Redis 用 3-5 个 key 的采样代替全局排序"],"tags":["Redis","过期","淘汰","内存"],"id":4083},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis 事务与 Lua 脚本","content":"Redis 事务（MULTI/EXEC）和 Lua 脚本（EVAL）的关系和区别是什么？Lua 脚本为什么能保证原子性？在 Redis 中使用 Lua 的最佳实践是什么？","answer":"答案：Redis 事务通过 MULTI（开启事务）→ 命令入队 → EXEC（批量执行）实现。事务中的命令在 EXEC 时按顺序执行，但不回滚（语法错误取消事务，运行时错误不回滚）。Lua 脚本通过 EVAL 在服务端执行一段 Lua 代码，整个脚本在 Redis 中原子执行。\n\n解析：Redis 事务——1）MULTI 后命令不立即执行（入队），EXEC 时依次执行。2）WATCH 提供乐观锁：WATCH 监视 key 后，如果其他客户端修改了这些 key，当前事务 EXEC 失败。3）事务不保证回滚：如果某个命令运行时失败（如对一个 string 类型执行 LPUSH），后续命令继续执行（不是整体回滚）。\n\n扩展延伸：Lua 脚本的优势——1）真正的原子性：脚本执行期间其他客户端命令不会插入。ECMAScript 承诺？不——是在 Redis 中单线程执行的。2）减少网络开销：将多个命令打包到一个 EVAL 请求中（一次网络往返）。3）Lua 脚本的最佳实践：脚本尽量短（长脚本阻塞 Redis 单线程，其他操作排队）。用 redis.call()（报错抛异常）和 redis.pcall()（捕获异常返回）处理错误。使用 SCRIPT LOAD + EVALSHA 减少带宽（缓存编译后的脚本）。KEYS[1] 和 ARGV[1] 传参。注意：生产环境不要用随机 key 名（影响复制）。场景：分布式锁的 Redlock Lua 脚本、限流的令牌桶脚本。","hints":["Redis 事务不回滚的原因——Redis 设计哲学：错误是编程问题而非运行时问题，不应该在服务端处理","Lua 脚本为什么在分布式锁场景中是核心——一条 EVAL 原子性地完成「检查-设置」操作"],"tags":["Redis","事务","Lua","原子性"],"id":4084},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis Pipeline 管道","content":"Redis Pipeline（管道）是什么？它如何提升批量操作的性能？Pipeline 和事务（MULTI/EXEC）有什么区别？使用 Pipeline 时应该注意什么？","answer":"答案：Pipeline 将多个命令一次性发送到 Redis 服务器，减少网络往返（RTT）。不使用 Pipeline 时 N 个命令需要 N 次网络往返，Pipeline 只需 1 次往返。性能提升在网络延迟高时尤为显著。\n\n解析：Pipeline 和事务的对比——1）Pipeline 不保证原子性：管道中的命令在服务端可以穿插执行其他客户端的命令。2）事务保证隔离性：EXEC 时所有命令连续执行不被其他命令打断。3）Pipeline 没有回滚机制。4）Pipeline 可以提升批量读取和写入的性能，但不要求命令之间有关联。5）两者可以组合使用：Pipeline + MULTI/EXEC 既减少网络开销又保证原子性。\n\n扩展延伸：性能提升的原理——1）微秒级命令执行时间 vs 毫秒级网络 RTT。100 个命令：无 Pipeline = 100 * RTT + 100 * 执行时间，Pipeline = 1 * RTT + 100 * 执行时间。2）如果 RTT = 1ms，命令执行 = 0.1ms：无 Pipeline = 110ms，Pipeline = 1.1ms（快 100 倍）。注意事项——1）Pipeline 命令数量不要太大（建议 < 5000），避免 Socket Buffer 溢出。2）不对 Pipeline 中的命令的响应做实时处理（所有响应在 Pipeline 关闭后一起读取）。3）Pipeline 导致客户端缓冲区占用增加（命令累积到缓冲区再发送）。4）客户端需要处理 Pipeline 部分失败的场景（网络断开时已发送的命令状态不确定）。","hints":["Pipeline 为什么在网络延迟高的场景下提升最大——100 个命令在 50ms RTT 的跨机房场景下节省 5s 网络时间","Pipeline 的命令数量为什么不是越大越好——Socket Buffer 溢出和客户端 OOM 风险"],"tags":["Redis","Pipeline","性能优化","网络"],"id":4085},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 分布式锁深入","content":"基于 Redis 的分布式锁如何实现？Redlock 算法的原理是什么？使用 Redis 实现分布式锁的常见问题（锁超时、GC 停顿、时钟漂移）有哪些？","answer":"答案：最基础的分布式锁：SET key uuid NX PX 30000（原子性地设置 key，value 为唯一标识，过期时间 30s）。释放时用 Lua 脚本检查 value 匹配再删除（防止误删其他客户端的锁）。Redlock 在 Redis 集群中的多数节点上获取锁来保证一致性。\n\n解析：基础锁的实现——1）加锁：`SET lock_key unique_id NX PX 10000`。NX = 不存在才设置（互斥），PX = 过期时间（避免死锁），unique_id（如 UUID + 线程 ID）保证只有持有者能释放锁。2）释放：Lua 脚本 `if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end`。\n\n扩展延伸：常见问题——1）锁超时：业务执行时间超过了锁过期时间，锁自动释放后其他客户端获取锁。解决：看门狗机制（Redisson 的 Watch Dog，锁剩余 1/3 时间时自动续期）。2）GC 停顿：GC Stop-The-World 导致线程暂停，锁超时后其他线程获取锁，原线程 GC 完成后以为自己仍持有锁（认为业务没执行完）。3）时钟漂移：Redis 节点时钟不同步导致过期时间不一致。Redlock 算法（Redis 之父 Antirez 提出）——1）在 N/2+1 个 Redis 节点上获取锁（通常 5 个奇数节点）。2）获取锁的总耗时必须小于锁的有效时间。3）如果超过半数节点获取成功且耗时小于有效时间，则认为锁获取成功。4）争议：分布式系统专家认为 Redlock 在 GC 停顿下仍有安全性问题（「红锁的争议」是经典话题）。实践建议：大多数场景用基础 SET NX PX + Redisson Watch Dog 就够了。需要严格一致性时考虑 ZooKeeper 或 etcd 的锁。","hints":["释放锁的 Lua 脚本为什么要先 GET 比较 value 再 DEL——防止误释放其他客户端持有的锁","Redlock 的 GC 停顿问题为什么没有被完全解决——GC 暂停期间锁已过期但线程不知情"],"tags":["Redis","分布式锁","Redlock","并发"],"id":4086},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 持久化策略选型","content":"Redis 的 RDB 和 AOF 持久化各自的特点和适用场景？混合持久化的原理？RDB 和 AOF 同时开启时优先使用哪个恢复？AOF rewrite 的触发条件和过程？","answer":"答案：RDB（快照持久化）——定时将全部数据写入二进制 RDB 文件。AOF（追加文件）——记录每个写命令（以 Redis 协议格式追加到 AOF 文件）。Redis 4.0+ 支持混合持久化——RDB 全量快照 + AOF 增量日志。RDB 恢复快（二进制加载），AOF 数据更安全（每秒/每次写入同步）。同时开启时优先用 AOF 恢复（数据更完整）。\n\n解析：RDB——1）触发：save（同步阻塞）、bgsave（fork 子进程写）、配置自动触发（save 900 1 等）。2）优势：文件紧凑适合备份和灾难恢复、恢复速度快（直接加载二进制数据）。3）劣势：丢数据风险大（两次 RDB 之间的数据全部丢失）。AOF——1）同步策略：appendfsync always（每次写同步，最安全但最慢，磁盘 IO 成为瓶颈）、everysec（每秒同步，折中方案，推荐）、no（由 OS 决定同步时机）。2）AOF 文件可能比 RDB 大得多（记录命令而非数据）。\n\n扩展延伸：AOF Rewrite——1）触发条件：AOF 文件超过上次 rewrite 后大小的 100%（auto-aof-rewrite-percentage 100）且最小 64MB（auto-aof-rewrite-min-size 64mb）。2）过程：fork 子进程，子进程将当前内存中的数据重写为最小命令集（如将多个 INCR 合并为 SET），写入临时 AOF 文件，写入期间主进程的增量变化记录在重写缓冲区中，最终将缓冲区追加到新 AOF 文件，替换旧 AOF 文件。3）混合持久化（aof-use-rdb-preamble yes）：RDB + AOF 结合——RDB 作为全量基础，AOF 记录增量。加载时先加载 RDB 再回放 AOF。兼顾 RDB 的快速恢复和 AOF 的数据完整性。在生产环境——建议同时开启 RDB（灾难恢复）+ AOF（尽量不丢数据）或混合持久化。","hints":["RDB 恢复快但丢数据多——AOF 数据更完整但恢复慢——混合持久化兼顾两者","AOF rewrite 由子进程执行——不会阻塞主进程处理请求"],"tags":["数据库","Redis","持久化","RDB","AOF"],"id":4087},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 大 Key 治理","content":"什么是 Redis 的 Big Key（大 Key）？大 Key 有哪些危害？如何发现和治理大 Key？大 Key 的拆分策略？","answer":"答案：Big Key 通常指——单个 key 包含大量数据（String 类型值 > 10KB、List/Hash/Set/Zset 元素 > 几千个）。大 Key 的危害：阻塞 Redis 命令（如 key * 导致 O(N) 阻塞）、网络带宽占用大（大 Value 传输慢）、数据迁移慢（集群模式下大 Key 迁移卡住）、内存分布不均（集群中的数据倾斜）。\n\n解析：发现方法——1）redis-cli --bigkeys：扫描整个 Redis，按类型统计最大 key。2）DEBUG OBJECT key：查看 key 的编码和序列化长度。3）memory usage key：精确计算 key 的内存占用（4.0+ 提供）。4）monitor 命令：结合脚本分析使用模式（但生产环境慎用——阻塞式）。5）定期扫描脚本：扫描所有 key 并检查 size。\n\n扩展延伸：治理策略——1）拆分（Sharding）：大 Hash 拆分为多个小 Hash（根据 field 做 hash → field%N 分配到不同 key）。大 List 拆分为多个 List（按时间/ID 区间拆分）。2）压缩：对大 Value 做压缩（如 gzip/snappy）后存入 Redis，读取时解压。以 CPU 换内存和网络带宽。3）数据淘汰（Pruning）：大 Key 中的数据往往是积累了长时间未清理。建立 TTL 过期策略或定期清理过期子元素。4）数据结构变更：JSON 字符串 → Hash（利用 Hash 的字段级操作，只读写需要的字段）。5）本地缓存：大 Value 的频繁读取业务在应用层加本地缓存减少 Redis 压力。主动监控——设置大 Key 告警：memory usage 超过阈值时告警。大 Key 的删除需要谨慎——del 大 Key 会阻塞 Redis（单线程执行）。使用 UNLINK（4.0+）异步删除（后台线程逐步释放内存，不阻塞主线程）。","hints":["redis-cli --bigkeys 扫描大 Key——DEL 大 Key 会阻塞 Redis，用 UNLINK 异步删除","数据倾斜——大 Key 导致集群中单个节点内存使用远超其他节点（分布不均）"],"tags":["数据库","Redis","大Key","优化"],"id":4088},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Cluster 集群迁移与扩缩容","content":"Redis Cluster 如何做扩缩容？槽位迁移的过程？数据迁移时对客户端的影响？reshard 操作的时间复杂度？Redis Cluster 的局限性和替代方案？","answer":"答案：Redis Cluster 通过槽位（slot）迁移实现扩缩容。16384 个槽位在节点间重新分配，槽位中的数据从源节点迁移到目标节点。迁移过程对客户端是透明的（客户端在 MOVED/ASK 重定向时更新槽位缓存）。\n\n解析：迁移过程——1）准备：确定要迁移的槽位范围、目标节点。使用 `redis-cli --cluster reshard host:port` 交互式迁移。2）迁移数据：对每个 slot 中的每批 key——目标节点准备导入（CLUSTER SETSLOT slot IMPORTING）、源节点准备导出（CLUSTER SETSLOT slot MIGRATING）。对每个 key——源节点执行 MIGRATE 命令（原子操作：dump key + DEL key + RESTORE key 到目标）。3）完成后：通知所有节点槽位已分配给目标节点（CLUSTER SETSLOT slot NODE target_id）。\n\n扩展延伸：客户端影响——1）MOVED 重定向：迁移完成后，客户端请求的槽位在旧节点时收到 MOVED 错误（永久重定向——客户端更新槽位缓存后直接访问新节点）。2）ASK 重定向：迁移过程中，槽位正在迁移时，客户端请求旧节点时如果 key 已迁移走收到 ASK 错误（临时重定向——客户端先向新节点发送 ASKING 再请求）。局限与替代——1）跨 slot 多 key 操作受限（只能在同一 slot 的 key 间执行 mset/mget/事务）。用 hash tag 将相关 key 强制分配到同一 slot。2）Cluster 模式不支持多数据库（只有 db0）。3）数据迁移时性能下降（MIGRATE 命令的 dump/del/restore 有开销）。4）替代方案：Codis（代理模式，中间层做分片，客户端无需感知）、Redis Sharding（客户端分片库，如 Jedis/JedisCluster）、云服务（阿里云 Redis/Tencent CRS 等托管集群）。","hints":["MOVED（永久迁移完成）vs ASK（临时迁移中）——客户端处理两者的方式不同","Redis Cluster 的跨 slot 多 key 操作受限——用 hash tag { } 强制相关 key 到同一 slot"],"tags":["数据库","Redis","Cluster","迁移"],"id":4089},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 生产配置最佳实践","content":"Redis 生产环境有哪些关键的配置参数？内存配置、持久化配置、网络配置、安全配置分别需要注意什么？监控 Redis 的关键指标有哪些？","answer":"答案：生产配置三大要点——内存（maxmemory + 淘汰策略）、持久化（AOF + RDB 策略）、安全（密码 + 绑定 + ACL）。监控核心指标：内存使用率、连接数、OPS（每秒操作数）、缓存命中率、复制延迟。\n\n解析：关键配置——1）内存：maxmemory 设置为物理内存的 60-80%（留出系统内存和 Fork 内存）。maxmemory-policy allkeys-lru（缓存场景）或 volatile-lru（有过期时间的场景）。2）持久化：appendonly yes（开启 AOF）。appendfsync everysec（每秒刷盘，兼顾安全与性能）。aof-use-rdb-preamble yes（混合持久化）。save 900 1 / save 300 10（RDB 自动触发）。3）网络：bind 127.0.0.1（绑定内网 IP，不暴露到公网）。protected-mode yes。requirepass / ACL 配置密码认证。timeout 300（空闲连接超时）。4）连接：maxclients 10000（最大连接数，受限于系统 ulimit）。tcp-keepalive 300（检测死连接）。\n\n扩展延伸：监控指标——1）info memory：used_memory、used_memory_rss、mem_fragmentation_ratio（碎片率，>1.5 需处理）。2）info stats：total_commands_processed（OPS）、instantaneous_ops_per_sec（实时 QPS）。3）info replication：master_link_status、slave_lag（复制延迟）。4）info persistence：rdb_last_bgsave_status、aof_last_bgrewrite_status。5）info clients：connected_clients、blocked_clients。常见问题——1）fork 耗时：RDB/AOF rewrite 需要 fork 子进程，fork 耗时与内存大小正相关。大实例（> 10GB）fork 可能阻塞服务数十 ms 到数秒。2）碎片率 > 1.5：主动 defrag（activedefrag yes）或重启。3）慢查询：SLOWLOG GET 查看。","hints":["maxmemory 设置（物理内存的 60-80%）+ 合适的淘汰策略——防止 Redis OOM 被系统杀掉","fork 耗时随内存增长——大实例（> 10GB）的 fork 可能导致毫秒到秒级的服务暂停"],"tags":["数据库","Redis","配置","运维"],"id":4090},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 发布订阅（Pub/Sub）机制","content":"Redis 的发布订阅（Pub/Sub）模式是如何工作的？与消息队列（如 RabbitMQ、Kafka）相比有什么优缺点？有哪些注意事项？","answer":"答案：Redis Pub/Sub 通过 SUBSCRIBE channel / PUBLISH channel message 实现。订阅者订阅频道后收到 PUBLISH 的消息。消息即发即弃、不持久化。\n\n解析：工作机制——1）PUBLISH channel msg：向该频道的所有订阅者发送消息。O(N) 复杂度。2）SUBSCRIBE channel [channel ...]：订阅一或多个频道。3）PSUBSCRIBE pattern：通过 glob 模式订阅（如 news.*）。4）消息格式：订阅者收到的是数组回复（包括消息类型、频道名、消息体）。5）Sharded Pub/Sub（Redis 7.0+）：SSUBSCRIBE / SPUBLISH——与 Cluster 的槽位绑定，避免跨节点广播。6）底层实现：每个 Redis Server 维护一个 dict（频道 → list(订阅者)）。PUBLISH 时遍历所有订阅者对应的 client 结构发送消息。\n\n扩展延伸：与消息队列的对比——1）可靠性：MQ 有持久化 + 消费确认 + 重试机制，Redis Pub/Sub 不持久化、即发即弃，消费端宕机期间消息永久丢失。2）积压能力：MQ 可积压百万条消息，Redis Pub/Sub 用 TCP 缓冲区，发布快而消费慢时缓冲区满会被强制断开连接（client-output-buffer-limit pubsub）。3）消费模型：MQ 支持消费组（一条消息被组内一个消费者消费），Redis Pub/Sub 所有订阅者都收到（广播模式）。4）适用场景：实时消息广播（如实时通知、消息推送、状态广播）。不适合：可靠性要求高的业务消息、需要回溯消费的消息。替代方案：Redis Stream（Redis 5.0+）——支持持久化、消费组、ACK 确认，更接近传统 MQ。","hints":["消费端断连重连后还能收到断开期间的消息吗","发布快于消费时 Redis Pub/Sub 会发生什么"],"tags":["Redis","Pub/Sub","发布订阅","消息"],"id":4091},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Lua 脚本原理与应用","content":"Redis 中 Lua 脚本的执行机制是什么？EVAL 和 EVALSHA 的区别？Lua 脚本的原子性、沙箱限制和性能优化怎么做？","answer":"答案：Redis Lua 脚本通过 EVAL / EVALSHA 执行，脚本在沙箱环境中运行、具备原子性（脚本执行期间其他命令不插入）。EVALSHA 通过缓存脚本的 SHA1 摘要避免每次传输完整脚本。\n\n解析：执行机制——1）EVAL 'script' numkeys key... arg...——Redis 将 Lua 脚本放入全局缓存（SCRIPT FLUSH 清除）。2）EVALSHA — 客户端先发送 EVALSHA，如果服务端未缓存则返回 NOSCRIPT 错误，客户端回退为 EVAL。3）原子性：Lua 脚本是同步执行的（阻塞整个 Redis 实例），脚本执行期间不会处理其他命令。这意味着长耗时的脚本会阻塞所有请求（生产环境必须避免）。\n\n扩展延伸：沙箱限制——1）可用库：base、table、string、math、debug（但 debug 的大部分功能被禁用）、cjson、cmsgpack。2）禁用的操作：文件 I/O (io.*)、网络 (socket.*)、OS 命令 (os.execute)。3）随机函数：math.random 默认种子固定，需要手动 redis.call('TIME') 获取时间做 seed。4）脚本中不能访问外部全局变量（必须通过 KEYS/ARGV 传入）。性能优化——1）脚本尽量短小（每次执行不超过几毫秒）。2）用 EVALSHA 减少网络传输。3）善用 redis.log(redis.LOG_WARNING, msg) 调试。4）用 SCRIPT LOAD 预热缓存 + EVALSHA 调用。5）计算结果尽量在 Lua 中聚合后返回，减少客户端与服务端之间的数据量。\n\n扩展延伸：Redis 7.0+ 的函数（Function）功能——替代 EVAL/EVALSHA：SCRIPT 命令管理脚本。FUNCTION 命令管理函数（可被多次调用、有命名空间、自动缓存）。建议新项目使用 Redis Functions（API 更规范、调试更友好）。","hints":["Lua 脚本为什么不能太长——对 Redis 实例有什么影响","为什么 EVALSHA 比 EVAL 更高效"],"tags":["Redis","Lua","脚本","原子性"],"id":4092},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 连接池设计","content":"Redis 连接池的作用是什么？如何合理配置连接池参数（如 maxTotal、maxIdle、minIdle、timeout）？连接池耗尽时会发生什么？","answer":"答案：Redis 连接池通过复用 TCP 连接避免频繁创建/销毁连接的开销，同时通过池化控制并发连接数，防止资源耗尽。\n\n解析：核心参数（以 JedisPool / Lettuce 为例）——1）maxTotal（最大活跃连接数）：控制与 Redis 的最大并发连接。经验值：根据 QPS × 平均响应时间 × 冗余系数。示例：QPS 5000、平均响应 2ms，则约需 10 个连接，一般设 50-100 留余量。2）maxIdle（最大空闲连接数）：连接池中最多保留的空闲连接。太高浪费 Redis 资源，太低高峰期可能要新建连接。3）minIdle（最小空闲连接数）：维持的连接数，快速响应突发流量。4）timeout（连接超时 + 读写超时）：连接超时建议 500ms-2s（内网），读写超时根据业务特点设（一般 2s-10s）。5）maxWaitMillis（获取连接的最大等待时间）：池中无可用连接时的等待超时，超时抛出异常。\n\n扩展延伸：连接池耗尽的表现——1）客户端抛出 JedisException: Could not get a resource from the pool（连接池借不到连接）。2）Redis 端连接数达到 maxclients（默认 10000）拒绝新连接。3）CPU 和内存上升（每个连接占用约 65KB 内核缓冲区 + Redis 端的内存开销）。排查方法——1）检查慢查询（SLOWLOG GET 100）是否有阻塞型操作（如 KEYS *、大 key 删除 DEL bigkey）。2）检查客户端是否泄漏连接（没有归还连接）。3）Lettuce 的连接池设计为异步（基于 Netty），可以复用连接做多路复用，不建议设置过大池子。4）Redis 6+ 支持多线程网络 IO，连接数多一点影响变小但仍需合理控制。","hints":["连接池 maxTotal 设置多大合适——怎么根据 QPS 计算","连接池泄漏怎么排查——客户端不归还连接的表现和应对"],"tags":["Redis","连接池","性能","Jedis","Lettuce"],"id":4093},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 多线程模型","content":"Redis 6.0 引入的多线程 IO 模型是什么？Redis 为什么从单线程改为多线程？多线程模式下命令执行是单线程吗？与 Memcached 的多线程模型有何不同？","answer":"答案：Redis 6.0 引入多线程 IO（输入输出处理使用多线程），但命令执行依然在单线程中执行（核心处理引擎是单线程的）。多线程仅用于网络 IO 的读写——将 Socket 数据解析/序列化分散到多个线程处理。\n\n解析：为什么引入多线程——1）瓶颈不是 CPU 而是网络 IO：Redis 单线程处理命令非常快（纯内存、o(1) 操作常见），但网络 IO（read()/write() 系统调用）在大并发下成为瓶颈。2）带宽饱和：10 Gbps 网卡场景下单线程无法充分利用网络带宽，多线程 IO 能更高效利用。3）大 key 的场景：操作已经够快，但数据量大时的网络传输（如批量 MGET 大量数据）受益于多线程 IO。Redis 6.0 多线程 IO 的工作原理——1）主线程接受新连接（Accept）。2）将读/写任务分发给 IO 线程（轮询分配）。3）IO 线程执行 read() 系统调用、解析协议（RESP）、序列化结果。4）主线程执行命令（单线程）。5）主线程将写任务分发给 IO 线程 write() 回客户端。\n\n扩展延伸：配置方式——1）通过 io-threads 配置（默认为 4），建议不超过 CPU 核数。2）io-threads-do-reads yes 开启读多线程（默认 only write）。3）写入线程数一般设为 CPU 核数。与 Memcached 的对比——Memcached 默认就是多线程架构（每个线程处理自己的事件循环），命令执行也是多线程的（通过锁保证原子操作）。Redis 保持了命令执行的单线程，避免了锁竞争和并发复杂性。Redis 7.0+ 将部分后台任务用多线程（如 lazy-free 异步删除 bigkey 的释放操作在后台线程进行）。","hints":["Redis 多线程 IO 为什么不把命令执行也做成多线程——对比 Memcached 的设计","Redis 6.0 的多线程 IO 在什么场景下收益最大"],"tags":["Redis","多线程","IO模型","性能","架构"],"id":4094},{"category":"database","difficulty":"easy","type":"short_answer","title":"Redis 核心数据结构与底层编码","content":"Redis 支持哪些核心数据结构？每种数据结构的底层编码（Encoding）是什么？如何根据业务场景选择合适的数据结构？","answer":"答案：Redis 核心数据结构有 5 种：String（字符串）、Hash（哈希）、List（列表）、Set（集合）、Sorted Set（有序集合）。扩展结构：Bitmap、HyperLogLog、GEO、Stream。底层编码根据数据特征自动切换以平衡内存和性能。\n\n解析：各数据结构的底层编码——1）String：int（整数）、embstr（<= 44 字节短字符串）、raw（> 44 字节）。2）Hash：ziplist（字段数 < 512 且每个字段长度 < 64 字节）→ hashtable。3）List：quicklist（双向链表 + ziplist 混合）。4）Set：intset（全部为整数且数量 < 512）→ hashtable。5）Sorted Set：ziplist（元素数 < 128 且长度 < 64 字节）→ skiplist + dict。\n\n扩展延伸：选型建议——1）计数：String（INCR/DECR 原子操作）。2）对象存储：Hash（单独读写字段，内存效率高于 String 序列化）。3）消息队列：List（LPUSH + BRPOP）或 Stream（Redis 5.0+，支持消费者组和 ACK）。4）去重/标签：Set（SADD/SISMEMBER）。5）排行榜：Sorted Set（ZADD/ZRANK/ZREVRANGE）。6）布隆过滤器：RedisBloom 模块防缓存穿透。Stream vs List：Stream 支持多消费者组、消息持久化、消费者确认机制，更适合可靠的异步任务队列。","hints":["Hash 在字段数少时的编码是什么——ziplist 比 hashtable 节省多少内存","Sorted Set 的底层为什么用 skiplist 而不是平衡树"],"tags":["Redis","数据结构","底层编码","选型"],"id":4095},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 集群模式与数据分片","content":"Redis Cluster 的数据分片机制是什么？16384 个 Hash Slot 如何分配？节点间的 Gossip 通信协议如何工作？主从自动切换机制？集群有哪些限制和坑？","answer":"答案：Redis Cluster 通过哈希槽分片——CRC16(key) % 16384 计算槽位，16384 个槽均匀分布在集群节点上。节点间通过 Gossip 协议交换元数据（PING/PONG 携带节点状态和槽位信息）。主节点宕机后从节点通过集群选举（多数主节点投票）晋升。\n\n解析：分片机制——1）槽映射表：维护在集群每个节点内存中。2）MOVED 重定向：请求的槽不在当前节点时返回 MOVED + 目标节点地址。Smart 客户端缓存映射表直接路由。3）ASK 重定向：迁移过程中部分 key 已迁走，返回 ASK 引导客户端。\n\nGossip 协议——每秒随机选 5 个节点发 PING（含自身状态 + 随机 2-3 个其他节点状态）。收到 PONG 更新本地视图。节点超过 node_timeout（默认 15s）未响应标记 PFAIL，超过半数主节点认为 PFAIL 升级为 FAIL。16384 个槽的位图仅占 2KB（16384 bits / 8），Gossip 消息中可高效传递。\n\n扩展延伸：限制与实践——1）不支持多数据库（仅 db0）。2）批量操作（mget/pipeline）的 key 必须在同节点（用 hash tag { } 解决）。3）Lua 脚本 key 必须通过 KEYS 传入且在同一个槽。4）集群建议节点数 < 1000（Gossip 在大集群下带宽消耗大）。5）跨机房不推荐 Redis Cluster（延迟高）。异地多活建议用 CRDT 方案（Redis 7.0+ 实验性支持）。","hints":["16384 个槽的位图为什么只有 2KB——Gossip 消息槽位传播机制","MOVED 和 ASK 重定向的区别是什么"],"tags":["Redis","集群","Redis Cluster","Gossip"],"id":4096},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 持久化：RDB 与 AOF","content":"Redis RDB 和 AOF 持久化机制分别是什么？各自的优缺点？RDB 和 AOF 如何配合使用？AOF 重写过程中新写入如何处理？Redis 7 的持久化改进？","answer":"答案：RDB（快照）定期保存全量数据到 dump.rdb，适合备份和灾难恢复。AOF（Append Only File）记录所有写操作指令，支持秒级数据恢复。RDB 体积小、加载快但可能丢数据。AOF 更安全但文件大、恢复慢。生产环境通常两者同时开启，或仅用 AOF（Redis 7 优化后）。\n\n解析：RDB 原理——fork 子进程，通过写时复制（Copy-on-Write）写入临时文件后替换。触发：bgsave、save 配置（如 save 900 1）、主从复制首次连接。缺点：fork 耗时（大实例可能几百 ms），两次快照间数据丢失。\n\nAOF 原理——写命令追加到 aof_buf，按 appendfsync 策略刷盘：always（每条同步——安全但慢）、everysec（每秒同步——推荐）、no（OS 决定）。AOF 重写：fork 子进程将当前内存转命令集写入新 AOF，期间新命令由父进程缓存到重写缓冲区，子进程完成后追加。\n\n扩展延伸：Redis 7 改进——AOF 格式更紧凑，重启加载性能提升。混合持久化（Redis 4.0+）：AOF 重写时生成 RDB 格式 + 增量命令，兼顾快速加载和低数据丢失。选型：RDB only 适合可接受分钟级丢失的缓存场景；AOF only 适合不能丢数据的存储场景。注意：AOF fsync 在磁盘 IO 高时可能成为瓶颈。","hints":["RDB 的写时复制（COW）在写密集型场景下需要额外内存","AOF 重写期间的新写入命令如何处理——重写缓冲区的作用"],"tags":["Redis","持久化","RDB","AOF","混合持久化"],"id":4097},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 缓存策略与常见问题","content":"Redis 作为缓存时有哪些常见模式？缓存穿透、缓存击穿、缓存雪崩分别是什么？如何解决？缓存一致性如何保证？过期策略和内存淘汰机制是什么？","answer":"答案：旁路缓存（Cache-Aside）：读时先查缓存，miss 则查库并回填；更新时先更新数据库再删缓存。三大问题：穿透（查不存在的数据）→ 布隆过滤器/缓存空值。击穿（热点 key 过期并发请求）→ 互斥锁/永不过期+后台更新。雪崩（大量 key 同时过期）→ 过期时间加随机值/集群高可用。\n\n解析：缓存穿透——查询一个不存在的数据，所有请求绕过缓存直接打 DB，DB 压力剧增。解决方案：1）布隆过滤器（Bloom Filter），说「不存在」一定不存在。2）缓存空值（即使 DB 查不到也缓存一个 null，设置较短的 TTL）。\n\n缓存击穿——某个热点 key 过期瞬间，大量并发请求同时打到 DB。解决：1）互斥锁（SET NX，只让一个线程去查 DB 回填，其他等待）。2）热点 key 不设过期时间（永不过期） + 后台线程定期更新。\n\n缓存雪崩——大量 key 同一时间过期或 Redis 宕机失效。解决：1）过期时间加随机值（3600 + random(0, 600)）。2）Redis 高可用（主从 + 哨兵/集群）。3）本地缓存（Caffeine/Guava Cache）做二级兜底。\n\n扩展延伸：过期与淘汰——1）过期删除策略：惰性删除（访问时检查）+ 定期删除（每秒 10 次随机抽 20 个 key，超 25% 过期则重复）。2）内存淘汰（maxmemory-policy）：allkeys-lru（最常用）、volatile-lru、allkeys-lfu（Redis 4.0+）、noeviction。大 key 问题：单个 value 超 10MB 拆分为小 key。","hints":["缓存击穿和缓存雪崩的区别是什么——一个是热点 key 过期，一个是大量 key 同时过期","布隆过滤器为什么能防止缓存穿透——不存在的一定不存在存在的不一定存在"],"tags":["Redis","缓存","穿透","击穿","雪崩","淘汰策略"],"id":4098},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 分布式锁原理与 Redlock","content":"如何用 Redis 实现可靠的分布式锁？SET NX EX 的用法？解锁为什么要用 Lua 脚本？什么是 Redlock 算法？分布式锁的死锁、续期和时钟漂移问题如何解决？","answer":"答案：核心命令 SET key unique_id NX EX 30。NX 只在 key 不存在时设置，EX 30 设 30 秒过期。value 用 UUID 作为锁标识。解锁用 Lua 脚本原子校验 value 后 DEL，防止误删别人加的锁。Redlock 算法在多个独立 Redis 节点上依次加锁，超半数成功才算获取，解决单点故障。\n\n解析：解锁的原子性——不直接 DEL 的原因是：线程 A 的锁过期自动释放，线程 B 加锁成功，线程 A 执行时 DEL 会误删 B 的锁。正确做法：if redis.call('get', lock_key) == unique_id then return redis.call('del', lock_key) else return 0 end（Lua 脚本保证原子执行）。\n\n锁续期（Watch Dog）——业务执行超时自动续期。Redisson 的 watchdog 默认每 10 秒检查续期（锁默认 TTL 30 秒）。实现：加锁时启动后台定时任务，锁仍由自己持有时 EXPIRE 续期。\n\n扩展延伸：Redlock 的争议——Martin Kleppmann（DDIA 作者）指出 Redlock 依赖时钟同步，GC 停顿或时钟跳跃时安全保证失效。推荐使用有 fencing token 的方案（如 etcd 的 revision）。实际建议：大多数场景用单 Redis SET NX 够用；安全性极高（如防重复扣款）用 ZooKeeper/etcd；Redlock 介于两者之间。","hints":["解锁时为什么必须用 Lua 脚本——防止误删其他线程的锁","Redlock 的时钟依赖问题是什么——Martin Kleppmann 的批评"],"tags":["Redis","分布式锁","Redlock","原子性","并发"],"id":4099},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 7 RedisJSON 与 JSONPath 查询","content":"Redis 的 RedisJSON 模块支持 JSON 数据类型。在 Redis 7 中它有哪些核心功能？JSONPath 查询如何工作？RedisJSON 相比直接存 JSON 字符串的优势是什么？","answer":"答案：RedisJSON（redisjson 模块）为 Redis 提供原生的 JSON 数据类型支持，允许对 JSON 文档的部分字段做原子读写操作，无需读取整个文档。Redis 7 还增强了 JSONPath 查询语法支持（支持 $.store.book[0].title 等路径表达式）。优势：字段级操作、减少网络传输、内置 JSONPath 查询。\n\n解析：1）核心命令——JSON.SET key $ path value（设置 JSON 值）、JSON.GET key $ path（获取指定路径的值）、JSON.DEL key path（删除路径）、JSON.ARRAPPEND/ARRPOP/ARRTRIM（数组操作）、JSON.OBJKEYS/OBJLEN（对象操作）。2）JSONPath 语法——$ 表示根节点，. 表示子节点，[] 表示数组索引或过滤器，* 表示通配符。示例：JSON.GET user:123 $ .address.city（获取城市的地址）。JSON.GET orders $ .items[?(@.price > 100)]（查询价格大于 100 的商品）。\n\n扩展延伸：3）相比存 JSON 字符串的优势——String 存 JSON：要修改一个字段需要 GET 整个 JSON -> 反序列化 -> 修改 -> 序列化 -> SET（O(N) 网络传输 + 序列化开销）。RedisJSON：JSON.SET key $ .field new_value 只传输修改部分（O(1) 大小）。4）存储效率——RedisJSON 使用二进制 JSON 格式（JSONB），比纯字符串 JSON 更紧凑且支持部分读取。5）注意事项——RedisJSON 是模块，不是 Redis 内置数据类型（需通过 Redis Stack 或单独加载模块）。JSONPath 的 $ 前缀在 RedisJSON v2（Redis 7）中是标准前缀。使用 @ 前缀引用过滤器中的当前节点属性。","hints":["RedisJSON 的 JSON.SET 和普通 Redis SET 在处理 JSON 字段修改时的网络开销差异","JSONPath 查询中 $ 和 @ 的作用分别是什么"],"tags":["Redis","RedisJSON","JSONPath","Redis 7"],"id":4127},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis TimeSeries 时序数据结构","content":"Redis TimeSeries（时序数据模块）的数据结构是什么？它解决了什么问题？TimeSeries 的压缩机制和聚合查询如何工作？","answer":"答案：Redis TimeSeries 是 Redis 的时序数据类型（Module），专用于存储和查询时间序列数据（如监控指标、传感器数据）。支持以时间范围为条件的聚合查询、自动压缩（Compaction）、保留策略（Retention）。核心数据结构是每个 key 对应一个时序序列，内部使用分块存储（Chunk）来优化写入和查询。\n\n解析：1）核心命令——TS.CREATE key（创建时序序列，可配置 retention、labels、chunk size）。TS.ADD key timestamp value（添加数据点，可选 ON_DUPLICATE 策略）。TS.RANGE key fromTimestamp toTimestamp（范围查询，支持 AGGREGATION 参数做降采样）。TS.MRANGE（多 key 范围查询，按 labels 匹配）。2）压缩（Compaction）——通过 TS.CREATERULE 创建压缩规则（如原始序列每 10 秒一个点，压缩为每 5 分钟最大值）。压缩后的数据存储在不同的 key 中（规则自动触发）。\n\n扩展延伸：3）存储优化——每个 TimeSeries 内部将数据分块存储（默认每块包含 3600 个数据点）。写入时追加到当前块，查询时跳过不相关的块。内存效率高于使用 ZSet 或 List 存储时序数据。4）聚合查询——TS.RANGE ... AGGREGATION avg 5m 表示以 5 分钟为窗口计算平均值。支持 avg、sum、min、max、range、count、first、last、std.p（总体标准差）、std.s（样本标准差）、var.p、var.s。5）适用场景——监控指标采集（CPU、内存、网络）、IoT 传感器数据、应用性能指标（APM）、实时分析。优势：相比 ZSet 存时序数据，TimeSeries 提供原生的压缩、聚合、保留策略，无需应用层实现。","hints":["TimeSeries 的 Compaction（压缩规则）是如何自动触发写入的","TimeSeries 的 Chunk 分块存储为什么能同时优化写入和范围查询"],"tags":["Redis","TimeSeries","时序数据","监控"],"id":4128},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Cluster 重新分片与槽位迁移","content":"Redis Cluster 的重新分片（Resharding）和槽位迁移（Slot Migration）是如何工作的？迁移过程中对客户端访问有什么影响？MOVED 和 ASK 重定向的区别是什么？","answer":"答案：Redis Cluster 重新分片是将部分哈希槽及其数据从源节点迁移到目标节点的过程。通过 redis-cli --cluster reshard 触发，底层使用 CLUSTER SETSLOT 命令设置槽位状态（MIGRATING/IMPORTING），通过 MIGRATE 命令逐 key 迁移数据。迁移过程中客户端可能收到 MOVED（槽位已永久迁移）或 ASK（槽位正在迁移中）重定向。\n\n解析：1）迁移流程——确定要迁移的槽位和目标节点 -> 目标节点执行 CLUSTER SETSLOT slot IMPORTING -> 源节点执行 CLUSTER SETSLOT slot MIGRATING -> 源节点遍历槽位中的 key 逐个执行 MIGRATE（原子 DUMP + DEL + RESTORE）-> 所有 key 迁移完成后通知所有节点更新槽位分配（CLUSTER SETSLOT slot NODE target_id）。\n\n2）MOVED 重定向——槽位已经永久分配给目标节点。客户端收到 MOVED 后应更新本地槽位缓存，后续请求直接发往目标节点。这是永久性重定向。3）ASK 重定向——槽位正在迁移中。客户端请求的 key 可能在源节点也可能在目标节点。客户端先向目标节点发送 ASKING 命令（仅单次有效），再发送操作命令。ASK 不更新客户端路由缓存。\n\n扩展延伸：4）迁移对性能的影响——MIGRATE 命令对每个 key 执行 DUMP（序列化数据）-> 网络传输 -> RESTORE（反序列化存入目标节点）-> DEL（从源节点删除）。批量迁移大量 key 时产生较大的 CPU 和网络开销。5）在线迁移的注意事项——迁移期间建议低峰期执行，避免大量写操作。一次迁移的 key 数量可分批进行（--cluster-slots 控制每批迁移的槽位数）。6）Redis 7.0 的改进——支持更灵活的副本迁移（replicas migration 优化），减少节点故障时的数据恢复时间。","hints":["MOVED 和 ASK 重定向在客户端处理方式上的核心区别是什么","为什么 MIGRATE 命令是原子的（DUMP + DEL + RESTORE 组合）"],"tags":["Redis Cluster","重新分片","槽位迁移","MOVED","ASK"],"id":4129},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis Pipeline 与事务的对比分析","content":"Redis Pipeline 和事务（MULTI/EXEC）有什么区别？它们可以一起使用吗？在什么场景下应该选择 Pipeline 而非事务，反之亦然？","answer":"答案：Pipeline 是网络层面的批量传输优化——将多个命令一次发送减少 RTT，不保证原子性。事务（MULTI/EXEC）是服务端层面的原子执行保证——所有命令在 EXEC 时连续执行不被其他命令打断，但不保证回滚。两者可以结合使用（Pipeline 中包含 MULTI/EXEC 命令块）。\n\n解析：核心区别——1）网络优化 vs 原子性：Pipeline 将 N 次网络往返降为 1 次，但命令之间可能插入其他客户端的命令。事务通过 EXEC 确保命令序列不被中断（原子执行），但每个命令依然单独发送（除非配合 Pipeline）。2）错误处理：Pipeline 中某个命令失败不影响其他命令的执行。事务中如果命令入队时语法错误，整个事务被拒绝；如果运行时错误（如对 string 执行 LPUSH），前面的命令已生效且不会回滚。3）返回结果：Pipeline 返回所有命令的响应数组，事务同样返回 QUEUED + EXEC 后的结果数组。\n\n扩展延伸：4）组合使用——批量执行需要原子性保证的命令：在 Pipeline 中发送 MULTI -> 命令序列 -> EXEC。这样既有 Pipeline 的网络优化（批量发送），又有事务的原子性保证。5）选择建议——只需要批量发送不要求原子性 -> Pipeline。需要命令序列原子执行但不关心网络 RTT -> 事务。两者都需要 -> Pipeline + 事务。需要条件逻辑（if/else）-> Lua 脚本（比事务更灵活）。6）性能对比——Pipeline 批量发送 100 条命令，网络开销从 100 RTT 降为 1 RTT，性能提升显著。事务本身的性能开销很小（主要在命令入队队列的管理上）。","hints":["Pipeline 和事务组合使用时命令的发送与执行顺序是怎样的","在需要原子性保证的同时还想减少网络 RTT 应该怎么做"],"tags":["Redis","Pipeline","事务","MULTI/EXEC","性能优化"],"id":4130},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 键空间通知（Keyspace Notification）的投递保证","content":"Redis 的键空间通知（Keyspace Notification）机制是什么？它如何工作？键空间通知的投递保证是怎样的？有哪些限制和注意事项？","answer":"答案：键空间通知（Keyspace Notification）是 Redis 在密钥发生特定事件（如过期、删除、修改）时通过 Pub/Sub 频道发送通知的机制。通过 notify-keyspace-events 配置启用。投递保证是「即发即弃」（Fire-and-Forget）——如果订阅者不在线，通知会丢失。\n\n解析：1）启用配置——在 redis.conf 中设置 notify-keyspace-events Ex（E 表示 key 事件，x 表示过期事件）。可选事件类型：K（keyspace 事件）、E（keyevent 事件）、g（通用命令）、$（字符串命令）、l（列表命令）、s（集合命令）、h（哈希命令）、z（有序集合命令）、x（过期事件）、e（驱逐事件）、A（所有事件的别名）。2）两种频道——__keyspace@0__:keyname（接收指定 key 的所有事件）和 __keyevent@0__:eventname（接收某种事件的所有 key）。例如 SUBSCRIBE __keyevent@0__:expired 订阅所有过期事件。\n\n扩展延伸：3）投递保证——键空间通知使用 Pub/Sub 实现，不持久化、不重试。如果客户端断开连接，断开期间的所有通知永久丢失。对于需要可靠通知的场景（如缓存过期后的数据同步），应使用 Redis Stream 或外部消息队列。4）性能影响——频繁的键变更（如 TTL 大量 key 同时过期）会产生大量通知消息，可能压垮订阅者或占用网络带宽。建议只订阅需要的事件类型。5）注意事项——Redis 6.0+ 的 ACL 用户可以限制通知权限。Cluster 模式下通知只在本节点发布，不会跨节点广播。7.0+ 增加了 __keyevent@* 通配符订阅支持。6）典型应用——缓存过期后的异步数据刷新、分布式锁过期告警、TTL 到期后的状态清理任务触发。","hints":["键空间通知为什么使用 Pub/Sub 而不是 Stream——历史原因和设计取舍","大量 key 同时过期时键空间通知会产生什么问题"],"tags":["Redis","键空间通知","Pub/Sub","过期事件"],"id":4131},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 主从异步复制数据丢失与应对","content":"默认配置下 Redis 主从架构如果主节点宕机，会丢失多少数据？可能导致数据丢失的场景有哪几种？如何通过配置策略最小化数据丢失风险？","answer":"答案：异步复制下主节点宕机可能丢失 repl-backlog 中的数据（默认 1MB）+ 未刷盘的 AOF 缓冲。通过 min-replicas-to-write、min-replicas-max-lag 和 AOF 刷盘策略可降低风险。\n\n解析：数据丢失场景：1）主节点已写入内存但尚未发送给从节点——这部分数据在复制积压缓冲区（repl-backlog-size 默认 1MB）中。2）主节点内存中的数据尚未写入 AOF 文件或 RDB——取决于持久化策略。\n\n扩展延伸：Reduce risk 策略：1）min-replicas-to-write + min-replicas-max-lag——设置当从节点少于 N 个或延迟超过 M 秒时，主节点拒绝写入。例如 min-replicas-to-write=1 + min-replicas-max-lag=10，保证至少有一个从节点数据同步在 10s 内。2）AOF 持久化——appendfsync always（最安全，每条命令刷盘，性能下降 50-70%）或 everysec（折中）。3）repl-backlog-size 调大（如 64MB-512MB）给从节点更多追赶时间。4）Redis 7.0+ 的 WAITAOF 命令——主节点写后等待指定数量的从节点确认 AOF 刷盘后再返回客户端，类似 Kafka 的 acks=all。","hints":["min-replicas-to-write=2 且只有 1 个从节点时会发生什么——主节点拒绝写入","WAITAOF 与 ACK 机制的相似之处——同步等待副本确认"],"tags":["Redis","主从","复制","数据丢失","高可用"],"id":4142},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 持久化 RDB vs AOF 选择","content":"关于 Redis 的 RDB 和 AOF 持久化机制，以下说法正确的是？","options":["A) RDB 是增量持久化，只记录上次备份以来的数据变更","B) AOF 文件采用二进制格式，因此比 RDB 文件更小","C) RDB 在 bgsave 时会 fork 子进程，fork 期间主进程完全阻塞无法处理任何请求","D) AOF 重写（Rewrite）时 fork 子进程扫描当前内存状态生成最小 AOF 文件，重写期间的新写入缓存在重写缓冲区，重写完成后合并"],"answer":"答案：D)。解析：AOF 重写通过 fork 子进程读取当前内存键值对状态（不是重放旧 AOF），生成最小的 AOF 文件。主进程在此期间继续服务——新数据写请求同时追加到旧 AOF 和重写缓冲区，子进程完成后发信号给主进程，主进程将重写缓冲区内容追加到新 AOF 文件，然后原子替换旧文件。A) 错，RDB 是全量快照（保存某个时间点的所有数据）。B) 错，AOF 是文本协议格式（*N\\r\\n$M\\r\\n 格式），比 RDB 的压缩二进制大得多。C) 错，fork 是系统调用会阻塞主进程（耗时几十到几百毫秒），但 fork 完成后子进程异步写 RDB 不阻塞主进程。","hints":["fork 子进程的写时复制（Copy-On-Write）如何工作——子进程共享主进程的物理页，写入时才复制","Redis 7.0+ 混合持久化如何结合 RDB 和 AOF 优势——RDB 全量 + AOF 增量"],"tags":["Redis","RDB","AOF","持久化","AOF重写"],"id":4143},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 热 Key 与大 Key 的发现与治理","content":"什么是 Redis 的热 Key 和大 Key？各自会导致哪些线上问题？如何自动化发现并系统性治理？","answer":"答案：热 Key 指访问频率极高的 Key（如秒杀商品），导致单节点 CPU 打满。大 Key 指 String > 10MB 或集合元素超万级，导致读写延迟高和阻塞。发现方式：hotkeys 参数、--bigkeys 扫描、客户端统计。\n\n解析：热 Key 发现：1) Redis 6.2+ redis-cli --hotkeys（基于 LFU 的 COUNTER 采样）。2) 客户端侧本地统计（如每 10s 上报 Top N 访问频次）。3) 代理层（Codis/Twemproxy/Redis Enterprise）统一统计。热 Key 影响：单节点 CPU 饱和、网络带宽打满、所有请求集中在一个节点导致整体吞吐受限。大 Key 发现：1) redis-cli --bigkeys 扫描（遍历全库，不建议生产高峰期执行）。2) memory usage key 精确查询内存占用（Redis 4.0+）。大 Key 影响：读/写大 Key 阻塞主线程、集群数据倾斜（部分节点内存高）、删除大 Key 导致主线程卡顿。\n\n扩展延伸：系统性治理方案：热 Key——1）本地缓存（Caffeine/Guava Cache 挡掉大部分请求）。2）读写分离（从节点分担读流量）。3）打散：key:0 到 key:N，客户端随机选择一个访问。4）Redis 7.0+ Function 服务端聚合。大 Key——1）拆分（Hash 拆成多个小 Hash，如 user:123:friends:1···user:123:friends:10）。2）不同类型选择不同数据结构（如用户标签用 Set 而非 String 序列化）。3）渐进删除——DEL 大 Key 用 UNLINK 替代（异步释放内存，Redis 4.0+）。4）集合类型分批——HSCAN/SSCAN 游标遍历避免一次性全量。","hints":["hotkeys 参数依赖 LFU 淘汰策略才能生效——需要设置 maxmemory-policy allkeys-lfu 或 volatile-lfu","为什么 UNLINK 比 DEL 更适合删除大 Key——UNLINK 异步回收内存不阻塞主线程"],"tags":["Redis","热Key","大Key","性能","LFU"],"id":4144},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 过期策略与惰性删除","content":"Redis 对过期 key 的删除策略包括定期删除和惰性删除组合使用。关于定期删除的实现，以下描述正确的是？","options":["A) 每隔 100ms 随机抽查 20 个设置了 TTL 的 key，删除已过期的，如果过期比例超过 25% 则继续抽查，直到低于 25% 或达到时间上限","B) 每秒扫描全库所有设置了 TTL 的 key，全部检查一遍是否过期","C) 仅在 key 被客户端访问时才检查是否过期，过期则删除","D) 使用独立的后台线程逐个遍历所有 key 并删除过期 key"],"answer":"答案：A)。解析：Redis 单线程架构下，定期删除由 serverCron 每 100ms 触发，每次随机取 ACTIVE_EXPIRE_CYCLE_LOOKUPS_PER_LOOP（默认 20）个设置了 TTL 的 key 检查。如果过期比例 > 25%，继续抽查下一批（最多循环 16 次），每次循环耗时上限 25% 的 CPU 时间。这个机制的目的是防止过多过期的 key 同时到期导致 CPU 瞬间飙高。B) 描述的是全量扫描——每 100ms 全量扫描会严重阻塞主线程。C) 是惰性删除（lazy free 中的 lazy expiry），不是定期删除。D) Redis 4.0 的 lazy free 机制虽然用了后台线程，但那是惰性删除和 UNLINK 的场景，不是定期删除。两种删除策略互补：惰性删除确保过期 key 被访问时立即释放，定期删除确保未被访问的过期 key 最终被清理。","hints":["大量 key 同时过期（如缓存雪崩前兆）会导致什么——定期删除循环耗时增加，主线程卡顿","EXPIREAT 和 EXPIRE 的精度问题——过期时间是秒级精度，PEXPIRE 是毫秒级"],"tags":["Redis","过期策略","定期删除","惰性删除","serverCron"],"id":4145},{"category":"database","difficulty":"hard","type":"short_answer","content":"一致性哈希（Consistent Hashing）在 Redis 分片中的应用与局限是什么？虚拟节点解决了什么问题？对比 Redis Cluster 的哈希槽方案，一致性哈希的优劣势在哪里？","title":"Redis 一致性哈希分片与虚拟节点","answer":"答案：一致性哈希将 hash 值空间组织成环，节点和 key 都 hash 到环上，key 沿顺时针找到最近的节点。虚拟节点让每个真实节点映射到多个环上位置，解决数据分布不均的问题。相比 Redis Cluster 的 16384 个固定槽，一致性哈希扩容影响更小但缺乏原生管理能力。\n\n解析：一致性哈希的优势：1）节点增减只影响相邻节点（而不像普通哈希取模导致 N/N-1 比例的数据迁移）。2）虚拟节点（每个真实节点 150-200 个虚拟节点）让环上分布更均匀，动态变化时负载更均衡。\n\n扩展延伸：与 Redis Cluster 哈希槽方案对比：1）数据分布粒度——一致性哈希在环上连续分布，无法精细控制；Redis Cluster 每个主节点管理一段连续的槽位，支持通过 reshare 精确控制迁移量。2）客户端复杂度——一致性哈希客户端需要实现哈希环和虚拟节点映射（如 Jedis 的 ShardedJedis）；Redis Cluster 客户端通过 MOVED/ASK 重定向自动感知路由变化。3）高可用——一致性哈希方案通常额外需要 Sentinel 做故障转移；Redis Cluster 内置主从复制和自动 failover。4）扩缩容——一致性哈希扩容仅影响相邻节点；Redis Cluster 扩缩容需要 re-shard（数据迁移），用 ASK 重定向对外透明。实践建议：中小规模（< 100GB）用 Redis Cluster，有自建代理层需求时用一致性哈希 + 代理（如 Codis/Predis）。","hints":["一致性哈希中环上节点数很少时为什么不均匀——虚拟节点通过增加「粒度」让分布更均匀","Redis Cluster 为什么要用 16384 而不是更多或更少的槽——Gossip 消息大小限制"],"tags":["Redis","一致性哈希","虚拟节点","Redis Cluster","分片"],"id":4146},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 换页策略与内存碎片整理对比","content":"关于 Redis 内存碎片整理（Active Defragmentation）和内存淘汰（Eviction），以下说法正确的是？","options":["A) 内存碎片整理和内存淘汰都在内存不足时触发，两者的作用相同","B) 内存碎片整理通过移动对象合并空闲内存，内存淘汰通过删除 key 释放空间","C) 开启 activedefrag 后可以完全避免内存碎片，不需要监控碎片率","D) 内存碎片整理只在主从切换时触发一次"],"answer":"答案：B) 内存碎片整理通过移动对象合并空闲内存，内存淘汰通过删除 key 释放空间\n\n解析：内存碎片整理（Active Defrag）和内存淘汰是 Redis 两种完全不同的机制。内存碎片整理（activedefrag yes）在后台进程中扫描并移动 Redis 对象，将分散的空闲内存合并为连续可用内存，解决的是内存利用率低的问题（碎片率高时虽然 used_memory 不大但 RSS 占用很高）。内存淘汰（Eviction）是在内存达到 maxmemory 阈值时，根据淘汰策略删除 key 来释放内存——它解决的是内存不足的问题。\n\n扩展延伸：Active Defrag 的参数控制：active-defrag-ignore-bytes 100MB（碎片大小超过此值启动）、active-defrag-threshold-lower 10（碎片率超过 10% 启动）。碎片整理期间 CPU 使用率会上升，可通过 active-defrag-cycle-min/max 控制 CPU 时间占比。主动碎片整理无法完全消除碎片——当碎片率过高（> 1.5）且影响系统稳定性时，最佳方案是主从切换或重启（重新加载 RDB 后内存连续）。mem_fragmentation_ratio = used_memory_rss / used_memory，大于 1.5 需关注，小于 1 说明使用了 swap（危险）。","hints":["mem_fragmentation_ratio > 1.5 和 < 1 各代表什么","RDB 重加载为什么能解决碎片问题"],"tags":["Redis","内存碎片","主动整理","淘汰策略"],"id":4147},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis Cluster 集群脑裂与数据丢失","content":"Redis Cluster 在网络分区时可能发生脑裂（Split-brain）吗？Cluster 模式下主节点宕机导致数据丢失的场景有哪些？如何配置减少数据丢失风险？","answer":"答案：Redis Cluster 在设计上存在脑裂窗口。当主节点（Master）与集群中大多数节点网络隔离时，Cluster 会从该主节点的从节点（Slave）中选举新主。但原主节点可能认为自己是合法的，继续接受写入请求。网络恢复后，原主节点降级为从节点，其数据被新主节点覆盖（脑裂期间写入的数据丢失）。这是 Redis Cluster 在 AP 和 CP 之间权衡的结果——保证可用性优先于强一致性。\n\n解析：除了脑裂，主节点宕机时数据丢失的场景包括：1）未同步的数据：主节点宕机时，从节点的数据未追上主节点（复制滞后），新主节点的数据比原主节点少。2）异步复制：Redis 主从复制默认是异步的，主节点返回客户端写入成功时数据可能还没复制到从节点。3）全量同步覆盖：从节点重新同步时，如果持久化配置不当，重启后加载到旧的 RDB 文件。\n\n扩展延伸：减少数据丢失风险的配置：1）min-replicas-to-write 1（至少有一个从节点连接时才可写）和 min-replicas-max-lag 10（从节点延迟超过 10s 时禁止写入）。这两个配置让主节点在从节点数量不足或延迟过大时拒绝写入，减少脑裂和复制滞后导致的数据丢失。2）设置合适的 repl-backlog-size（默认 1MB，建议增大到 64-256MB）让从节点在断线重连后有更大的概率做部分重同步而非全量同步。3）开启主节点和从节点的 AOF 持久化（appendfsync everysec）。注意：这些配置不能完全消除数据丢失，只能将丢失窗口缩小到秒级。对于不能接受任何数据丢失的场景，应考虑 ZooKeeper/etcd 等强一致性系统。","hints":["min-replicas-to-write 如何减少脑裂造成的数据丢失","repl-backlog-size 为什么影响部分重同步的成功率"],"tags":["Redis","Cluster","脑裂","数据丢失"],"id":4148},{"category":"database","difficulty":"medium","type":"short_answer","title":"Redis 客户端缓存（Client-side Caching）","content":"什么是 Redis 6.0+ 的客户端缓存（Client-side Caching，也称 Tracking）？它是如何工作的？与本地缓存相比有什么优势？","answer":"答案：Redis 6.0+ 的客户端缓存（Tracking）是一种服务器端协助的客户端缓存机制。Redis 服务端跟踪客户端访问了哪些 key，当 key 发生变更时主动通知客户端使失效缓存。这解决了传统客户端缓存中缓存一致性的难题——客户端不再需要设置固定的过期时间来猜测缓存何时失效。\n\n解析：两种模式：1）默认模式（Tracking 非连接关联）——服务端记录全局映射表（key → client ID），当 key 被修改时向所有缓存了该 key 的客户端发送 invalidation 消息。2）OPTIN/OPTOUT 模式——客户端通过 CLIENT TRACKING ON|OFF 控制是否参与缓存跟踪。\n\n扩展延伸：实现机制：1）客户端通过 HELLO 3（RESP3 协议）或 CLIENT TRACKING ON 启用。2）服务端在 Internally maintained 的 Tracking Table（全局失效表）中记录每个 client 缓存的 key 列表。3）当 key 被修改（SET/EXPIRE/DEL/FLUSHDB 等）时，服务端广播 Invalidation Message 到相关客户端。4）客户端收到 Invalidation Message 后淘汰本地缓存，下次读取时重新从 Redis 获取。优势：相比本地缓存的固定 TTL（要么不一致要么过短频繁刷新），Redis Tracking 实现了「精准失效」——key 没变就一直用缓存，变了立刻通知。劣势：Tracking Table 占 Redis 内存（每个被缓存的 key 存一条记录），且网络分区时可能丢失失效消息。适用场景：高并发读少写场景（如配置信息、数据字典）。","hints":["Redis Tracking 与等过期时间本地缓存的本质区别","Tracking Table 的内存开销如何控制"],"tags":["Redis","客户端缓存","Tracking","RESP3"],"id":4149},{"category":"database","difficulty":"hard","type":"short_answer","title":"Redis 阻塞命令排查与异步化改造","content":"Redis 单线程模型下，哪些命令会导致长时间阻塞？如何排查阻塞原因？Redis 4.0+ 的懒删除（Lazy Free）机制如何缓解阻塞？","answer":"答案：Redis 是单线程执行命令，以下操作会长时间阻塞主线程：O(N) 命令（KEYS *、SMEMBERS、HGETALL 等在大集合上执行）、大 key 删除（DEL 一个包含数百万元素的 Set/List/ZSet）、大 key 的阻塞弹出（BRPOP/BLPOP 等）、AOF rewrite 和 RDB bgsave 的 fork 子进程（fork 本身可能阻塞数十毫秒到秒级）、慢查询（如复杂的 Lua 脚本）。\n\n解析：排查阻塞的方法：1）SLOWLOG GET——查看慢查询日志，检查执行时间超过阈值的命令。2）LATENCY DOCTOR/GRAPH/HISTORY——Redis 内建延迟诊断工具，自动分析延迟峰值的原因。3）redis-cli --intrinsic-latency 100——测试 Redis 服务器的原生延迟。4）INFO COMMANDSTATS——查看各命令的调用次数和总耗时。5）MONITOR（生产慎用，本身消耗性能）。\n\n扩展延伸：懒删除（Lazy Free，Redis 4.0+）：将大 key 的释放操作放到后台线程执行，避免阻塞主线程。命令：UNLINK（替代 DEL，O(1) 返回，后台异步释放内存）、FLUSHDB ASYNC / FLUSHALL ASYNC（异步清空数据库）。LAZY-FREE 的相关配置：lazyfree-lazy-eviction（淘汰数据时异步释放）、lazyfree-lazy-expire（过期 key 异步释放）、lazyfree-lazy-server-del（隐式 DEL 操作异步化）、replica-lazy-flush（从节点全量同步时异步清空旧数据）。注意：UNLINK 不保证立即释放内存——后台线程需要时间回收。但主线程的操作是 O(1) 的，不阻塞。对于大 Hash 的字段删除，使用 HSCAN + HDEL 分批处理，或直接用 UNLINK 删除整个 key 再重新构建。","hints":["如何通过 SLOWLOG 和 LATENCY 命令定位阻塞来源","UNLINK 和 DEL 的本质区别"],"tags":["Redis","阻塞","Lazy Free","排查"],"id":4150},{"category":"database","difficulty":"medium","type":"choice","title":"Redis 内存碎片形成原因","content":"以下哪种操作最容易导致 Redis 产生内存碎片？","options":["A) 持续写入固定长度的 String 类型数据","B) 频繁创建和删除不同大小的 key，且 key 的大小分布离散","C) 只使用 List 类型进行 LPUSH/LPOP 操作（队列模式）","D) 在 Cluster 模式下，所有 key 均匀分布到各节点"],"answer":"答案：B) 频繁创建和删除不同大小的 key，且 key 的大小分布离散\n\n解析：Redis 使用 jemalloc 内存分配器，它通过固定 size class（如 8、16、32、64、128、256、512 字节等）分配内存。当 key 的值大小与分配器的 size class 不完全匹配时会产生内部碎片。频繁创建和删除不同大小的 key，且 key 大小离散分布时，jemalloc 的底层 page（连续内存块）会被拆分成不同大小的 chunk，后续分配时无法完全利用这些碎片空间，形成外部碎片。例如：先存一个 100 字节的值（占用 128B size class，浪费 28 字节），然后删除它，再存一个 200 字节的值（占用 256B size class），100 字节留下的 128B 碎片无法被 200 字节利用。\n\n扩展延伸：选项分析：A：固定长度的 String 持续写入会产生可预测的分配模式，碎片较少（每次分配同样的 size class，删除后新分配可以复用）。C：LPUSH/LPOP 操作队列模式，对象大小基本固定且生命周期短，碎片率低。D：Cluster 分片与内存碎片没有直接关系（数据分布到不同节点不影响单个节点的内存分配模式）。减少碎片的实践：1）尽量统一 key 的 value 大小分布（避免又大又小混杂）。2）对于已知会频繁增删的 key，考虑预留一定空间。3）碎片率 > 1.5 时开启 activedefrag，或通过主从切换重新加载 RDB。","hints":["为什么 key 大小离散比 key 大小统一更容易产生碎片","jemalloc 的 size class 机制如何影响碎片率"],"tags":["Redis","内存碎片","jemalloc","性能"],"id":4151}];
